    fn call_list_subclass(
        &mut self,
        name: String,
        attrs: Scope,
        bases: Vec<Value>,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let has_own_new = attrs.borrow().contains_key("__new__");
        if has_own_new {
            let class = Value::Class {
                name: name.clone(),
                type_params: Vec::new(),
                metaclass: None,
                bases: bases.clone(),
                attrs: attrs.clone(),
            };
            let instance =
                self.call_user_new(&class, &attrs, args.clone(), keywords.clone(), "__new__")?;
            if !value_matches_class_value(&instance, &class) {
                return Ok(instance);
            }
            if let Some(init) = find_class_attr(&attrs, &[], "__init__") {
                let result = self.call_value_with_keywords(
                    bind_method(init, instance.clone()),
                    args,
                    keywords,
                )?;
                if !matches!(result, Value::None) {
                    return Err("__init__() should return None".to_string());
                }
            } else {
                self.initialize_list_storage(&instance, args, keywords)?;
            }
            return Ok(instance);
        }

        let has_own_init = attrs.borrow().contains_key("__init__");
        let storage = if has_own_init {
            list_value(Vec::new())
        } else {
            if !keywords.is_empty() {
                return Err("TypeError: list() takes no keyword arguments".to_string());
            }
            self.call_list(args.clone())?
        };
        let Value::List(storage) = storage else {
            unreachable!("list constructor always returns a list")
        };
        let fields = new_scope();
        fields.borrow_mut().insert(
            LIST_SUBCLASS_STORAGE_FIELD.to_string(),
            Value::List(storage),
        );

        let instance = Value::Instance {
            class_name: name,
            fields,
            class_attrs: attrs.clone(),
            class_bases: bases,
        };

        if has_own_init && let Some(init) = find_class_attr(&attrs, &[], "__init__") {
            let result =
                self.call_value_with_keywords(bind_method(init, instance.clone()), args, keywords)?;
            if !matches!(result, Value::None) {
                return Err("__init__() should return None".to_string());
            }
        }

        Ok(instance)
    }

    fn initialize_list_storage(
        &mut self,
        instance: &Value,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<(), String> {
        if !keywords.is_empty() {
            return Err("TypeError: list() takes no keyword arguments".to_string());
        }
        let values = match args.as_slice() {
            [] => Vec::new(),
            [value] => self.collect_iterable_values(value.clone())?,
            values => {
                return Err(format!(
                    "list() expected at most 1 argument, got {}",
                    values.len()
                ));
            }
        };
        let storage = list_subclass_storage(instance).expect("matching list subclass has storage");
        *storage.borrow_mut() = values;
        Ok(())
    }

    fn call_set_subclass(
        &mut self,
        name: String,
        type_params: Vec<Value>,
        attrs: Scope,
        bases: Vec<Value>,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let has_own_new = attrs.borrow().contains_key("__new__");
        if has_own_new {
            let class = Value::Class {
                name: name.clone(),
                type_params,
                metaclass: None,
                bases: bases.clone(),
                attrs: attrs.clone(),
            };
            let instance =
                self.call_user_new(&class, &attrs, args.clone(), keywords.clone(), "__new__")?;
            if !value_matches_class_value(&instance, &class) {
                return Ok(instance);
            }
            if let Some(init) = find_class_attr(&attrs, &[], "__init__") {
                let result = self.call_value_with_keywords(
                    bind_method(init, instance.clone()),
                    args,
                    keywords,
                )?;
                if !matches!(result, Value::None) {
                    return Err("__init__() should return None".to_string());
                }
                return Ok(instance);
            }

            let init = Value::BoundMethod {
                function: Box::new(Value::Builtin("set.__init__".to_string())),
                receiver: Box::new(instance.clone()),
                identity: Rc::new(()),
            };
            let result = self.call_value_with_keywords(init, args, keywords)?;
            if !matches!(result, Value::None) {
                return Err("__init__() should return None".to_string());
            }
            return Ok(instance);
        }

        let fields = new_scope();
        let has_own_init = attrs.borrow().contains_key("__init__");
        let storage = if has_own_init {
            self.build_set(Vec::new())?
        } else {
            if !keywords.is_empty() {
                return Err("TypeError: set() takes no keyword arguments".to_string());
            }
            self.call_set(args.clone())?
        };
        fields
            .borrow_mut()
            .insert(SET_SUBCLASS_STORAGE_FIELD.to_string(), storage);

        let instance = Value::Instance {
            class_name: name.clone(),
            fields,
            class_attrs: attrs.clone(),
            class_bases: bases.clone(),
        };

        if has_own_init && let Some(init) = find_class_attr(&attrs, &[], "__init__") {
            let result =
                self.call_value_with_keywords(bind_method(init, instance.clone()), args, keywords)?;
            if !matches!(result, Value::None) {
                return Err("__init__() should return None".to_string());
            }
        }

        Ok(instance)
    }

