    fn call_json_function_get(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((function, rest)) = args.split_first() else {
            return Err("TypeError: __get__() expected a function receiver".to_string());
        };
        let function = function.clone();
        let Value::Builtin(function_name) = &function else {
            return Err("TypeError: __get__() expected a function receiver".to_string());
        };
        if !is_json_builtin(function_name) {
            return Err("TypeError: __get__() expected a json function receiver".to_string());
        }
        descriptor_get_reject_method_wrapper_args("__get__", rest, &keywords)?;
        if matches!(rest[0], Value::None) {
            let owner_missing_or_none = match rest.get(1) {
                Some(owner) => matches!(owner, Value::None),
                None => true,
            };
            if owner_missing_or_none {
                return Err("TypeError: __get__(None, None) is invalid".to_string());
            }
            return Ok(function);
        }

        Ok(Value::BoundMethod {
            function: Box::new(function),
            receiver: Box::new(rest[0].clone()),
            identity: Rc::new(()),
        })
    }

    fn super_descriptor_get(
        &mut self,
        descriptor: Value,
        object: Value,
        owner: Option<Value>,
    ) -> Result<Value, String> {
        let Value::Super {
            class,
            object: current_object,
            identity,
        } = descriptor
        else {
            unreachable!("super_descriptor_get is only called with super values");
        };

        let descriptor = Value::Super {
            class: class.clone(),
            object: current_object.clone(),
            identity: identity.clone(),
        };
        if !matches!(current_object.as_ref(), Value::None) {
            return Ok(descriptor);
        }
        if matches!(object, Value::None) {
            if owner
                .as_ref()
                .is_some_and(|owner| !matches!(owner, Value::None))
            {
                return Ok(descriptor);
            }
            return Err("TypeError: __get__(None, None) is invalid".to_string());
        }

        validate_super_args(&class, &object)?;
        Ok(Value::Super {
            class,
            object: Box::new(object),
            identity: Rc::new(()),
        })
    }

    fn load_super_attribute(
        &mut self,
        class: Value,
        object: Value,
        identity: Rc<()>,
        name: &str,
    ) -> Result<Value, String> {
        if name == "__class__" {
            return Ok(Value::Builtin("super".to_string()));
        }
        if name == "__thisclass__" {
            return Ok(class);
        }
        if name == "__self__" {
            return Ok(object);
        }
        if name == "__self_class__" {
            if matches!(object, Value::None) {
                return Ok(Value::None);
            }
            return super_lookup_owner_class(&class, &object);
        }
        if name == "__get__" {
            return Ok(Value::BoundMethod {
                function: Box::new(Value::Builtin("super.__get__".to_string())),
                receiver: Box::new(Value::Super {
                    class: Box::new(class),
                    object: Box::new(object),
                    identity,
                }),
                identity: Rc::new(()),
            });
        }
        if matches!(object, Value::None) {
            return Err(format!(
                "AttributeError: 'super' object has no attribute '{name}'"
            ));
        }

        let owner = super_lookup_owner_class(&class, &object)?;
        let mro = class_mro(&owner)?;
        let Some(start_index) = mro
            .iter()
            .position(|candidate| same_class_value(candidate, &class))
        else {
            return Err(
                "TypeError: super(type, obj): obj must be an instance or subtype of type"
                    .to_string(),
            );
        };

        for candidate in mro.iter().skip(start_index + 1) {
            if let Value::Builtin(type_name) = candidate {
                if type_name == "type" && name == "__new__" {
                    return Ok(Value::Builtin(format!("type.{name}")));
                }
                if type_name == "type" && name == "__init__" {
                    return Ok(Value::BoundMethod {
                        function: Box::new(Value::Builtin("type.__init__".to_string())),
                        receiver: Box::new(object.clone()),
                        identity: Rc::new(()),
                    });
                }
                if type_name == "type" && name == "__prepare__" {
                    return Ok(Value::Builtin("type.__prepare__".to_string()));
                }
                if type_name == "object" && name == "__new__" {
                    return Ok(Value::Builtin("object.__new__".to_string()));
                }
                if type_name == "float" && name == "__new__" {
                    return Ok(Value::Builtin("float.__new__".to_string()));
                }
                if type_name == "complex" && name == "__new__" {
                    return Ok(Value::Builtin("complex.__new__".to_string()));
                }
                if type_name == "str" && name == "__new__" {
                    return Ok(Value::Builtin("str.__new__".to_string()));
                }
                if type_name == "array.array" && name == "__new__" {
                    return Ok(Value::Builtin("array.array.__new__".to_string()));
                }
                if ast_builtin_kind(type_name).is_some() && name == "__init__" {
                    let kind = ast_builtin_kind(type_name).expect("guard checked AST builtin kind");
                    return Ok(Value::BoundMethod {
                        function: Box::new(Value::Builtin(format!("ast.{kind}.__init__"))),
                        receiver: Box::new(object.clone()),
                        identity: Rc::new(()),
                    });
                }
                if is_builtin_set_type_method(type_name, name) {
                    if name == "__new__" {
                        return Ok(Value::Builtin(format!("{type_name}.{name}")));
                    }
                    return Ok(Value::BoundMethod {
                        function: Box::new(Value::Builtin(format!("{type_name}.{name}"))),
                        receiver: Box::new(object.clone()),
                        identity: Rc::new(()),
                    });
                }
                if type_name == "SimpleNamespace" && name == "__new__" {
                    return Ok(Value::Builtin("SimpleNamespace.__new__".to_string()));
                }
                if type_name == "dict" && is_builtin_dict_type_method(name) {
                    return Ok(Value::BoundMethod {
                        function: Box::new(Value::Builtin(format!("dict.{name}"))),
                        receiver: Box::new(object.clone()),
                        identity: Rc::new(()),
                    });
                }
                if type_name == "ChainMap" && is_builtin_chain_map_type_method(name) {
                    return Ok(Value::BoundMethod {
                        function: Box::new(Value::Builtin(format!("ChainMap.{name}"))),
                        receiver: Box::new(object.clone()),
                        identity: Rc::new(()),
                    });
                }
                if type_name == "complex" && is_builtin_complex_type_method(name) {
                    return Ok(Value::BoundMethod {
                        function: Box::new(Value::Builtin(format!("complex.{name}"))),
                        receiver: Box::new(object.clone()),
                        identity: Rc::new(()),
                    });
                }
                if type_name == "Hashable" && name == "__hash__" {
                    return Ok(Value::BoundMethod {
                        function: Box::new(Value::Builtin("Hashable.__hash__".to_string())),
                        receiver: Box::new(object.clone()),
                        identity: Rc::new(()),
                    });
                }
                if let Some(method) = collections_abc_builtin_mixin_method(type_name, name) {
                    return Ok(Value::BoundMethod {
                        function: Box::new(Value::Builtin(method.to_string())),
                        receiver: Box::new(object.clone()),
                        identity: Rc::new(()),
                    });
                }
                continue;
            }

            let Value::Class { attrs, .. } = candidate else {
                continue;
            };
            let Some(value) = attrs.borrow().get(name).cloned() else {
                continue;
            };

            let descriptor_object = if matches!(object, Value::Class { .. }) {
                Value::None
            } else {
                object.clone()
            };
            if let Some(descriptor_value) =
                self.descriptor_get(value.clone(), descriptor_object, owner.clone())?
            {
                return Ok(descriptor_value);
            }
            if matches!(object, Value::Class { .. }) {
                return Ok(value);
            }
            return Ok(bind_method(value, object.clone()));
        }

        Err(format!(
            "AttributeError: 'super' object has no attribute '{name}'"
        ))
    }

    fn descriptor_set(
        &mut self,
        descriptor: Value,
        object: Value,
        value: Value,
    ) -> Result<(), String> {
        if matches!(descriptor, Value::Property { .. }) {
            return self.property_set(descriptor, object, value);
        }
        if matches!(descriptor, Value::MemberDescriptor { .. }) {
            return self.member_descriptor_set(descriptor, object, value);
        }
        let Some(set) = instance_special_method(&descriptor, "__set__") else {
            return Err("AttributeError: __set__".to_string());
        };
        self.call_value(set, vec![object, value])?;
        Ok(())
    }

    fn descriptor_delete(&mut self, descriptor: Value, object: Value) -> Result<(), String> {
        if matches!(descriptor, Value::Property { .. }) {
            return self.property_delete(descriptor, object);
        }
        if matches!(descriptor, Value::MemberDescriptor { .. }) {
            return self.member_descriptor_delete(descriptor, object);
        }
        let Some(delete) = instance_special_method(&descriptor, "__delete__") else {
            return Err("AttributeError: __delete__".to_string());
        };
        self.call_value(delete, vec![object])?;
        Ok(())
    }

    fn load_attribute_catching(
        &mut self,
        object: Value,
        name: &str,
    ) -> Result<Result<Value, MiniException>, String> {
        self.call_with_exception_capture(|vm| vm.load_attribute_value(object, name))
    }

    fn call_value_catching(
        &mut self,
        callee: Value,
        args: Vec<Value>,
    ) -> Result<Result<Value, MiniException>, String> {
        self.call_with_exception_capture(|vm| vm.call_value(callee, args))
    }

    fn call_value_with_keywords_catching(
        &mut self,
        callee: Value,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Result<Value, MiniException>, String> {
        self.call_with_exception_capture(|vm| vm.call_value_with_keywords(callee, args, keywords))
    }

    fn call_with_exception_capture<F>(
        &mut self,
        call: F,
    ) -> Result<Result<Value, MiniException>, String>
    where
        F: FnOnce(&mut Self) -> Result<Value, String>,
    {
        let saved_handlers = std::mem::take(&mut self.exception_handlers);
        let previous_exception = self.current_exception.clone();
        let previous_pending_exception = self.pending_exception_after_clear.clone();
        let result = call(self);
        let raised_exception = self.current_exception.clone();
        self.exception_handlers = saved_handlers;
        self.current_exception = previous_exception;
        self.pending_exception_after_clear = previous_pending_exception;

        match result {
            Ok(value) => Ok(Ok(value)),
            Err(message) => {
                if let Some(exception) =
                    runtime_exception_from_current_or_message(raised_exception, &message)
                {
                    Ok(Err(exception))
                } else {
                    Err(message)
                }
            }
        }
    }

    fn raise_runtime_exception_value(&mut self, exception: MiniException) -> Result<Value, String> {
        self.raise_exception(exception, true)?;
        Ok(Value::None)
    }

    fn remember_runtime_exception_error(&mut self, exception: MiniException) -> String {
        let message = format_exception_error(&exception);
        self.current_exception = Some(exception);
        message
    }

    fn load_subscript_value(&mut self, object: Value, index: Value) -> Result<Value, String> {
        if let Value::WeakProxy { target, .. } = &object {
            return self.load_subscript_value(target.as_ref().clone(), index);
        }

        if let Value::MappingProxyObject { mapping, .. } = object {
            return self.load_subscript_value(*mapping, index);
        }

        if let Some(method) = instance_special_method(&object, "__getitem__") {
            return self.call_value(method, vec![index]);
        }

        if let Some(items) = list_subclass_storage(&object) {
            return load_subscript(Value::List(items), index);
        }

        if let Some(items) = tuple_subclass_items(&object) {
            return load_subscript(Value::Tuple(items), index);
        }

        if let Some(entries) = counter_subclass_entries(&object) {
            ensure_hashable_key(&index)?;
            return Ok(entries
                .borrow()
                .iter()
                .find(|(key, _)| dict_keys_equal(key, &index))
                .map(|(_, value)| value.clone())
                .unwrap_or(Value::Number(0)));
        }

        if let Some(entries) = dict_subclass_entries(&object) {
            return self.load_dict_subclass_subscript(object, entries, index);
        }

        if let Some(data) = user_dict_subclass_data(&object) {
            return self.load_user_dict_subclass_subscript(object, data, index);
        }

        if let Some(maps) = chain_map_subclass_maps(&object) {
            return self.chain_map_get_item_for_receiver(&object, &maps, index);
        }

        if let Value::DefaultDict {
            entries,
            default_factory,
        } = &object
        {
            return self.load_default_dict_subscript(
                entries.clone(),
                default_factory.borrow().clone(),
                index,
            );
        }

        if let Value::ChainMap { maps } = &object {
            let maps = maps.clone();
            return self.chain_map_get_item_for_receiver(&object, &maps, index);
        }

        if let Value::MemoryView(view) = &object {
            return match index {
                Value::Slice {
                    start, stop, step, ..
                } => self.load_memoryview_slice_subscript(view.clone(), start, stop, step),
                index => {
                    let index = self.memoryview_tuple_subscript_index(view, index, false)?;
                    load_subscript(object, index)
                }
            };
        }

        let index = if uses_sequence_index_protocol(&object) {
            self.sequence_subscript_index(index)?
        } else {
            index
        };

        load_subscript_or_raise_key_error(self, object, index)
    }

    fn load_dict_subclass_subscript(
        &mut self,
        object: Value,
        entries: DictRef,
        key: Value,
    ) -> Result<Value, String> {
        ensure_hashable_key(&key)?;
        if let Some((_, value)) = entries
            .borrow()
            .iter()
            .find(|(existing_key, _)| dict_keys_equal(existing_key, &key))
        {
            return Ok(value.clone());
        }
        if let Some(missing) = instance_special_method(&object, "__missing__") {
            return self.call_value(missing, vec![key]);
        }
        self.raise_runtime_exception_value(key_error_exception(key))
    }

    fn load_user_dict_subclass_subscript(
        &mut self,
        object: Value,
        data: DictRef,
        key: Value,
    ) -> Result<Value, String> {
        ensure_hashable_key(&key)?;
        if let Some((_, value)) = data
            .borrow()
            .iter()
            .find(|(existing_key, _)| dict_keys_equal(existing_key, &key))
        {
            return Ok(value.clone());
        }
        if let Some(missing) = instance_special_method(&object, "__missing__") {
            return self.call_value(missing, vec![key]);
        }
        self.raise_runtime_exception_value(key_error_exception(key))
    }

    fn load_default_dict_subscript(
        &mut self,
        entries: DictRef,
        default_factory: Value,
        key: Value,
    ) -> Result<Value, String> {
        ensure_hashable_key(&key)?;
        if let Some((_, value)) = entries
            .borrow()
            .iter()
            .find(|(existing_key, _)| dict_keys_equal(existing_key, &key))
        {
            return Ok(value.clone());
        }
        if matches!(default_factory, Value::None) {
            return self.raise_runtime_exception_value(key_error_exception(key));
        }

        let value = self.call_value(default_factory, Vec::new())?;
        insert_live_dict_entry(&mut entries.borrow_mut(), key, value.clone())?;
        Ok(value)
    }

    fn store_subscript_value(
        &mut self,
        object: Value,
        index: Value,
        value: Value,
    ) -> Result<Value, String> {
        if let Value::WeakProxy {
            target,
            callable,
            identity,
        } = object
        {
            self.store_subscript_value(target.as_ref().clone(), index, value)?;
            return Ok(Value::WeakProxy {
                target,
                callable,
                identity,
            });
        }

        if matches!(object, Value::MappingProxyObject { .. }) {
            return Err(
                "TypeError: 'mappingproxy' object does not support item assignment".to_string(),
            );
        }

        if let Some(method) = instance_special_method(&object, "__setitem__") {
            self.call_value(method, vec![index, value])?;
            return Ok(object);
        }

        if let Some(items) = list_subclass_storage(&object) {
            store_subscript(Value::List(items), index, value)?;
            return Ok(object);
        }

        if let Value::MemoryView(view) = &object {
            return match index {
                Value::Slice {
                    start, stop, step, ..
                } => {
                    let index = self.sequence_subscript_index(Value::Slice {
                        start,
                        stop,
                        step,
                        identity: Rc::new(()),
                    })?;
                    store_subscript(object, index, value)
                }
                index => {
                    let index = self.memoryview_tuple_subscript_index(view, index, true)?;
                    self.store_memoryview_item_value(view.clone(), index, value)
                }
            };
        }

        if let Some(maps) = chain_map_subclass_maps(&object) {
            chain_map_set_item(&maps, index, value)?;
            return Ok(object);
        }

        if array_array_storage(&object).is_some() {
            return self.store_array_array_subscript_value(object, index, value);
        }

        let index = if uses_sequence_index_protocol(&object) {
            self.sequence_subscript_index(index)?
        } else {
            index
        };

        if let Value::ByteArray(bytes) = &object
            && !matches!(index, Value::Slice { .. })
        {
            let index = normalized_index(index, bytes.borrow().len(), "bytearray")?;
            let byte = self.bytearray_assignment_byte_value(value)?;
            let mut borrowed = bytes.borrow_mut();
            if let Some(slot) = borrowed.get_mut(index) {
                *slot = byte;
                return Ok(Value::ByteArray(bytes.clone()));
            }
            return Err("bytearray index out of range".to_string());
        }

        store_subscript(object, index, value)
    }

    fn delete_subscript_value(&mut self, object: Value, index: Value) -> Result<Value, String> {
        if let Value::WeakProxy {
            target,
            callable,
            identity,
        } = object
        {
            self.delete_subscript_value(target.as_ref().clone(), index)?;
            return Ok(Value::WeakProxy {
                target,
                callable,
                identity,
            });
        }

        if matches!(object, Value::MappingProxyObject { .. }) {
            return Err(
                "TypeError: 'mappingproxy' object does not support item deletion".to_string(),
            );
        }

        if let Some(method) = instance_special_method(&object, "__delitem__") {
            self.call_value(method, vec![index])?;
            return Ok(object);
        }

        if let Some(items) = list_subclass_storage(&object) {
            delete_subscript(Value::List(items), index)?;
            return Ok(object);
        }

        if let Some(maps) = chain_map_subclass_maps(&object) {
            if let Err(message) = chain_map_delete_item(&maps, index) {
                if let Some(payload) = chain_map_first_mapping_key_error_payload(&message) {
                    raise_key_error_string(self, payload)?;
                    return Ok(object);
                }
                return Err(message);
            }
            return Ok(object);
        }

        if let Value::ChainMap { maps } = &object {
            if let Err(message) = chain_map_delete_item(maps, index) {
                if let Some(payload) = chain_map_first_mapping_key_error_payload(&message) {
                    raise_key_error_string(self, payload)?;
                    return Ok(object);
                }
                return Err(message);
            }
            return Ok(object);
        }

        if array_array_storage(&object).is_some() {
            return self.delete_array_array_subscript_value(object, index);
        }

        let index = if uses_sequence_index_protocol(&object) {
            self.sequence_subscript_index(index)?
        } else {
            index
        };

        match object {
            Value::Dict(entries) => {
                ensure_hashable_key(&index)?;
                if remove_mapping_entry(&entries, &index)? {
                    return Ok(Value::Dict(entries));
                }
                raise_key_error_value(self, index)?;
                Ok(Value::Dict(entries))
            }
            Value::OrderedDict(entries) => {
                ensure_hashable_key(&index)?;
                if remove_mapping_entry(&entries, &index)? {
                    return Ok(Value::OrderedDict(entries));
                }
                raise_key_error_value(self, index)?;
                Ok(Value::OrderedDict(entries))
            }
            object if dict_subclass_entries(&object).is_some() => {
                ensure_hashable_key(&index)?;
                let entries = dict_subclass_entries(&object)
                    .expect("dict subclass entries exist after guard");
                if remove_mapping_entry(&entries, &index)? {
                    return Ok(object);
                }
                raise_key_error_value(self, index)?;
                Ok(object)
            }
            Value::UserDict { data, attrs } => {
                ensure_hashable_key(&index)?;
                if remove_mapping_entry(&data, &index)? {
                    return Ok(Value::UserDict { data, attrs });
                }
                raise_key_error_value(self, index)?;
                Ok(Value::UserDict { data, attrs })
            }
            object if user_dict_subclass_data(&object).is_some() => {
                ensure_hashable_key(&index)?;
                let data = user_dict_subclass_data(&object)
                    .expect("UserDict subclass data exists after guard");
                if remove_mapping_entry(&data, &index)? {
                    return Ok(object);
                }
                raise_key_error_value(self, index)?;
                Ok(object)
            }
            object => delete_subscript(object, index),
        }
    }

    fn sequence_subscript_index(&mut self, index: Value) -> Result<Value, String> {
        match index {
            Value::Slice {
                start, stop, step, ..
            } => Ok(Value::Slice {
                start: self.index_slice_part(start)?,
                stop: self.index_slice_part(stop)?,
                step: self.index_slice_part(step)?,
                identity: Rc::new(()),
            }),
            value => self.maybe_index_integer_value(value),
        }
    }

    fn memoryview_tuple_subscript_index(
        &mut self,
        view: &MemoryViewRef,
        index: Value,
        assignment: bool,
    ) -> Result<Value, String> {
        let Value::Tuple(items) = index else {
            if memoryview_ndim(view)? == 0 {
                return Err("TypeError: invalid indexing of 0-dim memory".to_string());
            }
            return self.maybe_index_integer_value(index);
        };

        if items.is_empty() {
            if memoryview_ndim(view)? == 0 {
                return Ok(Value::Number(0));
            }
            return Err("NotImplementedError: sub-views are not implemented".to_string());
        }

        let has_slice = items.iter().any(|item| matches!(item, Value::Slice { .. }));
        if has_slice {
            if items.iter().all(|item| matches!(item, Value::Slice { .. })) {
                let message = if assignment {
                    "memoryview slice assignments are currently restricted to ndim = 1"
                } else {
                    "multi-dimensional slicing is not implemented"
                };
                return Err(format!("NotImplementedError: {message}"));
            }
            return Err("TypeError: memoryview: invalid slice key".to_string());
        }

        let mut normalized = Vec::with_capacity(items.len());
        for item in items.as_ref() {
            let item = self.maybe_index_integer_value(item.clone())?;
            if !matches!(item, Value::Number(_) | Value::BigInt(_)) {
                return Err("TypeError: memoryview: invalid slice key".to_string());
            }
            normalized.push(item);
        }

        if normalized.len() == 1 {
            return Ok(normalized.remove(0));
        }

        Err(format!(
            "TypeError: cannot index 1-dimension view with {}-element tuple",
            normalized.len()
        ))
    }

    fn index_slice_part(
        &mut self,
        value: Option<Box<Value>>,
    ) -> Result<Option<Box<Value>>, String> {
        match value.map(|value| *value) {
            None | Some(Value::None) => Ok(None),
            Some(value) => self
                .maybe_index_integer_value(value)
                .map(|value| Some(Box::new(value))),
        }
    }

    fn load_memoryview_slice_subscript(
        &mut self,
        view: MemoryViewRef,
        start: Option<Box<Value>>,
        stop: Option<Box<Value>>,
        step: Option<Box<Value>>,
    ) -> Result<Value, String> {
        let (
            bytes,
            obj,
            exported_bytearray,
            source_offset,
            source_len,
            source_stride,
            readonly,
            format,
        ) = {
            let state = view.borrow();
            if state.released {
                return Err(released_memoryview_error());
            }
            (
                state.bytes.clone(),
                state.obj.clone(),
                state.exported_bytearray.clone(),
                state.offset,
                state.len,
                state.stride,
                state.readonly,
                state.format.clone(),
            )
        };

        let start = self.index_slice_part(start)?.map(|value| *value);
        let stop = self.index_slice_part(stop)?.map(|value| *value);
        let step = self.index_slice_part(step)?.map(|value| *value);
        let start = slice_bound(start)?;
        let stop = slice_bound(stop)?;
        let step = slice_bound(step)?;
        let len = i64::try_from(source_len).map_err(|_| "sequence is too large".to_string())?;
        let (_, _, normalized_step) = normalized_slice_indices(len, start, stop, step)?;
        let indices = slice_indices(source_len, start, stop, step)?;
        let offset = indices
            .first()
            .map(|index| memoryview_physical_index_from_parts(source_offset, source_stride, *index))
            .transpose()?
            .unwrap_or(source_offset);
        let stride = if indices.len() > 1 {
            let first =
                memoryview_physical_index_from_parts(source_offset, source_stride, indices[0])?;
            let second =
                memoryview_physical_index_from_parts(source_offset, source_stride, indices[1])?;
            isize::try_from(second).map_err(|_| "memoryview index out of range".to_string())?
                - isize::try_from(first).map_err(|_| "memoryview index out of range".to_string())?
        } else {
            source_stride
                .checked_mul(
                    isize::try_from(normalized_step)
                        .map_err(|_| "memoryview stride is too large".to_string())?,
                )
                .ok_or_else(|| "memoryview stride is too large".to_string())?
        };

        Ok(memory_view_from_parts_with_exported_bytearray(
            bytes,
            obj,
            exported_bytearray,
            offset,
            indices.len(),
            stride,
            readonly,
            format,
        ))
    }

    fn normalize_slice_parts(
        &mut self,
        start: Option<Value>,
        stop: Option<Value>,
        step: Option<Value>,
    ) -> Result<(Option<Value>, Option<Value>, Option<Value>), String> {
        Ok((
            self.normalize_slice_part(start)?,
            self.normalize_slice_part(stop)?,
            self.normalize_slice_part(step)?,
        ))
    }

    fn normalize_slice_part(&mut self, value: Option<Value>) -> Result<Option<Value>, String> {
        match value {
            None | Some(Value::None) => Ok(None),
            Some(value) => self.maybe_index_integer_value(value).map(Some),
        }
    }

    fn load_slice_value(
        &mut self,
        object: Value,
        start: Option<Value>,
        stop: Option<Value>,
        step: Option<Value>,
    ) -> Result<Value, String> {
        let (start, stop, step) = self.normalize_slice_parts(start, stop, step)?;
        load_slice(object, start, stop, step)
    }

    fn store_slice_value(
        &mut self,
        object: Value,
        start: Option<Value>,
        stop: Option<Value>,
        step: Option<Value>,
        value: Value,
    ) -> Result<Value, String> {
        let (start, stop, step) = self.normalize_slice_parts(start, stop, step)?;
        store_slice(object, start, stop, step, value)
    }

    fn delete_slice_value(
        &mut self,
        object: Value,
        start: Option<Value>,
        stop: Option<Value>,
        step: Option<Value>,
    ) -> Result<Value, String> {
        let (start, stop, step) = self.normalize_slice_parts(start, stop, step)?;
        delete_slice(object, start, stop, step)
    }

    fn truth_value(&mut self, value: Value) -> Result<bool, String> {
        if let Value::WeakProxy { target, .. } = &value {
            return self.truth_value(target.as_ref().clone());
        }

        if instance_special_method_is_none(&value, "__bool__") {
            return Err(format!(
                "TypeError: '{}' cannot be interpreted as a boolean",
                type_name(&value)
            ));
        }

        if let Some(method) = instance_special_method(&value, "__bool__") {
            let result = match self.call_value_catching(method, Vec::new())? {
                Ok(result) => result,
                Err(exception) => return Err(format_exception_error(&exception)),
            };
            return match result {
                Value::Bool(value) => Ok(value),
                value => Err(format!(
                    "TypeError: __bool__ should return bool, returned {}",
                    type_name(&value)
                )),
            };
        }

        if let Some(method) = instance_special_method(&value, "__len__") {
            let result = match self.call_value_catching(method, Vec::new())? {
                Ok(result) => result,
                Err(exception) => return Err(format_exception_error(&exception)),
            };
            return Ok(len_result_from_value(result)? != 0);
        }

        match value {
            value if list_subclass_storage(&value).is_some() => Ok(self.len_value(value)? != 0),
            value if tuple_subclass_items(&value).is_some() => Ok(self.len_value(value)? != 0),
            value if dict_subclass_entries(&value).is_some() => Ok(self.len_value(value)? != 0),
            value if chain_map_subclass_maps(&value).is_some() => {
                let maps = chain_map_subclass_maps(&value)
                    .expect("ChainMap subclass maps exist after guard");
                self.chain_map_maps_truth_value(&maps)
            }
            value if set_subclass_items(&value).is_some() => Ok(self.len_value(value)? != 0),
            value if frozen_set_subclass_items(&value).is_some() => Ok(self.len_value(value)? != 0),
            value if str_subclass_string(&value).is_some() => Ok(self.len_value(value)? != 0),
            value if float_subclass_float(&value).is_some() => Ok(*float_subclass_float(&value)
                .expect("float subclass storage exists after guard")
                != 0.0),
            value if complex_subclass_parts(&value).is_some() => {
                let (real, imag) =
                    complex_subclass_parts(&value).expect("complex subclass storage exists");
                Ok(real != 0.0 || imag != 0.0)
            }
            value if bytes_subclass_bytes(&value).is_some() => Ok(self.len_value(value)? != 0),
            value if bytearray_subclass_storage(&value).is_some() => {
                Ok(self.len_value(value)? != 0)
            }
            value if array_array_storage(&value).is_some() => Ok(self.len_value(value)? != 0),
            Value::ChainMap { maps } => self.chain_map_maps_truth_value(&maps),
            Value::UserList { data, .. } => Ok(!data.borrow().is_empty()),
            Value::UserString { data, .. } => Ok(!data.borrow().is_empty()),
            Value::Deque { data, .. } => Ok(!data.borrow().is_empty()),
            Value::UserDict { data, .. } => Ok(!data.borrow().is_empty()),
            Value::MappingView { mapping, .. } => Ok(self.len_value(*mapping)? != 0),
            Value::MappingProxyObject { mapping, .. } => self.truth_value(*mapping),
            value if counter_subclass_entries(&value).is_some() => {
                Ok(!counter_subclass_entries(&value)
                    .expect("Counter subclass entries exist after guard")
                    .borrow()
                    .is_empty())
            }
            value => is_truthy(&value),
        }
    }

    fn chain_map_maps_truth_value(&mut self, maps: &[Value]) -> Result<bool, String> {
        for map in maps {
            if self.truth_value(map.clone())? {
                return Ok(true);
            }
        }
        Ok(false)
    }

    fn len_value(&mut self, value: Value) -> Result<usize, String> {
        if let Value::WeakProxy { target, .. } = &value {
            return self.len_value(target.as_ref().clone());
        }

        if let Some(method) = instance_special_method(&value, "__len__") {
            let result = match self.call_value_catching(method, Vec::new())? {
                Ok(result) => result,
                Err(exception) => return Err(format_exception_error(&exception)),
            };
            return len_result_from_value(result);
        }

        match value {
            value if list_subclass_storage(&value).is_some() => Ok(list_subclass_storage(&value)
                .expect("list subclass storage exists after guard")
                .borrow()
                .len()),
            value if counter_subclass_entries(&value).is_some() => {
                Ok(counter_subclass_entries(&value)
                    .expect("Counter subclass entries exist after guard")
                    .borrow()
                    .len())
            }
            value if dict_subclass_entries(&value).is_some() => Ok(dict_subclass_entries(&value)
                .expect("dict subclass entries exist after guard")
                .borrow()
                .len()),
            value if chain_map_subclass_maps(&value).is_some() => {
                let maps = chain_map_subclass_maps(&value)
                    .expect("ChainMap subclass maps exist after guard");
                chain_map_key_count(&maps)
            }
            value if set_subclass_items(&value).is_some() => Ok(set_subclass_items(&value)
                .expect("set subclass items exist after guard")
                .borrow()
                .len()),
            value if frozen_set_subclass_items(&value).is_some() => {
                Ok(frozen_set_subclass_items(&value)
                    .expect("frozenset subclass items exist after guard")
                    .len())
            }
            value if str_subclass_string(&value).is_some() => Ok(str_subclass_string(&value)
                .expect("str subclass storage exists after guard")
                .chars()
                .count()),
            value if bytes_subclass_bytes(&value).is_some() => Ok(bytes_subclass_bytes(&value)
                .expect("bytes subclass storage exists after guard")
                .len()),
            value if bytearray_subclass_storage(&value).is_some() => {
                Ok(bytearray_subclass_storage(&value)
                    .expect("bytearray subclass storage exists after guard")
                    .borrow()
                    .len())
            }
            value if array_array_storage(&value).is_some() => {
                Ok(array_array_len(&value).expect("array storage exists after guard"))
            }
            Value::ChainMap { maps } => chain_map_key_count(&maps),
            Value::UserList { data, .. } => Ok(data.borrow().len()),
            Value::UserString { data, .. } => Ok(data.borrow().chars().count()),
            Value::Deque { data, .. } => Ok(data.borrow().len()),
            Value::UserDict { data, .. } => Ok(data.borrow().len()),
            Value::MappingView { mapping, .. } => self.len_value(*mapping),
            Value::MappingProxyObject { mapping, .. } => self.len_value(*mapping),
            value => value_len(&value),
        }
    }

    fn call_format(&mut self, args: Vec<Value>) -> Result<Value, String> {
        let (value, format_spec, format_spec_object) = match args.as_slice() {
            [value] => {
                return self.format_value(value, None, Some("")).map(Value::String);
            }
            [value, format_spec] => (
                value,
                format_spec_string(format_spec, "format()")?,
                format_spec.clone(),
            ),
            [] => return Err("format expected at least 1 argument, got 0".to_string()),
            values => {
                return Err(format!(
                    "format expected at most 2 arguments, got {}",
                    values.len()
                ));
            }
        };

        self.format_value_with_spec_object(
            value,
            None,
            Some(&format_spec),
            Some(format_spec_object),
        )
        .map(Value::String)
    }

    fn call_compile(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut values = vec![None, None, None, None, None, None, None, None];
        let names = [
            "source",
            "filename",
            "mode",
            "flags",
            "dont_inherit",
            "optimize",
            "module",
            "_feature_version",
        ];
        if args.len() > 6 {
            return Err(format!(
                "TypeError: compile() takes at most 6 arguments ({} given)",
                args.len()
            ));
        }
        for (index, value) in args.into_iter().enumerate() {
            values[index] = Some(value);
        }
        for (name, value) in keywords {
            let Some(index) = names.iter().position(|candidate| candidate == &name) else {
                return Err(format!(
                    "TypeError: compile() got an unexpected keyword argument '{name}'"
                ));
            };
            if values[index].is_some() {
                return Err(format!(
                    "TypeError: compile() got multiple values for argument '{name}'"
                ));
            }
            values[index] = Some(value);
        }

        let source = values[0]
            .take()
            .ok_or_else(|| "TypeError: compile() missing required argument 'source'".to_string())?;
        let filename = values[1].take().ok_or_else(|| {
            "TypeError: compile() missing required argument 'filename'".to_string()
        })?;
        let mode = values[2]
            .take()
            .ok_or_else(|| "TypeError: compile() missing required argument 'mode'".to_string())?;
        let filename = self.compile_filename_argument(filename)?;
        let mode = compile_mode_argument(mode)?;
        let flags = values[3]
            .take()
            .map(|value| compile_int_argument(value, "flags"))
            .transpose()?
            .unwrap_or(0);
        if flags & !(PYCF_OPTIMIZED_AST | PYCF_ALLOW_TOP_LEVEL_AWAIT) != 0 {
            return Err("ValueError: compile(): unrecognised flags".to_string());
        }
        if let Some(dont_inherit) = values[4].take() {
            self.truth_value(dont_inherit)?;
        }
        let optimize = values[5]
            .take()
            .map(|value| compile_int_argument(value, "optimize"))
            .transpose()?
            .unwrap_or(-1);
        let warning_module = match values[6].take() {
            Some(Value::String(module)) => Some(module),
            Some(Value::None) | None => None,
            Some(value) => {
                return Err(format!(
                    "TypeError: compile() argument 'module' must be str or None, not {}",
                    type_name(&value)
                ));
            }
        };
        let feature_version = values[7]
            .take()
            .map(|value| compile_int_argument(value, "_feature_version"))
            .transpose()?
            .unwrap_or(-1);

        if flags & PYCF_ONLY_AST != 0 {
            code_mode_from_string(&mode)?;
            let ast_optimize = if flags & PYCF_OPTIMIZED_AST == PYCF_OPTIMIZED_AST {
                normalize_ast_optimize_level(optimize)
            } else {
                -1
            };
            let feature_version = if feature_version >= 0 {
                Some(AstFeatureVersion {
                    major: 3,
                    minor: feature_version,
                })
            } else {
                None
            };
            return parse_ast_node(source, &mode, false, ast_optimize, feature_version);
        }

        self.compile_code_object_with_warnings(
            source,
            filename,
            &mode,
            optimize,
            warning_module,
            flags & PYCF_ALLOW_TOP_LEVEL_AWAIT != 0,
        )
    }

    fn call_breakpoint(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let sys = self.load_stdlib_module("sys")?;
        let Value::Module { attrs, .. } = sys else {
            return Err("RuntimeError: lost sys.breakpointhook".to_string());
        };
        let hook = attrs
            .borrow()
            .get("breakpointhook")
            .cloned()
            .ok_or_else(|| "RuntimeError: lost sys.breakpointhook".to_string())?;
        self.call_value_with_keywords(hook, args, keywords)
    }

    fn compile_filename_argument(&mut self, value: Value) -> Result<CompileFilename, String> {
        match value {
            Value::String(filename)
            | Value::IdentityString {
                value: filename, ..
            } => Ok(CompileFilename::from_string(filename)),
            value if str_subclass_string(&value).is_some() => Ok(CompileFilename {
                text: str_subclass_string(&value).expect("str subclass storage exists after guard"),
                public_value: value,
            }),
            Value::Bytes(bytes) => compile_filename_from_bytes(bytes.as_ref().clone())
                .map(CompileFilename::from_string),
            value if bytes_subclass_bytes(&value).is_some() => compile_filename_from_bytes(
                bytes_subclass_bytes(&value).expect("bytes subclass storage exists after guard"),
            )
            .map(CompileFilename::from_string),
            value @ Value::Instance { .. } => {
                let path_type = type_name(&value).to_string();
                let Some(method) = instance_special_method(&value, "__fspath__") else {
                    return Err(compile_filename_type_error(&value));
                };
                match self.call_value_catching(method, Vec::new())? {
                    Err(exception) => Err(format_exception_error(&exception)),
                    Ok(
                        Value::String(filename)
                        | Value::IdentityString {
                            value: filename, ..
                        },
                    ) => Ok(CompileFilename::from_string(filename)),
                    Ok(result) if str_subclass_string(&result).is_some() => Ok(CompileFilename {
                        text: str_subclass_string(&result)
                            .expect("str subclass storage exists after guard"),
                        public_value: result,
                    }),
                    Ok(Value::Bytes(bytes)) => compile_filename_from_bytes(bytes.as_ref().clone())
                        .map(CompileFilename::from_string),
                    Ok(result) if bytes_subclass_bytes(&result).is_some() => {
                        compile_filename_from_bytes(
                            bytes_subclass_bytes(&result)
                                .expect("bytes subclass storage exists after guard"),
                        )
                        .map(CompileFilename::from_string)
                    }
                    Ok(result) => Err(format!(
                        "TypeError: expected {path_type}.__fspath__() to return str or bytes, not {}",
                        type_name(&result)
                    )),
                }
            }
            value => Err(compile_filename_type_error(&value)),
        }
    }

    fn compile_code_object_with_warnings(
        &mut self,
        source: Value,
        filename: CompileFilename,
        mode: &str,
        optimize: i64,
        warning_module: Option<String>,
        allow_top_level_await: bool,
    ) -> Result<Value, String> {
        let mode = code_mode_from_string(mode)?;
        let options =
            CompileOptions::optimized(optimize).with_allow_top_level_await(allow_top_level_await);
        let filename_text = filename.text;
        let public_filename = filename.public_value;
        let (instructions, line_spans, flags) = match source {
            Value::AstNode { .. } => {
                let (instructions, flags) = self.compile_ast_code_object_with_warnings(
                    &source,
                    mode,
                    &filename_text,
                    options,
                    warning_module.as_deref(),
                )?;
                (instructions, default_code_line_spans(), flags)
            }
            source => {
                let (instructions, line_spans, flags) = self
                    .compile_source_code_object_with_warnings(
                        source,
                        mode,
                        &filename_text,
                        options,
                        warning_module.as_deref(),
                    )?;
                (instructions, line_spans, flags)
            }
        };

        Ok(Value::CodeObject {
            mode,
            filename: filename_text,
            public_filename: Box::new(public_filename),
            consts: function_code_constants(&instructions),
            instructions,
            line_spans,
            varnames: Vec::new(),
            flags,
            freevars: Vec::new(),
            positional_only: Vec::new(),
            params: Vec::new(),
            vararg: None,
            keyword_only: Vec::new(),
            kwarg: None,
            name: "<module>".to_string(),
            identity: Rc::new(()),
        })
    }

    fn compile_ast_code_object_with_warnings(
        &mut self,
        node: &Value,
        mode: CodeMode,
        filename: &str,
        options: CompileOptions,
        warning_module: Option<&str>,
    ) -> Result<(Vec<Instruction>, i64), String> {
        match mode {
            CodeMode::Exec => {
                let function_first_lines = ast_function_definition_start_lines(node);
                let function_line_sequences = ast_function_definition_line_sequences(node);
                let generator_expression_line_sequences =
                    ast_generator_expression_line_sequences(node)?;
                let program = syntax_program_from_ast_module(node)?;
                emit_compile_warnings(
                    self,
                    crate::static_syntax_warnings(&program),
                    filename,
                    warning_module,
                )?;
                let flags = module_code_flags(options.allow_top_level_await, &program);
                let options = options
                    .with_function_first_lines(function_first_lines)
                    .with_function_line_sequences(function_line_sequences)
                    .with_generator_expression_line_sequences(generator_expression_line_sequences);
                let instructions = compile_with_options(&program, options)
                    .map_err(|message| format!("SyntaxError: {message}"))?;
                Ok((instructions, flags))
            }
            CodeMode::Eval => {
                let generator_expression_line_sequences =
                    ast_generator_expression_line_sequences(node)?;
                let expr = syntax_expr_from_ast_expression(node)?;
                let program = syntax::Program {
                    statements: vec![syntax::Stmt::Expr(expr.clone())],
                };
                emit_compile_warnings(
                    self,
                    crate::static_syntax_warnings(&program),
                    filename,
                    warning_module,
                )?;
                let flags = expr_code_flags(options.allow_top_level_await, &expr);
                let options = options
                    .with_generator_expression_line_sequences(generator_expression_line_sequences);
                let instructions = compile_eval_with_options(&expr, options)
                    .map_err(|message| format!("SyntaxError: {message}"))?;
                Ok((instructions, flags))
            }
            CodeMode::Single => {
                let function_first_lines = ast_function_definition_start_lines(node);
                let function_line_sequences = ast_function_definition_line_sequences(node);
                let generator_expression_line_sequences =
                    ast_generator_expression_line_sequences(node)?;
                let program = syntax_program_from_ast_interactive(node)?;
                emit_compile_warnings(
                    self,
                    crate::static_syntax_warnings(&program),
                    filename,
                    warning_module,
                )?;
                let flags = module_code_flags(options.allow_top_level_await, &program);
                let options = options
                    .with_function_first_lines(function_first_lines)
                    .with_function_line_sequences(function_line_sequences)
                    .with_generator_expression_line_sequences(generator_expression_line_sequences);
                let instructions = compile_interactive_with_options(&program, options)
                    .map_err(|message| format!("SyntaxError: {message}"))?;
                Ok((instructions, flags))
            }
        }
    }

    fn compile_source_code_object_with_warnings(
        &mut self,
        source: Value,
        mode: CodeMode,
        filename: &str,
        options: CompileOptions,
        warning_module: Option<&str>,
    ) -> Result<(Vec<Instruction>, Vec<CodeLineSpan>, i64), String> {
        let source = compile_source_text(source)?;
        let line_spans = code_line_spans_from_source(&source, mode);
        let (instructions, flags) = match mode {
            CodeMode::Exec => {
                let (spanned_tokens, lexer_warnings) = lex_with_spans_for_parse(&source)
                    .map_err(|error| syntax_error_location_error(&error, filename, &source))?;
                emit_compile_warnings(self, lexer_warnings, filename, warning_module)?;
                let tokens = spanned_tokens
                    .iter()
                    .map(|spanned| spanned.token.clone())
                    .collect::<Vec<_>>();
                let program =
                    parse(&tokens).map_err(|message| format!("SyntaxError: {message}"))?;
                emit_compile_warnings(
                    self,
                    static_syntax_warnings_with_source_locations(&program, &spanned_tokens),
                    filename,
                    warning_module,
                )?;
                let flags = module_code_flags(options.allow_top_level_await, &program);
                let options = options
                    .with_function_first_lines(function_definition_start_lines(&spanned_tokens))
                    .with_function_line_sequences(function_definition_line_sequences(
                        &spanned_tokens,
                    ))
                    .with_function_position_columns(function_definition_position_columns(
                        &spanned_tokens,
                    ))
                    .with_function_is_lambdas(function_definition_is_lambdas(&spanned_tokens))
                    .with_generator_expression_line_sequences(generator_expression_line_sequences(
                        &spanned_tokens,
                    ));
                let instructions = compile_with_options(&program, options)
                    .map_err(|message| format!("SyntaxError: {message}"))?;
                (instructions, flags)
            }
            CodeMode::Eval => {
                let source = source.trim();
                let (spanned_tokens, lexer_warnings) = lex_with_spans_for_parse(source)
                    .map_err(|error| syntax_error_location_error(&error, filename, source))?;
                emit_compile_warnings(self, lexer_warnings, filename, warning_module)?;
                let tokens = spanned_tokens
                    .iter()
                    .map(|spanned| spanned.token.clone())
                    .collect::<Vec<_>>();
                let expr =
                    parse_eval(&tokens).map_err(|message| format!("SyntaxError: {message}"))?;
                let program = syntax::Program {
                    statements: vec![syntax::Stmt::Expr(expr.clone())],
                };
                emit_compile_warnings(
                    self,
                    static_syntax_warnings_with_source_locations(&program, &spanned_tokens),
                    filename,
                    warning_module,
                )?;
                let flags = expr_code_flags(options.allow_top_level_await, &expr);
                let options = options
                    .with_function_first_lines(function_definition_start_lines(&spanned_tokens))
                    .with_function_line_sequences(function_definition_line_sequences(
                        &spanned_tokens,
                    ))
                    .with_function_position_columns(function_definition_position_columns(
                        &spanned_tokens,
                    ))
                    .with_function_is_lambdas(function_definition_is_lambdas(&spanned_tokens))
                    .with_generator_expression_line_sequences(generator_expression_line_sequences(
                        &spanned_tokens,
                    ));
                let instructions = compile_eval_with_options(&expr, options)
                    .map_err(|message| format!("SyntaxError: {message}"))?;
                (instructions, flags)
            }
            CodeMode::Single => {
                let (spanned_tokens, lexer_warnings) = lex_with_spans_for_parse(&source)
                    .map_err(|error| syntax_error_location_error(&error, filename, &source))?;
                emit_compile_warnings(self, lexer_warnings, filename, warning_module)?;
                let tokens = spanned_tokens
                    .iter()
                    .map(|spanned| spanned.token.clone())
                    .collect::<Vec<_>>();
                let program = parse_interactive(&tokens)
                    .map_err(|message| format!("SyntaxError: {message}"))?;
                emit_compile_warnings(
                    self,
                    static_syntax_warnings_with_source_locations(&program, &spanned_tokens),
                    filename,
                    warning_module,
                )?;
                let flags = module_code_flags(options.allow_top_level_await, &program);
                let options = options
                    .with_function_first_lines(function_definition_start_lines(&spanned_tokens))
                    .with_function_line_sequences(function_definition_line_sequences(
                        &spanned_tokens,
                    ))
                    .with_function_position_columns(function_definition_position_columns(
                        &spanned_tokens,
                    ))
                    .with_function_is_lambdas(function_definition_is_lambdas(&spanned_tokens))
                    .with_generator_expression_line_sequences(generator_expression_line_sequences(
                        &spanned_tokens,
                    ));
                let instructions = compile_interactive_with_options(&program, options)
                    .map_err(|message| format!("SyntaxError: {message}"))?;
                (instructions, flags)
            }
        };
        Ok((instructions, line_spans, flags))
    }

    fn call_eval(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut values = bind_eval_exec_args("eval", args, keywords, false)?;
        let source = values[0]
            .take()
            .ok_or_else(|| "TypeError: eval() missing required argument 'source'".to_string())?;
        let default_locals = if self.is_module {
            self.globals.clone()
        } else {
            self.locals.clone()
        };
        let (globals, locals, writebacks, is_module) = eval_scopes_from_optional_args(
            values[1].take(),
            values[2].take(),
            self.globals.clone(),
            default_locals,
            self.is_module,
        )?;
        let code = compile_eval_argument(source)?;
        let result = self.run_code_object(code, globals, locals, is_module, true, None);

        match self.sync_exec_writebacks(&writebacks) {
            Ok(()) => result,
            Err(writeback_error) if result.is_ok() => Err(writeback_error),
            Err(_) => result,
        }
    }

    fn call_exec(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut values = bind_eval_exec_args("exec", args, keywords, true)?;
        let source = values[0]
            .take()
            .ok_or_else(|| "TypeError: exec() missing required argument 'source'".to_string())?;
        let source_is_code_object = matches!(source, Value::CodeObject { .. });
        let closure_arg = values[3].take();
        let default_locals = if self.is_module {
            self.globals.clone()
        } else {
            self.locals.clone()
        };
        let (globals, locals, writebacks, is_module) = exec_scopes_from_optional_args(
            values[1].take(),
            values[2].take(),
            self.globals.clone(),
            default_locals,
            self.is_module,
        )?;
        let warning_module = if source_is_code_object {
            None
        } else {
            exec_warning_module_from_globals(&globals)
        };
        let code = self.compile_exec_argument(source, warning_module)?;
        let closure = self.exec_closure_for_code(&code, closure_arg, source_is_code_object)?;
        let result = self.run_code_object(
            code,
            globals.clone(),
            locals.clone(),
            is_module,
            false,
            closure,
        );
        if result.is_ok() {
            install_exec_annotate_function(&locals, &globals);
        }
        match self.sync_exec_writebacks(&writebacks) {
            Ok(()) => result,
            Err(writeback_error) if result.is_ok() => Err(writeback_error),
            Err(_) => result,
        }
    }

    fn compile_exec_argument(
        &mut self,
        value: Value,
        warning_module: Option<String>,
    ) -> Result<Value, String> {
        match value {
            code @ Value::CodeObject { .. } => Ok(code),
            Value::String(source) | Value::IdentityString { value: source, .. } => self
                .compile_code_object_with_warnings(
                    Value::String(source),
                    CompileFilename::from_string("<string>".to_string()),
                    "exec",
                    -1,
                    warning_module,
                    false,
                ),
            value if str_subclass_string(&value).is_some() => self
                .compile_code_object_with_warnings(
                    Value::String(
                        str_subclass_string(&value)
                            .expect("str subclass storage exists after guard"),
                    ),
                    CompileFilename::from_string("<string>".to_string()),
                    "exec",
                    -1,
                    warning_module,
                    false,
                ),
            Value::Bytes(bytes) => self.compile_code_object_with_warnings(
                Value::Bytes(bytes),
                CompileFilename::from_string("<string>".to_string()),
                "exec",
                -1,
                warning_module,
                false,
            ),
            value if bytes_subclass_bytes(&value).is_some() => self
                .compile_code_object_with_warnings(
                    bytes_value(
                        bytes_subclass_bytes(&value)
                            .expect("bytes subclass storage exists after guard"),
                    ),
                    CompileFilename::from_string("<string>".to_string()),
                    "exec",
                    -1,
                    warning_module,
                    false,
                ),
            Value::ByteArray(bytes) => self.compile_code_object_with_warnings(
                Value::ByteArray(bytes),
                CompileFilename::from_string("<string>".to_string()),
                "exec",
                -1,
                warning_module,
                false,
            ),
            value if bytearray_subclass_bytes(&value).is_some() => self
                .compile_code_object_with_warnings(
                    byte_array_value(
                        bytearray_subclass_bytes(&value)
                            .expect("bytearray subclass storage exists after guard"),
                    ),
                    CompileFilename::from_string("<string>".to_string()),
                    "exec",
                    -1,
                    warning_module,
                    false,
                ),
            Value::MemoryView(view) => self.compile_code_object_with_warnings(
                Value::MemoryView(view),
                CompileFilename::from_string("<string>".to_string()),
                "exec",
                -1,
                warning_module,
                false,
            ),
            value => Err(format!(
                "TypeError: exec() arg 1 must be a string or code object, not {}",
                type_name(&value)
            )),
        }
    }

    fn exec_closure_for_code(
        &self,
        code: &Value,
        closure_arg: Option<Value>,
        source_is_code_object: bool,
    ) -> Result<Option<Vec<Scope>>, String> {
        let Value::CodeObject { freevars, .. } = code else {
            unreachable!("caller passes a code object")
        };
        if !source_is_code_object {
            if closure_arg.is_some() {
                return Err(
                    "TypeError: closure can only be used when source is a code object".to_string(),
                );
            }
            return Ok(None);
        }

        if freevars.is_empty() {
            return match closure_arg {
                None | Some(Value::None) => Ok(None),
                Some(_) => Err("TypeError: cannot use a closure with this code object".to_string()),
            };
        }

        let Some(closure) = closure_arg else {
            return Err(format!(
                "TypeError: code object requires a closure of exactly length {}",
                freevars.len()
            ));
        };
        let Value::Tuple(cells) = closure else {
            return Err("TypeError: closure must be a tuple of cell objects".to_string());
        };
        if cells.len() != freevars.len() {
            return Err(format!(
                "TypeError: code object requires a closure of exactly length {}",
                freevars.len()
            ));
        }

        let scope = new_scope();
        {
            let mut bindings = scope.borrow_mut();
            for (name, cell) in freevars.iter().zip(cells.iter()) {
                if !matches!(cell, Value::Cell { .. }) {
                    return Err("TypeError: closure must be a tuple of cell objects".to_string());
                }
                bindings.insert(name.clone(), cell.clone());
            }
        }
        Ok(Some(vec![scope]))
    }

    fn run_code_object(
        &mut self,
        code: Value,
        globals: Scope,
        locals: Scope,
        is_module: bool,
        value_context: bool,
        closure_override: Option<Vec<Scope>>,
    ) -> Result<Value, String> {
        let Value::CodeObject {
            mode,
            instructions,
            line_spans,
            flags,
            name,
            identity,
            ..
        } = code
        else {
            unreachable!("caller passes a code object");
        };
        let closure = closure_override.unwrap_or_else(|| self.closure.clone());
        if flags & CO_COROUTINE != 0 {
            let (first_line, line_sequence) = code_object_function_lines(&line_spans);
            let state = Rc::new(RefCell::new(CoroutineState {
                name,
                instructions,
                ip: 0,
                registers: Vec::new(),
                globals,
                locals,
                closure,
                current_class: self.current_class.clone(),
                first_arg_name: self.first_arg_name.clone(),
                qualname_prefix: self.qualname_prefix.clone(),
                exception_handlers: Vec::new(),
                current_exception: None,
                pending_exception_after_clear: None,
                done: false,
                running: false,
                first_line,
                line_sequence,
                code_identity: identity,
                frame_fields: None,
            }));
            let frame_fields = {
                let state_ref = state.borrow();
                coroutine_frame_fields(&state_ref)?
            };
            state.borrow_mut().frame_fields = Some(frame_fields);
            let coroutine = Value::Coroutine(state);
            return Ok(if value_context {
                coroutine
            } else {
                Value::None
            });
        }
        let mut code_vm = Vm::new_eval(
            instructions,
            globals,
            locals,
            closure,
            is_module,
            self.abc_registry.clone(),
            self.module_cache.clone(),
            self.source_modules.clone(),
            self.stdlib_import_policy.clone(),
            self.runtime_options,
            self.frame_stack.clone(),
        );
        code_vm.current_class = self.current_class.clone();
        code_vm.first_arg_name = self.first_arg_name.clone();
        code_vm.qualname_prefix = self.qualname_prefix.clone();

        if value_context && mode == CodeMode::Eval {
            let result = code_vm.run_eval();
            self.absorb_output_from(&mut code_vm);
            return match result {
                Ok(value) => Ok(value),
                Err(message) => {
                    if let Some(exception) = code_vm.current_exception {
                        self.raise_exception(exception, true)?;
                        Ok(Value::None)
                    } else {
                        Err(message)
                    }
                }
            };
        }

        if !value_context && mode == CodeMode::Eval {
            let result = code_vm.run_eval();
            self.absorb_output_from(&mut code_vm);
            return match result {
                Ok(_) => Ok(Value::None),
                Err(message) => {
                    if let Some(exception) = code_vm.current_exception {
                        self.raise_exception(exception, true)?;
                        Ok(Value::None)
                    } else {
                        Err(message)
                    }
                }
            };
        }

        match code_vm.run_inner() {
            Ok(ExecutionExit::Halt | ExecutionExit::Return(_)) => {
                self.absorb_output_from(&mut code_vm);
                Ok(Value::None)
            }
            Ok(ExecutionExit::Yield { .. }) => Err("yield outside exec".to_string()),
            Err(message) => {
                self.absorb_output_from(&mut code_vm);
                if let Some(exception) = code_vm.current_exception {
                    self.raise_exception(exception, true)?;
                    Ok(Value::None)
                } else {
                    Err(message)
                }
            }
        }
    }

    fn call_str_format_method(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let [Value::String(template), positional @ ..] = args.as_slice() else {
            return Err("TypeError: format() expected a str receiver".to_string());
        };

        self.render_str_format(template, positional, &keywords, None)
            .map(Value::String)
    }

    fn call_str_format_map_method(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: str.format_map() takes no keyword arguments".to_string());
        }
        let [Value::String(template), mapping] = args.as_slice() else {
            return Err(format!(
                "TypeError: format_map() expected 1 argument, got {}",
                method_arg_count(&args)
            ));
        };

        self.render_str_format(template, &[], &[], Some(mapping))
            .map(Value::String)
    }

    fn render_str_format(
        &mut self,
        template: &str,
        positional: &[Value],
        keywords: &[(String, Value)],
        mapping: Option<&Value>,
    ) -> Result<String, String> {
        let chars = template.chars().collect::<Vec<_>>();
        let mut output = String::new();
        let mut index = 0usize;
        let mut auto_index = 0usize;
        let mut used_auto = false;
        let mut used_manual = false;

        while index < chars.len() {
            match chars[index] {
                '{' if chars.get(index + 1) == Some(&'{') => {
                    output.push('{');
                    index += 2;
                }
                '}' if chars.get(index + 1) == Some(&'}') => {
                    output.push('}');
                    index += 2;
                }
                '{' => {
                    let field_start = index + 1;
                    let Some(field_end) = chars[field_start..]
                        .iter()
                        .position(|ch| *ch == '}')
                        .map(|offset| field_start + offset)
                    else {
                        return Err("ValueError: expected '}' before end of string".to_string());
                    };
                    if chars[field_start..field_end].contains(&'{') {
                        return Err("ValueError: unexpected '{' in field name".to_string());
                    }
                    let field = chars[field_start..field_end].iter().collect::<String>();
                    let value = self.render_str_format_field(
                        &field,
                        positional,
                        keywords,
                        mapping,
                        &mut auto_index,
                        &mut used_auto,
                        &mut used_manual,
                    )?;
                    output.push_str(&value);
                    index = field_end + 1;
                }
                '}' => {
                    return Err("ValueError: Single '}' encountered in format string".to_string());
                }
                ch => {
                    output.push(ch);
                    index += 1;
                }
            }
        }

        Ok(output)
    }

    fn render_str_format_field(
        &mut self,
        field: &str,
        positional: &[Value],
        keywords: &[(String, Value)],
        mapping: Option<&Value>,
        auto_index: &mut usize,
        used_auto: &mut bool,
        used_manual: &mut bool,
    ) -> Result<String, String> {
        let parts = parse_str_format_field(field)?;
        let value = self.resolve_str_format_field(
            parts.field_name,
            positional,
            keywords,
            mapping,
            auto_index,
            used_auto,
            used_manual,
        )?;
        self.format_value(&value, parts.conversion, Some(parts.format_spec))
    }

    fn resolve_str_format_field(
        &mut self,
        field_name: &str,
        positional: &[Value],
        keywords: &[(String, Value)],
        mapping: Option<&Value>,
        auto_index: &mut usize,
        used_auto: &mut bool,
        used_manual: &mut bool,
    ) -> Result<Value, String> {
        let root_end = field_name
            .find(|ch| ch == '.' || ch == '[')
            .unwrap_or(field_name.len());
        let root = &field_name[..root_end];
        let mut tail = &field_name[root_end..];

        let mut value = if mapping.is_some()
            && (root.is_empty() || root.chars().all(|ch| ch.is_ascii_digit()))
        {
            return Err("ValueError: Format string contains positional fields".to_string());
        } else if root.is_empty() {
            if *used_manual {
                return Err(
                    "ValueError: cannot switch from manual field specification to automatic field numbering"
                        .to_string(),
                );
            }
            *used_auto = true;
            let value = positional.get(*auto_index).cloned().ok_or_else(|| {
                format!(
                    "IndexError: Replacement index {} out of range for positional args tuple",
                    *auto_index
                )
            })?;
            *auto_index += 1;
            value
        } else if root.chars().all(|ch| ch.is_ascii_digit()) {
            if *used_auto {
                return Err(
                    "ValueError: cannot switch from automatic field numbering to manual field specification"
                        .to_string(),
                );
            }
            *used_manual = true;
            let index = root
                .parse::<usize>()
                .map_err(|_| "ValueError: replacement index is too large".to_string())?;
            positional.get(index).cloned().ok_or_else(|| {
                format!(
                    "IndexError: Replacement index {index} out of range for positional args tuple"
                )
            })?
        } else if let Some(mapping) = mapping {
            self.load_subscript_value(mapping.clone(), Value::String(root.to_string()))?
        } else {
            keywords
                .iter()
                .find(|(name, _)| name == root)
                .map(|(_, value)| value.clone())
                .ok_or_else(|| format!("KeyError: {}", repr_string(root)))?
        };

        while !tail.is_empty() {
            if let Some(rest) = tail.strip_prefix('.') {
                let next_end = rest.find(|ch| ch == '.' || ch == '[').unwrap_or(rest.len());
                let attr = &rest[..next_end];
                if attr.is_empty() {
                    return Err("ValueError: empty attribute in format string".to_string());
                }
                value = self.load_attribute_value(value, attr)?;
                tail = &rest[next_end..];
            } else if let Some(rest) = tail.strip_prefix('[') {
                let Some(end) = rest.find(']') else {
                    return Err("ValueError: missing ']' in format string".to_string());
                };
                let key_text = &rest[..end];
                let key = if key_text.chars().all(|ch| ch.is_ascii_digit()) {
                    Value::Number(
                        key_text
                            .parse::<i64>()
                            .map_err(|_| "ValueError: item index is too large".to_string())?,
                    )
                } else {
                    Value::String(key_text.to_string())
                };
                value = self.load_subscript_value(value, key)?;
                tail = &rest[end + 1..];
            } else {
                return Err("ValueError: unexpected field name syntax".to_string());
            }
        }

        Ok(value)
    }

    fn format_value(
        &mut self,
        value: &Value,
        conversion: Option<FormatConversion>,
        format_spec: Option<&str>,
    ) -> Result<String, String> {
        self.format_value_with_spec_object(value, conversion, format_spec, None)
    }

    fn str_value(&mut self, value: &Value) -> Result<String, String> {
        if let Some(method) = instance_special_method(value, "__str__") {
            let result = match self.call_value_catching(method, Vec::new())? {
                Ok(result) => result,
                Err(exception) => return Err(format_exception_error(&exception)),
            };
            return dunder_str_result_text(result);
        }

        if let Some(method) = instance_special_method(value, "__repr__") {
            let result = match self.call_value_catching(method, Vec::new())? {
                Ok(result) => result,
                Err(exception) => return Err(format_exception_error(&exception)),
            };
            return dunder_str_result_text(result);
        }

        str_value_checked(value)
    }

    fn format_value_with_spec_object(
        &mut self,
        value: &Value,
        conversion: Option<FormatConversion>,
        format_spec: Option<&str>,
        format_spec_object: Option<Value>,
    ) -> Result<String, String> {
        if conversion.is_none()
            && let Some(method) = instance_special_method(value, "__format__")
        {
            let format_spec_value = format_spec_object
                .clone()
                .unwrap_or_else(|| Value::String(format_spec.unwrap_or_default().to_string()));
            let result = self.call_value(method, vec![format_spec_value])?;
            return match result {
                Value::String(value) | Value::IdentityString { value, .. } => Ok(value),
                value if str_subclass_string(&value).is_some() => {
                    Ok(str_subclass_string(&value)
                        .expect("str subclass storage exists after guard"))
                }
                value => Err(format!(
                    "__format__ must return a string, got {}",
                    type_name(&value)
                )),
            };
        }

        if conversion.is_none()
            && let Some(storage) = str_subclass_string(value)
        {
            if format_spec.map_or(true, str::is_empty) {
                let rendered = self.str_value(value)?;
                return apply_format_spec(value, &rendered, false, format_spec);
            }
            return format_builtin_value(
                Some(self),
                &Value::String(storage),
                conversion,
                format_spec,
            );
        }

        if conversion.is_none() && is_set_subclass_display_value(value) {
            return format_set_subclass_value(Some(self), value, format_spec);
        }

        if conversion.is_none() && matches!(value, Value::Instance { .. }) {
            return self.call_object_format(vec![
                value.clone(),
                format_spec_object
                    .unwrap_or_else(|| Value::String(format_spec.unwrap_or_default().to_string())),
            ]);
        }

        format_builtin_value(Some(self), value, conversion, format_spec)
    }

    fn call_range(&mut self, args: Vec<Value>) -> Result<Value, String> {
        let numbers = args
            .into_iter()
            .map(|arg| self.index_big_int(arg))
            .collect::<Result<Vec<_>, _>>()?;

        match numbers.as_slice() {
            [] => Err("range expected at least 1 argument, got 0".to_string()),
            [stop] => Ok(Value::Range {
                start: BigInt::zero(),
                stop: stop.clone(),
                step: BigInt::from(1),
                identity: Rc::new(()),
            }),
            [start, stop] => Ok(Value::Range {
                start: start.clone(),
                stop: stop.clone(),
                step: BigInt::from(1),
                identity: Rc::new(()),
            }),
            [start, stop, step] if step.is_zero() => {
                let _ = (start, stop);
                Err("range() arg 3 must not be zero".to_string())
            }
            [start, stop, step] => Ok(Value::Range {
                start: start.clone(),
                stop: stop.clone(),
                step: step.clone(),
                identity: Rc::new(()),
            }),
            values => Err(format!(
                "range expected at most 3 arguments, got {}",
                values.len()
            )),
        }
    }

    fn call_range_new(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: range() takes no keyword arguments".to_string());
        }
        let Some((class, values)) = args.split_first() else {
            return Err("TypeError: range.__new__(): not enough arguments".to_string());
        };

        match class {
            Value::Builtin(name) if name == "range" => self.call_range(values.to_vec()),
            value @ (Value::Builtin(_) | Value::Class { .. } | Value::NamedTupleType(_)) => {
                Err(format!(
                    "TypeError: range.__new__({}): {} is not a subtype of range",
                    class_display_name(value),
                    class_display_name(value)
                ))
            }
            value => Err(format!(
                "TypeError: range.__new__(X): X is not a type object ({})",
                type_name(value)
            )),
        }
    }

    fn call_bytes(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        self.call_bytes_constructor(args, keywords)
    }

    fn call_bytearray(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        self.call_bytes_like_constructor("bytearray", args, keywords, false)
            .map(byte_array_value)
    }

    fn call_bytes_new(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((class, rest)) = args.split_first() else {
            return Err("TypeError: bytes.__new__(): not enough arguments".to_string());
        };
        let storage = self.call_bytes_like_constructor("bytes", rest.to_vec(), keywords, true)?;
        match class {
            Value::Builtin(name) if name == "bytes" => Ok(bytes_value(storage)),
            Value::Class {
                name, attrs, bases, ..
            } if class_bases_include_builtin(bases, "bytes") => Ok(bytes_subclass_instance(
                name.clone(),
                attrs.clone(),
                bases.clone(),
                storage,
            )),
            value => Err(format!(
                "TypeError: bytes.__new__({}): {} is not a subtype of bytes",
                value,
                type_name(value)
            )),
        }
    }

    fn call_bytearray_new(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((class, _rest)) = args.split_first() else {
            return Err("TypeError: bytearray.__new__(): not enough arguments".to_string());
        };
        // CPython ignores constructor arguments here and leaves population to
        // bytearray.__init__.
        let _ = keywords;
        match class {
            Value::Builtin(name) if name == "bytearray" => Ok(byte_array_value(Vec::new())),
            Value::Class {
                name, attrs, bases, ..
            } if class_bases_include_builtin(bases, "bytearray") => Ok(
                bytearray_subclass_instance(name.clone(), attrs.clone(), bases.clone(), Vec::new()),
            ),
            value => Err(format!(
                "TypeError: bytearray.__new__({}): {} is not a subtype of bytearray",
                value,
                type_name(value)
            )),
        }
    }

    fn call_bytearray_init(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((receiver, rest)) = args.split_first() else {
            return Err("TypeError: bytearray.__init__(): not enough arguments".to_string());
        };
        let storage = bytearray_receiver_storage(receiver, "__init__")?;
        if let Some(bytes) = self.call_bytearray_init_source(&storage, rest.to_vec(), keywords)? {
            if !bytes.is_empty() || !storage.borrow().is_empty() {
                ensure_bytearray_resizable(&storage)?;
            }
            **storage.borrow_mut() = bytes;
        }
        Ok(Value::None)
    }

    fn call_bytearray_init_source(
        &mut self,
        storage: &ByteArrayRef,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Option<Vec<u8>>, String> {
        let mut slots = constructor_slots(
            "bytearray",
            args,
            keywords,
            &["source", "encoding", "errors"],
        )?;
        let errors = slots[2].take();
        let encoding = slots[1].take();
        let source = slots[0].take();

        let Some(source) = source else {
            reject_bytes_encoding_without_string(encoding.as_ref(), errors.as_ref())?;
            return Ok(Some(Vec::new()));
        };

        match source {
            Value::String(value) | Value::IdentityString { value, .. } => {
                if encoding.is_none() {
                    return Err("TypeError: string argument without an encoding".to_string());
                }
                let (encoding, errors) =
                    codec_options_from_values("bytearray", encoding.as_ref(), errors.as_ref())?;
                encode_text(&value, encoding, errors).map(Some)
            }
            Value::Bytes(value) => {
                reject_bytes_encoding_without_string(encoding.as_ref(), errors.as_ref())?;
                Ok(Some(value.as_ref().clone()))
            }
            Value::ByteArray(value) => {
                reject_bytes_encoding_without_string(encoding.as_ref(), errors.as_ref())?;
                Ok(Some(bytearray_bytes(&value)))
            }
            Value::MemoryView(view) => {
                reject_bytes_encoding_without_string(encoding.as_ref(), errors.as_ref())?;
                memoryview_bytes(&view).map(Some)
            }
            value => {
                if let Some(value_text) = str_subclass_string(&value) {
                    if encoding.is_some() || errors.is_some() {
                        let (encoding, errors) = codec_options_from_values(
                            "bytearray",
                            encoding.as_ref(),
                            errors.as_ref(),
                        )?;
                        return encode_text(&value_text, encoding, errors).map(Some);
                    }
                }
                reject_bytes_encoding_without_string(encoding.as_ref(), errors.as_ref())?;
                if let Some(bytes) = bytes_subclass_bytes(&value) {
                    return Ok(Some(bytes));
                }
                if let Some(bytes) = bytearray_subclass_bytes(&value) {
                    return Ok(Some(bytes));
                }
                if let Some(bytes) = array_array_bytes(&value) {
                    return Ok(Some(bytes));
                }
                match self.maybe_index_integer_value(value.clone())? {
                    count @ (Value::Number(_) | Value::BigInt(_)) => {
                        let count = byte_sequence_constructor_length_from_index(count)?;
                        Ok(Some(vec![0; count]))
                    }
                    _ => {
                        self.bytearray_init_from_iterable(storage, value)?;
                        Ok(None)
                    }
                }
            }
        }
    }

    fn bytearray_init_from_iterable(
        &mut self,
        storage: &ByteArrayRef,
        value: Value,
    ) -> Result<(), String> {
        let source_type = type_name(&value).to_string();
        let mut iterator = match self.get_iter(value) {
            Ok(iterator) => iterator,
            Err(error) if error.ends_with(" is not iterable") => {
                return Err(format!(
                    "TypeError: cannot convert '{source_type}' object to bytearray"
                ));
            }
            Err(error) => return Err(error),
        };
        ensure_bytearray_resizable(storage)?;
        storage.borrow_mut().clear();

        loop {
            match self.advance_owned_iterator_capturing(&mut iterator)? {
                Ok(IteratorAdvance::Yield(value)) => {
                    let byte = self.bytes_constructor_item(value)?;
                    storage.borrow_mut().push(byte);
                }
                Ok(IteratorAdvance::Complete(_)) => return Ok(()),
                Ok(IteratorAdvance::Raised) => {
                    return Err("iterator raised exception".to_string());
                }
                Err(exception) => return Err(format_exception_error(&exception)),
            }
        }
    }

    fn call_bytes_fromhex_classmethod(
        &mut self,
        name: &str,
        args: Vec<Value>,
    ) -> Result<Value, String> {
        let [class, source] = args.as_slice() else {
            return Err(format!(
                "fromhex() expected 1 argument, got {}",
                args.len().saturating_sub(1)
            ));
        };
        let bytes = bytes_fromhex(source)?;
        let source = if name.starts_with("bytearray.") {
            byte_array_value(bytes)
        } else {
            bytes_value(bytes)
        };
        self.call_value(class.clone(), vec![source])
    }

    fn call_memoryview(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let positional_count = args.len();
        let keyword_count = keywords.len();
        let total_count = positional_count + keyword_count;
        if positional_count > 0 && total_count > 1 {
            return Err(format!(
                "TypeError: memoryview() takes at most 1 argument ({total_count} given)"
            ));
        }
        if positional_count == 0 && keyword_count > 1 {
            return Err(format!(
                "TypeError: memoryview() takes at most 1 keyword argument ({keyword_count} given)"
            ));
        }

        let mut source = args.into_iter().next();
        if source.is_none() {
            source = keywords
                .into_iter()
                .find_map(|(keyword, value)| (keyword == "object").then_some(value));
        }
        let Some(source) = source else {
            return Err(
                "TypeError: memoryview() missing required argument 'object' (pos 1)".to_string(),
            );
        };
        match source {
            Value::Bytes(bytes) => Ok(memory_view_value(bytes.as_ref().clone(), true)),
            Value::ByteArray(bytes) => Ok(memory_view_from_byte_array(bytes, false)),
            value if array_array_storage(&value).is_some() => {
                let storage =
                    array_array_storage(&value).expect("array storage exists after guard");
                let format = array_array_typecode(&value).unwrap_or_else(|| "B".to_string());
                let itemsize = array_array_itemsize_for_typecode(&format)
                    .ok_or_else(|| "TypeError: unsupported array typecode".to_string())?;
                let len = storage.borrow().len() / itemsize;
                let stride = isize::try_from(itemsize)
                    .map_err(|_| "memoryview stride is too large".to_string())?;
                Ok(memory_view_from_parts_with_format(
                    storage, value, 0, len, stride, false, format,
                ))
            }
            Value::MemoryView(view) => {
                let view = view.borrow();
                if view.released {
                    return Err(released_memoryview_error());
                }
                Ok(memory_view_from_parts_with_exported_bytearray_and_ndim(
                    view.bytes.clone(),
                    view.obj.clone(),
                    view.exported_bytearray.clone(),
                    view.offset,
                    view.len,
                    view.stride,
                    view.readonly,
                    view.format.clone(),
                    view.ndim,
                ))
            }
            value => Err(format!(
                "TypeError: memoryview: a bytes-like object is required, not '{}'",
                type_name(&value)
            )),
        }
    }

    fn call_io_bytesio(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if args.len() + keywords.len() > 1 {
            return Err(format!(
                "TypeError: BytesIO() takes at most 1 argument ({} given)",
                args.len() + keywords.len()
            ));
        }

        let mut source = args.into_iter().next();
        for (keyword, value) in keywords {
            if keyword != "initial_bytes" {
                return Err(format!(
                    "TypeError: BytesIO() got an unexpected keyword argument '{keyword}'"
                ));
            }
            source = Some(value);
        }

        let buffer = source
            .map(bytesio_initial_bytes)
            .transpose()?
            .unwrap_or_default();
        Ok(bytes_io_value(buffer))
    }

