    fn call_io_bytesio_readinto_impl(
        &mut self,
        args: Vec<Value>,
        method: &str,
    ) -> Result<Value, String> {
        let [Value::BytesIO(bytes_io), target] = args.as_slice() else {
            let display = if method == "readinto1" {
                "_BufferedIOBase.readinto1"
            } else {
                "BytesIO.readinto"
            };
            return Err(format!(
                "TypeError: {display}() takes exactly one argument ({} given)",
                method_arg_count(&args)
            ));
        };
        bytes_io_ensure_open(bytes_io)?;
        let target_len = writable_readinto_buffer_len(target, method)?;
        let chunk = bytes_io_readinto_chunk(bytes_io, target_len);
        write_bytes_into_readinto_buffer(target, &chunk, method)?;
        i64::try_from(chunk.len())
            .map(Value::Number)
            .map_err(|_| format!("{method}() result is too large"))
    }

