    fn call_io_bytesio_read_impl(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
        method: &str,
    ) -> Result<Value, String> {
        let Some((receiver, rest)) = args.split_first() else {
            return Err(format!(
                "TypeError: unbound method BytesIO.{method}() needs an argument"
            ));
        };
        let Value::BytesIO(bytes_io) = receiver else {
            return Err(format!(
                "TypeError: descriptor '{method}' for '_io.BytesIO' objects doesn't apply to a '{}' object",
                type_name(receiver)
            ));
        };
        reject_bytesio_method_keywords(method, &keywords)?;
        bytes_io_ensure_open(bytes_io)?;
        if rest.len() > 1 {
            return Err(format!(
                "TypeError: {method} expected at most 1 argument, got {}",
                rest.len()
            ));
        }
        let size = match rest {
            [] | [Value::None] => None,
            [value] => {
                let size = self.index_i64(value.clone(), "argument")?;
                if size < 0 {
                    None
                } else {
                    Some(usize::try_from(size).map_err(|_| {
                        "OverflowError: cannot fit 'int' into an index-sized integer".to_string()
                    })?)
                }
            }
            _ => unreachable!("BytesIO read arity is checked before reading size"),
        };
        Ok(bytes_value(bytes_io_read_chunk(bytes_io, size)))
    }

