    fn call_io_bytesio_readlines(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((receiver, rest)) = args.split_first() else {
            return Err(format!(
                "TypeError: unbound method BytesIO.readlines() needs an argument"
            ));
        };
        let Value::BytesIO(bytes_io) = receiver else {
            return Err(format!(
                "TypeError: descriptor 'readlines' for '_io.BytesIO' objects doesn't apply to a '{}' object",
                type_name(receiver)
            ));
        };
        reject_bytesio_method_keywords("readlines", &keywords)?;
        bytes_io_ensure_open(bytes_io)?;
        if rest.len() > 1 {
            return Err(format!(
                "TypeError: readlines expected at most 1 argument, got {}",
                rest.len()
            ));
        }
        let hint = match rest {
            [] | [Value::None] => None,
            [value] => {
                let hint = self.index_i64(value.clone(), "argument")?;
                if hint <= 0 {
                    None
                } else {
                    Some(usize::try_from(hint).map_err(|_| {
                        "OverflowError: cannot fit 'int' into an index-sized integer".to_string()
                    })?)
                }
            }
            _ => unreachable!("BytesIO.readlines arity is checked before reading hint"),
        };
        let mut lines = Vec::new();
        let mut total = 0_usize;
        loop {
            let line = bytes_io_readline_chunk(bytes_io, None);
            if line.is_empty() {
                break;
            }
            total = total.saturating_add(line.len());
            lines.push(bytes_value(line));
            if hint.is_some_and(|limit| total >= limit) {
                break;
            }
        }
        Ok(list_value(lines))
    }

