    fn call_io_bytesio_getstate(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((receiver, rest)) = args.split_first() else {
            return Err(
                "TypeError: unbound method BytesIO.__getstate__() needs an argument".to_string(),
            );
        };
        let Value::BytesIO(bytes_io) = receiver else {
            return Err(format!(
                "TypeError: descriptor '__getstate__' for '_io.BytesIO' objects doesn't apply to a '{}' object",
                type_name(receiver)
            ));
        };
        reject_bytesio_method_keywords("__getstate__", &keywords)?;
        if !rest.is_empty() {
            return Err(format!(
                "TypeError: BytesIO.__getstate__() takes no arguments ({} given)",
                rest.len()
            ));
        }
        bytes_io_ensure_open(bytes_io)?;
        let state = bytes_io.borrow();
        let attrs = state.attrs.borrow();
        let attrs_value = if attrs.is_empty() && !state.attrs_materialized {
            Value::None
        } else {
            let mut entries = Vec::with_capacity(attrs.len());
            for (key, value) in attrs.iter() {
                entries.push((Value::String(key.clone()), value.clone()));
            }
            dict_value(entries)
        };
        let position = i64::try_from(state.position)
            .map_err(|_| "OverflowError: position does not fit in an integer".to_string())?;
        Ok(tuple_value(vec![
            bytes_value(state.buffer.borrow().to_vec()),
            Value::Number(position),
            attrs_value,
        ]))
    }

    fn call_io_bytesio_setstate(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((receiver, rest)) = args.split_first() else {
            return Err(
                "TypeError: unbound method BytesIO.__setstate__() needs an argument".to_string(),
            );
        };
        let Value::BytesIO(bytes_io) = receiver else {
            return Err(format!(
                "TypeError: descriptor '__setstate__' for '_io.BytesIO' objects doesn't apply to a '{}' object",
                type_name(receiver)
            ));
        };
        reject_bytesio_method_keywords("__setstate__", &keywords)?;
        let [state] = rest else {
            return Err(format!(
                "TypeError: BytesIO.__setstate__() takes exactly one argument ({} given)",
                rest.len()
            ));
        };
        bytes_io_ensure_open(bytes_io)?;
        bytes_io_ensure_resizable(bytes_io)?;
        let Value::Tuple(items) = state else {
            return Err(format!(
                "TypeError: _io.BytesIO.__setstate__ argument should be 3-tuple, got {}",
                type_name(state)
            ));
        };
        if items.len() < 3 {
            return Err(
                "TypeError: _io.BytesIO.__setstate__ argument should be 3-tuple, got tuple"
                    .to_string(),
            );
        }

        let buffer = bytesio_initial_bytes(items[0].clone())?;
        let position = match &items[1] {
            Value::Bool(value) => usize::from(*value),
            Value::Number(value) => {
                if *value < 0 {
                    return Err("ValueError: position value cannot be negative".to_string());
                }
                usize::try_from(*value).map_err(|_| {
                    "OverflowError: cannot fit 'int' into an index-sized integer".to_string()
                })?
            }
            Value::BigInt(value) => {
                if value.is_negative() {
                    return Err("ValueError: position value cannot be negative".to_string());
                }
                value.to_usize().ok_or_else(|| {
                    "OverflowError: cannot fit 'int' into an index-sized integer".to_string()
                })?
            }
            value => {
                return Err(format!(
                    "TypeError: second item of state must be an integer, not {}",
                    type_name(value)
                ));
            }
        };

        let attrs = match &items[2] {
            Value::None => None,
            Value::Dict(entries) => Some(entries.borrow().entries.clone()),
            value => {
                return Err(format!(
                    "TypeError: third item of state should be a dict, got a {}",
                    type_name(value)
                ));
            }
        };

        {
            let mut io_state = bytes_io.borrow_mut();
            {
                let mut stream_buffer = io_state.buffer.borrow_mut();
                stream_buffer.clear();
                stream_buffer.extend_from_slice(&buffer);
            }
            io_state.position = position;
            if let Some(attrs) = attrs {
                io_state.attrs_materialized = true;
                let mut io_attrs = io_state.attrs.borrow_mut();
                for (key, value) in attrs {
                    if let Value::String(name) = key {
                        io_attrs.insert(name, value);
                    }
                }
            }
        }

        Ok(Value::None)
    }

