    fn call_itertools_islice(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: islice() takes no keyword arguments".to_string());
        }
        if args.len() < 2 {
            return Err(format!(
                "TypeError: islice expected at least 2 arguments, got {}",
                args.len()
            ));
        }
        if args.len() > 4 {
            return Err(format!(
                "TypeError: islice expected at most 4 arguments, got {}",
                args.len()
            ));
        }
        let iterator = get_iter(args[0].clone())?;
        let (start, stop, step) = match args.len() {
            2 => (0, self.itertools_islice_stop(args[1].clone())?, 1),
            3 => (
                self.itertools_islice_index(args[1].clone(), "Start")?,
                self.itertools_islice_stop(args[2].clone())?,
                1,
            ),
            4 => (
                self.itertools_islice_index(args[1].clone(), "Start")?,
                self.itertools_islice_stop(args[2].clone())?,
                self.itertools_islice_step(args[3].clone())?,
            ),
            _ => unreachable!("argument count checked above"),
        };
        Ok(shared_iterator(Value::ItertoolsIslice {
            iterator: Box::new(iterator),
            position: 0,
            next_position: start,
            stop,
            step,
        }))
    }

    fn itertools_islice_stop(&mut self, value: Value) -> Result<Option<i64>, String> {
        if matches!(value, Value::None) {
            Ok(None)
        } else {
            self.itertools_islice_index(value, "Stop").map(Some)
        }
    }

    fn itertools_islice_step(&mut self, value: Value) -> Result<i64, String> {
        if matches!(value, Value::None) {
            return Ok(1);
        }
        let step = self.itertools_islice_index(value, "Step")?;
        if step <= 0 {
            Err("ValueError: Step for islice() must be a positive integer or None".to_string())
        } else {
            Ok(step)
        }
    }

    fn itertools_islice_index(&mut self, value: Value, name: &str) -> Result<i64, String> {
        let index = self.index_i64(value, name).map_err(|error| {
            if error.contains("__index__ returned non-int") {
                if name == "Step" {
                    "ValueError: Step for islice() must be a positive integer or None.".to_string()
                } else if name == "Start" {
                    "ValueError: Indices for islice() must be None or an integer: 0 <= x <= sys.maxsize.".to_string()
                } else {
                    format!(
                        "ValueError: {name} argument for islice() must be None or an integer: 0 <= x <= sys.maxsize."
                    )
                }
            } else {
                error
            }
        })?;
        if index < 0 {
            if name == "Start" {
                Err(
                    "ValueError: Indices for islice() must be None or an integer: 0 <= x <= sys.maxsize."
                        .to_string(),
                )
            } else {
                Err(format!(
                    "ValueError: {name} argument for islice() must be None or an integer: 0 <= x <= sys.maxsize."
                ))
            }
        } else {
            Ok(index)
        }
    }

    fn call_itertools_pairwise(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: pairwise() takes no keyword arguments".to_string());
        }
        let [iterable] = args.as_slice() else {
            return Err(format!(
                "TypeError: pairwise expected 1 argument, got {}",
                args.len()
            ));
        };
        Ok(shared_iterator(Value::ItertoolsPairwise {
            iterator: Box::new(get_iter(iterable.clone())?),
            previous: None,
            initialized: false,
        }))
    }

    fn call_itertools_product(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut repeat = BigInt::from(1);
        let mut repeat_seen = false;
        for (keyword, value) in keywords {
            if keyword != "repeat" {
                return Err(format!(
                    "TypeError: product() got an unexpected keyword argument '{keyword}'"
                ));
            }
            if repeat_seen {
                return Err(
                    "TypeError: product() got multiple values for keyword argument 'repeat'"
                        .to_string(),
                );
            }
            repeat = self.index_big_int(value)?;
            if repeat.is_negative() {
                return Err("ValueError: repeat argument cannot be negative".to_string());
            }
            repeat_seen = true;
        }

        let repeat = repeat.to_usize().ok_or_else(|| {
            "OverflowError: Python int too large to convert to C ssize_t".to_string()
        })?;
        let base_pools = args
            .into_iter()
            .map(|value| self.collect_iterable_values(value))
            .collect::<Result<Vec<_>, _>>()?;
        let mut pools = Vec::with_capacity(base_pools.len().saturating_mul(repeat));
        for _ in 0..repeat {
            pools.extend(base_pools.iter().cloned());
        }
        let done = pools.iter().any(Vec::is_empty);
        let indices = vec![0; pools.len()];
        Ok(shared_iterator(Value::ItertoolsProduct {
            pools,
            indices,
            first: true,
            done,
        }))
    }

    fn call_itertools_combinations(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut values =
            bind_itertools_keyword_call("combinations", &["iterable", "r"], 2, args, keywords)?;
        let iterable = values[0].take().ok_or_else(|| {
            "TypeError: combinations() missing required argument 'iterable'".to_string()
        })?;
        let r_value = values[1]
            .take()
            .ok_or_else(|| "TypeError: combinations() missing required argument 'r'".to_string())?;
        let r = self.index_big_int(r_value)?;
        if r.is_negative() {
            return Err("ValueError: r must be non-negative".to_string());
        }
        let r = r.to_usize().ok_or_else(|| {
            "OverflowError: Python int too large to convert to C ssize_t".to_string()
        })?;
        let pool = self.collect_iterable_values(iterable)?;
        let done = r > pool.len();
        let indices = (0..r).collect();
        Ok(shared_iterator(Value::ItertoolsCombinations {
            pool,
            indices,
            r,
            first: true,
            done,
        }))
    }

    fn call_itertools_combinations_with_replacement(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut values = bind_itertools_keyword_call(
            "combinations_with_replacement",
            &["iterable", "r"],
            2,
            args,
            keywords,
        )?;
        let iterable = values[0].take().ok_or_else(|| {
            "TypeError: combinations_with_replacement() missing required argument 'iterable'"
                .to_string()
        })?;
        let r_value = values[1].take().ok_or_else(|| {
            "TypeError: combinations_with_replacement() missing required argument 'r'".to_string()
        })?;
        let r = self.index_big_int(r_value)?;
        if r.is_negative() {
            return Err("ValueError: r must be non-negative".to_string());
        }
        let r = r.to_usize().ok_or_else(|| {
            "OverflowError: Python int too large to convert to C ssize_t".to_string()
        })?;
        let pool = self.collect_iterable_values(iterable)?;
        let done = pool.is_empty() && r > 0;
        let indices = vec![0; r];
        Ok(shared_iterator(
            Value::ItertoolsCombinationsWithReplacement {
                pool,
                indices,
                r,
                first: true,
                done,
            },
        ))
    }

    fn call_itertools_permutations(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut values =
            bind_itertools_keyword_call("permutations", &["iterable", "r"], 1, args, keywords)?;
        let iterable = values[0].take().ok_or_else(|| {
            "TypeError: permutations() missing required argument 'iterable'".to_string()
        })?;
        let pool = self.collect_iterable_values(iterable)?;
        let n = pool.len();
        let r = match values[1].take() {
            Some(Value::None) => n,
            Some(value) => self.itertools_permutations_r(value)?,
            None => n,
        };
        let done = r > n;
        let indices = (0..n).collect();
        let cycles = (0..r).map(|index| n - index).collect();
        Ok(shared_iterator(Value::ItertoolsPermutations {
            pool,
            indices,
            cycles,
            r,
            first: true,
            done,
        }))
    }

    fn itertools_permutations_r(&self, value: Value) -> Result<usize, String> {
        let value = int_subclass_integer(&value).unwrap_or_else(|| numeric_bool_value(value));
        let integer = match value {
            Value::Number(value) => BigInt::from(value),
            Value::BigInt(value) => value,
            _ => return Err("TypeError: Expected int as r".to_string()),
        };
        if integer.is_negative() {
            return Err("ValueError: r must be non-negative".to_string());
        }
        integer.to_usize().ok_or_else(|| {
            "OverflowError: Python int too large to convert to C ssize_t".to_string()
        })
    }

    fn call_itertools_tee(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: itertools.tee() takes no keyword arguments".to_string());
        }
        if args.is_empty() {
            return Err("TypeError: tee expected at least 1 argument, got 0".to_string());
        }
        if args.len() > 2 {
            return Err(format!(
                "TypeError: tee expected at most 2 arguments, got {}",
                args.len()
            ));
        }
        let n = if let Some(value) = args.get(1) {
            let n = self.index_big_int(value.clone())?;
            if n.is_negative() {
                return Err("ValueError: n must be >= 0".to_string());
            }
            n.to_usize().ok_or_else(|| {
                "OverflowError: Python int too large to convert to C ssize_t".to_string()
            })?
        } else {
            2
        };
        if n == 0 {
            return Ok(tuple_value(Vec::new()));
        }

        if let Some((state, index)) = itertools_tee_flatten_source(&args[0]) {
            let iterators = (0..n)
                .map(|_| {
                    shared_iterator(Value::ItertoolsTee {
                        state: state.clone(),
                        index,
                    })
                })
                .collect();
            return Ok(tuple_value(iterators));
        }

        let iterator = get_iter(args[0].clone())?;
        let state = Rc::new(RefCell::new(TeeState {
            iterator,
            buffer: Vec::new(),
            exhausted: false,
        }));
        let iterators = (0..n)
            .map(|_| {
                shared_iterator(Value::ItertoolsTee {
                    state: state.clone(),
                    index: 0,
                })
            })
            .collect();
        Ok(tuple_value(iterators))
    }

    fn call_ast_replace_method(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((object, rest)) = args.split_first() else {
            return Err("TypeError: __replace__() missing required argument 'self'".to_string());
        };
        if !rest.is_empty() {
            return Err(format!(
                "TypeError: {}.__replace__ expected 0 positional arguments, got {}",
                ast_replace_kind_name(object),
                rest.len()
            ));
        }
        self.replace_ast_value(object.clone(), keywords)
    }

    fn call_ast_reduce_method(
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: __reduce__() does not accept keyword arguments".to_string());
        }
        let [object] = args.as_slice() else {
            return Err(format!(
                "TypeError: __reduce__() expected 0 positional arguments, got {}",
                args.len().saturating_sub(1)
            ));
        };
        let Value::AstNode { kind, attrs, .. } = object else {
            return Err(format!(
                "TypeError: copy protocol does not support '{}'",
                type_name(object)
            ));
        };
        let state_entries = attrs.borrow().entries.clone();
        Ok(tuple_value(vec![
            Value::Builtin(kind.clone()),
            tuple_value(Vec::new()),
            Value::Dict(Rc::new(RefCell::new(DictStorage::new(state_entries)))),
        ]))
    }

    fn replace_ast_value(
        &mut self,
        object: Value,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        match object {
            Value::AstNode {
                kind,
                fields,
                attrs,
                ..
            } => self.replace_native_ast_node(kind, fields, attrs, keywords),
            Value::Instance {
                class_name,
                fields,
                class_attrs,
                class_bases,
            } if class_bases_include_builtin(&class_bases, "AST") => {
                self.replace_ast_subclass(class_name, fields, class_attrs, class_bases, keywords)
            }
            value => Err(copy_replace_unsupported_type_error(&value)),
        }
    }

    fn replace_native_ast_node(
        &mut self,
        kind: String,
        fields: Vec<String>,
        attrs: DictRef,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut replacements = HashMap::new();
        for (name, value) in keywords {
            if replacements.insert(name.clone(), value).is_some() {
                return Err(format!(
                    "TypeError: {kind}.__replace__ got multiple values for argument '{name}'"
                ));
            }
        }

        let mut entries = Vec::new();
        for field in &fields {
            let value = if let Some(value) = replacements.remove(field) {
                value
            } else if let Some(value) = lookup_string_key(&attrs, field) {
                value
            } else if let Some(value) = ast_constructor_default(&kind, field) {
                value
            } else {
                return Err(format!(
                    "TypeError: {kind}.__replace__ missing 1 keyword argument: '{field}'."
                ));
            };
            entries.push((Value::String(field.clone()), ast_stored_value(value)));
        }

        for attribute in ast_location_attributes(&kind) {
            let value = if let Some(value) = replacements.remove(*attribute) {
                Some(value)
            } else {
                lookup_string_key(&attrs, attribute)
            };
            if let Some(value) = value {
                entries.push((
                    Value::String((*attribute).to_string()),
                    ast_stored_value(value),
                ));
            }
        }

        if let Some((name, _)) = replacements.into_iter().next() {
            return Err(format!(
                "TypeError: {kind}.__replace__ got an unexpected keyword argument '{name}'."
            ));
        }

        Ok(Value::AstNode {
            kind,
            fields,
            attrs: Rc::new(RefCell::new(DictStorage::new(entries))),
            identity: Rc::new(()),
        })
    }

    fn replace_ast_subclass(
        &mut self,
        class_name: String,
        fields: Scope,
        class_attrs: Scope,
        class_bases: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut replacements = HashMap::new();
        for (name, value) in keywords {
            if replacements.insert(name.clone(), value).is_some() {
                return Err(format!(
                    "TypeError: {class_name}.__replace__ got multiple values for argument '{name}'"
                ));
            }
        }

        let known_fields = ast_subclass_string_sequence_attr(&class_attrs, "_fields");
        let known_attributes = ast_subclass_string_sequence_attr(&class_attrs, "_attributes");
        let copied_fields = new_scope();

        for field in &known_fields {
            if let Some(value) = replacements.remove(field) {
                copied_fields
                    .borrow_mut()
                    .insert(field.clone(), ast_stored_value(value));
            } else if let Some(value) = fields.borrow().get(field).cloned() {
                copied_fields.borrow_mut().insert(field.clone(), value);
            } else if class_attrs.borrow().contains_key(field) {
                continue;
            } else if let Some(field_type) = ast_subclass_field_type(&class_attrs, field)
                && let Some(default) = ast_subclass_default_for_field_type(&field_type)
            {
                copied_fields.borrow_mut().insert(field.clone(), default);
            } else {
                return Err(format!(
                    "TypeError: {class_name}.__replace__ missing 1 keyword argument: '{field}'."
                ));
            }
        }

        for attribute in &known_attributes {
            if let Some(value) = replacements.remove(attribute) {
                copied_fields
                    .borrow_mut()
                    .insert(attribute.clone(), ast_stored_value(value));
            } else if let Some(value) = fields.borrow().get(attribute).cloned() {
                copied_fields.borrow_mut().insert(attribute.clone(), value);
            }
        }

        if let Some((name, _)) = replacements.into_iter().next() {
            return Err(format!(
                "TypeError: {class_name}.__replace__ got an unexpected keyword argument '{name}'."
            ));
        }

        Ok(Value::Instance {
            class_name,
            fields: copied_fields,
            class_attrs,
            class_bases,
        })
    }

    fn simple_namespace_fields_from_args(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<DictRef, String> {
        if args.len() > 1 {
            return Err(format!(
                "TypeError: no more than 1 positional argument expected, got {}",
                args.len()
            ));
        }

        let mut entries = Vec::new();
        if let [source] = args.as_slice() {
            for (key, value) in self.dict_entries_from_update_source(source.clone())? {
                let Value::String(name) = key else {
                    return Err(
                        "TypeError: SimpleNamespace attribute name must be string".to_string()
                    );
                };
                insert_dict_entry(&mut entries, Value::String(name), value)?;
            }
        }

        for (name, value) in keywords {
            insert_dict_entry(&mut entries, Value::String(name), value)?;
        }

        dict_ref_from_entries(entries)
    }

    fn call_dict_fromkeys(&mut self, args: Vec<Value>) -> Result<Value, String> {
        let (iterable, default) = match args.as_slice() {
            [] => return Err("TypeError: fromkeys expected at least 1 argument, got 0".to_string()),
            [iterable] => (iterable.clone(), Value::None),
            [iterable, default] => (iterable.clone(), default.clone()),
            values => {
                return Err(format!(
                    "TypeError: fromkeys expected at most 2 arguments, got {}",
                    values.len()
                ));
            }
        };

        let mut entries = Vec::new();
        for key in self.collect_iterable_values_propagating(iterable)? {
            insert_dict_entry(&mut entries, key, default.clone())?;
        }

        build_dict(entries)
    }

