    fn cmp_to_key_order_values(
        &mut self,
        left: &Value,
        right: &Value,
        op: SequenceOrder,
    ) -> Result<Option<bool>, String> {
        let (
            Value::CmpToKeyObject {
                comparator,
                object: left_object,
                ..
            },
            Value::CmpToKeyObject {
                object: right_object,
                ..
            },
        ) = (left, right)
        else {
            if matches!(left, Value::CmpToKeyObject { .. })
                || matches!(right, Value::CmpToKeyObject { .. })
            {
                return Err("TypeError: other argument must be K instance".to_string());
            }
            return Ok(None);
        };

        let result = self.call_value(
            *comparator.clone(),
            vec![left_object.borrow().clone(), right_object.borrow().clone()],
        )?;
        let zero = Value::Number(0);
        let ordered = match op {
            SequenceOrder::Less => self.less_values(result, zero)?,
            SequenceOrder::LessEqual => self.less_equal_values(result, zero)?,
            SequenceOrder::Greater => self.greater_values(result, zero)?,
            SequenceOrder::GreaterEqual => self.greater_equal_values(result, zero)?,
        };
        Ok(Some(ordered))
    }

    fn cmp_to_key_equal_values(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<bool>, String> {
        let (
            Value::CmpToKeyObject {
                comparator,
                object: left_object,
                ..
            },
            Value::CmpToKeyObject {
                object: right_object,
                ..
            },
        ) = (left, right)
        else {
            if matches!(left, Value::CmpToKeyObject { .. })
                || matches!(right, Value::CmpToKeyObject { .. })
            {
                return Err("TypeError: other argument must be K instance".to_string());
            }
            return Ok(None);
        };

        let result = self.call_value(
            *comparator.clone(),
            vec![left_object.borrow().clone(), right_object.borrow().clone()],
        )?;
        Ok(Some(self.rich_equal_values(&result, &Value::Number(0))?))
    }

    fn cell_rich_equal_if_cells(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<bool>, String> {
        if matches!(left, Value::Cell { .. }) && matches!(right, Value::Cell { .. }) {
            return self.cell_rich_equal_values(left, right).map(Some);
        }
        Ok(None)
    }

    fn cell_rich_equal_values(&mut self, left: &Value, right: &Value) -> Result<bool, String> {
        let (Some(left), Some(right)) = (cell_compare_contents(left), cell_compare_contents(right))
        else {
            return Ok(false);
        };

        match (left, right) {
            (None, None) => Ok(true),
            (None, Some(_)) | (Some(_), None) => Ok(false),
            (Some(left), Some(right)) => self.rich_equal_values(&left, &right),
        }
    }

    fn cell_order_values(
        &mut self,
        left: &Value,
        right: &Value,
        op: SequenceOrder,
    ) -> Result<Option<bool>, String> {
        let (Some(left), Some(right)) = (cell_compare_contents(left), cell_compare_contents(right))
        else {
            return Ok(None);
        };

        match (left, right) {
            (None, None) => Ok(Some(matches!(
                op,
                SequenceOrder::LessEqual | SequenceOrder::GreaterEqual
            ))),
            (None, Some(_)) => Ok(Some(matches!(
                op,
                SequenceOrder::Less | SequenceOrder::LessEqual
            ))),
            (Some(_), None) => Ok(Some(matches!(
                op,
                SequenceOrder::Greater | SequenceOrder::GreaterEqual
            ))),
            (Some(left), Some(right)) => Ok(Some(match op {
                SequenceOrder::Less => self.less_values(left, right)?,
                SequenceOrder::LessEqual => self.less_equal_values(left, right)?,
                SequenceOrder::Greater => self.greater_values(left, right)?,
                SequenceOrder::GreaterEqual => self.greater_equal_values(left, right)?,
            })),
        }
    }

    fn less_values(&mut self, left: Value, right: Value) -> Result<bool, String> {
        if let Some(result) = self.cmp_to_key_order_values(&left, &right, SequenceOrder::Less)? {
            return Ok(result);
        }
        if let Some(result) = self.cell_order_values(&left, &right, SequenceOrder::Less)? {
            return Ok(result);
        }
        if let Some(result) = self.rich_sequence_order_values(&left, &right, SequenceOrder::Less)? {
            return Ok(result);
        }
        if let Some(result) = self.dict_item_view_less(&left, &right)? {
            return Ok(result);
        }
        if let Some(result) = self.counter_compare_values(&left, &right, CounterCompareOp::Less)? {
            return Ok(result);
        }

        if self.is_set_operator_value(&left) || self.is_set_operator_value(&right) {
            let left_is_set = self.is_set_operator_value(&left);
            let right_is_set = self.is_set_operator_value(&right);
            if left_is_set && right_is_set {
                let left = self.set_operator_values(left, "<")?;
                let right = self.set_operator_values(right, "<")?;
                return self.set_is_proper_subset(&left, &right);
            }
        }
        if let Some(value) = self.call_order_special(left.clone(), right.clone(), "__lt__")? {
            return Ok(value);
        }
        if let Some(value) = self.call_order_special(right.clone(), left.clone(), "__gt__")? {
            return Ok(value);
        }
        if let Some(message) = mappingproxy_order_type_error(&left, &right, "<") {
            return Err(message);
        }
        if let Some(message) = array_array_order_type_error(&left, &right, "<") {
            return Err(message);
        }
        less_values(left, right)
    }

    fn less_equal_values(&mut self, left: Value, right: Value) -> Result<bool, String> {
        if let Some(result) =
            self.cmp_to_key_order_values(&left, &right, SequenceOrder::LessEqual)?
        {
            return Ok(result);
        }
        if let Some(result) = self.cell_order_values(&left, &right, SequenceOrder::LessEqual)? {
            return Ok(result);
        }
        if let Some(result) =
            self.rich_sequence_order_values(&left, &right, SequenceOrder::LessEqual)?
        {
            return Ok(result);
        }
        if let Some(result) = self.dict_item_view_less_equal(&left, &right)? {
            return Ok(result);
        }
        if let Some(result) =
            self.counter_compare_values(&left, &right, CounterCompareOp::LessEqual)?
        {
            return Ok(result);
        }

        if self.is_set_operator_value(&left) || self.is_set_operator_value(&right) {
            let left_is_set = self.is_set_operator_value(&left);
            let right_is_set = self.is_set_operator_value(&right);
            if left_is_set && right_is_set {
                let left = self.set_operator_values(left, "<=")?;
                let right = self.set_operator_values(right, "<=")?;
                return self.set_is_subset(&left, &right);
            }
        }
        if let Some(value) = self.call_order_special(left.clone(), right.clone(), "__le__")? {
            return Ok(value);
        }
        if let Some(value) = self.call_order_special(right.clone(), left.clone(), "__ge__")? {
            return Ok(value);
        }
        if let Some(message) = mappingproxy_order_type_error(&left, &right, "<=") {
            return Err(message);
        }
        if let Some(message) = array_array_order_type_error(&left, &right, "<=") {
            return Err(message);
        }
        less_equal_values(left, right)
    }

    fn greater_values(&mut self, left: Value, right: Value) -> Result<bool, String> {
        if let Some(result) = self.cmp_to_key_order_values(&left, &right, SequenceOrder::Greater)? {
            return Ok(result);
        }
        if let Some(result) = self.cell_order_values(&left, &right, SequenceOrder::Greater)? {
            return Ok(result);
        }
        if let Some(result) =
            self.rich_sequence_order_values(&left, &right, SequenceOrder::Greater)?
        {
            return Ok(result);
        }
        if let Some(result) = self.dict_item_view_greater(&left, &right)? {
            return Ok(result);
        }
        if let Some(result) =
            self.counter_compare_values(&left, &right, CounterCompareOp::Greater)?
        {
            return Ok(result);
        }

        if self.is_set_operator_value(&left) || self.is_set_operator_value(&right) {
            let left_is_set = self.is_set_operator_value(&left);
            let right_is_set = self.is_set_operator_value(&right);
            if left_is_set && right_is_set {
                let left = self.set_operator_values(left, ">")?;
                let right = self.set_operator_values(right, ">")?;
                return self.set_is_proper_superset(&left, &right);
            }
        }
        if let Some(value) = self.call_order_special(left.clone(), right.clone(), "__gt__")? {
            return Ok(value);
        }
        if let Some(value) = self.call_order_special(right.clone(), left.clone(), "__lt__")? {
            return Ok(value);
        }
        if let Some(message) = mappingproxy_order_type_error(&left, &right, ">") {
            return Err(message);
        }
        if let Some(message) = array_array_order_type_error(&left, &right, ">") {
            return Err(message);
        }
        greater_values(left, right)
    }

    fn greater_equal_values(&mut self, left: Value, right: Value) -> Result<bool, String> {
        if let Some(result) =
            self.cmp_to_key_order_values(&left, &right, SequenceOrder::GreaterEqual)?
        {
            return Ok(result);
        }
        if let Some(result) = self.cell_order_values(&left, &right, SequenceOrder::GreaterEqual)? {
            return Ok(result);
        }
        if let Some(result) =
            self.rich_sequence_order_values(&left, &right, SequenceOrder::GreaterEqual)?
        {
            return Ok(result);
        }
        if let Some(result) = self.dict_item_view_greater_equal(&left, &right)? {
            return Ok(result);
        }
        if let Some(result) =
            self.counter_compare_values(&left, &right, CounterCompareOp::GreaterEqual)?
        {
            return Ok(result);
        }

        if self.is_set_operator_value(&left) || self.is_set_operator_value(&right) {
            let left_is_set = self.is_set_operator_value(&left);
            let right_is_set = self.is_set_operator_value(&right);
            if left_is_set && right_is_set {
                let left = self.set_operator_values(left, ">=")?;
                let right = self.set_operator_values(right, ">=")?;
                return self.set_is_superset(&left, &right);
            }
        }
        if let Some(value) = self.call_order_special(left.clone(), right.clone(), "__ge__")? {
            return Ok(value);
        }
        if let Some(value) = self.call_order_special(right.clone(), left.clone(), "__le__")? {
            return Ok(value);
        }
        if let Some(message) = mappingproxy_order_type_error(&left, &right, ">=") {
            return Err(message);
        }
        if let Some(message) = array_array_order_type_error(&left, &right, ">=") {
            return Err(message);
        }
        greater_equal_values(left, right)
    }

    fn is_set_operator_value(&self, value: &Value) -> bool {
        match value {
            Value::Set(_) | Value::FrozenSet(_) => true,
            Value::DictView { kind, .. } | Value::MappingView { kind, .. } => {
                dict_view_is_set_like(*kind)
            }
            value => {
                set_subclass_items(value).is_some() || frozen_set_subclass_items(value).is_some()
            }
        }
    }

    fn is_set_like_equality_operand(&self, value: &Value) -> bool {
        is_set_abc_value(value)
    }

    fn set_operator_values(&mut self, value: Value, op: &str) -> Result<Vec<Value>, String> {
        match value {
            Value::Set(items) => Ok(items.borrow().clone()),
            Value::FrozenSet(items) => Ok(items.as_ref().clone()),
            value if set_subclass_items(&value).is_some() => Ok(set_subclass_items(&value)
                .expect("set subclass items exist after guard")
                .borrow()
                .clone()),
            value if frozen_set_subclass_items(&value).is_some() => {
                Ok(frozen_set_subclass_items(&value)
                    .expect("frozenset subclass items exist after guard")
                    .as_ref()
                    .clone())
            }
            value if is_set_abc_value(&value) => self.collect_iterable_values(value),
            Value::DictView { kind, entries, .. } if dict_view_is_set_like(kind) => {
                Ok(dict_view_values(kind, &entries))
            }
            Value::MappingView { kind, mapping, .. } if dict_view_is_set_like(kind) => {
                self.mapping_view_values(kind, *mapping)
            }
            value => Err(format!(
                "TypeError: unsupported operand type(s) for {op}: 'set' and '{}'",
                type_name(&value)
            )),
        }
    }

    fn set_iterable_lookup_values(&mut self, iterable: Value) -> Result<Vec<Value>, String> {
        let values = self.collect_iterable_values_propagating(iterable)?;
        for value in &values {
            self.ensure_hashable_key(value)?;
        }
        Ok(values)
    }

    fn set_union_from_iterables_with_kind(
        &mut self,
        kind: SetResultKind,
        mut items: Vec<Value>,
        iterables: &[Value],
    ) -> Result<Value, String> {
        for iterable in iterables {
            for value in self.collect_iterable_values_propagating(iterable.clone())? {
                self.insert_set_item(&mut items, value)?;
            }
        }
        Ok(set_result_value(kind, items))
    }

    fn set_intersection_from_iterables_with_kind(
        &mut self,
        kind: SetResultKind,
        mut items: Vec<Value>,
        iterables: &[Value],
    ) -> Result<Value, String> {
        for iterable in iterables {
            let other = self.set_iterable_lookup_values(iterable.clone())?;
            let mut retained = Vec::new();
            for item in items {
                if self.set_position(&other, &item)?.is_some() {
                    retained.push(item);
                }
            }
            items = retained;
        }
        Ok(set_result_value(kind, items))
    }

    fn set_difference_from_iterables_with_kind(
        &mut self,
        kind: SetResultKind,
        mut items: Vec<Value>,
        iterables: &[Value],
    ) -> Result<Value, String> {
        for iterable in iterables {
            let other = self.set_iterable_lookup_values(iterable.clone())?;
            let mut retained = Vec::new();
            for item in items {
                if self.set_position(&other, &item)?.is_none() {
                    retained.push(item);
                }
            }
            items = retained;
        }
        Ok(set_result_value(kind, items))
    }

    fn set_symmetric_difference_from_iterable_with_kind(
        &mut self,
        kind: SetResultKind,
        mut items: Vec<Value>,
        iterable: &Value,
    ) -> Result<Value, String> {
        let mut other = Vec::new();
        for value in self.collect_iterable_values_propagating(iterable.clone())? {
            self.insert_set_item(&mut other, value)?;
        }

        for value in other {
            if let Some(position) = self.set_position(&items, &value)? {
                items.remove(position);
            } else {
                items.push(value);
            }
        }
        Ok(set_result_value(kind, items))
    }

    fn set_is_disjoint_from_iterable(
        &mut self,
        items: &[Value],
        iterable: Value,
    ) -> Result<bool, String> {
        let other = self.set_iterable_lookup_values(iterable)?;
        for item in items {
            if self.set_position(&other, item)?.is_some() {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn set_is_subset_of_iterable(
        &mut self,
        items: &[Value],
        iterable: Value,
    ) -> Result<bool, String> {
        let other = self.set_iterable_lookup_values(iterable)?;
        for item in items {
            if self.set_position(&other, item)?.is_none() {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn set_is_superset_of_iterable(
        &mut self,
        items: &[Value],
        iterable: Value,
    ) -> Result<bool, String> {
        let other = self.set_iterable_lookup_values(iterable)?;
        for item in &other {
            if self.set_position(items, item)?.is_none() {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn set_values_equal(&mut self, left: &[Value], right: &[Value]) -> Result<bool, String> {
        Ok(left.len() == right.len() && self.set_is_subset(left, right)?)
    }

    fn dict_item_view_equal(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<bool>, String> {
        let Some(left) = self.dict_item_view_entries(left)? else {
            return Ok(None);
        };
        let Some(right) = self.dict_item_view_entries(right)? else {
            return Ok(None);
        };
        Ok(Some(
            left.len() == right.len() && self.dict_item_entries_subset(&left, &right)?,
        ))
    }

    fn dict_item_view_less(&mut self, left: &Value, right: &Value) -> Result<Option<bool>, String> {
        let Some(left) = self.dict_item_view_entries(left)? else {
            return Ok(None);
        };
        let Some(right) = self.dict_item_view_entries(right)? else {
            return Ok(None);
        };
        Ok(Some(
            left.len() < right.len() && self.dict_item_entries_subset(&left, &right)?,
        ))
    }

    fn dict_item_view_less_equal(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<bool>, String> {
        let Some(left) = self.dict_item_view_entries(left)? else {
            return Ok(None);
        };
        let Some(right) = self.dict_item_view_entries(right)? else {
            return Ok(None);
        };
        Ok(Some(self.dict_item_entries_subset(&left, &right)?))
    }

    fn dict_item_view_greater(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<bool>, String> {
        let Some(left) = self.dict_item_view_entries(left)? else {
            return Ok(None);
        };
        let Some(right) = self.dict_item_view_entries(right)? else {
            return Ok(None);
        };
        Ok(Some(
            left.len() > right.len() && self.dict_item_entries_subset(&right, &left)?,
        ))
    }

    fn dict_item_view_greater_equal(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<bool>, String> {
        let Some(left) = self.dict_item_view_entries(left)? else {
            return Ok(None);
        };
        let Some(right) = self.dict_item_view_entries(right)? else {
            return Ok(None);
        };
        Ok(Some(self.dict_item_entries_subset(&right, &left)?))
    }

    fn dict_item_view_entries(
        &mut self,
        value: &Value,
    ) -> Result<Option<Vec<(Value, Value)>>, String> {
        match value {
            Value::DictView {
                kind: DictViewKind::Items,
                entries,
                ..
            } => Ok(Some(entries.borrow().clone())),
            Value::MappingView {
                kind: DictViewKind::Items,
                mapping,
                ..
            } => self.mapping_abc_entries(*mapping.clone()).map(Some),
            _ => Ok(None),
        }
    }

    fn dict_item_entries_subset(
        &mut self,
        left: &[(Value, Value)],
        right: &[(Value, Value)],
    ) -> Result<bool, String> {
        for (key, value) in left {
            let Some((_, other_value)) = right
                .iter()
                .find(|(other_key, _)| dict_keys_equal(other_key, key))
            else {
                return Ok(false);
            };
            if !self.rich_equal_values(value, other_value)? {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn scope_backed_mapping_equal(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<bool>, String> {
        if !is_scope_backed_mapping_value(left) && !is_scope_backed_mapping_value(right) {
            return Ok(None);
        }
        let left_entries = match mapping_entries(left) {
            Ok(entries) => entries,
            Err(_) => return Ok(Some(false)),
        };
        let right_entries = match mapping_entries(right) {
            Ok(entries) => entries,
            Err(_) => return Ok(Some(false)),
        };
        Ok(Some(
            left_entries.len() == right_entries.len()
                && self.dict_item_entries_subset(&left_entries, &right_entries)?,
        ))
    }

    fn set_is_subset(&mut self, left: &[Value], right: &[Value]) -> Result<bool, String> {
        for item in left {
            if !self.set_contains_rich(right, item)? {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn set_is_proper_subset(&mut self, left: &[Value], right: &[Value]) -> Result<bool, String> {
        Ok(left.len() < right.len() && self.set_is_subset(left, right)?)
    }

    fn set_is_superset(&mut self, left: &[Value], right: &[Value]) -> Result<bool, String> {
        self.set_is_subset(right, left)
    }

    fn set_is_proper_superset(&mut self, left: &[Value], right: &[Value]) -> Result<bool, String> {
        Ok(left.len() > right.len() && self.set_is_superset(left, right)?)
    }

    fn set_contains_rich(&mut self, items: &[Value], value: &Value) -> Result<bool, String> {
        Ok(self.set_position(items, value)?.is_some())
    }

    fn rich_equal_values(&mut self, left: &Value, right: &Value) -> Result<bool, String> {
        if let Some(value) = self.cmp_to_key_equal_values(left, right)? {
            return Ok(value);
        }

        if is_identical(left, right)
            && !matches!(left, Value::Float(_))
            && !matches!(left, Value::Complex { .. })
            && float_subclass_float(left).is_none()
            && complex_subclass_parts(left).is_none()
        {
            return Ok(true);
        }

        if let Some(value) = self.cell_rich_equal_if_cells(left, right)? {
            return Ok(value);
        }

        if let Some(value) = self.counter_equal_values(left, right)? {
            return Ok(value);
        }

        if let Some(value) = self.dict_item_view_equal(left, right)? {
            return Ok(value);
        }

        if let Some(value) = self.scope_backed_mapping_equal(left, right)? {
            return Ok(value);
        }

        if array_array_storage(left).is_some() || array_array_storage(right).is_some() {
            return if array_array_storage(left).is_some() && array_array_storage(right).is_some() {
                let left = array_array_values(left).expect("array storage exists after guard");
                let right = array_array_values(right).expect("array storage exists after guard");
                self.rich_sequence_equal(&left, &right)
            } else {
                Ok(false)
            };
        }

        if let Some(value) = self.union_aliases_equal(left, right)? {
            return Ok(value);
        }

        if let Some(value) = bound_methods_directly_equal(left, right) {
            return Ok(value);
        }

        if let Some(value) = user_string_rich_equal_values(left, right) {
            return Ok(value);
        }

        if let Some(message) = bytes_comparison_warning_message(left, right) {
            self.emit_bytes_comparison_warning(message)?;
        }

        if let Some(left_items) = tuple_subclass_items(left) {
            match right {
                Value::Tuple(right_items) => {
                    return self.rich_sequence_equal(left_items.as_ref(), right_items.as_ref());
                }
                Value::NamedTuple { values, .. } => {
                    return self.rich_sequence_equal(left_items.as_ref(), values.as_ref());
                }
                value if tuple_subclass_items(value).is_some() => {
                    let right_items = tuple_subclass_items(value)
                        .expect("tuple subclass items exist after guard");
                    return self.rich_sequence_equal(left_items.as_ref(), right_items.as_ref());
                }
                _ => {}
            }
        }

        if let Some(right_items) = tuple_subclass_items(right) {
            match left {
                Value::Tuple(left_items) => {
                    return self.rich_sequence_equal(left_items.as_ref(), right_items.as_ref());
                }
                Value::NamedTuple { values, .. } => {
                    return self.rich_sequence_equal(values.as_ref(), right_items.as_ref());
                }
                _ => {}
            }
        }

        match (left, right) {
            (Value::Tuple(left), Value::Tuple(right)) => {
                return self.rich_sequence_equal(left.as_ref(), right.as_ref());
            }
            (Value::Deque { data: left, .. }, Value::Deque { data: right, .. }) => {
                return self.rich_sequence_equal(&left.borrow(), &right.borrow());
            }
            (Value::List(left), Value::List(right)) => {
                return self.rich_sequence_equal(&left.borrow(), &right.borrow());
            }
            (Value::UserList { data: left, .. }, Value::UserList { data: right, .. }) => {
                return self.rich_sequence_equal(&left.borrow(), &right.borrow());
            }
            (Value::List(left), Value::UserList { data: right, .. })
            | (Value::UserList { data: right, .. }, Value::List(left)) => {
                return self.rich_sequence_equal(&left.borrow(), &right.borrow());
            }
            (Value::Dict(left), Value::Dict(right)) => {
                let left = left.borrow().entries.clone();
                let right = right.borrow().entries.clone();
                return Ok(
                    left.len() == right.len() && self.dict_item_entries_subset(&left, &right)?
                );
            }
            (Value::UserDict { data: left, .. }, Value::UserDict { data: right, .. }) => {
                let left = left.borrow().entries.clone();
                let right = right.borrow().entries.clone();
                return Ok(
                    left.len() == right.len() && self.dict_item_entries_subset(&left, &right)?
                );
            }
            (Value::SimpleNamespace { fields: left }, Value::SimpleNamespace { fields: right }) => {
                let left = left.borrow().entries.clone();
                let right = right.borrow().entries.clone();
                if let Some(value) = code_metadata_namespace_entries_equal(&left, &right) {
                    return Ok(value);
                }
                return Ok(
                    left.len() == right.len() && self.dict_item_entries_subset(&left, &right)?
                );
            }
            _ => {}
        }

        if let (Some(left_bytes), Some(right_bytes)) = (
            bytes_equality_value_bytes(left),
            bytes_equality_value_bytes(right),
        ) {
            return Ok(left_bytes == right_bytes);
        }

        if let (
            Value::WeakRef {
                target: left_target,
                ..
            },
            Value::WeakRef {
                target: right_target,
                ..
            },
        ) = (left, right)
        {
            return self.rich_equal_values(left_target, right_target);
        }

        if let Some(value) = forward_ref_equal_values(left, right)? {
            return Ok(value);
        }

        if let Some(value) = self.call_eq_special(left.clone(), right.clone())? {
            return Ok(value);
        }
        if let Some(value) = self.call_eq_special(right.clone(), left.clone())? {
            return Ok(value);
        }
        if let Some(left) = generic_alias_subclass_alias(left) {
            return self.rich_equal_values(&left, right);
        }
        if let Some(right) = generic_alias_subclass_alias(right) {
            return self.rich_equal_values(left, &right);
        }
        if let Some(left) = int_subclass_integer(left) {
            return self.rich_equal_values(&left, right);
        }
        if let Some(right) = int_subclass_integer(right) {
            return self.rich_equal_values(left, &right);
        }
        if let Some(left) = float_subclass_value(left) {
            return self.rich_equal_values(&left, right);
        }
        if let Some(right) = float_subclass_value(right) {
            return self.rich_equal_values(left, &right);
        }
        if let Some(left) = complex_subclass_value(left) {
            return self.rich_equal_values(&left, right);
        }
        if let Some(right) = complex_subclass_value(right) {
            return self.rich_equal_values(left, &right);
        }
        if matches!(left, Value::Instance { .. }) || matches!(right, Value::Instance { .. }) {
            return Ok(false);
        }
        Ok(left == right)
    }

    fn union_aliases_equal(&mut self, left: &Value, right: &Value) -> Result<Option<bool>, String> {
        let (Some(left_args), Some(right_args)) = (union_args(left), union_args(right)) else {
            return Ok(None);
        };
        if left_args.len() != right_args.len() {
            return Ok(Some(false));
        }

        let mut matched = vec![false; right_args.len()];
        for left_arg in left_args {
            let mut found = false;
            for (index, right_arg) in right_args.iter().enumerate() {
                if matched[index] {
                    continue;
                }
                let equal = if is_identical(left_arg, right_arg) {
                    true
                } else if union_dedupe_uses_rich_equality(left_arg, right_arg) {
                    self.rich_equal_values(left_arg, right_arg)?
                } else {
                    left_arg == right_arg
                };
                if equal {
                    matched[index] = true;
                    found = true;
                    break;
                }
            }
            if !found {
                return Ok(Some(false));
            }
        }
        Ok(Some(true))
    }

    fn counter_equal_values(
        &mut self,
        left: &Value,
        right: &Value,
    ) -> Result<Option<bool>, String> {
        let (Some(left), Some(right)) = (
            counter_entries_if_value(left),
            counter_entries_if_value(right),
        ) else {
            return Ok(None);
        };
        let left = left.borrow().entries.clone();
        let right = right.borrow().entries.clone();
        for key in counter_union_keys(&left, &right) {
            let left_count = dict_lookup(&left, &key).unwrap_or(Value::Number(0));
            let right_count = dict_lookup(&right, &key).unwrap_or(Value::Number(0));
            if !self.rich_equal_values(&left_count, &right_count)? {
                return Ok(Some(false));
            }
        }
        Ok(Some(true))
    }

    fn counter_compare_values(
        &mut self,
        left: &Value,
        right: &Value,
        op: CounterCompareOp,
    ) -> Result<Option<bool>, String> {
        let (Some(left), Some(right)) = (
            counter_entries_if_value(left),
            counter_entries_if_value(right),
        ) else {
            return Ok(None);
        };
        let left = left.borrow().entries.clone();
        let right = right.borrow().entries.clone();
        Ok(Some(match op {
            CounterCompareOp::LessEqual => self.counter_entries_less_equal(&left, &right)?,
            CounterCompareOp::Less => {
                self.counter_entries_less_equal(&left, &right)?
                    && !self.counter_entries_equal(&left, &right)?
            }
            CounterCompareOp::GreaterEqual => self.counter_entries_less_equal(&right, &left)?,
            CounterCompareOp::Greater => {
                self.counter_entries_less_equal(&right, &left)?
                    && !self.counter_entries_equal(&left, &right)?
            }
        }))
    }

    fn counter_entries_equal(
        &mut self,
        left: &[(Value, Value)],
        right: &[(Value, Value)],
    ) -> Result<bool, String> {
        for key in counter_union_keys(left, right) {
            let left_count = dict_lookup(left, &key).unwrap_or(Value::Number(0));
            let right_count = dict_lookup(right, &key).unwrap_or(Value::Number(0));
            if !self.rich_equal_values(&left_count, &right_count)? {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn counter_entries_less_equal(
        &mut self,
        left: &[(Value, Value)],
        right: &[(Value, Value)],
    ) -> Result<bool, String> {
        for key in counter_union_keys(left, right) {
            let left_count = dict_lookup(left, &key).unwrap_or(Value::Number(0));
            let right_count = dict_lookup(right, &key).unwrap_or(Value::Number(0));
            if !self.less_equal_values(left_count, right_count)? {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn rich_sequence_equal(&mut self, left: &[Value], right: &[Value]) -> Result<bool, String> {
        if left.len() != right.len() {
            return Ok(false);
        }
        for (left_item, right_item) in left.iter().zip(right.iter()) {
            if !sequence_items_match(left_item, right_item)
                && !self.rich_equal_values(left_item, right_item)?
            {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn rich_sequence_order_values(
        &mut self,
        left: &Value,
        right: &Value,
        op: SequenceOrder,
    ) -> Result<Option<bool>, String> {
        if array_array_storage(left).is_some() || array_array_storage(right).is_some() {
            return if array_array_storage(left).is_some() && array_array_storage(right).is_some() {
                let left = array_array_values(left).expect("array storage exists after guard");
                let right = array_array_values(right).expect("array storage exists after guard");
                Ok(Some(self.rich_sequence_order(&left, &right, op)?))
            } else {
                Ok(None)
            };
        }

        if let (Value::Deque { data: left, .. }, Value::Deque { data: right, .. }) = (left, right) {
            let left = left.borrow().clone();
            let right = right.borrow().clone();
            return Ok(Some(self.rich_sequence_order(&left, &right, op)?));
        }

        let Some((left, right)) = sequence_order_operands(left, right) else {
            return Ok(None);
        };

        Ok(Some(self.rich_sequence_order(&left, &right, op)?))
    }

    fn rich_sequence_order(
        &mut self,
        left: &[Value],
        right: &[Value],
        op: SequenceOrder,
    ) -> Result<bool, String> {
        for (left_item, right_item) in left.iter().zip(right.iter()) {
            if self.rich_equal_values(left_item, right_item)? {
                continue;
            }
            return self.sequence_item_order(left_item.clone(), right_item.clone(), op);
        }

        Ok(match op {
            SequenceOrder::Less => left.len() < right.len(),
            SequenceOrder::LessEqual => left.len() <= right.len(),
            SequenceOrder::Greater => left.len() > right.len(),
            SequenceOrder::GreaterEqual => left.len() >= right.len(),
        })
    }

    fn sequence_item_order(
        &mut self,
        left: Value,
        right: Value,
        op: SequenceOrder,
    ) -> Result<bool, String> {
        match op {
            SequenceOrder::Less => self.less_values(left, right),
            SequenceOrder::LessEqual => self.less_equal_values(left, right),
            SequenceOrder::Greater => self.greater_values(left, right),
            SequenceOrder::GreaterEqual => self.greater_equal_values(left, right),
        }
    }

    fn call_eq_special(&mut self, left: Value, right: Value) -> Result<Option<bool>, String> {
        let Some(method) = instance_special_method(&left, "__eq__")
            .or_else(|| metaclass_special_method(&left, "__eq__"))
        else {
            return Ok(None);
        };
        let result = self.call_value(method, vec![right])?;
        if matches!(result, Value::NotImplemented) {
            return Ok(None);
        }
        self.truth_value(result).map(Some)
    }

    fn call_ne_special(&mut self, left: Value, right: Value) -> Result<Option<bool>, String> {
        let Some(method) = instance_special_method(&left, "__ne__")
            .or_else(|| metaclass_special_method(&left, "__ne__"))
        else {
            return Ok(None);
        };
        let result = self.call_value(method, vec![right])?;
        if matches!(result, Value::NotImplemented) {
            return Ok(None);
        }
        self.truth_value(result).map(Some)
    }

    fn call_order_special(
        &mut self,
        left: Value,
        right: Value,
        method_name: &str,
    ) -> Result<Option<bool>, String> {
        let Some(method) = instance_special_method(&left, method_name) else {
            return Ok(None);
        };
        let result = self.call_value(method, vec![right])?;
        if matches!(result, Value::NotImplemented) {
            return Ok(None);
        }
        self.truth_value(result).map(Some)
    }

    fn mutable_mapping_abc_update_from_source(
        &mut self,
        receiver: Value,
        source: Value,
    ) -> Result<(), String> {
        if is_mapping_abc_value(&source) {
            for key in self.collect_iterable_values(source.clone())? {
                let value = self.mapping_abc_get_item(source.clone(), key.clone())?;
                self.store_subscript_value(receiver.clone(), key, value)?;
            }
            return Ok(());
        }

        match self.load_attribute_catching(source.clone(), "keys")? {
            Ok(keys_method) => {
                let keys = match self.call_value_catching(keys_method, Vec::new())? {
                    Ok(keys) => keys,
                    Err(exception) => return Err(format_exception_error(&exception)),
                };
                for key in self.collect_iterable_values_propagating(keys)? {
                    let value = self.mapping_abc_get_item(source.clone(), key.clone())?;
                    self.store_subscript_value(receiver.clone(), key, value)?;
                }
            }
            Err(exception) if exception.type_name == "AttributeError" => {
                for (index, item) in self
                    .collect_iterable_values_propagating(source)?
                    .into_iter()
                    .enumerate()
                {
                    let pair = self.collect_iterable_values_propagating(item)?;
                    match pair.as_slice() {
                        [key, value] => {
                            self.store_subscript_value(
                                receiver.clone(),
                                key.clone(),
                                value.clone(),
                            )?;
                        }
                        values => {
                            return Err(format!(
                                "ValueError: dictionary update sequence element #{index} has length {}; 2 is required",
                                values.len()
                            ));
                        }
                    }
                }
            }
            Err(exception) => return Err(format_exception_error(&exception)),
        }

        Ok(())
    }

    fn call_set_abc_method(
        &mut self,
        name: &str,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        match method_display_name(name) {
            "__le__" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("__le__", "other", args, keywords)?;
                self.set_abc_less_equal(receiver, other)
            }
            "__lt__" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("__lt__", "other", args, keywords)?;
                self.set_abc_less(receiver, other)
            }
            "__gt__" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("__gt__", "other", args, keywords)?;
                self.set_abc_greater(receiver, other)
            }
            "__ge__" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("__ge__", "other", args, keywords)?;
                self.set_abc_greater_equal(receiver, other)
            }
            "__eq__" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("__eq__", "other", args, keywords)?;
                self.set_abc_equal(receiver, other)
            }
            "__ne__" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("__ne__", "other", args, keywords)?;
                self.set_abc_not_equal(receiver, other)
            }
            "__and__" | "__rand__" => {
                let (receiver, other) = mutable_sequence_abc_bind_one_arg(
                    method_display_name(name),
                    "other",
                    args,
                    keywords,
                )?;
                self.set_abc_and(receiver, other)
            }
            "isdisjoint" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("isdisjoint", "other", args, keywords)?;
                self.set_abc_is_disjoint(receiver, other)
            }
            "__or__" | "__ror__" => {
                let (receiver, other) = mutable_sequence_abc_bind_one_arg(
                    method_display_name(name),
                    "other",
                    args,
                    keywords,
                )?;
                self.set_abc_or(receiver, other)
            }
            "__sub__" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("__sub__", "other", args, keywords)?;
                self.set_abc_sub(receiver, other)
            }
            "__rsub__" => {
                let (receiver, other) =
                    mutable_sequence_abc_bind_one_arg("__rsub__", "other", args, keywords)?;
                self.set_abc_sub(other, receiver)
            }
            "__xor__" | "__rxor__" => {
                let (receiver, other) = mutable_sequence_abc_bind_one_arg(
                    method_display_name(name),
                    "other",
                    args,
                    keywords,
                )?;
                self.set_abc_xor(receiver, other)
            }
            "_from_iterable" => {
                let (receiver, iterable) =
                    mutable_sequence_abc_bind_one_arg("_from_iterable", "it", args, keywords)?;
                let class = type_object_for_value(&receiver);
                self.call_value(class, vec![iterable])
            }
            "_hash" => {
                reject_method_keywords(name, &keywords)?;
                let [receiver] = args.as_slice() else {
                    return Err(format!(
                        "_hash() expected 0 arguments, got {}",
                        method_arg_count(&args)
                    ));
                };
                self.set_abc_hash(receiver.clone())
            }
            _ => Err(format!("unknown builtin: {name}")),
        }
    }

    fn set_abc_less_equal(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_set_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let receiver_len = self.sequence_abc_len_i64(receiver.clone())?;
        let other_len = self.sequence_abc_len_i64(other.clone())?;
        if receiver_len > other_len {
            return Ok(Value::Bool(false));
        }
        for value in self.collect_iterable_values(receiver)? {
            if !self.set_abc_contains(other.clone(), value)? {
                return Ok(Value::Bool(false));
            }
        }
        Ok(Value::Bool(true))
    }

    fn set_abc_less(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_set_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let receiver_len = self.sequence_abc_len_i64(receiver.clone())?;
        let other_len = self.sequence_abc_len_i64(other.clone())?;
        if receiver_len >= other_len {
            return Ok(Value::Bool(false));
        }
        self.set_abc_less_equal(receiver, other)
    }

    fn set_abc_not_equal(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        match self.set_abc_equal(receiver, other)? {
            Value::Bool(value) => Ok(Value::Bool(!value)),
            Value::NotImplemented => Ok(Value::NotImplemented),
            value => Err(format!("__eq__ returned non-boolean value: {value}")),
        }
    }

    fn set_abc_greater_equal(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_set_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let receiver_len = self.sequence_abc_len_i64(receiver.clone())?;
        let other_len = self.sequence_abc_len_i64(other.clone())?;
        if receiver_len < other_len {
            return Ok(Value::Bool(false));
        }
        for value in self.collect_iterable_values(other)? {
            if !self.set_abc_contains(receiver.clone(), value)? {
                return Ok(Value::Bool(false));
            }
        }
        Ok(Value::Bool(true))
    }

    fn set_abc_greater(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_set_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let receiver_len = self.sequence_abc_len_i64(receiver.clone())?;
        let other_len = self.sequence_abc_len_i64(other.clone())?;
        if receiver_len <= other_len {
            return Ok(Value::Bool(false));
        }
        self.set_abc_greater_equal(receiver, other)
    }

    fn set_abc_equal(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_set_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let receiver_len = self.sequence_abc_len_i64(receiver.clone())?;
        let other_len = self.sequence_abc_len_i64(other.clone())?;
        if receiver_len != other_len {
            return Ok(Value::Bool(false));
        }
        self.set_abc_less_equal(receiver, other)
    }

    fn set_abc_and(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_iterable_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let mut values = Vec::new();
        for value in self.collect_iterable_values(other)? {
            if self.set_abc_contains(receiver.clone(), value.clone())? {
                push_unique_set_value(&mut values, value)?;
            }
        }
        self.set_abc_from_iterable(receiver, values)
    }

    fn set_abc_is_disjoint(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        for value in self.collect_iterable_values(other)? {
            if self.set_abc_contains(receiver.clone(), value)? {
                return Ok(Value::Bool(false));
            }
        }
        Ok(Value::Bool(true))
    }

    fn set_abc_or(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_iterable_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let mut values = Vec::new();
        for value in self.collect_iterable_values(receiver.clone())? {
            push_unique_set_value(&mut values, value)?;
        }
        for value in self.collect_iterable_values(other)? {
            push_unique_set_value(&mut values, value)?;
        }
        self.set_abc_from_iterable(receiver, values)
    }

    fn set_abc_sub(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_set_abc_value(&other) && !is_iterable_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let other_values = self.collect_iterable_values(other)?;
        let mut values = Vec::new();
        for value in self.collect_iterable_values(receiver.clone())? {
            if !set_contains_value(&other_values, &value) {
                push_unique_set_value(&mut values, value)?;
            }
        }
        self.set_abc_from_iterable(receiver, values)
    }

    fn set_abc_xor(&mut self, receiver: Value, other: Value) -> Result<Value, String> {
        if !is_set_abc_value(&other) && !is_iterable_abc_value(&other) {
            return Ok(Value::NotImplemented);
        }
        let receiver_values = self.collect_iterable_values(receiver.clone())?;
        let other_values = self.collect_iterable_values(other)?;
        let mut values = Vec::new();
        for value in receiver_values.iter() {
            if !set_contains_value(&other_values, value) {
                push_unique_set_value(&mut values, value.clone())?;
            }
        }
        for value in other_values {
            if !set_contains_value(&receiver_values, &value) {
                push_unique_set_value(&mut values, value)?;
            }
        }
        self.set_abc_from_iterable(receiver, values)
    }

    fn set_abc_hash(&mut self, receiver: Value) -> Result<Value, String> {
        let values = self.collect_iterable_values(receiver)?;
        self.frozenset_hash(values)
    }

    fn frozenset_hash(&mut self, values: Vec<Value>) -> Result<Value, String> {
        let mask = u64::MAX;
        let mut hash = 1_927_868_237_u64.wrapping_mul(values.len() as u64 + 1) & mask;
        for value in values {
            let item_hash = call_hash_builtin(self, vec![value], Vec::new())?;
            let item_hash = py_hash_to_u64(item_hash)?;
            let mixed = (item_hash ^ item_hash.wrapping_shl(16) ^ 89_869_747_u64)
                .wrapping_mul(3_644_798_167_u64);
            hash = (hash ^ mixed) & mask;
        }
        hash ^= hash.wrapping_shr(11) ^ hash.wrapping_shr(25);
        hash = hash.wrapping_mul(69_069).wrapping_add(907_133_923) & mask;
        let signed = hash as i64;
        if signed == -1 {
            Ok(Value::Number(590_923_713))
        } else {
            Ok(normalize_big_int(BigInt::from(signed)))
        }
    }

    fn set_abc_contains(&mut self, receiver: Value, value: Value) -> Result<bool, String> {
        self.contains_value(value, receiver)
    }

    fn set_abc_from_iterable(
        &mut self,
        receiver: Value,
        values: Vec<Value>,
    ) -> Result<Value, String> {
        let iterable = list_value(values);
        match self.load_attribute_catching(receiver.clone(), "_from_iterable")? {
            Ok(method) => self.call_value(method, vec![iterable]),
            Err(exception) if exception.type_name == "AttributeError" => {
                let class = type_object_for_value(&receiver);
                self.call_value(class, vec![iterable])
            }
            Err(exception) => Err(format_exception_error(&exception)),
        }
    }

    fn call_mutable_set_abc_method(
        &mut self,
        name: &str,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        match method_display_name(name) {
            "remove" => {
                let (receiver, value) = sequence_abc_bind_one_value_arg("remove", args, keywords)?;
                self.mutable_set_abc_remove(receiver, value)
            }
            "pop" => {
                reject_method_keywords(name, &keywords)?;
                let [receiver] = args.as_slice() else {
                    return Err(format!(
                        "pop() expected 0 arguments, got {}",
                        method_arg_count(&args)
                    ));
                };
                self.mutable_set_abc_pop(receiver.clone())
            }
            "clear" => {
                reject_method_keywords(name, &keywords)?;
                let [receiver] = args.as_slice() else {
                    return Err(format!(
                        "clear() expected 0 arguments, got {}",
                        method_arg_count(&args)
                    ));
                };
                self.mutable_set_abc_clear(receiver.clone())
            }
            "__ior__" => {
                let (receiver, values) =
                    mutable_sequence_abc_bind_one_arg("__ior__", "it", args, keywords)?;
                self.mutable_set_abc_ior(receiver, values)
            }
            "__iand__" => {
                let (receiver, values) =
                    mutable_sequence_abc_bind_one_arg("__iand__", "it", args, keywords)?;
                self.mutable_set_abc_iand(receiver, values)
            }
            "__ixor__" => {
                let (receiver, values) =
                    mutable_sequence_abc_bind_one_arg("__ixor__", "it", args, keywords)?;
                self.mutable_set_abc_ixor(receiver, values)
            }
            "__isub__" => {
                let (receiver, values) =
                    mutable_sequence_abc_bind_one_arg("__isub__", "it", args, keywords)?;
                self.mutable_set_abc_isub(receiver, values)
            }
            _ => Err(format!("unknown builtin: {name}")),
        }
    }

    fn mutable_set_abc_remove(&mut self, receiver: Value, value: Value) -> Result<Value, String> {
        if !self.set_abc_contains(receiver.clone(), value.clone())? {
            return Err(format!("KeyError: {}", format_key_error(&value)));
        }
        self.mutable_set_abc_discard(receiver, value)?;
        Ok(Value::None)
    }

    fn mutable_set_abc_pop(&mut self, receiver: Value) -> Result<Value, String> {
        let Some(value) = self
            .collect_iterable_values(receiver.clone())?
            .into_iter()
            .next()
        else {
            return Err("KeyError".to_string());
        };
        self.mutable_set_abc_discard(receiver, value.clone())?;
        Ok(value)
    }

    fn mutable_set_abc_clear(&mut self, receiver: Value) -> Result<Value, String> {
        loop {
            match self.call_with_exception_capture(|vm| vm.mutable_set_abc_pop(receiver.clone()))? {
                Ok(_) => {}
                Err(exception) if exception.type_name == "KeyError" => return Ok(Value::None),
                Err(exception) => return Err(format_exception_error(&exception)),
            }
        }
    }

    fn mutable_set_abc_ior(&mut self, receiver: Value, values: Value) -> Result<Value, String> {
        for value in self.collect_iterable_values(values)? {
            self.mutable_set_abc_add(receiver.clone(), value)?;
        }
        Ok(receiver)
    }

    fn mutable_set_abc_iand(&mut self, receiver: Value, values: Value) -> Result<Value, String> {
        let other = self.collect_iterable_values(values)?;
        let mut to_remove = Vec::new();
        for value in self.collect_iterable_values(receiver.clone())? {
            if !set_contains_value(&other, &value) {
                to_remove.push(value);
            }
        }
        for value in to_remove {
            self.mutable_set_abc_discard(receiver.clone(), value)?;
        }
        Ok(receiver)
    }

    fn mutable_set_abc_ixor(&mut self, receiver: Value, values: Value) -> Result<Value, String> {
        if is_identical(&receiver, &values) {
            self.mutable_set_abc_clear(receiver.clone())?;
            return Ok(receiver);
        }
        let values = self.collect_iterable_values(values)?;
        for value in values {
            if self.set_abc_contains(receiver.clone(), value.clone())? {
                self.mutable_set_abc_discard(receiver.clone(), value)?;
            } else {
                self.mutable_set_abc_add(receiver.clone(), value)?;
            }
        }
        Ok(receiver)
    }

    fn mutable_set_abc_isub(&mut self, receiver: Value, values: Value) -> Result<Value, String> {
        if is_identical(&receiver, &values) {
            self.mutable_set_abc_clear(receiver.clone())?;
            return Ok(receiver);
        }
        for value in self.collect_iterable_values(values)? {
            self.mutable_set_abc_discard(receiver.clone(), value)?;
        }
        Ok(receiver)
    }

    fn mutable_set_abc_add(&mut self, receiver: Value, value: Value) -> Result<(), String> {
        let add = self.load_attribute_value(receiver, "add")?;
        self.call_value(add, vec![value])?;
        Ok(())
    }

    fn mutable_set_abc_discard(&mut self, receiver: Value, value: Value) -> Result<(), String> {
        let discard = self.load_attribute_value(receiver, "discard")?;
        self.call_value(discard, vec![value])?;
        Ok(())
    }

    fn call_iterator_length_hint(&mut self, receiver: Value) -> Result<Value, String> {
        match self.iterator_length_hint(receiver)? {
            Some(length) => {
                let length = i64::try_from(length)
                    .map_err(|_| "__length_hint__() result is too large".to_string())?;
                Ok(Value::Number(length))
            }
            None => Ok(Value::NotImplemented),
        }
    }

    fn call_operator_length_hint(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err(
                "TypeError: _operator.length_hint() takes no keyword arguments".to_string(),
            );
        }

        let (object, default) = match args.as_slice() {
            [object] => (object.clone(), Value::Number(0)),
            [object, default] => {
                let default = self.index_integer_value(default.clone())?;
                let default = operator_length_hint_default_value(&default)?;
                (object.clone(), default)
            }
            values => {
                if values.is_empty() {
                    return Err(
                        "TypeError: length_hint expected at least 1 argument, got 0".to_string()
                    );
                }
                return Err(format!(
                    "TypeError: length_hint expected at most 2 arguments, got {}",
                    values.len()
                ));
            }
        };

        match self.len_value(object.clone()) {
            Ok(length) => {
                let length = i64::try_from(length)
                    .map_err(|_| "OverflowError: len() result is too large".to_string())?;
                return Ok(Value::Number(length));
            }
            Err(message) if is_type_exception_message(&message) => {}
            Err(message) => return Err(message),
        }

        let method = match self.load_attribute_catching(object.clone(), "__length_hint__")? {
            Ok(method) => method,
            Err(exception) if exception_matches_type_name(&exception, "AttributeError") => {
                return Ok(default);
            }
            Err(exception) => return self.raise_runtime_exception_value(exception),
        };

        let value = match self.call_value_catching(method, Vec::new())? {
            Ok(value) => value,
            Err(exception) if exception_matches_type_name(&exception, "TypeError") => {
                return Ok(default);
            }
            Err(exception) => return self.raise_runtime_exception_value(exception),
        };

        operator_length_hint_result(value, default)
    }

    fn call_operator_builtin(
        &mut self,
        name: &str,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let function = name.strip_prefix("operator.").unwrap_or(name);
        if function == "length_hint" {
            return self.call_operator_length_hint(args, keywords);
        }
        if function == "call" {
            let Some((callee, rest)) = args.split_first() else {
                return Err("TypeError: call expected at least 1 argument, got 0".to_string());
            };
            let mut seen_keywords = HashSet::new();
            for (keyword, _) in &keywords {
                if !seen_keywords.insert(keyword.as_str()) {
                    return Err(format!(
                        "TypeError: _operator.call() got multiple values for keyword argument '{keyword}'"
                    ));
                }
            }
            if !is_callable_value(callee) {
                return Err(format!(
                    "TypeError: '{}' object is not callable",
                    type_name(callee)
                ));
            }
            return self.call_value_with_keywords(callee.clone(), rest.to_vec(), keywords);
        }
        if function == "methodcaller" {
            return self.call_operator_methodcaller_constructor(args, keywords);
        }
        if matches!(function, "attrgetter" | "itemgetter") && !keywords.is_empty() {
            return Err(format!(
                "TypeError: {function}() takes no keyword arguments"
            ));
        }
        if function == "index" {
            if !keywords.is_empty() {
                return Err("TypeError: _operator.index() takes no keyword arguments".to_string());
            }
            let count = args.len();
            let [value]: [Value; 1] = args.try_into().map_err(|_| {
                format!("TypeError: _operator.index() takes exactly one argument ({count} given)")
            })?;
            return self.index_integer_value(value);
        }
        if !keywords.is_empty() {
            return Err(format!(
                "TypeError: _operator.{function}() takes no keyword arguments"
            ));
        }

        match function {
            "lt" => {
                let (left, right) = operator_binary_args(function, args)?;
                Ok(Value::Bool(self.less_values(left, right)?))
            }
            "le" => {
                let (left, right) = operator_binary_args(function, args)?;
                Ok(Value::Bool(self.less_equal_values(left, right)?))
            }
            "eq" => {
                let (left, right) = operator_binary_args(function, args)?;
                Ok(Value::Bool(self.equal_values(left, right)?))
            }
            "ne" => {
                let (left, right) = operator_binary_args(function, args)?;
                Ok(Value::Bool(self.not_equal_values(left, right)?))
            }
            "ge" => {
                let (left, right) = operator_binary_args(function, args)?;
                Ok(Value::Bool(self.greater_equal_values(left, right)?))
            }
            "gt" => {
                let (left, right) = operator_binary_args(function, args)?;
                Ok(Value::Bool(self.greater_values(left, right)?))
            }
            "truth" => {
                let value = operator_unary_arg(function, args)?;
                Ok(Value::Bool(self.truth_value(value)?))
            }
            "not_" => {
                let value = operator_unary_arg(function, args)?;
                Ok(Value::Bool(!self.truth_value(value)?))
            }
            "is_" => {
                let (left, right) = operator_binary_args(function, args)?;
                Ok(Value::Bool(is_identical(&left, &right)))
            }
            "is_not" => {
                let (left, right) = operator_binary_args(function, args)?;
                Ok(Value::Bool(!is_identical(&left, &right)))
            }
            "is_none" => {
                let value = operator_unary_arg(function, args)?;
                Ok(Value::Bool(matches!(value, Value::None)))
            }
            "is_not_none" => {
                let value = operator_unary_arg(function, args)?;
                Ok(Value::Bool(!matches!(value, Value::None)))
            }
            "abs" => {
                let value = operator_unary_arg(function, args)?;
                self.abs_value(value)
            }
            "add" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.add_values(left, right)
            }
            "and_" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.bit_and_values(left, right)
            }
            "attrgetter" => self.call_operator_attrgetter_constructor(args),
            "concat" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.operator_concat_values(left, right)
            }
            "contains" => {
                let (haystack, needle) = operator_binary_args(function, args)?;
                Ok(Value::Bool(self.contains_value(needle, haystack)?))
            }
            "countOf" => {
                let (iterable, needle) = operator_binary_args(function, args)?;
                self.operator_count_of(iterable, needle)
            }
            "delitem" => {
                let (object, index) = operator_binary_args(function, args)?;
                self.delete_subscript_value(object, index)?;
                Ok(Value::None)
            }
            "floordiv" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.floor_divide_values(left, right)
            }
            "iadd" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_add_values(left, right)
            }
            "iand" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_bit_and_values(left, right)
            }
            "iconcat" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.operator_iconcat_values(left, right)
            }
            "getitem" => {
                let (object, index) = operator_binary_args(function, args)?;
                self.load_subscript_value(object, index)
            }
            "ifloordiv" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_floor_divide_values(left, right)
            }
            "ilshift" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_left_shift_values(left, right)
            }
            "imatmul" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_matrix_multiply_values(left, right)
            }
            "imod" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_modulo_values(left, right)
            }
            "imul" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_multiply_values(left, right)
            }
            "index" => unreachable!("operator.index is handled before generic keyword rejection"),
            "indexOf" => {
                let (iterable, needle) = operator_binary_args(function, args)?;
                self.operator_index_of(iterable, needle)
            }
            "inv" | "invert" => {
                let value = operator_unary_arg(function, args)?;
                invert_value(value)
            }
            "itemgetter" => self.call_operator_itemgetter_constructor(args),
            "ior" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_bit_or_values(left, right)
            }
            "ipow" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_power_values(left, right)
            }
            "irshift" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_right_shift_values(left, right)
            }
            "isub" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_subtract_values(left, right)
            }
            "itruediv" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_true_divide_values(left, right)
            }
            "ixor" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.in_place_bit_xor_values(left, right)
            }
            "lshift" => {
                let (left, right) = operator_binary_args(function, args)?;
                left_shift_values(left, right)
            }
            "matmul" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.matrix_multiply_values(left, right)
            }
            "mod" => {
                let (left, right) = operator_binary_args(function, args)?;
                modulo_values_with_vm(self, left, right)
            }
            "mul" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.multiply_values(left, right)
            }
            "neg" => {
                let value = operator_unary_arg(function, args)?;
                negate_value(value)
            }
            "or_" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.bit_or_values(left, right)
            }
            "pos" => {
                let value = operator_unary_arg(function, args)?;
                positive_value(value)
            }
            "pow" => {
                let (left, right) = operator_binary_args(function, args)?;
                power_values(left, right)
            }
            "rshift" => {
                let (left, right) = operator_binary_args(function, args)?;
                right_shift_values(left, right)
            }
            "setitem" => {
                let (object, index, value) = operator_ternary_args(function, args)?;
                self.store_subscript_value(object, index, value)?;
                Ok(Value::None)
            }
            "sub" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.subtract_values(left, right)
            }
            "truediv" => {
                let (left, right) = operator_binary_args(function, args)?;
                true_divide_values(left, right)
            }
            "xor" => {
                let (left, right) = operator_binary_args(function, args)?;
                self.bit_xor_values(left, right)
            }
            _ => Err(format!("unknown builtin: {name}")),
        }
    }

    fn call_operator_attrgetter_constructor(&mut self, args: Vec<Value>) -> Result<Value, String> {
        if args.is_empty() {
            return Err("TypeError: attrgetter expected 1 argument, got 0".to_string());
        }

        let mut attrs = Vec::with_capacity(args.len());
        for arg in args {
            match arg {
                Value::String(name) | Value::IdentityString { value: name, .. } => attrs.push(name),
                value if str_subclass_string(&value).is_some() => {
                    attrs.push(
                        str_subclass_string(&value)
                            .expect("str subclass storage exists after guard"),
                    );
                }
                _ => {
                    return Err("TypeError: attribute name must be a string".to_string());
                }
            }
        }

        Ok(Value::OperatorAttrGetter {
            attrs,
            identity: Rc::new(()),
        })
    }

    fn call_operator_itemgetter_constructor(&mut self, args: Vec<Value>) -> Result<Value, String> {
        if args.is_empty() {
            return Err("TypeError: itemgetter expected 1 argument, got 0".to_string());
        }

        Ok(Value::OperatorItemGetter {
            items: args,
            identity: Rc::new(()),
        })
    }

    fn call_operator_methodcaller_constructor(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let Some((name, bound_args)) = args.split_first() else {
            return Err(
                "TypeError: methodcaller needs at least one argument, the method name".to_string(),
            );
        };
        let name = match name {
            Value::String(name) | Value::IdentityString { value: name, .. } => name.clone(),
            value if str_subclass_string(value).is_some() => {
                str_subclass_string(value).expect("str subclass storage exists after guard")
            }
            _ => return Err("TypeError: method name must be a string".to_string()),
        };

        Ok(Value::OperatorMethodCaller {
            name,
            args: bound_args.to_vec(),
            keywords,
            identity: Rc::new(()),
        })
    }

    fn call_operator_attrgetter(
        &mut self,
        attrs: Vec<String>,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: attrgetter() takes no keyword arguments".to_string());
        }
        let object = operator_call_object_arg("attrgetter", args)?;
        let mut values = Vec::with_capacity(attrs.len());
        for attr in attrs {
            values.push(self.operator_attrgetter_value(object.clone(), &attr)?);
        }
        Ok(operator_getter_result(values))
    }

    fn operator_attrgetter_value(&mut self, object: Value, attr: &str) -> Result<Value, String> {
        let mut value = object;
        for name in attr.split('.') {
            value = self.load_attribute_value(value, name)?;
        }
        Ok(value)
    }

    fn call_operator_itemgetter(
        &mut self,
        items: Vec<Value>,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: itemgetter() takes no keyword arguments".to_string());
        }
        let object = operator_call_object_arg("itemgetter", args)?;
        let mut values = Vec::with_capacity(items.len());
        for item in items {
            values.push(self.load_subscript_value(object.clone(), item)?);
        }
        Ok(operator_getter_result(values))
    }

    fn call_operator_methodcaller(
        &mut self,
        name: String,
        bound_args: Vec<Value>,
        bound_keywords: Vec<(String, Value)>,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if !keywords.is_empty() {
            return Err("TypeError: methodcaller() takes no keyword arguments".to_string());
        }
        let object = operator_call_object_arg("methodcaller", args)?;
        let method = self.load_attribute_value(object, &name)?;
        self.call_value_with_keywords(method, bound_args, bound_keywords)
    }

    fn operator_concat_values(&mut self, left: Value, right: Value) -> Result<Value, String> {
        if !operator_concat_operand(&left) {
            return Err(format!(
                "TypeError: '{}' object can't be concatenated",
                type_name(&left)
            ));
        }
        self.add_values(left, right)
    }

    fn operator_iconcat_values(&mut self, left: Value, right: Value) -> Result<Value, String> {
        if !operator_concat_operand(&left) {
            return Err(format!(
                "TypeError: '{}' object can't be concatenated",
                type_name(&left)
            ));
        }
        self.in_place_add_values(left, right)
    }

    fn operator_count_of(&mut self, iterable: Value, needle: Value) -> Result<Value, String> {
        let mut iterator = self.get_iter(iterable)?;
        let mut count = 0_i64;
        loop {
            match self.advance_owned_iterator_capturing(&mut iterator)? {
                Ok(IteratorAdvance::Yield(value)) => {
                    if self.operator_item_matches(&value, &needle)? {
                        count += 1;
                    }
                }
                Ok(IteratorAdvance::Complete(_)) => return Ok(Value::Number(count)),
                Ok(IteratorAdvance::Raised) => {
                    return Err("iterator raised exception".to_string());
                }
                Err(exception) => return Err(format_exception_error(&exception)),
            }
        }
    }

    fn operator_index_of(&mut self, iterable: Value, needle: Value) -> Result<Value, String> {
        let mut iterator = self.get_iter(iterable)?;
        let mut index = 0_i64;
        loop {
            match self.advance_owned_iterator_capturing(&mut iterator)? {
                Ok(IteratorAdvance::Yield(value)) => {
                    if self.operator_item_matches(&value, &needle)? {
                        return Ok(Value::Number(index));
                    }
                    index += 1;
                }
                Ok(IteratorAdvance::Complete(_)) => {
                    return Err("ValueError: sequence.index(x): x not in sequence".to_string());
                }
                Ok(IteratorAdvance::Raised) => {
                    return Err("iterator raised exception".to_string());
                }
                Err(exception) => return Err(format_exception_error(&exception)),
            }
        }
    }

    fn operator_item_matches(&mut self, left: &Value, right: &Value) -> Result<bool, String> {
        if is_identical(left, right) {
            return Ok(true);
        }
        self.equal_values(left.clone(), right.clone())
    }

    fn call_iterator_reduce(&mut self, receiver: Value) -> Result<Value, String> {
        let (sequence, index) = match receiver {
            Value::Iterator(state) => {
                let iterator = state.borrow().clone();
                return self.call_iterator_reduce(iterator);
            }
            Value::RangeIterator {
                current,
                stop,
                step,
            } => {
                return self.range_iterator_reduce_result(current, stop, step);
            }
            Value::ListIterator {
                items,
                index,
                exhausted,
            } => {
                if exhausted {
                    return self.iterator_reduce_result(list_value(Vec::new()), None);
                } else {
                    (Value::List(items), Some(index))
                }
            }
            Value::TupleIterator { items, index } => (tuple_value(items), Some(index)),
            Value::StringIterator { chars, index } => (Value::String(chars.concat()), Some(index)),
            Value::BytesIterator { bytes, index } => (bytes_value(bytes), Some(index)),
            Value::ByteArrayIterator {
                bytes,
                index,
                exhausted,
            } => {
                if exhausted {
                    return self.iterator_reduce_result(tuple_value(Vec::new()), None);
                } else {
                    (byte_array_value(bytearray_bytes(&bytes)), Some(index))
                }
            }
            Value::ArrayIterator { object, index } => (*object, Some(index)),
            Value::SetIterator {
                items,
                index,
                source,
                expected_len,
            } => {
                if source
                    .as_ref()
                    .is_some_and(|items| items.borrow().len() != expected_len)
                {
                    return Err("RuntimeError: Set changed size during iteration".to_string());
                }
                let remaining = items.iter().skip(index).cloned().collect();
                return self.iterator_reduce_result(list_value(remaining), None);
            }
            Value::DictIterator {
                kind,
                entries,
                index,
                expected_len,
                expected_version,
            } => {
                let entries = entries.borrow();
                if entries.len() != expected_len {
                    return Err(
                        "RuntimeError: dictionary changed size during iteration".to_string()
                    );
                }
                if entries.version != expected_version {
                    return Err(
                        "RuntimeError: dictionary keys changed during iteration".to_string()
                    );
                }
                let remaining = entries
                    .iter()
                    .skip(index)
                    .map(|(key, value)| dict_iterator_item(kind, key.clone(), value.clone()))
                    .collect();
                return self.iterator_reduce_result(list_value(remaining), None);
            }
            Value::DictReverseIterator {
                kind,
                entries,
                keys,
                index,
                expected_len,
                expected_version,
            } => {
                let entries = entries.borrow();
                if entries.len() != expected_len {
                    return Err(
                        "RuntimeError: dictionary changed size during iteration".to_string()
                    );
                }
                if entries.version != expected_version {
                    return Err(
                        "RuntimeError: dictionary keys changed during iteration".to_string()
                    );
                }
                let remaining = (0..keys.len().saturating_sub(index))
                    .rev()
                    .filter_map(|position| {
                        entries
                            .iter()
                            .enumerate()
                            .find(|(_, (candidate, _))| dict_keys_equal(candidate, &keys[position]))
                            .and_then(|(current_index, (key, value))| {
                                if current_index <= position {
                                    Some(dict_iterator_item(kind, key.clone(), value.clone()))
                                } else {
                                    None
                                }
                            })
                    })
                    .collect();
                return self.iterator_reduce_result(list_value(remaining), None);
            }
            Value::ReverseIterator { items, index } => {
                let (items, index) = if index >= items.len() {
                    (Vec::new(), None)
                } else {
                    let index = items.len() - 1 - index;
                    (items, Some(index))
                };
                return self.reverse_iterator_reduce_result(list_value(items), index);
            }
            Value::SequenceReverseIterator { object, index } => {
                if index < 0 {
                    return self.reverse_iterator_reduce_result(tuple_value(Vec::new()), None);
                }
                let index = usize::try_from(index)
                    .map_err(|_| "OverflowError: iterator index is too large".to_string())?;
                return self.reverse_iterator_reduce_result(*object, Some(index));
            }
            Value::EnumerateIterator { iterator, index } => {
                return Ok(tuple_value(vec![
                    Value::Builtin("enumerate".to_string()),
                    tuple_value(vec![*iterator, normalize_big_int(index)]),
                ]));
            }
            Value::FilterIterator { function, iterator } => {
                return Ok(tuple_value(vec![
                    Value::Builtin("filter".to_string()),
                    tuple_value(vec![*function, *iterator]),
                ]));
            }
            Value::CallIterator {
                callable,
                sentinel,
                done,
            } => {
                if done {
                    return self.iterator_reduce_result(tuple_value(Vec::new()), None);
                }
                let iter = self
                    .load_builtin_name("iter")?
                    .ok_or_else(|| "AttributeError: iter".to_string())?;
                return Ok(tuple_value(vec![
                    iter,
                    tuple_value(vec![*callable, *sentinel]),
                ]));
            }
            value => {
                return Err(format!(
                    "TypeError: copy protocol does not support '{}'",
                    type_name(&value)
                ));
            }
        };
        self.iterator_reduce_result(sequence, index)
    }

    fn call_array_iterator_setstate(
        &mut self,
        receiver: Value,
        index: Value,
    ) -> Result<Value, String> {
        let index = array_iterator_setstate_index(&index)?;
        match receiver {
            Value::Iterator(state) => {
                let mut iterator = state.borrow_mut();
                if matches!(&*iterator, Value::ArrayIterator { .. }) {
                    if let Value::ArrayIterator { index: current, .. } = &mut *iterator {
                        *current = index;
                    }
                    Ok(Value::None)
                } else {
                    Err(array_iterator_setstate_receiver_error(&*iterator))
                }
            }
            Value::ArrayIterator { .. } => Ok(Value::None),
            value => Err(array_iterator_setstate_receiver_error(&value)),
        }
    }

    fn call_range_iterator_setstate(
        &mut self,
        receiver: Value,
        index: Value,
    ) -> Result<Value, String> {
        match receiver {
            Value::Iterator(state) => {
                let (current, stop, step) = {
                    let iterator = state.borrow();
                    let Value::RangeIterator {
                        current,
                        stop,
                        step,
                    } = &*iterator
                    else {
                        return Err(range_iterator_setstate_receiver_error(&*iterator));
                    };
                    (current.clone(), stop.clone(), step.clone())
                };
                let new_current =
                    self.range_iterator_setstate_current(current, stop, step, index)?;
                let mut iterator = state.borrow_mut();
                if let Value::RangeIterator { current, .. } = &mut *iterator {
                    *current = new_current;
                    Ok(Value::None)
                } else {
                    Err(range_iterator_setstate_receiver_error(&*iterator))
                }
            }
            Value::RangeIterator {
                current,
                stop,
                step,
            } => {
                self.range_iterator_setstate_current(current, stop, step, index)?;
                Ok(Value::None)
            }
            value => Err(range_iterator_setstate_receiver_error(&value)),
        }
    }

    fn range_iterator_setstate_current(
        &mut self,
        current: BigInt,
        stop: BigInt,
        step: BigInt,
        index: Value,
    ) -> Result<BigInt, String> {
        let mut offset = range_iterator_setstate_offset(self.index_integer_value(index)?)?;
        if offset.is_negative() {
            offset = BigInt::zero();
        }
        let remaining = range_len_bigint(&current, &stop, &step);
        if offset > remaining {
            offset = remaining;
        }
        Ok(current + step * offset)
    }

    fn call_list_iterator_setstate(
        &mut self,
        receiver: Value,
        index: Value,
    ) -> Result<Value, String> {
        let index = list_iterator_setstate_index(&index)?;
        match receiver {
            Value::Iterator(state) => {
                let mut iterator = state.borrow_mut();
                if let Value::ListIterator {
                    index: current,
                    exhausted,
                    ..
                } = &mut *iterator
                {
                    match index {
                        Some(index) => {
                            *current = index;
                            *exhausted = false;
                        }
                        None => {
                            *exhausted = true;
                        }
                    }
                    Ok(Value::None)
                } else {
                    Err(list_iterator_setstate_receiver_error(&*iterator))
                }
            }
            Value::ListIterator { .. } => Ok(Value::None),
            value => Err(list_iterator_setstate_receiver_error(&value)),
        }
    }

    fn call_list_reverseiterator_setstate(
        &mut self,
        receiver: Value,
        index: Value,
    ) -> Result<Value, String> {
        match receiver {
            Value::Iterator(state) => {
                let mut iterator = state.borrow_mut();
                if let Value::ReverseIterator {
                    items,
                    index: current,
                } = &mut *iterator
                {
                    *current = list_reverseiterator_setstate_index(items.len(), &index)?;
                    Ok(Value::None)
                } else {
                    Err(list_reverseiterator_setstate_receiver_error(&*iterator))
                }
            }
            Value::ReverseIterator { items, .. } => {
                list_reverseiterator_setstate_index(items.len(), &index)?;
                Ok(Value::None)
            }
            value => Err(list_reverseiterator_setstate_receiver_error(&value)),
        }
    }

    fn call_reversed_setstate(&mut self, receiver: Value, index: Value) -> Result<Value, String> {
        match receiver {
            Value::Iterator(state) => {
                let object = {
                    let iterator = state.borrow();
                    let Value::SequenceReverseIterator { object, .. } = &*iterator else {
                        return Err(reversed_setstate_receiver_error(&*iterator));
                    };
                    object.as_ref().clone()
                };
                let index = self.reversed_setstate_index(object, &index)?;
                let mut iterator = state.borrow_mut();
                if let Value::SequenceReverseIterator { index: current, .. } = &mut *iterator {
                    *current = index;
                    Ok(Value::None)
                } else {
                    Err(reversed_setstate_receiver_error(&*iterator))
                }
            }
            Value::SequenceReverseIterator { object, .. } => {
                self.reversed_setstate_index(*object, &index)?;
                Ok(Value::None)
            }
            value => Err(reversed_setstate_receiver_error(&value)),
        }
    }

    fn reversed_setstate_index(&mut self, object: Value, value: &Value) -> Result<i64, String> {
        let length = self.sequence_iterator_length(object)?.unwrap_or(0);
        reversed_setstate_index(length, value)
    }

