    fn iterator_reduce_result(
        &mut self,
        sequence: Value,
        index: Option<usize>,
    ) -> Result<Value, String> {
        let iter = self
            .load_builtin_name("iter")?
            .ok_or_else(|| "AttributeError: iter".to_string())?;
        let args = tuple_value(vec![sequence]);
        let mut items = vec![iter, args];
        if let Some(index) = index {
            let index =
                i64::try_from(index).map_err(|_| "OverflowError: iterator index is too large")?;
            items.push(Value::Number(index));
        }
        Ok(tuple_value(items))
    }

    fn range_iterator_reduce_result(
        &mut self,
        current: BigInt,
        stop: BigInt,
        step: BigInt,
    ) -> Result<Value, String> {
        let iter = self
            .load_builtin_name("iter")?
            .ok_or_else(|| "AttributeError: iter".to_string())?;
        let remaining_len = range_len_bigint(&current, &stop, &step);
        let stop = current.clone() + remaining_len * step.clone();
        let range = Value::Range {
            start: current,
            stop,
            step,
            identity: Rc::new(()),
        };
        Ok(tuple_value(vec![
            iter,
            tuple_value(vec![range]),
            Value::None,
        ]))
    }

    fn reverse_iterator_reduce_result(
        &mut self,
        sequence: Value,
        index: Option<usize>,
    ) -> Result<Value, String> {
        let reversed = self
            .load_builtin_name("reversed")?
            .ok_or_else(|| "AttributeError: reversed".to_string())?;
        let args = tuple_value(vec![sequence]);
        let mut items = vec![reversed, args];
        if let Some(index) = index {
            let index =
                i64::try_from(index).map_err(|_| "OverflowError: iterator index is too large")?;
            items.push(Value::Number(index));
        }
        Ok(tuple_value(items))
    }

    fn iterator_length_hint(&mut self, receiver: Value) -> Result<Option<usize>, String> {
        match receiver {
            Value::Iterator(state) => {
                let iterator = state.borrow().clone();
                self.iterator_length_hint(iterator)
            }
            Value::RangeIterator {
                current,
                stop,
                step,
            } => Ok(Some(range_len_usize(&current, &stop, &step)?)),
            Value::ListIterator {
                items,
                index,
                exhausted,
            } => {
                if exhausted {
                    Ok(Some(0))
                } else {
                    Ok(Some(items.borrow().len().saturating_sub(index)))
                }
            }
            Value::TupleIterator { items, index } => Ok(Some(items.len().saturating_sub(index))),
            Value::SetIterator {
                items,
                index,
                source,
                expected_len,
            } => {
                if source.is_some_and(|items| items.borrow().len() != expected_len) {
                    Ok(Some(0))
                } else {
                    Ok(Some(items.len().saturating_sub(index)))
                }
            }
            Value::StringIterator { chars, index } => Ok(Some(chars.len().saturating_sub(index))),
            Value::BytesIterator { bytes, index } => Ok(Some(bytes.len().saturating_sub(index))),
            Value::ByteArrayIterator {
                bytes,
                index,
                exhausted,
            } => {
                if exhausted {
                    Ok(Some(0))
                } else {
                    Ok(Some(bytes.borrow().len().saturating_sub(index)))
                }
            }
            Value::DictIterator {
                entries,
                index,
                expected_len,
                ..
            } => {
                if entries.borrow().len() != expected_len {
                    Ok(Some(0))
                } else {
                    Ok(Some(expected_len.saturating_sub(index)))
                }
            }
            Value::ReverseIterator { items, index } => Ok(Some(items.len().saturating_sub(index))),
            Value::DictReverseIterator {
                entries,
                keys,
                index,
                expected_len,
                ..
            } => {
                if entries.borrow().len() != expected_len {
                    Ok(Some(0))
                } else {
                    Ok(Some(keys.len().saturating_sub(index)))
                }
            }
            Value::SequenceIterator { object, index } => {
                let Some(length) = self.sequence_iterator_length(*object)? else {
                    return Ok(None);
                };
                let index = usize::try_from(index).unwrap_or(usize::MAX);
                Ok(Some(length.saturating_sub(index)))
            }
            Value::SequenceReverseIterator { object, index } => {
                if index < 0 {
                    Ok(Some(0))
                } else {
                    let current = usize::try_from(index + 1)
                        .map_err(|_| "__length_hint__() result is too large".to_string())?;
                    let Some(length) = self.sequence_iterator_length(*object)? else {
                        return Ok(None);
                    };
                    Ok(Some(current.min(length)))
                }
            }
            Value::ItertoolsRepeat { remaining, .. } => match remaining {
                Some(remaining) => {
                    let length = remaining
                        .to_usize()
                        .ok_or_else(|| "__length_hint__() result is too large".to_string())?;
                    Ok(Some(length))
                }
                None => Err("TypeError: len() of unsized object".to_string()),
            },
            value => Err(format!(
                "AttributeError: {} has no attribute '__length_hint__'",
                type_name(&value)
            )),
        }
    }

    fn sequence_iterator_length(&mut self, object: Value) -> Result<Option<usize>, String> {
        if let Some(method) = instance_special_method(&object, "__len__") {
            let value = self.call_value(method, Vec::new())?;
            return len_result_from_value(value).map(Some);
        }

        match value_len(&object) {
            Ok(length) => Ok(Some(length)),
            Err(_) => Ok(None),
        }
    }

    fn call_enumerate(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let mut iterable = None;
        let mut start = None;

        match args.as_slice() {
            [] => {}
            [value] => iterable = Some(value.clone()),
            [value, start_value] => {
                iterable = Some(value.clone());
                start = Some(start_value.clone());
            }
            values => {
                return Err(format!(
                    "TypeError: enumerate() takes at most 2 arguments ({} given)",
                    values.len()
                ));
            }
        }

        let total_args = args.len() + keywords.len();
        if !args.is_empty() && total_args > 2 {
            return Err(format!(
                "TypeError: enumerate() takes at most 2 arguments ({total_args} given)"
            ));
        }

        for (keyword, value) in keywords {
            match keyword.as_str() {
                "iterable" => {
                    if iterable.is_some() {
                        if !args.is_empty() {
                            return Err(
                                "TypeError: 'iterable' is an invalid keyword argument for enumerate()"
                                    .to_string(),
                            );
                        }
                        return Err(
                            "TypeError: enumerate() got multiple values for argument 'iterable'"
                                .to_string(),
                        );
                    }
                    iterable = Some(value);
                }
                "start" => {
                    if start.is_some() {
                        return Err(
                            "TypeError: enumerate() got multiple values for argument 'start'"
                                .to_string(),
                        );
                    }
                    start = Some(value);
                }
                _ => {
                    return Err(format!(
                        "TypeError: '{keyword}' is an invalid keyword argument for enumerate()"
                    ));
                }
            }
        }

        let iterable = iterable.ok_or_else(|| {
            "TypeError: enumerate() missing required argument 'iterable'".to_string()
        })?;
        let Some(iterator) = self.get_iter_or_raise(iterable)? else {
            return Ok(Value::None);
        };
        Ok(shared_iterator(Value::EnumerateIterator {
            iterator: Box::new(iterator),
            index: self.index_big_int(start.unwrap_or(Value::Number(0)))?,
        }))
    }

    fn call_zip(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if keywords.len() > 1 {
            return Err(format!(
                "TypeError: zip() takes at most 1 keyword argument ({} given)",
                keywords.len()
            ));
        }

        let mut strict = false;
        for (keyword, value) in keywords {
            match keyword.as_str() {
                "strict" => strict = self.truth_value(value)?,
                _ => {
                    return Err(format!(
                        "TypeError: zip() got an unexpected keyword argument '{keyword}'"
                    ));
                }
            }
        }

        let mut iterators = Vec::new();
        for arg in args {
            let Some(iterator) = self.get_iter_or_raise(arg)? else {
                return Ok(Value::None);
            };
            iterators.push(iterator);
        }
        Ok(shared_iterator(Value::ZipIterator { iterators, strict }))
    }

    fn call_map(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if keywords.len() > 1 {
            return Err(format!(
                "TypeError: map() takes at most 1 keyword argument ({} given)",
                keywords.len()
            ));
        }

        let mut strict = false;
        for (keyword, value) in keywords {
            match keyword.as_str() {
                "strict" => strict = self.truth_value(value)?,
                _ => {
                    return Err(format!(
                        "TypeError: map() got an unexpected keyword argument '{keyword}'"
                    ));
                }
            }
        }

        if args.len() < 2 {
            return Err("TypeError: map() must have at least two arguments.".to_string());
        }

        let mut values = args.into_iter();
        let function = values
            .next()
            .ok_or_else(|| "TypeError: map() must have at least two arguments.".to_string())?;
        let mut iterators = Vec::new();
        for value in values {
            let Some(iterator) = self.get_iter_or_raise(value)? else {
                return Ok(Value::None);
            };
            iterators.push(iterator);
        }

        Ok(shared_iterator(Value::MapIterator {
            function: Box::new(function),
            iterators,
            strict,
        }))
    }

    fn call_filter(&mut self, args: Vec<Value>) -> Result<Value, String> {
        let [function, iterable] = args.as_slice() else {
            return Err(format!(
                "TypeError: filter expected 2 arguments, got {}",
                args.len()
            ));
        };

        let Some(iterator) = self.get_iter_or_raise(iterable.clone())? else {
            return Ok(Value::None);
        };

        Ok(shared_iterator(Value::FilterIterator {
            function: Box::new(function.clone()),
            iterator: Box::new(iterator),
        }))
    }

    fn abs_value(&mut self, value: Value) -> Result<Value, String> {
        match numeric_bool_value(value) {
            Value::Number(value) => Ok(normalize_big_int(BigInt::from(value).abs())),
            Value::BigInt(value) => Ok(normalize_big_int(value.abs())),
            Value::Float(value) => Ok(float_value(value.abs())),
            Value::Complex { real, imag, .. } => complex_abs_value(real, imag),
            value => {
                if let Some(method) = instance_special_method(&value, "__abs__") {
                    return match self.call_value_catching(method, Vec::new())? {
                        Ok(result) => Ok(result),
                        Err(exception) => Err(format_exception_error(&exception)),
                    };
                }
                Err(format!(
                    "TypeError: bad operand type for abs(): '{}'",
                    type_name(&value)
                ))
            }
        }
    }

    fn call_sorted(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let options = sorted_options(self, args.len(), keywords)?;
        let [iterable] = args.as_slice() else {
            return Err(format!(
                "TypeError: sorted expected 1 argument, got {}",
                args.len()
            ));
        };

        let mut items = Vec::new();
        for value in self.collect_iterable_values(iterable.clone())? {
            let key = self.sort_key_value(options.key.as_ref(), &value)?;
            items.push(SortItem { value, key });
        }

        self.sort_items_by_key(&mut items, options.reverse.unwrap_or(false))?;
        Ok(list_value(
            items.into_iter().map(|item| item.value).collect(),
        ))
    }

    fn call_list_method(
        &mut self,
        name: &str,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if name == "list.sort" {
            return self.call_list_sort_method(args, keywords);
        }

        if !keywords.is_empty() {
            return Err(format!(
                "TypeError: {}() takes no keyword arguments",
                method_keyword_error_name(name)
            ));
        }

        if matches!(method_display_name(name), "__eq__" | "__ne__") {
            return self.call_list_equality_method(name, args);
        }

        if matches!(
            name,
            "list.__contains__" | "list.count" | "list.index" | "list.remove"
        ) {
            return self.call_list_search_method(name, args);
        }

        call_list_method(name, args)
    }

    fn list_item_matches(&mut self, item: Value, needle: &Value) -> Result<bool, String> {
        if sequence_items_match(&item, needle) {
            return Ok(true);
        }
        self.equal_values(item, needle.clone())
    }

    fn list_contains_rich(&mut self, items: &ListRef, needle: &Value) -> Result<bool, String> {
        Ok(self.list_find_rich(items, needle, 0, None)?.is_some())
    }

    fn list_count_rich(&mut self, items: &ListRef, needle: &Value) -> Result<i64, String> {
        let mut count = 0_i64;
        let mut index = 0_usize;
        loop {
            let item = {
                let items = items.borrow();
                if index >= items.len() {
                    return Ok(count);
                }
                items[index].clone()
            };
            if self.list_item_matches(item, needle)? {
                count = count
                    .checked_add(1)
                    .ok_or_else(|| "count() result is too large".to_string())?;
            }
            index = index
                .checked_add(1)
                .ok_or_else(|| "list index overflow".to_string())?;
        }
    }

    fn list_search_bounds_for_dynamic_list(
        &mut self,
        args: &[Value],
        len: usize,
    ) -> Result<(usize, Option<usize>), String> {
        let len = i64::try_from(len).map_err(|_| "list is too large".to_string())?;
        let start = match args.first() {
            Some(value) => self.list_search_bound_argument(value)?,
            None => 0,
        };
        let start = normalize_positive_slice_bound(start, len);
        let stop = match args.get(1) {
            Some(value) => {
                let stop = self.list_search_bound_argument(value)?;
                Some(normalize_positive_slice_bound(stop, len).max(start))
            }
            None => None,
        };
        let start = usize::try_from(start).map_err(|_| "list index out of range".to_string())?;
        let stop = stop
            .map(|stop| usize::try_from(stop).map_err(|_| "list index out of range".to_string()))
            .transpose()?;
        Ok((start, stop))
    }

    fn list_search_bound_argument(&mut self, value: &Value) -> Result<i64, String> {
        if let Value::WeakProxy { target, .. } = value {
            return self.list_search_bound_argument(target);
        }
        let integer = if let Some(value) = int_subclass_integer(value) {
            value
        } else {
            match numeric_bool_value(value.clone()) {
                value @ (Value::Number(_) | Value::BigInt(_)) => value,
                value => {
                    let Some(method) = instance_special_method(&value, "__index__") else {
                        return Err(
                            "TypeError: slice indices must be integers or have an __index__ method"
                                .to_string(),
                        );
                    };
                    let result = match self.call_value_catching(method, Vec::new())? {
                        Ok(result) => result,
                        Err(exception) => {
                            return Err(self.remember_runtime_exception_error(exception));
                        }
                    };
                    integer_dunder_result("__index__", result)?
                }
            }
        };
        match integer {
            Value::Number(value) => Ok(value),
            Value::BigInt(value) => Ok(value.to_i64().unwrap_or_else(|| {
                if value.is_negative() {
                    i64::MIN
                } else {
                    i64::MAX
                }
            })),
            _ => unreachable!("list search bound conversion returns an integer"),
        }
    }

    fn list_find_rich(
        &mut self,
        items: &ListRef,
        needle: &Value,
        start: usize,
        stop: Option<usize>,
    ) -> Result<Option<usize>, String> {
        let mut index = start;
        loop {
            if stop.is_some_and(|stop| index >= stop) {
                return Ok(None);
            }
            let item = {
                let items = items.borrow();
                if index >= items.len() {
                    return Ok(None);
                }
                items[index].clone()
            };
            if self.list_item_matches(item, needle)? {
                return Ok(Some(index));
            }
            index = index
                .checked_add(1)
                .ok_or_else(|| "list index overflow".to_string())?;
        }
    }

    fn list_remove_rich(&mut self, items: &ListRef, needle: &Value) -> Result<Value, String> {
        let Some(index) = self.list_find_rich(items, needle, 0, None)? else {
            return Err("ValueError: list.remove(x): x not in list".to_string());
        };
        let mut items = items.borrow_mut();
        if index < items.len() {
            items.remove(index);
        }
        Ok(Value::None)
    }

    fn call_list_search_method(&mut self, name: &str, args: Vec<Value>) -> Result<Value, String> {
        match name {
            "list.__contains__" => {
                let [Value::List(items), needle] = args.as_slice() else {
                    return Err(format!(
                        "__contains__() expected 1 argument, got {}",
                        method_arg_count(&args)
                    ));
                };
                Ok(Value::Bool(self.list_contains_rich(items, needle)?))
            }
            "list.count" => {
                let [Value::List(items), needle] = args.as_slice() else {
                    return Err(format!(
                        "count() expected 1 argument, got {}",
                        method_arg_count(&args)
                    ));
                };
                Ok(Value::Number(self.list_count_rich(items, needle)?))
            }
            "list.index" => {
                let [Value::List(items), needle, rest @ ..] = args.as_slice() else {
                    return Err(format!(
                        "index expected at least 1 argument, got {}",
                        method_arg_count(&args)
                    ));
                };
                if rest.len() > 2 {
                    return Err(format!(
                        "index expected at most 3 arguments, got {}",
                        method_arg_count(&args)
                    ));
                }

                let len = items.borrow().len();
                let (start, stop) = self.list_search_bounds_for_dynamic_list(rest, len)?;
                match self.list_find_rich(items, needle, start, stop)? {
                    Some(index) => {
                        let index = i64::try_from(index)
                            .map_err(|_| "index() result is too large".to_string())?;
                        Ok(Value::Number(index))
                    }
                    None => Err("ValueError: list.index(x): x not in list".to_string()),
                }
            }
            "list.remove" => {
                let [Value::List(items), needle] = args.as_slice() else {
                    return Err(format!(
                        "remove() expected 1 argument, got {}",
                        method_arg_count(&args)
                    ));
                };
                self.list_remove_rich(items, needle)
            }
            _ => unreachable!("list search method is filtered before dispatch"),
        }
    }

    fn call_user_list_method(
        &mut self,
        name: &str,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let method = method_display_name(name);
        if method == "__init__" {
            return self.call_user_list_init_method(args, keywords);
        }

        let [Value::UserList { data, attrs }, rest @ ..] = args.as_slice() else {
            return Err(format!("{method}() expected a UserList receiver"));
        };

        if matches!(method, "copy" | "__copy__") {
            reject_method_keywords(name, &keywords)?;
            if !rest.is_empty() {
                return Err(format!(
                    "copy() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            }
            return Ok(Value::UserList {
                data: Rc::new(RefCell::new(data.borrow().clone())),
                attrs: dict_ref_from_entries(attrs.borrow().entries.clone())?,
            });
        }

        if method == "__iter__" {
            reject_method_keywords(name, &keywords)?;
            if !rest.is_empty() {
                return Err(format!(
                    "__iter__() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            }
            return get_iter(Value::List(data.clone()));
        }

        if matches!(method, "__repr__" | "__str__") {
            reject_method_keywords(name, &keywords)?;
            if !rest.is_empty() {
                return Err(format!(
                    "{method}() expected 0 arguments, got {}",
                    method_arg_count(&args)
                ));
            }
            return Ok(Value::String(repr_value_checked(&Value::List(
                data.clone(),
            ))?));
        }

        if method == "__format__" {
            reject_method_keywords(name, &keywords)?;
            let [format_spec] = rest else {
                return Err(format!(
                    "__format__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let format_spec = format_spec_string(format_spec, "object.__format__()")?;
            if format_spec.is_empty() {
                return Ok(Value::String(repr_value_checked(&Value::List(
                    data.clone(),
                ))?));
            }
            return Err(format!(
                "TypeError: unsupported format string passed to {}.__format__",
                type_name(&Value::UserList {
                    data: data.clone(),
                    attrs: attrs.clone()
                })
            ));
        }

        if matches!(method, "__eq__" | "__ne__") {
            reject_method_keywords(name, &keywords)?;
            let [other] = rest else {
                return Err(format!(
                    "{method}() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let left = Value::List(data.clone());
            let right = user_list_comparison_operand(other);
            let equal = self.rich_equal_values(&left, &right)?;
            return Ok(Value::Bool(if method == "__ne__" { !equal } else { equal }));
        }

        if matches!(method, "__lt__" | "__le__" | "__gt__" | "__ge__") {
            reject_method_keywords(name, &keywords)?;
            let [other] = rest else {
                return Err(format!(
                    "{method}() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let left = Value::List(data.clone());
            let right = user_list_comparison_operand(other);
            let result = match method {
                "__lt__" => self.less_values(left, right)?,
                "__le__" => self.less_equal_values(left, right)?,
                "__gt__" => self.greater_values(left, right)?,
                "__ge__" => self.greater_equal_values(left, right)?,
                _ => unreachable!("method is filtered above"),
            };
            return Ok(Value::Bool(result));
        }

        if matches!(method, "__add__" | "__radd__") {
            reject_method_keywords(name, &keywords)?;
            let [other] = rest else {
                return Err(format!(
                    "{method}() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let mut items = if method == "__add__" {
                data.borrow().clone()
            } else {
                self.collect_iterable_values(other.clone())?
            };
            if method == "__add__" {
                items.extend(self.collect_iterable_values(other.clone())?);
            } else {
                items.extend(data.borrow().iter().cloned());
            }
            return user_list_value(items);
        }

        if method == "__iadd__" {
            reject_method_keywords(name, &keywords)?;
            let [other] = rest else {
                return Err(format!(
                    "__iadd__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let values = self.collect_iterable_values(other.clone())?;
            data.borrow_mut().extend(values);
            return Ok(Value::UserList {
                data: data.clone(),
                attrs: attrs.clone(),
            });
        }

        if matches!(method, "__mul__" | "__rmul__") {
            reject_method_keywords(name, &keywords)?;
            let [count] = rest else {
                return Err(format!(
                    "{method}() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let count = self.index_integer_value(count.clone())?;
            let count = repeat_count_from_integer_value(count)?;
            return user_list_value(repeat_values(data.borrow().clone(), count)?);
        }

        if method == "__imul__" {
            reject_method_keywords(name, &keywords)?;
            let [count] = rest else {
                return Err(format!(
                    "__imul__() expected 1 argument, got {}",
                    method_arg_count(&args)
                ));
            };
            let count = self.index_integer_value(count.clone())?;
            let count = repeat_count_from_integer_value(count)?;
            let repeated = repeat_values(data.borrow().clone(), count)?;
            *data.borrow_mut() = repeated;
            return Ok(Value::UserList {
                data: data.clone(),
                attrs: attrs.clone(),
            });
        }

        let mut list_args = Vec::with_capacity(args.len());
        list_args.push(Value::List(data.clone()));
        list_args.extend(rest.iter().cloned());
        let list_method = format!("list.{method}");
        self.call_list_method(&list_method, list_args, keywords)
    }

    fn call_user_list_init_method(
        &mut self,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        if args.len() > 2 {
            return Err(format!(
                "TypeError: UserList.__init__() takes from 1 to 2 positional arguments but {} were given",
                args.len()
            ));
        }

        let mut args = args.into_iter();
        let mut receiver = args.next();
        let mut initlist = args.next();

        for (name, value) in keywords {
            match name.as_str() {
                "self" => {
                    if receiver.is_some() {
                        return Err(
                            "TypeError: UserList.__init__() got multiple values for argument 'self'"
                                .to_string(),
                        );
                    }
                    receiver = Some(value);
                }
                "initlist" => {
                    if initlist.is_some() {
                        return Err(
                            "TypeError: UserList.__init__() got multiple values for argument 'initlist'"
                                .to_string(),
                        );
                    }
                    initlist = Some(value);
                }
                _ => {
                    return Err(format!(
                        "TypeError: UserList.__init__() got an unexpected keyword argument '{name}'"
                    ));
                }
            }
        }

        let Some(receiver) = receiver else {
            return Err(
                "TypeError: UserList.__init__() missing 1 required positional argument: 'self'"
                    .to_string(),
            );
        };
        let data = match receiver {
            Value::UserList { data, .. } => data,
            value => {
                return Err(format!(
                    "TypeError: UserList.__init__() expected a UserList receiver, got {}",
                    type_name(&value)
                ));
            }
        };

        let values = self.user_list_values_from_initlist(initlist)?;
        *data.borrow_mut() = values;
        Ok(Value::None)
    }

    fn call_user_string_method(
        &mut self,
        name: &str,
        args: Vec<Value>,
        keywords: Vec<(String, Value)>,
    ) -> Result<Value, String> {
        let method = match method_display_name(name) {
            "__rmul__" => "__mul__",
            method => method,
        };
        match method {
            "__init__" => {
                if args.len() > 2 {
                    return Err(format!(
                        "TypeError: UserString.__init__() takes 2 positional arguments but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                let mut seq = args.get(1).cloned();
                for (name, value) in keywords {
                    match name.as_str() {
                        "self" => {
                            if receiver.is_some() {
                                return Err(
                                    "TypeError: UserString.__init__() got multiple values for argument 'self'"
                                        .to_string(),
                                );
                            }
                            receiver = Some(value);
                        }
                        "seq" => {
                            if seq.is_some() {
                                return Err(
                                    "TypeError: UserString.__init__() got multiple values for argument 'seq'"
                                        .to_string(),
                                );
                            }
                            seq = Some(value);
                        }
                        _ => {
                            return Err(format!(
                                "TypeError: UserString.__init__() got an unexpected keyword argument '{name}'"
                            ));
                        }
                    }
                }
                let Some(receiver) = receiver else {
                    return Err(if seq.is_some() {
                        "TypeError: UserString.__init__() missing 1 required positional argument: 'self'"
                    } else {
                        "TypeError: UserString.__init__() missing 2 required positional arguments: 'self' and 'seq'"
                    }
                    .to_string());
                };
                let Some(seq) = seq else {
                    return Err(
                        "TypeError: UserString.__init__() missing 1 required positional argument: 'seq'"
                            .to_string(),
                    );
                };
                let data = match seq {
                    Value::UserString { data, .. } => data.borrow().clone(),
                    value => self.str_value(&value)?,
                };
                store_attribute(receiver, "data", Value::String(data))?;
                Ok(Value::None)
            }
            "__mul__" => {
                if args.len() > 2 {
                    return Err(format!(
                        "TypeError: UserString.__mul__() takes 2 positional arguments but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                let mut count = args.get(1).cloned();
                for (name, value) in keywords {
                    match name.as_str() {
                        "self" => {
                            if receiver.is_some() {
                                return Err(
                                    "TypeError: UserString.__mul__() got multiple values for argument 'self'"
                                        .to_string(),
                                );
                            }
                            receiver = Some(value);
                        }
                        "n" => {
                            if count.is_some() {
                                return Err(
                                    "TypeError: UserString.__mul__() got multiple values for argument 'n'"
                                        .to_string(),
                                );
                            }
                            count = Some(value);
                        }
                        _ => {
                            return Err(format!(
                                "TypeError: UserString.__mul__() got an unexpected keyword argument '{name}'"
                            ));
                        }
                    }
                }
                let Some(receiver) = receiver else {
                    return Err(
                        if count.is_some() {
                            "TypeError: UserString.__mul__() missing 1 required positional argument: 'self'"
                        } else {
                            "TypeError: UserString.__mul__() missing 2 required positional arguments: 'self' and 'n'"
                        }
                        .to_string(),
                    );
                };
                let Some(count) = count else {
                    return Err(
                        "TypeError: UserString.__mul__() missing 1 required positional argument: 'n'"
                            .to_string(),
                    );
                };
                self.user_string_repeat_value(&receiver, count)
            }
            "__add__" | "__radd__" => {
                if args.len() > 2 {
                    return Err(format!(
                        "TypeError: UserString.{method}() takes 2 positional arguments but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                let mut other = args.get(1).cloned();
                for (name, value) in keywords {
                    match name.as_str() {
                        "self" => {
                            if receiver.is_some() {
                                return Err(format!(
                                    "TypeError: UserString.{method}() got multiple values for argument 'self'"
                                ));
                            }
                            receiver = Some(value);
                        }
                        "other" => {
                            if other.is_some() {
                                return Err(format!(
                                    "TypeError: UserString.{method}() got multiple values for argument 'other'"
                                ));
                            }
                            other = Some(value);
                        }
                        _ => {
                            return Err(format!(
                                "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                            ));
                        }
                    }
                }
                let Some(receiver) = receiver else {
                    return Err(if other.is_some() {
                        format!(
                            "TypeError: UserString.{method}() missing 1 required positional argument: 'self'"
                        )
                    } else {
                        format!(
                            "TypeError: UserString.{method}() missing 2 required positional arguments: 'self' and 'other'"
                        )
                    });
                };
                let Some(other) = other else {
                    return Err(format!(
                        "TypeError: UserString.{method}() missing 1 required positional argument: 'other'"
                    ));
                };
                if method == "__radd__" {
                    self.user_string_radd_value(&receiver, &other)
                } else {
                    self.user_string_add_value(&receiver, &other)
                }
            }
            "__eq__" => {
                if args.len() > 2 {
                    return Err(format!(
                        "TypeError: UserString.__eq__() takes 2 positional arguments but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                let mut string = args.get(1).cloned();
                for (name, value) in keywords {
                    match name.as_str() {
                        "self" => {
                            if receiver.is_some() {
                                return Err(
                                    "TypeError: UserString.__eq__() got multiple values for argument 'self'"
                                        .to_string(),
                                );
                            }
                            receiver = Some(value);
                        }
                        "string" => {
                            if string.is_some() {
                                return Err(
                                    "TypeError: UserString.__eq__() got multiple values for argument 'string'"
                                        .to_string(),
                                );
                            }
                            string = Some(value);
                        }
                        _ => {
                            return Err(format!(
                                "TypeError: UserString.__eq__() got an unexpected keyword argument '{name}'"
                            ));
                        }
                    }
                }
                let Some(receiver) = receiver else {
                    return Err(
                        if string.is_some() {
                            "TypeError: UserString.__eq__() missing 1 required positional argument: 'self'"
                        } else {
                            "TypeError: UserString.__eq__() missing 2 required positional arguments: 'self' and 'string'"
                        }
                        .to_string(),
                    );
                };
                let Some(string) = string else {
                    return Err(
                        "TypeError: UserString.__eq__() missing 1 required positional argument: 'string'"
                            .to_string(),
                    );
                };
                let Value::UserString { data, .. } = &receiver else {
                    return Err(format!(
                        "AttributeError: '{}' object has no attribute 'data'",
                        type_name(&receiver)
                    ));
                };
                Ok(Value::Bool(user_string_equal_value(
                    &data.borrow(),
                    &string,
                )))
            }
            "__lt__" | "__le__" | "__gt__" | "__ge__" => {
                if args.len() > 2 {
                    return Err(format!(
                        "TypeError: UserString.{method}() takes 2 positional arguments but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                let mut string = args.get(1).cloned();
                for (name, value) in keywords {
                    match name.as_str() {
                        "self" => {
                            if receiver.is_some() {
                                return Err(format!(
                                    "TypeError: UserString.{method}() got multiple values for argument 'self'"
                                ));
                            }
                            receiver = Some(value);
                        }
                        "string" => {
                            if string.is_some() {
                                return Err(format!(
                                    "TypeError: UserString.{method}() got multiple values for argument 'string'"
                                ));
                            }
                            string = Some(value);
                        }
                        _ => {
                            return Err(format!(
                                "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                            ));
                        }
                    }
                }
                let Some(receiver) = receiver else {
                    return Err(if string.is_some() {
                        format!(
                            "TypeError: UserString.{method}() missing 1 required positional argument: 'self'"
                        )
                    } else {
                        format!(
                            "TypeError: UserString.{method}() missing 2 required positional arguments: 'self' and 'string'"
                        )
                    });
                };
                let Some(string) = string else {
                    return Err(format!(
                        "TypeError: UserString.{method}() missing 1 required positional argument: 'string'"
                    ));
                };
                user_string_order_value(&receiver, &string, method)
            }
            "__hash__" => {
                if args.len() > 1 {
                    return Err(format!(
                        "TypeError: UserString.__hash__() takes 1 positional argument but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                for (name, value) in keywords {
                    if name != "self" {
                        return Err(format!(
                            "TypeError: UserString.__hash__() got an unexpected keyword argument '{name}'"
                        ));
                    }
                    if receiver.is_some() {
                        return Err(
                            "TypeError: UserString.__hash__() got multiple values for argument 'self'"
                                .to_string(),
                        );
                    }
                    receiver = Some(value);
                }
                let Some(receiver) = receiver else {
                    return Err(
                        "TypeError: UserString.__hash__() missing 1 required positional argument: 'self'"
                            .to_string(),
                    );
                };
                let Value::UserString { .. } = &receiver else {
                    return Err(format!(
                        "AttributeError: '{}' object has no attribute 'data'",
                        type_name(&receiver)
                    ));
                };
                hash_value(&receiver)
            }
            "__int__" => {
                let receiver = user_string_self_argument(method, &args, keywords)?;
                user_string_int_value(&receiver)
            }
            "__float__" => {
                let receiver = user_string_self_argument(method, &args, keywords)?;
                user_string_float_value(&receiver)
            }
            "__complex__" => {
                let receiver = user_string_self_argument(method, &args, keywords)?;
                user_string_complex_value(&receiver)
            }
            "__getnewargs__" => {
                let receiver = user_string_self_argument(method, &args, keywords)?;
                user_string_getnewargs_value(&receiver)
            }
            "__repr__" | "__str__" => {
                if args.len() > 1 {
                    return Err(format!(
                        "TypeError: UserString.{method}() takes 1 positional argument but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                for (name, value) in keywords {
                    if name != "self" {
                        return Err(format!(
                            "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                        ));
                    }
                    if receiver.is_some() {
                        return Err(format!(
                            "TypeError: UserString.{method}() got multiple values for argument 'self'"
                        ));
                    }
                    receiver = Some(value);
                }
                let Some(receiver) = receiver else {
                    return Err(format!(
                        "TypeError: UserString.{method}() missing 1 required positional argument: 'self'"
                    ));
                };
                let Value::UserString { data, .. } = receiver else {
                    return Err(format!(
                        "AttributeError: '{}' object has no attribute 'data'",
                        type_name(&receiver)
                    ));
                };
                let text = if method == "__repr__" {
                    repr_string(&data.borrow())
                } else {
                    data.borrow().clone()
                };
                Ok(Value::String(text))
            }
            "lower" | "upper" | "capitalize" | "casefold" | "swapcase" | "title" => {
                if args.len() > 1 {
                    return Err(format!(
                        "TypeError: UserString.{method}() takes 1 positional argument but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                for (name, value) in keywords {
                    if name != "self" {
                        return Err(format!(
                            "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                        ));
                    }
                    if receiver.is_some() {
                        return Err(format!(
                            "TypeError: UserString.{method}() got multiple values for argument 'self'"
                        ));
                    }
                    receiver = Some(value);
                }
                let Some(receiver) = receiver else {
                    return Err(format!(
                        "TypeError: UserString.{method}() missing 1 required positional argument: 'self'"
                    ));
                };
                user_string_case_transform_value(&receiver, method)
            }
            "islower" | "isupper" | "istitle" | "isspace" | "isalpha" | "isalnum" | "isdigit"
            | "isdecimal" | "isnumeric" | "isascii" | "isidentifier" | "isprintable" => {
                let receiver = user_string_self_argument(method, &args, keywords)?;
                user_string_predicate_value(&receiver, method)
            }
            "count" | "find" | "rfind" | "index" | "rindex" => {
                let (receiver, sub, start, end) =
                    user_string_search_arguments(method, &args, keywords)?;
                self.user_string_search_value(&receiver, &sub, start.as_ref(), end.as_ref(), method)
            }
            "startswith" | "endswith" => {
                let (receiver, affix, start, end) =
                    user_string_prefix_suffix_arguments(method, &args, keywords)?;
                self.user_string_prefix_suffix_value(
                    &receiver,
                    &affix,
                    start.as_ref(),
                    end.as_ref(),
                    method == "startswith",
                    method,
                )
            }
            "strip" | "lstrip" | "rstrip" => {
                let (receiver, chars) = user_string_strip_arguments(method, &args, keywords)?;
                user_string_strip_value(&receiver, chars.as_ref(), method)
            }
            "removeprefix" | "removesuffix" => {
                let (receiver, affix) =
                    user_string_remove_affix_arguments(method, &args, keywords)?;
                user_string_remove_affix_value(&receiver, &affix, method == "removeprefix", method)
            }
            "partition" | "rpartition" => {
                let (receiver, sep) = user_string_partition_arguments(method, &args, keywords)?;
                user_string_partition_value(&receiver, &sep, method == "partition", method)
            }
            "split" | "rsplit" => {
                let (receiver, separator, maxsplit) =
                    user_string_split_arguments(method, &args, keywords)?;
                self.user_string_split_value(&receiver, separator, maxsplit, method)
            }
            "join" => {
                let (receiver, seq) = user_string_join_arguments(method, &args, keywords)?;
                self.user_string_join_value(&receiver, seq)
            }
            "format" => {
                let Some((receiver, positional)) = args.split_first() else {
                    return Err(
                        "TypeError: UserString.format() missing 1 required positional argument: 'self'"
                            .to_string(),
                    );
                };
                self.user_string_format_value(receiver, positional, &keywords)
            }
            "format_map" => {
                let (receiver, mapping) =
                    user_string_format_map_arguments(method, &args, keywords)?;
                self.user_string_format_map_value(&receiver, mapping)
            }
            "__mod__" => {
                let (receiver, format_args) =
                    user_string_binary_arguments(method, &args, keywords, "args")?;
                self.user_string_mod_value(&receiver, format_args)
            }
            "__rmod__" => {
                let (receiver, template) =
                    user_string_binary_arguments(method, &args, keywords, "template")?;
                self.user_string_rmod_value(&receiver, template)
            }
            "encode" => {
                let (receiver, encoding, errors) =
                    user_string_encode_arguments(method, &args, keywords)?;
                self.user_string_encode_value(&receiver, encoding.as_ref(), errors.as_ref())
            }
            "translate" => {
                let (receiver, translate_args) =
                    user_string_translate_arguments(method, &args, keywords)?;
                self.user_string_translate_value(&receiver, translate_args)
            }
            "splitlines" => {
                let (receiver, keepends) =
                    user_string_splitlines_arguments(method, &args, keywords)?;
                self.user_string_splitlines_value(&receiver, keepends)
            }
            "expandtabs" => {
                let (receiver, tabsize) =
                    user_string_expandtabs_arguments(method, &args, keywords)?;
                self.user_string_expandtabs_value(&receiver, tabsize, method)
            }
            "replace" => {
                let (receiver, old, new, maxsplit) =
                    user_string_replace_arguments(method, &args, keywords)?;
                self.user_string_replace_value(&receiver, &old, &new, maxsplit, method)
            }
            "center" => {
                let (receiver, width, fillchar, too_many_args) =
                    user_string_center_arguments(method, &args, keywords)?;
                self.user_string_center_value(&receiver, width, fillchar, too_many_args)
            }
            "ljust" => {
                let (receiver, width, fillchar, too_many_args) =
                    user_string_ljust_arguments(method, &args, keywords)?;
                self.user_string_ljust_value(&receiver, width, fillchar, too_many_args)
            }
            "rjust" => {
                let (receiver, width, fillchar, too_many_args) =
                    user_string_rjust_arguments(method, &args, keywords)?;
                self.user_string_rjust_value(&receiver, width, fillchar, too_many_args)
            }
            "zfill" => {
                let (receiver, width) = user_string_zfill_arguments(method, &args, keywords)?;
                self.user_string_zfill_value(&receiver, width)
            }
            "__contains__" => {
                let Some((receiver, rest)) = args.split_first() else {
                    return Err(
                        "TypeError: UserString.__contains__() missing 2 required positional arguments: 'self' and 'char'"
                            .to_string(),
                    );
                };
                let Value::UserString { data, .. } = receiver else {
                    return Err(format!(
                        "AttributeError: '{}' object has no attribute 'data'",
                        type_name(receiver)
                    ));
                };
                if rest.len() > 1 {
                    return Err(format!(
                        "TypeError: UserString.__contains__() takes 2 positional arguments but {} were given",
                        args.len()
                    ));
                }
                let mut char_value = rest.first().cloned();
                for (name, value) in keywords {
                    if name != "char" {
                        return Err(format!(
                            "TypeError: UserString.__contains__() got an unexpected keyword argument '{name}'"
                        ));
                    }
                    if char_value.is_some() {
                        return Err(
                            "TypeError: UserString.__contains__() got multiple values for argument 'char'"
                                .to_string(),
                        );
                    }
                    char_value = Some(value);
                }
                let Some(char_value) = char_value else {
                    return Err(
                        "TypeError: UserString.__contains__() missing 1 required positional argument: 'char'"
                            .to_string(),
                    );
                };
                Ok(Value::Bool(user_string_contains_value(
                    &data.borrow(),
                    char_value,
                )?))
            }
            "__iter__" => {
                if args.len() > 1 {
                    return Err(format!(
                        "TypeError: Sequence.__iter__() takes 1 positional argument but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                for (name, value) in keywords {
                    if name != "self" {
                        return Err(format!(
                            "TypeError: Sequence.__iter__() got an unexpected keyword argument '{name}'"
                        ));
                    }
                    if receiver.is_some() {
                        return Err(
                            "TypeError: Sequence.__iter__() got multiple values for argument 'self'"
                                .to_string(),
                        );
                    }
                    receiver = Some(value);
                }
                let Some(receiver) = receiver else {
                    return Err(
                        "TypeError: Sequence.__iter__() missing 1 required positional argument: 'self'"
                            .to_string(),
                    );
                };
                let Value::UserString { data, .. } = receiver else {
                    return Err(format!(
                        "AttributeError: '{}' object has no attribute 'data'",
                        type_name(&receiver)
                    ));
                };
                user_string_iter_value(&data.borrow())
            }
            "__reversed__" => {
                let receiver = sequence_abc_bind_reversed_self_arg(args, keywords)?;
                reversed_value(receiver)
            }
            "__len__" => {
                if args.len() > 1 {
                    return Err(format!(
                        "TypeError: UserString.__len__() takes 1 positional argument but {} were given",
                        args.len()
                    ));
                }
                let mut receiver = args.first().cloned();
                for (name, value) in keywords {
                    if name != "self" {
                        return Err(format!(
                            "TypeError: UserString.__len__() got an unexpected keyword argument '{name}'"
                        ));
                    }
                    if receiver.is_some() {
                        return Err(
                            "TypeError: UserString.__len__() got multiple values for argument 'self'"
                                .to_string(),
                        );
                    }
                    receiver = Some(value);
                }
                let Some(receiver) = receiver else {
                    return Err(
                        "TypeError: UserString.__len__() missing 1 required positional argument: 'self'"
                            .to_string(),
                    );
                };
                let Value::UserString { data, .. } = receiver else {
                    return Err(format!(
                        "AttributeError: '{}' object has no attribute 'data'",
                        type_name(&receiver)
                    ));
                };
                let len = i64::try_from(data.borrow().chars().count())
                    .map_err(|_| "OverflowError: len() result is too large".to_string())?;
                Ok(Value::Number(len))
            }
            "__getitem__" => {
                let Some((receiver, rest)) = args.split_first() else {
                    return Err(
                        "TypeError: UserString.__getitem__() missing 2 required positional arguments: 'self' and 'index'"
                            .to_string(),
                    );
                };
                let Value::UserString { data, .. } = receiver else {
                    return Err(format!(
                        "AttributeError: '{}' object has no attribute 'data'",
                        type_name(receiver)
                    ));
                };
                if rest.len() > 1 {
                    return Err(format!(
                        "TypeError: UserString.__getitem__() takes 2 positional arguments but {} were given",
                        args.len()
                    ));
                }
                let mut index = rest.first().cloned();
                for (name, value) in keywords {
                    if name != "index" {
                        return Err(format!(
                            "TypeError: UserString.__getitem__() got an unexpected keyword argument '{name}'"
                        ));
                    }
                    if index.is_some() {
                        return Err(
                            "TypeError: UserString.__getitem__() got multiple values for argument 'index'"
                                .to_string(),
                        );
                    }
                    index = Some(value);
                }
                let Some(index) = index else {
                    return Err(
                        "TypeError: UserString.__getitem__() missing 1 required positional argument: 'index'"
                            .to_string(),
                    );
                };
                load_subscript(
                    Value::UserString {
                        data: data.clone(),
                        attrs: dict_ref_from_entries(Vec::new())?,
                    },
                    index,
                )
            }
            _ => unreachable!("UserString method dispatch filters unsupported methods"),
        }
    }

