    fn user_string_splitlines_value(
        &mut self,
        receiver: &Value,
        keepends: Option<Value>,
    ) -> Result<Value, String> {
        let Value::UserString { data, .. } = receiver else {
            return Err(format!(
                "AttributeError: '{}' object has no attribute 'data'",
                type_name(receiver)
            ));
        };
        let keepends = match keepends {
            Some(value) => is_truthy(&value)?,
            None => false,
        };
        let lines = string_splitlines(&data.borrow(), keepends)
            .into_iter()
            .map(Value::String)
            .collect();
        Ok(list_value(lines))
    }

    fn user_string_split_value(
        &mut self,
        receiver: &Value,
        separator: Option<Value>,
        maxsplit: Option<Value>,
        method: &str,
    ) -> Result<Value, String> {
        let Value::UserString { data, .. } = receiver else {
            return Err(format!(
                "AttributeError: '{}' object has no attribute 'data'",
                type_name(receiver)
            ));
        };
        let separator = user_string_split_separator(separator)?;
        let maxsplit = match maxsplit {
            Some(value) => self.user_string_split_maxsplit(value)?,
            None => -1,
        };
        let text = data.borrow();
        let parts = match separator {
            Some(separator) => {
                string_split_separator(&text, &separator, maxsplit, method == "rsplit")?
            }
            None => string_split_whitespace(&text, maxsplit, method == "rsplit"),
        };
        Ok(list_value(parts.into_iter().map(Value::String).collect()))
    }

    fn user_string_split_maxsplit(&mut self, value: Value) -> Result<i64, String> {
        match self.index_integer_value(value)? {
            Value::Number(value) => Ok(value),
            Value::BigInt(value) => value.to_i64().ok_or_else(|| {
                "OverflowError: Python int too large to convert to C ssize_t".to_string()
            }),
            _ => unreachable!("index_integer_value returns an integer"),
        }
    }

    fn user_string_join_value(&mut self, receiver: &Value, seq: Value) -> Result<Value, String> {
        let Value::UserString { data, .. } = receiver else {
            return Err(format!(
                "AttributeError: '{}' object has no attribute 'data'",
                type_name(receiver)
            ));
        };
        let values = self.collect_iterable_values(seq).map_err(|error| {
            if error.ends_with(" is not iterable") {
                "TypeError: can only join an iterable".to_string()
            } else {
                error
            }
        })?;
        let mut parts = Vec::with_capacity(values.len());
        for (index, value) in values.into_iter().enumerate() {
            if let Some(part) = user_string_join_part(&value) {
                parts.push(part);
            } else {
                return Err(format!(
                    "TypeError: sequence item {index}: expected str instance, {} found",
                    type_name(&value)
                ));
            }
        }
        Ok(Value::String(parts.join(&data.borrow())))
    }

