fn find_class_attr(attrs: &Scope, bases: &[Value], name: &str) -> Option<Value> {
    if let Some(value) = attrs.borrow().get(name).cloned() {
        return Some(value);
    }

    find_base_attr_by_mro(bases, name)
}

fn find_base_attr_by_mro(bases: &[Value], name: &str) -> Option<Value> {
    find_base_attr_by_mro_with_owner(bases, name).map(|(value, _)| value)
}

fn find_base_attr_by_mro_with_owner(bases: &[Value], name: &str) -> Option<(Value, Value)> {
    mro_for_bases(bases).ok()?.into_iter().find_map(|base| {
        let Value::Class { attrs, .. } = &base else {
            return None;
        };
        attrs
            .borrow()
            .get(name)
            .cloned()
            .map(|value| (value, base.clone()))
    })
}

fn qualify_init_subclass_call_error(message: String, owner: &Value) -> String {
    let Value::Class { name, .. } = owner else {
        return message;
    };

    if let Some(rest) = message
        .strip_prefix("TypeError: __init_subclass__() got an unexpected keyword argument ")
        .or_else(|| message.strip_prefix("__init_subclass__() got an unexpected keyword argument "))
    {
        return format!(
            "TypeError: {name}.__init_subclass__() got an unexpected keyword argument {rest}"
        );
    }

    if let Some(parameter) = message
        .strip_prefix("TypeError: __init_subclass__() missing required argument ")
        .or_else(|| message.strip_prefix("__init_subclass__() missing required argument "))
    {
        return format!(
            "TypeError: {name}.__init_subclass__() missing 1 required positional argument: {parameter}"
        );
    }

    message
}

fn attach_owner_class_to_members(class: &Value) {
    let Value::Class { attrs, .. } = class else {
        return;
    };
    let updates = attrs
        .borrow()
        .iter()
        .map(|(name, value)| (name.clone(), attach_owner_class(value.clone(), class)))
        .collect::<Vec<_>>();
    attrs.borrow_mut().extend(updates);
}

fn wrap_dunder_new_as_staticmethod(attrs: &Scope) {
    let Some(value @ Value::Function { .. }) = attrs.borrow().get("__new__").cloned() else {
        return;
    };
    attrs.borrow_mut().insert(
        "__new__".to_string(),
        Value::StaticMethod {
            function: Box::new(value),
            identity: Rc::new(()),
        },
    );
}

fn wrap_init_subclass_as_classmethod(attrs: &Scope) {
    let Some(value @ Value::Function { .. }) = attrs.borrow().get("__init_subclass__").cloned()
    else {
        return;
    };
    attrs.borrow_mut().insert(
        "__init_subclass__".to_string(),
        Value::ClassMethod {
            function: Box::new(value),
            identity: Rc::new(()),
        },
    );
}

fn init_subclass_callable(descriptor: Value, class_value: Value) -> Value {
    match descriptor {
        Value::ClassMethod { function, .. } => Value::BoundMethod {
            function,
            receiver: Box::new(class_value),
            identity: Rc::new(()),
        },
        descriptor => bind_method(descriptor, class_value),
    }
}

fn class_new_callable(descriptor: Value, class_value: Value) -> Value {
    match descriptor {
        Value::StaticMethod { function, .. } => *function,
        Value::ClassMethod { function, .. } => Value::BoundMethod {
            function,
            receiver: Box::new(class_value),
            identity: Rc::new(()),
        },
        value => value,
    }
}

fn attach_owner_class(value: Value, class: &Value) -> Value {
    match value {
        Value::Function {
            name,
            type_params,
            globals,
            positional_only,
            params,
            defaults,
            vararg,
            keyword_only,
            keyword_defaults,
            kwarg,
            annotations,
            doc,
            attrs,
            closure,
            body,
            is_generator,
            is_async,
            locals_are_globals,
            first_line,
            line_sequence,
            position_columns,
            identity,
            owner_class,
        } => Value::Function {
            name,
            type_params,
            globals,
            positional_only,
            params,
            defaults,
            vararg,
            keyword_only,
            keyword_defaults,
            kwarg,
            annotations,
            doc,
            attrs,
            closure,
            body,
            is_generator,
            is_async,
            locals_are_globals,
            first_line,
            line_sequence,
            position_columns,
            identity,
            owner_class: owner_class.or_else(|| Some(Box::new(class.clone()))),
        },
        Value::StaticMethod { function, identity } => Value::StaticMethod {
            function: Box::new(attach_owner_class(*function, class)),
            identity,
        },
        Value::ClassMethod { function, identity } => Value::ClassMethod {
            function: Box::new(attach_owner_class(*function, class)),
            identity,
        },
        Value::Property {
            fget,
            fset,
            fdel,
            doc,
            doc_from_getter,
            name,
            identity,
        } => Value::Property {
            fget: fget.map(|value| Box::new(attach_owner_class(*value, class))),
            fset: fset.map(|value| Box::new(attach_owner_class(*value, class))),
            fdel: fdel.map(|value| Box::new(attach_owner_class(*value, class))),
            doc,
            doc_from_getter,
            name,
            identity,
        },
        Value::CachedProperty {
            function,
            attrname,
            attrs,
            identity,
        } => Value::CachedProperty {
            function: Box::new(attach_owner_class(*function, class)),
            attrname,
            attrs,
            identity,
        },
        Value::PartialMethod {
            function,
            args,
            keywords,
            attrs,
            identity,
        } => Value::PartialMethod {
            function: Box::new(attach_owner_class(*function, class)),
            args,
            keywords,
            attrs,
            identity,
        },
        value => value,
    }
}

#[derive(Debug, Clone)]
struct SlotSpec {
    names: Vec<String>,
    has_dict: bool,
    has_weakref: bool,
}

fn validate_class_slots(class: &Value) -> Result<(), String> {
    let Value::Class { attrs, bases, .. } = class else {
        return Ok(());
    };
    let Some(spec) = own_slot_spec(attrs) else {
        return Ok(());
    };
    let spec = spec?;

    if spec.has_dict && class_inherits_instance_dict(bases)? {
        return Err("TypeError: __dict__ slot disallowed: we already got one".to_string());
    }
    if spec.has_weakref && class_inherits_weakref(bases)? {
        return Err(
            "TypeError: __weakref__ slot disallowed: either we already got one, or __itemsize__ != 0"
                .to_string(),
        );
    }
    if class_bases_include_builtin(bases, "int")
        && spec
            .names
            .iter()
            .any(|name| !matches!(name.as_str(), "__dict__" | "__weakref__"))
    {
        return Err("TypeError: nonempty __slots__ not supported for subtype of 'int'".to_string());
    }

    Ok(())
}

fn install_slot_descriptors(class: &Value) -> Result<(), String> {
    let Value::Class {
        name: owner_name,
        attrs,
        ..
    } = class
    else {
        return Ok(());
    };
    let Some(spec) = own_slot_spec(attrs) else {
        return Ok(());
    };

    let mut installed = Vec::new();
    for name in spec?.names {
        if matches!(name.as_str(), "__dict__" | "__weakref__") {
            continue;
        }
        if installed.iter().any(|existing| existing == &name) {
            continue;
        }
        if attrs.borrow().contains_key(&name) {
            return Err(format!(
                "ValueError: '{name}' in __slots__ conflicts with class variable"
            ));
        }
        installed.push(name.clone());
        attrs.borrow_mut().insert(
            name.clone(),
            Value::MemberDescriptor {
                name,
                owner_name: owner_name.clone(),
                identity: Rc::new(()),
            },
        );
    }

    Ok(())
}

fn reject_disallowed_slot_attribute(
    class_name: &str,
    class_attrs: &Scope,
    class_bases: &[Value],
    name: &str,
) -> Result<(), String> {
    if instance_allows_attribute_dict(class_name, class_attrs, class_bases)? {
        return Ok(());
    }

    if class_slot_names(class_attrs, class_bases)?
        .iter()
        .any(|slot_name| slot_name == name)
    {
        return Ok(());
    }

    Err(format!(
        "AttributeError: '{class_name}' object has no attribute '{name}' and no __dict__ for setting new attributes"
    ))
}

fn instance_allows_attribute_dict(
    class_name: &str,
    attrs: &Scope,
    bases: &[Value],
) -> Result<bool, String> {
    if is_exact_builtin_object_instance(class_name, attrs, bases) {
        return Ok(false);
    }
    class_allows_instance_dict(attrs, bases)
}

fn is_exact_builtin_object_instance(class_name: &str, attrs: &Scope, bases: &[Value]) -> bool {
    class_name == "object" && bases.is_empty() && attrs.borrow().is_empty()
}

fn class_allows_instance_dict(attrs: &Scope, bases: &[Value]) -> Result<bool, String> {
    let Some(spec) = own_slot_spec(attrs) else {
        return Ok(true);
    };
    let spec = spec?;
    Ok(spec.has_dict || class_inherits_instance_dict(bases)?)
}

fn class_inherits_instance_dict(bases: &[Value]) -> Result<bool, String> {
    bases.iter().try_fold(false, |has_dict, base| {
        if has_dict {
            return Ok(true);
        }
        match base {
            Value::Class { attrs, bases, .. } => class_allows_instance_dict(attrs, bases),
            Value::Builtin(_) => Ok(false),
            _ => Ok(false),
        }
    })
}

fn class_allows_weakref(attrs: &Scope, bases: &[Value]) -> Result<bool, String> {
    let Some(spec) = own_slot_spec(attrs) else {
        return Ok(true);
    };
    let spec = spec?;
    Ok(spec.has_weakref || class_inherits_weakref(bases)?)
}

fn is_weakrefable_value(value: &Value) -> Result<bool, String> {
    match value {
        Value::MemoryView(_)
        | Value::Set(_)
        | Value::FrozenSet(_)
        | Value::Function { .. }
        | Value::TypesCoroutineFunction { .. }
        | Value::MagicMock { .. }
        | Value::MockMethod { .. }
        | Value::GeneratorWrapper { .. }
        | Value::Class { .. }
        | Value::Builtin(_)
        | Value::TypeParam { .. }
        | Value::ParamSpecAccess { .. }
        | Value::TypeAlias { .. }
        | Value::NewType { .. }
        | Value::GenericAlias { .. } => Ok(true),
        Value::Instance {
            class_name,
            class_attrs,
            class_bases,
            ..
        } => {
            if class_name == "object" {
                Ok(false)
            } else {
                class_allows_weakref(class_attrs, class_bases)
            }
        }
        Value::None
        | Value::NotImplemented
        | Value::Ellipsis
        | Value::Bool(_)
        | Value::Number(_)
        | Value::BigInt(_)
        | Value::Float(_)
        | Value::Complex { .. }
        | Value::String(_)
        | Value::IdentityString { .. }
        | Value::Bytes(_)
        | Value::ByteArray(_)
        | Value::List(_)
        | Value::Tuple(_)
        | Value::Dict(_)
        | Value::OrderedDict(_)
        | Value::ScopeDict(_)
        | Value::Range { .. } => Ok(false),
        _ => Ok(false),
    }
}

fn class_inherits_weakref(bases: &[Value]) -> Result<bool, String> {
    bases.iter().try_fold(false, |has_weakref, base| {
        if has_weakref {
            return Ok(true);
        }
        match base {
            Value::Class { attrs, bases, .. } => class_allows_weakref(attrs, bases),
            Value::Builtin(_) => Ok(false),
            _ => Ok(false),
        }
    })
}

fn default_dict_default_factory_descriptor() -> Value {
    let identity =
        DEFAULT_DICT_DEFAULT_FACTORY_DESCRIPTOR_IDENTITY.with(|identity| identity.clone());
    Value::MemberDescriptor {
        name: "default_factory".to_string(),
        owner_name: "collections.defaultdict".to_string(),
        identity,
    }
}

fn super_member_descriptor_names() -> &'static [&'static str] {
    &["__thisclass__", "__self__", "__self_class__"]
}

fn is_super_member_descriptor_name(name: &str) -> bool {
    super_member_descriptor_names().contains(&name)
}

fn super_wrapper_descriptor_names() -> &'static [&'static str] {
    &["__get__", "__repr__", "__getattribute__"]
}

fn is_super_wrapper_descriptor_name(name: &str) -> bool {
    super_wrapper_descriptor_names().contains(&name)
}

fn is_super_wrapper_descriptor_builtin(name: &str) -> bool {
    super_wrapper_descriptor_method_name(name).is_some()
}

fn super_wrapper_descriptor_method_name(name: &str) -> Option<&str> {
    let method = name.strip_prefix("super.")?;
    is_super_wrapper_descriptor_name(method).then_some(method)
}

fn super_wrapper_descriptor_doc(name: &str) -> &'static str {
    match name {
        "__get__" => "Return an attribute of instance, which is of type owner.",
        "__repr__" => "Return repr(self).",
        "__getattribute__" => "Return getattr(self, name).",
        _ => unreachable!("guard checked super wrapper descriptor name"),
    }
}

fn super_wrapper_descriptor_text_signature(name: &str) -> &'static str {
    match name {
        "__get__" => "($self, instance, owner=None, /)",
        "__repr__" => "($self, /)",
        "__getattribute__" => "($self, name, /)",
        _ => unreachable!("guard checked super wrapper descriptor name"),
    }
}

fn super_member_descriptor(name: &str) -> Value {
    debug_assert!(is_super_member_descriptor_name(name));
    Value::MemberDescriptor {
        name: name.to_string(),
        owner_name: "super".to_string(),
        identity: Rc::new(()),
    }
}

fn super_member_descriptor_get(object: &Value, name: &str) -> Result<Value, String> {
    let Value::Super {
        class,
        object: super_object,
        ..
    } = object
    else {
        return Err(super_member_descriptor_wrong_object_error(name, object));
    };

    match name {
        "__thisclass__" => Ok(class.as_ref().clone()),
        "__self__" => Ok(super_object.as_ref().clone()),
        "__self_class__" if matches!(super_object.as_ref(), Value::None) => Ok(Value::None),
        "__self_class__" => super_lookup_owner_class(class.as_ref(), super_object.as_ref()),
        _ => Err(format!(
            "AttributeError: member_descriptor has no attribute '{name}'"
        )),
    }
}

fn ensure_super_member_descriptor_object(object: &Value, name: &str) -> Result<(), String> {
    if matches!(object, Value::Super { .. }) {
        Ok(())
    } else {
        Err(super_member_descriptor_wrong_object_error(name, object))
    }
}

fn super_member_descriptor_wrong_object_error(name: &str, object: &Value) -> String {
    format!(
        "TypeError: descriptor '{name}' for 'super' objects doesn't apply to a '{}' object",
        type_name(object)
    )
}

fn default_dict_default_factory_descriptor_value(
    object: &Value,
) -> Result<Rc<RefCell<Value>>, String> {
    let Value::DefaultDict {
        default_factory, ..
    } = object
    else {
        return Err(format!(
            "TypeError: descriptor 'default_factory' for 'collections.defaultdict' objects doesn't apply to a '{}' object",
            type_name(object)
        ));
    };
    Ok(default_factory.clone())
}

fn member_descriptor_doc_value(descriptor_name: &str, owner_name: &str) -> Value {
    if descriptor_name == "default_factory" && owner_name == "collections.defaultdict" {
        return Value::String("Factory for default value called by __missing__().".to_string());
    }
    if owner_name == "super" {
        return match descriptor_name {
            "__thisclass__" => Value::String("the class invoking super()".to_string()),
            "__self__" => Value::String("the instance invoking super(); may be None".to_string()),
            "__self_class__" => {
                Value::String("the type of the instance invoking super(); may be None".to_string())
            }
            _ => Value::None,
        };
    }
    Value::None
}

fn member_descriptor_objclass_value(owner_name: &str) -> Option<Value> {
    match owner_name {
        "collections.defaultdict" => Some(Value::Builtin("defaultdict".to_string())),
        "super" => Some(Value::Builtin("super".to_string())),
        _ => None,
    }
}

fn member_descriptor_qualname(descriptor_name: &str, owner_name: &str) -> String {
    let owner_qualname = owner_name.rsplit('.').next().unwrap_or(owner_name);
    format!("{owner_qualname}.{descriptor_name}")
}

fn member_descriptor_fields(object: &Value, name: &str, owner_name: &str) -> Result<Scope, String> {
    let Value::Instance {
        class_name,
        fields,
        class_bases,
        ..
    } = object
    else {
        return Err(format!(
            "TypeError: descriptor '{name}' for '{owner_name}' objects doesn't apply to a '{}' object",
            type_name(object)
        ));
    };

    if class_name == owner_name || class_bases_have_name(class_bases, owner_name) {
        return Ok(fields.clone());
    }

    Err(format!(
        "TypeError: descriptor '{name}' for '{owner_name}' objects doesn't apply to a '{class_name}' object"
    ))
}

fn class_bases_have_name(bases: &[Value], owner_name: &str) -> bool {
    bases.iter().any(|base| match base {
        Value::Class {
            name,
            bases: base_bases,
            ..
        } => name == owner_name || class_bases_have_name(base_bases, owner_name),
        Value::Builtin(name) => name == owner_name,
        _ => false,
    })
}

fn class_slot_names(attrs: &Scope, bases: &[Value]) -> Result<Vec<String>, String> {
    let mut names = Vec::new();

    for base in bases {
        if let Value::Class {
            attrs: base_attrs,
            bases: base_bases,
            ..
        } = base
        {
            names.extend(class_slot_names(base_attrs, base_bases)?);
        }
    }

    if let Some(spec) = own_slot_spec(attrs) {
        names.extend(
            spec?
                .names
                .into_iter()
                .filter(|name| !matches!(name.as_str(), "__dict__" | "__weakref__")),
        );
    }

    Ok(names)
}

fn own_slot_spec(attrs: &Scope) -> Option<Result<SlotSpec, String>> {
    attrs
        .borrow()
        .get("__slots__")
        .cloned()
        .map(|value| slot_spec_from_value(&value))
}

fn slot_spec_from_value(value: &Value) -> Result<SlotSpec, String> {
    let names = match value {
        Value::String(name) | Value::IdentityString { value: name, .. } => vec![name.clone()],
        Value::Tuple(items) => items
            .iter()
            .map(slot_name_from_value)
            .collect::<Result<Vec<_>, _>>()?,
        Value::List(items) => items
            .borrow()
            .iter()
            .map(slot_name_from_value)
            .collect::<Result<Vec<_>, _>>()?,
        value => {
            return Err(format!(
                "TypeError: '{}' object is not iterable",
                type_name(value)
            ));
        }
    };

    let mut dict_count = 0;
    let mut weakref_count = 0;
    for name in &names {
        if !is_valid_slot_name(name) {
            return Err("TypeError: __slots__ must be identifiers".to_string());
        }

        match name.as_str() {
            "__dict__" => dict_count += 1,
            "__weakref__" => weakref_count += 1,
            _ => {}
        }
    }

    if dict_count > 1 {
        return Err("TypeError: __dict__ slot disallowed: we already got one".to_string());
    }
    if weakref_count > 1 {
        return Err(
            "TypeError: __weakref__ slot disallowed: either we already got one, or __itemsize__ != 0"
                .to_string(),
        );
    }

    Ok(SlotSpec {
        has_dict: dict_count == 1,
        has_weakref: weakref_count == 1,
        names,
    })
}

fn slot_name_from_value(value: &Value) -> Result<String, String> {
    match value {
        Value::String(name) | Value::IdentityString { value: name, .. } => Ok(name.clone()),
        value => Err(format!(
            "TypeError: __slots__ items must be strings, not '{}'",
            type_name(value)
        )),
    }
}

fn is_valid_slot_name(name: &str) -> bool {
    name == "__dict__" || name == "__weakref__" || is_ascii_identifier(name)
}

fn is_ascii_identifier(name: &str) -> bool {
    let mut chars = name.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    if !(first == '_' || first.is_ascii_alphabetic()) {
        return false;
    }
    chars.all(|ch| ch == '_' || ch.is_ascii_alphanumeric())
}

fn class_mro(class: &Value) -> Result<Vec<Value>, String> {
    match class {
        Value::Class { bases, .. } => {
            let mut values = vec![class.clone()];
            values.extend(mro_for_bases(bases)?);
            Ok(values)
        }
        Value::NamedTupleType(typ) => {
            let mut values = vec![class.clone()];
            values.extend(mro_for_bases(&typ.bases)?);
            Ok(values)
        }
        Value::Builtin(name) => builtin_class_mro(name),
        value => Err(format!("expected class, got {value}")),
    }
}

fn builtin_class_mro(name: &str) -> Result<Vec<Value>, String> {
    if name == "object" {
        return Ok(vec![builtin_type_value("object")]);
    }
    let mut values = vec![builtin_type_value(name)];
    values.extend(mro_for_bases(&builtin_class_bases(name))?);
    Ok(values)
}

fn builtin_class_bases(name: &str) -> Vec<Value> {
    if let Some(kind) = ast_builtin_kind(name) {
        return vec![
            ast_base_kind(kind)
                .map(ast_builtin_value_for_kind)
                .unwrap_or_else(|| builtin_type_value("object")),
        ];
    }
    if let Some(bases) = builtin_exception_bases(name) {
        return bases.iter().map(|base| builtin_type_value(base)).collect();
    }
    if let Some(base) = collections_type_direct_base_name(name) {
        return vec![builtin_type_value(base)];
    }
    if let Some(bases) = collections_abc_type_direct_base_names(name) {
        return bases.iter().map(|base| builtin_type_value(base)).collect();
    }
    match name {
        "object" => Vec::new(),
        "bool" => vec![builtin_type_value("int")],
        "enumerate" => vec![builtin_type_value("object")],
        "zip" => vec![builtin_type_value("object")],
        "map" => vec![builtin_type_value("object")],
        "filter" => vec![builtin_type_value("object")],
        "callable_iterator" => vec![builtin_type_value("object")],
        "range_iterator" => vec![builtin_type_value("object")],
        "list_iterator" => vec![builtin_type_value("object")],
        "tuple_iterator" => vec![builtin_type_value("object")],
        "str_iterator" => vec![builtin_type_value("object")],
        "str_ascii_iterator" => vec![builtin_type_value("object")],
        "bytes_iterator" => vec![builtin_type_value("object")],
        "bytearray_iterator" => vec![builtin_type_value("object")],
        "arrayiterator" => vec![builtin_type_value("object")],
        "set_iterator" => vec![builtin_type_value("object")],
        "dict_keyiterator" => vec![builtin_type_value("object")],
        "dict_valueiterator" => vec![builtin_type_value("object")],
        "dict_itemiterator" => vec![builtin_type_value("object")],
        "dict_reversekeyiterator" => vec![builtin_type_value("object")],
        "dict_reversevalueiterator" => vec![builtin_type_value("object")],
        "dict_reverseitemiterator" => vec![builtin_type_value("object")],
        "list_reverseiterator" => vec![builtin_type_value("object")],
        "reversed" => vec![builtin_type_value("object")],
        _ if is_dict_view_type_object_name(name) => {
            vec![builtin_type_value(dict_view_type_object_base_name(name))]
        }
        _ if is_class_like_builtin(name) => vec![builtin_type_value("object")],
        _ => Vec::new(),
    }
}

fn mro_for_bases(bases: &[Value]) -> Result<Vec<Value>, String> {
    reject_duplicate_bases(bases)?;
    if bases.is_empty() {
        return Ok(vec![builtin_type_value("object")]);
    }

    let mut sequences = Vec::new();
    for base in bases {
        sequences.push(class_mro(base)?);
    }
    sequences.push(bases.to_vec());

    c3_merge(sequences)
}

fn c3_merge(mut sequences: Vec<Vec<Value>>) -> Result<Vec<Value>, String> {
    let mut result = Vec::new();

    loop {
        sequences.retain(|sequence| !sequence.is_empty());
        if sequences.is_empty() {
            return Ok(result);
        }

        let candidate = sequences.iter().find_map(|sequence| {
            let candidate = sequence[0].clone();
            let appears_in_tail = sequences.iter().any(|other| {
                other
                    .iter()
                    .skip(1)
                    .any(|value| same_class_value(value, &candidate))
            });
            (!appears_in_tail).then_some(candidate)
        });

        let Some(candidate) = candidate else {
            return Err(format!(
                "TypeError: Cannot create a consistent method resolution order (MRO) for bases {}",
                mro_conflict_names(&sequences)
            ));
        };

        result.push(candidate.clone());
        for sequence in &mut sequences {
            if sequence
                .first()
                .is_some_and(|value| same_class_value(value, &candidate))
            {
                sequence.remove(0);
            }
        }
    }
}

fn reject_duplicate_bases(bases: &[Value]) -> Result<(), String> {
    for (index, base) in bases.iter().enumerate() {
        if bases
            .iter()
            .skip(index + 1)
            .any(|other| same_class_value(base, other))
        {
            return Err(format!(
                "TypeError: duplicate base class {}",
                class_display_name(base)
            ));
        }
    }

    Ok(())
}

fn mro_conflict_names(sequences: &[Vec<Value>]) -> String {
    let mut names = Vec::new();
    for sequence in sequences {
        if let Some(value) = sequence.first() {
            let name = class_display_name(value);
            if !names.iter().any(|existing| existing == &name) {
                names.push(name);
            }
        }
    }
    names.join(", ")
}

fn class_display_name(value: &Value) -> String {
    match value {
        Value::Class { name, .. } | Value::Builtin(name) => name.clone(),
        Value::NamedTupleType(typ) => typ.name.clone(),
        value => value.to_string(),
    }
}

fn same_class_value(left: &Value, right: &Value) -> bool {
    match (left, right) {
        (
            Value::Class {
                name: left_name,
                attrs: left_attrs,
                ..
            },
            Value::Class {
                name: right_name,
                attrs: right_attrs,
                ..
            },
        ) => left_name == right_name && Rc::ptr_eq(left_attrs, right_attrs),
        (Value::Builtin(left), Value::Builtin(right)) => left == right,
        (Value::NamedTupleType(left), Value::NamedTupleType(right)) => {
            Rc::ptr_eq(&left.identity, &right.identity)
        }
        _ => false,
    }
}

fn validate_super_args(class: &Value, object: &Value) -> Result<(), String> {
    super_lookup_owner_class(class, object).map(|_| ())
}

fn super_lookup_owner_class(class: &Value, object: &Value) -> Result<Value, String> {
    if !is_classinfo_type(class) {
        return Err(format!(
            "TypeError: super() argument 1 must be type, not {}",
            type_name(class)
        ));
    }

    if is_classinfo_type(object)
        && class_mro(object)?
            .iter()
            .any(|candidate| same_class_value(candidate, class))
    {
        return Ok(object.clone());
    }

    let owner = type_object_for_value(object);
    if class_mro(&owner)?
        .iter()
        .any(|candidate| same_class_value(candidate, class))
    {
        return Ok(owner);
    }

    Err("TypeError: super(type, obj): obj must be an instance or subtype of type".to_string())
}

fn instance_special_method(object: &Value, name: &str) -> Option<Value> {
    if let Value::WeakProxy { target, .. } = object {
        return if name == "__hash__" {
            None
        } else {
            instance_special_method(target, name)
        };
    }

    if let Value::MagicMock { attrs, methods, .. } = object {
        if let Some(value) = attrs.borrow().get(name).cloned() {
            return Some(bind_method(value, object.clone()));
        }
        return methods.borrow().get(name).cloned();
    }

    let Value::Instance {
        class_attrs,
        class_bases,
        ..
    } = object
    else {
        return None;
    };

    if let Some(method) = find_class_attr(class_attrs, class_bases, name) {
        return Some(bind_method(method, object.clone()));
    }

    if let Some(method) = array_array_bound_method(object.clone(), name) {
        return Some(method);
    }

    if let Some(method) = set_abc_mixin_method(class_bases, object.clone(), name) {
        return Some(method);
    }

    if let Some(method) = mutable_set_abc_mixin_method(class_bases, object.clone(), name) {
        return Some(method);
    }

    collections_abc_mixin_method_from_bases(class_bases, name).map(|method| Value::BoundMethod {
        function: Box::new(Value::Builtin(method.to_string())),
        receiver: Box::new(object.clone()),
        identity: Rc::new(()),
    })
}

fn context_manager_method_name(is_exit: bool, is_async: bool) -> &'static str {
    match (is_exit, is_async) {
        (false, false) => "__enter__",
        (true, false) => "__exit__",
        (false, true) => "__aenter__",
        (true, true) => "__aexit__",
    }
}

fn is_awaitable_value(value: &Value) -> bool {
    matches!(
        value,
        Value::Coroutine(_)
            | Value::GeneratorWrapper { .. }
            | Value::AsyncGeneratorNext { .. }
            | Value::AsyncGeneratorThrow { .. }
            | Value::AsyncGeneratorClose(_)
            | Value::AsyncGeneratorAthrowMixin { .. }
            | Value::AsyncGeneratorAcloseMixin { .. }
            | Value::AnextDefault { .. }
    ) || is_generic_awaitable_value(value)
}

fn is_runtime_awaitable_value(value: &Value) -> bool {
    is_awaitable_value(value) || is_iterable_coroutine_generator(value)
}

fn is_iterable_coroutine_generator(value: &Value) -> bool {
    matches!(value, Value::Generator(state) if state.borrow().is_iterable_coroutine)
}

fn types_coroutine_result_value(result: Value) -> Value {
    match &result {
        Value::Coroutine(_) | Value::GeneratorWrapper { .. } => result,
        Value::Generator(state) => {
            if state.borrow().is_iterable_coroutine {
                result
            } else {
                Value::GeneratorWrapper {
                    wrapped: Box::new(result),
                    exact_generator: true,
                    identity: Rc::new(()),
                }
            }
        }
        value if is_generator_abc_value(value) && !is_coroutine_abc_value(value) => {
            Value::GeneratorWrapper {
                wrapped: Box::new(result),
                exact_generator: false,
                identity: Rc::new(()),
            }
        }
        _ => result,
    }
}

fn is_generic_awaitable_value(value: &Value) -> bool {
    instance_special_method(value, "__await__").is_some()
}

fn await_iterator_value(value: Value) -> Result<Value, String> {
    if matches!(value, Value::Coroutine(_)) {
        return Err("__await__() returned a coroutine".to_string());
    }
    if is_iterator_value(&value) {
        return Ok(value);
    }
    Err(format!(
        "__await__() returned non-iterator of type '{}'",
        type_name(&value)
    ))
}

fn generator_wrapper_iter_value(receiver: &Value) -> Result<Value, String> {
    let Value::GeneratorWrapper {
        wrapped,
        exact_generator,
        ..
    } = receiver
    else {
        return Err(format!("{receiver} is not a _GeneratorWrapper"));
    };

    if *exact_generator {
        Ok(wrapped.as_ref().clone())
    } else {
        Ok(receiver.clone())
    }
}

fn generator_wrapper_wrapped(receiver: &Value) -> Result<Value, String> {
    let Value::GeneratorWrapper { wrapped, .. } = receiver else {
        return Err(format!("{receiver} is not a _GeneratorWrapper"));
    };
    Ok(wrapped.as_ref().clone())
}

fn call_generator_wrapper_await(args: Vec<Value>) -> Result<Value, String> {
    let [receiver] = args.as_slice() else {
        return Err(format!(
            "__await__() expected 0 arguments, got {}",
            args.len().saturating_sub(1)
        ));
    };
    generator_wrapper_iter_value(receiver)
}

fn descriptor_get_owner(args: &[Value]) -> Result<Value, String> {
    descriptor_get_reject_method_wrapper_args("__get__", args, &[])?;

    let object = &args[0];
    let owner = args.get(1).cloned().unwrap_or(Value::None);
    if !matches!(owner, Value::None) {
        return Ok(owner);
    }
    descriptor_owner_from_object(object)
        .ok_or_else(|| "TypeError: __get__(None, None) is invalid".to_string())
}

fn descriptor_get_reject_method_wrapper_args(
    method: &str,
    args: &[Value],
    keywords: &[(String, Value)],
) -> Result<(), String> {
    if !keywords.is_empty() {
        return Err(format!(
            "TypeError: wrapper {method}() takes no keyword arguments"
        ));
    }
    if args.is_empty() {
        return Err(format!(
            "TypeError: {method} expected at least 1 argument, got 0"
        ));
    }
    if args.len() > 2 {
        return Err(format!(
            "TypeError: {method} expected at most 2 arguments, got {}",
            args.len()
        ));
    }
    Ok(())
}

fn descriptor_set_reject_method_wrapper_args(
    method: &str,
    args: &[Value],
    keywords: &[(String, Value)],
) -> Result<(), String> {
    if !keywords.is_empty() {
        return Err(format!(
            "TypeError: wrapper {method}() takes no keyword arguments"
        ));
    }
    if args.len() != 2 {
        return Err(format!(
            "TypeError: {method} expected 2 arguments, got {}",
            args.len()
        ));
    }
    Ok(())
}

fn descriptor_delete_reject_method_wrapper_args(
    method: &str,
    args: &[Value],
    keywords: &[(String, Value)],
) -> Result<(), String> {
    if !keywords.is_empty() {
        return Err(format!(
            "TypeError: wrapper {method}() takes no keyword arguments"
        ));
    }
    if args.len() != 1 {
        return Err(format!(
            "TypeError: expected 1 argument, got {}",
            args.len()
        ));
    }
    Ok(())
}

fn readonly_deque_maxlen_descriptor_error(object: &Value) -> Result<Value, String> {
    if matches!(object, Value::Deque { .. }) {
        return Err(
            "AttributeError: attribute 'maxlen' of 'collections.deque' objects is not writable"
                .to_string(),
        );
    }
    Err(format!(
        "TypeError: descriptor 'maxlen' for 'collections.deque' objects doesn't apply to a '{}' object",
        type_name(object)
    ))
}

fn cell_contents_getset_descriptor_get(object: &Value) -> Result<Value, String> {
    let Value::Cell { name, scope, .. } = object else {
        return Err(cell_contents_getset_descriptor_type_error(object));
    };
    cell_contents(name, scope)
}

fn cell_contents_getset_descriptor_set(object: &Value, value: Value) -> Result<(), String> {
    let Value::Cell { name, scope, .. } = object else {
        return Err(cell_contents_getset_descriptor_type_error(object));
    };
    set_cell_contents(name, scope, value);
    Ok(())
}

fn cell_contents_getset_descriptor_delete(object: &Value) -> Result<(), String> {
    let Value::Cell { name, scope, .. } = object else {
        return Err(cell_contents_getset_descriptor_type_error(object));
    };
    scope.borrow_mut().remove(name);
    Ok(())
}

fn cell_contents_getset_descriptor_type_error(object: &Value) -> String {
    format!(
        "TypeError: descriptor 'cell_contents' for 'cell' objects doesn't apply to a '{}' object",
        type_name(object)
    )
}

fn descriptor_owner_from_object(object: &Value) -> Option<Value> {
    match object {
        Value::None => None,
        Value::Instance {
            class_name,
            class_attrs,
            class_bases,
            ..
        } => Some(instance_type_object(class_name, class_attrs, class_bases)),
        class @ Value::Class { .. } => Some(class_metaclass_value(class)),
        Value::Builtin(_) => Some(Value::Builtin("type".to_string())),
        value => Some(Value::Builtin(type_name(value).to_string())),
    }
}

fn instance_type_object(class_name: &str, class_attrs: &Scope, class_bases: &[Value]) -> Value {
    if class_name == "object" && class_bases.is_empty() && class_attrs.borrow().is_empty() {
        return builtin_type_value("object");
    }

    Value::Class {
        name: class_name.to_string(),
        type_params: Vec::new(),
        metaclass: None,
        bases: class_bases.to_vec(),
        attrs: class_attrs.clone(),
    }
}

fn type_object_for_value(value: &Value) -> Value {
    match value {
        Value::Instance {
            class_name,
            class_attrs,
            class_bases,
            ..
        } => instance_type_object(class_name, class_attrs, class_bases),
        Value::Exception {
            type_name,
            type_object,
            ..
        } => type_object
            .as_deref()
            .cloned()
            .unwrap_or_else(|| Value::Builtin(type_name.clone())),
        Value::AstNode { kind, .. } if kind == "Interpolation" => {
            Value::Builtin("ast.Interpolation".to_string())
        }
        Value::Cell { .. } => Value::Builtin("CellType".to_string()),
        Value::Frame { .. } => Value::Builtin("frame".to_string()),
        Value::FrameLocalsProxy { .. } => Value::Builtin("FrameLocalsProxy".to_string()),
        Value::SimpleNamespace { .. } => Value::Builtin("SimpleNamespace".to_string()),
        Value::BytesIO(_) => Value::Builtin("io.BytesIO".to_string()),
        Value::WeakRef { .. } => builtin_type_value("weakref.ReferenceType"),
        Value::WeakProxy { callable, .. } => {
            if *callable {
                builtin_type_value("weakref.CallableProxyType")
            } else {
                builtin_type_value("weakref.ProxyType")
            }
        }
        Value::NamedTuple { typ, .. } => Value::NamedTupleType(typ.clone()),
        Value::NamedTupleType(_) => Value::Builtin("type".to_string()),
        Value::TypeParam { kind, .. } => Value::Builtin(format!("typing.{kind}")),
        Value::ForwardRef { .. } => Value::Builtin("typing.ForwardRef".to_string()),
        Value::NewType { .. } => Value::Builtin("typing.NewType".to_string()),
        Value::ConstEvaluator { .. } => Value::Builtin(CONST_EVALUATOR_TYPE_NAME.to_string()),
        value @ Value::GenericAlias { .. } if is_union_alias(value) => {
            Value::Builtin("UnionType".to_string())
        }
        Value::FunctoolsPlaceholder => Value::Builtin("functools._PlaceholderType".to_string()),
        class @ Value::Class { .. } => class_metaclass_value(class),
        Value::Builtin(name) if is_builtin_type_object_name(name) => {
            Value::Builtin("type".to_string())
        }
        Value::Iterator(state) => Value::Builtin(iterator_type_name(&state.borrow()).to_string()),
        value => Value::Builtin(type_name(value).to_string()),
    }
}

fn class_metaclass_value(class: &Value) -> Value {
    match class {
        Value::Class {
            metaclass: Some(metaclass),
            ..
        } => metaclass.as_ref().clone(),
        _ => Value::Builtin("type".to_string()),
    }
}

fn metaclass_classinfo_check_method(classinfo: &Value, method_name: &str) -> Option<Value> {
    metaclass_special_method(classinfo, method_name)
}

fn metaclass_special_method(value: &Value, method_name: &str) -> Option<Value> {
    let metaclass = class_metaclass_value(value);
    let Value::Class { attrs, bases, .. } = metaclass else {
        return None;
    };
    find_class_attr(&attrs, &bases, method_name).map(|method| match method {
        Value::StaticMethod { function, .. } => *function,
        Value::ClassMethod { function, .. } => Value::BoundMethod {
            function,
            receiver: Box::new(value.clone()),
            identity: Rc::new(()),
        },
        method => bind_method(method, value.clone()),
    })
}

