                | "method"
                | "module"
                | "traceback"
                | "weakref.ReferenceType"
                | "weakref.ProxyType"
                | "weakref.CallableProxyType"
                | "generator"
                | "_GeneratorWrapper"
                | "coroutine"
                | "coroutine_wrapper"
                | "await_iterator"
                | "async_generator"
                | "async_generator_asend"
                | "async_generator_athrow"
                | "anext_awaitable"
                | "range_iterator"
                | "list_iterator"
                | "tuple_iterator"
                | "str_iterator"
                | "str_ascii_iterator"
                | "bytes_iterator"
                | "arrayiterator"
                | "set_iterator"
                | "dict_keyiterator"
                | "dict_valueiterator"
                | "dict_itemiterator"
                | "dict_reversekeyiterator"
                | "dict_reversevalueiterator"
                | "dict_reverseitemiterator"
                | "list_reverseiterator"
                | "reversed"
                | "enumerate"
                | "zip"
                | "map"
                | "filter"
                | "callable_iterator"
                | "iterator"
                | "dict_keys"
                | "dict_values"
                | "dict_items"
                | "odict_keys"
                | "odict_values"
                | "odict_items"
                | "mappingproxy"
                | "CellType"
                | "PyCapsule"
                | "classmethod_descriptor"
                | "DynamicClassAttribute"
                | "FrameLocalsProxy"
                | "getset_descriptor"
                | "lazy_import"
                | "method_descriptor"
                | "method-wrapper"
                | "wrapper_descriptor"
                | "TypeVar"
                | "TypeVarTuple"
                | "ParamSpec"
                | "ParamSpecArgs"
                | "ParamSpecKwargs"
                | "TypeAliasType"
                | "_typing._ConstEvaluator"
