fn is_dict_view_type_object_name(name: &str) -> bool {
    matches!(
        name,
        "dict_keys" | "dict_values" | "dict_items" | "odict_keys" | "odict_values" | "odict_items"
    )
}

fn dict_view_kind_from_type_object_name(name: &str) -> Option<DictViewKind> {
    match name {
        "dict_keys" | "odict_keys" => Some(DictViewKind::Keys),
        "dict_values" | "odict_values" => Some(DictViewKind::Values),
        "dict_items" | "odict_items" => Some(DictViewKind::Items),
        _ => None,
    }
}

fn dict_view_type_object_base_name(name: &str) -> &'static str {
    match name {
        "odict_keys" => "dict_keys",
        "odict_values" => "dict_values",
        "odict_items" => "dict_items",
        _ => "object",
    }
}

fn dict_view_type_object_direct_subclasses(name: &str) -> &'static [&'static str] {
    match name {
        "dict_keys" => &["odict_keys"],
        "dict_values" => &["odict_values"],
        "dict_items" => &["odict_items"],
        _ => &[],
    }
}

fn dict_view_type_dir_method_names(name: &str) -> &'static [&'static str] {
    let Some(kind) = dict_view_kind_from_type_object_name(name) else {
        return &[];
    };
    if dict_view_is_set_like(kind) {
        &[
            "__and__",
            "__contains__",
            "__eq__",
            "__format__",
            "__ge__",
            "__getstate__",
            "__gt__",
            "__hash__",
            "__iter__",
            "__le__",
            "__len__",
            "__lt__",
            "__ne__",
            "__or__",
            "__rand__",
            "__reduce__",
            "__reduce_ex__",
            "__repr__",
            "__reversed__",
            "__ror__",
            "__rsub__",
            "__rxor__",
            "__sizeof__",
            "__str__",
            "__sub__",
            "__xor__",
            "isdisjoint",
            "mapping",
        ]
    } else {
        &[
            "__eq__",
            "__format__",
            "__ge__",
            "__getstate__",
            "__gt__",
            "__hash__",
            "__iter__",
            "__le__",
            "__len__",
            "__lt__",
            "__ne__",
            "__reduce__",
            "__reduce_ex__",
            "__repr__",
            "__reversed__",
            "__sizeof__",
            "__str__",
            "mapping",
        ]
    }
}

fn is_dict_view_type_method(name: &str, method: &str) -> bool {
    dict_view_type_dir_method_names(name).contains(&method)
}

fn is_dict_view_set_like_only_method(method: &str) -> bool {
    matches!(
        method,
        "__and__"
            | "__contains__"
            | "__or__"
            | "__rand__"
            | "__ror__"
            | "__rsub__"
            | "__rxor__"
            | "__sub__"
            | "__xor__"
            | "isdisjoint"
    )
}

fn is_data_descriptor(value: &Value) -> bool {
    matches!(
        value,
        Value::Property { .. } | Value::MemberDescriptor { .. }
    ) || instance_special_method(value, "__set__").is_some()
        || instance_special_method(value, "__delete__").is_some()
}

const CELL_CONTENTS_GETSET_DESCRIPTOR: &str = "CellType.cell_contents.getset_descriptor";

fn dict_view_mapping_getset_descriptor_owner(name: &str) -> Option<&str> {
    let owner = name.strip_suffix(".mapping.getset_descriptor")?;
    is_dict_view_type_object_name(owner).then_some(owner)
}

fn is_builtin_getset_descriptor_name(name: &str) -> bool {
    matches!(
        name,
        "deque.maxlen.getset_descriptor" | CELL_CONTENTS_GETSET_DESCRIPTOR
    ) || dict_view_mapping_getset_descriptor_owner(name).is_some()
}

fn getset_descriptor_public_name(name: &str) -> String {
    if dict_view_mapping_getset_descriptor_owner(name).is_some() {
        return "mapping".to_string();
    }
    match name {
        "deque.maxlen.getset_descriptor" => "maxlen".to_string(),
        CELL_CONTENTS_GETSET_DESCRIPTOR => "cell_contents".to_string(),
        _ => unreachable!("builtin getset descriptor guard checked the descriptor name"),
    }
}

fn getset_descriptor_qualname(name: &str) -> String {
    if let Some(owner) = dict_view_mapping_getset_descriptor_owner(name) {
        return format!("{owner}.mapping");
    }
    match name {
        "deque.maxlen.getset_descriptor" => "deque.maxlen".to_string(),
        CELL_CONTENTS_GETSET_DESCRIPTOR => "cell.cell_contents".to_string(),
        _ => unreachable!("builtin getset descriptor guard checked the descriptor name"),
    }
}

fn getset_descriptor_owner_name(name: &str) -> String {
    if let Some(owner) = dict_view_mapping_getset_descriptor_owner(name) {
        return owner.to_string();
    }
    match name {
        "deque.maxlen.getset_descriptor" => "deque".to_string(),
        CELL_CONTENTS_GETSET_DESCRIPTOR => "CellType".to_string(),
        _ => unreachable!("builtin getset descriptor guard checked the descriptor name"),
    }
}

fn getset_descriptor_doc_value(name: &str) -> Value {
    if dict_view_mapping_getset_descriptor_owner(name).is_some() {
        return Value::String("dictionary that this view refers to".to_string());
    }
    match name {
        "deque.maxlen.getset_descriptor" => {
            Value::String("maximum size of a deque or None if unbounded".to_string())
        }
        CELL_CONTENTS_GETSET_DESCRIPTOR => Value::None,
        _ => unreachable!("builtin getset descriptor guard checked the descriptor name"),
    }
}

fn is_iterator_value(value: &Value) -> bool {
    matches!(
        value,
        Value::Iterator(_)
            | Value::Generator(_)
            | Value::GeneratorWrapper { .. }
            | Value::CoroutineAwait(_)
            | Value::AwaitIterator(_)
            | Value::RangeIterator { .. }
            | Value::ListIterator { .. }
            | Value::TupleIterator { .. }
            | Value::TemplateIterator { .. }
            | Value::StringIterator { .. }
            | Value::BytesIterator { .. }
            | Value::ByteArrayIterator { .. }
            | Value::ArrayIterator { .. }
            | Value::SetIterator { .. }
            | Value::DictIterator { .. }
            | Value::ReverseIterator { .. }
            | Value::DictReverseIterator { .. }
            | Value::EnumerateIterator { .. }
            | Value::ZipIterator { .. }
            | Value::MapIterator { .. }
            | Value::FilterIterator { .. }
            | Value::CallIterator { .. }
            | Value::SequenceIterator { .. }
            | Value::SequenceReverseIterator { .. }
    ) || instance_special_method(value, "__next__").is_some()
}

fn is_iterator_abc_value(value: &Value) -> bool {
    if instance_class_explicitly_inherits_builtin(value, "Iterator") {
        return true;
    }
    if instance_special_method_is_none(value, "__iter__")
        || instance_special_method_is_none(value, "__next__")
    {
        return false;
    }

    matches!(
        value,
        Value::Iterator(_)
            | Value::Generator(_)
            | Value::GeneratorWrapper { .. }
            | Value::RangeIterator { .. }
            | Value::ListIterator { .. }
            | Value::TupleIterator { .. }
            | Value::TemplateIterator { .. }
            | Value::StringIterator { .. }
            | Value::BytesIterator { .. }
            | Value::ByteArrayIterator { .. }
            | Value::ArrayIterator { .. }
            | Value::SetIterator { .. }
            | Value::DictIterator { .. }
            | Value::ReverseIterator { .. }
            | Value::DictReverseIterator { .. }
            | Value::EnumerateIterator { .. }
            | Value::ZipIterator { .. }
            | Value::MapIterator { .. }
            | Value::FilterIterator { .. }
            | Value::CallIterator { .. }
            | Value::SequenceIterator { .. }
            | Value::SequenceReverseIterator { .. }
    ) || instance_abc_bases_include(value, "Iterator")
        || (instance_has_callable_special_method(value, "__iter__")
            && instance_has_callable_special_method(value, "__next__"))
}

fn is_generator_abc_value(value: &Value) -> bool {
    if instance_class_explicitly_inherits_builtin(value, "Generator") {
        return true;
    }
    if instance_special_method_is_none(value, "__iter__")
        || instance_special_method_is_none(value, "__next__")
        || instance_special_method_is_none(value, "send")
        || instance_special_method_is_none(value, "throw")
        || instance_special_method_is_none(value, "close")
    {
        return false;
    }

    matches!(value, Value::Generator(_) | Value::GeneratorWrapper { .. })
        || instance_abc_bases_include(value, "Generator")
        || (instance_has_callable_special_method(value, "__iter__")
            && instance_has_callable_special_method(value, "__next__")
            && instance_has_callable_special_method(value, "send")
            && instance_has_callable_special_method(value, "throw")
            && instance_has_callable_special_method(value, "close"))
}

fn is_iterable_abc_value(value: &Value) -> bool {
    if instance_class_explicitly_inherits_builtin(value, "Iterable") {
        return true;
    }
    if instance_special_method_is_none(value, "__iter__") {
        return false;
    }

    is_iterator_abc_value(value)
        || matches!(
            value,
            Value::String(_)
                | Value::Bytes(_)
                | Value::ByteArray(_)
                | Value::MemoryView(_)
                | Value::List(_)
                | Value::Tuple(_)
                | Value::Set(_)
                | Value::FrozenSet(_)
                | Value::Dict(_)
                | Value::OrderedDict(_)
                | Value::ScopeDict(_)
                | Value::DictView { .. }
                | Value::MappingView { .. }
                | Value::MappingProxy { .. }
                | Value::ChainMap { .. }
                | Value::Deque { .. }
                | Value::Range { .. }
                | Value::Template { .. }
        )
        || list_subclass_storage(value).is_some()
        || instance_abc_bases_include(value, "Iterable")
        || instance_has_callable_special_method(value, "__iter__")
}

fn is_reversible_abc_value(value: &Value) -> bool {
    if instance_class_explicitly_inherits_builtin(value, "Reversible") {
        return true;
    }
    if instance_special_method_is_none(value, "__iter__")
        || instance_special_method_is_none(value, "__reversed__")
    {
        return false;
    }

    matches!(
        value,
        Value::String(_)
            | Value::Bytes(_)
            | Value::ByteArray(_)
            | Value::MemoryView(_)
            | Value::List(_)
            | Value::Tuple(_)
            | Value::Dict(_)
            | Value::OrderedDict(_)
            | Value::Counter { .. }
            | Value::ScopeDict(_)
            | Value::DictView { .. }
            | Value::MappingView { .. }
            | Value::MappingProxy { .. }
            | Value::Deque { .. }
            | Value::Range { .. }
    ) || list_subclass_storage(value).is_some()
        || instance_abc_bases_include(value, "Reversible")
        || (instance_has_callable_special_method(value, "__iter__")
            && instance_has_callable_special_method(value, "__reversed__"))
}

fn is_sequence_abc_value(value: &Value) -> bool {
    matches!(
        value,
        Value::String(_)
            | Value::Bytes(_)
            | Value::ByteArray(_)
            | Value::MemoryView(_)
            | Value::List(_)
            | Value::Deque { .. }
            | Value::Tuple(_)
            | Value::Range { .. }
    ) || list_subclass_storage(value).is_some()
        || instance_abc_bases_include(value, "Sequence")
}

fn is_mutable_sequence_abc_value(value: &Value) -> bool {
    matches!(
        value,
        Value::List(_) | Value::ByteArray(_) | Value::Deque { .. }
    ) || list_subclass_storage(value).is_some()
        || bytearray_subclass_storage(value).is_some()
        || array_array_storage(value).is_some()
        || instance_abc_bases_include(value, "MutableSequence")
}

fn is_byte_string_abc_value(value: &Value) -> bool {
    matches!(value, Value::Bytes(_) | Value::ByteArray(_))
        || instance_abc_bases_include(value, "ByteString")
}

fn is_buffer_abc_value(value: &Value) -> bool {
    if instance_class_explicitly_inherits_builtin(value, "Buffer") {
        return true;
    }
    if instance_special_method_is_none(value, "__buffer__") {
        return false;
    }

    matches!(
        value,
        Value::Bytes(_) | Value::ByteArray(_) | Value::MemoryView(_)
    ) || instance_abc_bases_include(value, "Buffer")
        || instance_has_callable_special_method(value, "__buffer__")
}

fn is_mapping_view_abc_value(value: &Value) -> bool {
    matches!(value, Value::DictView { .. } | Value::MappingView { .. })
        || instance_abc_bases_include(value, "MappingView")
}

fn is_mapping_abc_value(value: &Value) -> bool {
    matches!(
        value,
        Value::Dict(_)
            | Value::OrderedDict(_)
            | Value::ScopeDict(_)
            | Value::FrameLocalsProxy { .. }
            | Value::MappingProxy { .. }
            | Value::MappingProxyObject { .. }
            | Value::ChainMap { .. }
            | Value::Counter { .. }
            | Value::UserDict { .. }
    ) || counter_subclass_entries(value).is_some()
        || dict_subclass_entries(value).is_some()
        || user_dict_subclass_data(value).is_some()
        || chain_map_subclass_maps(value).is_some()
        || instance_abc_bases_include(value, "Mapping")
}

fn is_mapping_proxy_source(value: &Value) -> bool {
    is_mapping_abc_value(value) || instance_special_method(value, "__getitem__").is_some()
}

fn is_mapping_proxy_value(value: &Value) -> bool {
    matches!(
        value,
        Value::MappingProxy { .. } | Value::MappingProxyObject { .. }
    )
}

