fn install_int_enum_members(class_value: &Value) -> Result<(), String> {
    let Value::Class {
        name, bases, attrs, ..
    } = class_value
    else {
        return Ok(());
    };
    if !class_bases_include_builtin(bases, "enum.IntEnum") {
        return Ok(());
    }

    let candidates = scope_dict_entries(attrs)
        .into_iter()
        .filter_map(|(member_name, value)| {
            let Some(member_name) = value_as_string(&member_name).map(str::to_string) else {
                return None;
            };
            if !is_int_enum_member_name(&member_name) {
                return None;
            }
            int_enum_member_storage(&value).map(|storage| (member_name, storage))
        })
        .collect::<Vec<_>>();

    let mut canonical_members: Vec<(Value, Value)> = Vec::new();
    let mut member_entries = Vec::new();
    for (member_name, storage) in candidates {
        let member = canonical_members
            .iter()
            .find(|(existing_storage, _)| existing_storage == &storage)
            .map(|(_, member)| member.clone())
            .unwrap_or_else(|| {
                let member =
                    int_enum_member_value(name, attrs, bases, member_name.clone(), storage.clone());
                canonical_members.push((storage.clone(), member.clone()));
                member
            });
        attrs
            .borrow_mut()
            .insert(member_name.clone(), member.clone());
        member_entries.push((Value::String(member_name), member));
    }

    if !member_entries.is_empty() {
        attrs.borrow_mut().insert(
            "__members__".to_string(),
            mapping_proxy_value(Rc::new(RefCell::new(DictStorage::new(member_entries)))),
        );
    }
    Ok(())
}

fn is_int_enum_member_name(name: &str) -> bool {
    !name.starts_with('_') && !name.starts_with('\0')
}

fn int_enum_member_storage(value: &Value) -> Option<Value> {
    if let Some(value) = int_subclass_integer(value) {
        return Some(value);
    }
    match numeric_bool_value(value.clone()) {
        value @ (Value::Number(_) | Value::BigInt(_)) => Some(value),
        _ => None,
    }
}

fn int_enum_member_repr(class_name: &str, fields: &Scope) -> Option<String> {
    let fields_ref = fields.borrow();
    let member_name = match fields_ref.get(INT_ENUM_MEMBER_NAME_FIELD)? {
        Value::String(value) | Value::IdentityString { value, .. } => value.clone(),
        _ => return None,
    };
    let value = fields_ref.get(INT_ENUM_MEMBER_VALUE_FIELD).cloned()?;
    Some(format!(
        "<{class_name}.{member_name}: {}>",
        repr_value(&value)
    ))
}

fn int_enum_member_value(
    class_name: &str,
    class_attrs: &Scope,
    class_bases: &[Value],
    member_name: String,
    storage: Value,
) -> Value {
    let fields = new_scope();
    {
        let mut fields = fields.borrow_mut();
        fields.insert(INT_SUBCLASS_STORAGE_FIELD.to_string(), storage.clone());
        fields.insert(
            INT_ENUM_MEMBER_NAME_FIELD.to_string(),
            Value::String(member_name.clone()),
        );
        fields.insert(INT_ENUM_MEMBER_VALUE_FIELD.to_string(), storage.clone());
        fields.insert("name".to_string(), Value::String(member_name));
        fields.insert("value".to_string(), storage);
    }

    Value::Instance {
        class_name: class_name.to_string(),
        fields,
        class_attrs: class_attrs.clone(),
        class_bases: class_bases.to_vec(),
    }
}

fn install_str_enum_members(class_value: &Value) -> Result<(), String> {
    let Value::Class {
        name, bases, attrs, ..
    } = class_value
    else {
        return Ok(());
    };
    if !class_bases_include_builtin(bases, "enum.StrEnum") {
        return Ok(());
    }

    let mut candidates = Vec::new();
    for (member_name, value) in scope_dict_entries(attrs) {
        let Some(member_name) = value_as_string(&member_name).map(str::to_string) else {
            continue;
        };
        if !is_int_enum_member_name(&member_name) {
            continue;
        }
        if let Some(storage) = str_enum_candidate_storage(&value) {
            candidates.push((member_name, storage));
            continue;
        }
        if str_enum_nonmember_descriptor(&value) {
            continue;
        }
        return Err(format!("TypeError: {} is not a string", repr_value(&value)));
    }

    let mut canonical_members: Vec<(Value, Value)> = Vec::new();
    let mut member_entries = Vec::new();
    for (member_name, storage) in candidates {
        let member = canonical_members
            .iter()
            .find(|(existing_storage, _)| existing_storage == &storage)
            .map(|(_, member)| member.clone())
            .unwrap_or_else(|| {
                let member =
                    str_enum_member_value(name, attrs, bases, member_name.clone(), storage.clone());
                canonical_members.push((storage.clone(), member.clone()));
                member
            });
        attrs
            .borrow_mut()
            .insert(member_name.clone(), member.clone());
        member_entries.push((Value::String(member_name), member));
    }

    if !member_entries.is_empty() {
        attrs.borrow_mut().insert(
            "__members__".to_string(),
            mapping_proxy_value(Rc::new(RefCell::new(DictStorage::new(member_entries)))),
        );
    }
    Ok(())
}

fn str_enum_candidate_storage(value: &Value) -> Option<Value> {
    match value {
        Value::String(value) | Value::IdentityString { value, .. } => {
            Some(Value::String(value.clone()))
        }
        value if str_subclass_string(value).is_some() => Some(Value::String(
            str_subclass_string(value).expect("str subclass storage exists after guard"),
        )),
        _ => None,
    }
}

fn str_enum_nonmember_descriptor(value: &Value) -> bool {
    matches!(
        value,
        Value::Function { .. }
            | Value::TypesCoroutineFunction { .. }
            | Value::StaticMethod { .. }
            | Value::ClassMethod { .. }
            | Value::Property { .. }
            | Value::CachedProperty { .. }
    )
}

fn str_enum_lookup_storage(value: &Value) -> Option<Value> {
    str_enum_member_storage(value).or_else(|| str_enum_candidate_storage(value))
}

fn str_enum_member_storage(value: &Value) -> Option<Value> {
    let Value::Instance { fields, .. } = value else {
        return None;
    };
    match fields.borrow().get(STR_ENUM_MEMBER_VALUE_FIELD).cloned() {
        Some(Value::String(value)) => Some(Value::String(value)),
        _ => None,
    }
}

fn str_enum_member_repr(class_name: &str, fields: &Scope) -> Option<String> {
    let fields_ref = fields.borrow();
    let member_name = match fields_ref.get(STR_ENUM_MEMBER_NAME_FIELD)? {
        Value::String(value) | Value::IdentityString { value, .. } => value.clone(),
        _ => return None,
    };
    let value = fields_ref.get(STR_ENUM_MEMBER_VALUE_FIELD).cloned()?;
    Some(format!(
        "<{class_name}.{member_name}: {}>",
        repr_value(&value)
    ))
}

fn str_enum_member_value(
    class_name: &str,
    class_attrs: &Scope,
    class_bases: &[Value],
    member_name: String,
    storage: Value,
) -> Value {
    let fields = new_scope();
    {
        let mut fields = fields.borrow_mut();
        fields.insert(STR_SUBCLASS_STORAGE_FIELD.to_string(), storage.clone());
        fields.insert(
            STR_ENUM_MEMBER_NAME_FIELD.to_string(),
            Value::String(member_name.clone()),
        );
        fields.insert(STR_ENUM_MEMBER_VALUE_FIELD.to_string(), storage.clone());
        fields.insert("name".to_string(), Value::String(member_name));
        fields.insert("value".to_string(), storage);
    }

    Value::Instance {
        class_name: class_name.to_string(),
        fields,
        class_attrs: class_attrs.clone(),
        class_bases: class_bases.to_vec(),
    }
}

fn int_subclass_attribute(value: Value, name: &str) -> Option<Value> {
    let storage = int_subclass_integer(&value)?;
    match name {
        "bit_length" | "bit_count" | "conjugate" | "as_integer_ratio" | "to_bytes"
        | "__format__" | "__hash__" | "__eq__" | "__ne__" | "__lt__" | "__le__" | "__gt__"
        | "__ge__" => Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("int.{name}"))),
            receiver: Box::new(storage),
            identity: Rc::new(()),
        }),
        "numerator" | "real" => Some(storage),
        "denominator" => Some(Value::Number(1)),
        "imag" => Some(Value::Number(0)),
        _ => None,
    }
}

