fn float_subclass_float(value: &Value) -> Option<Rc<f64>> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "float") {
        return None;
    }
    match fields.borrow().get(FLOAT_SUBCLASS_STORAGE_FIELD).cloned() {
        Some(Value::Float(value)) => Some(value),
        _ => None,
    }
}

fn float_subclass_value(value: &Value) -> Option<Value> {
    float_subclass_float(value).map(Value::Float)
}

fn float_protocol_result(receiver: &Value, result: Value) -> Result<Value, String> {
    if let Some(value) = float_subclass_value(&result) {
        return Ok(value);
    }
    match result {
        Value::Float(value) => Ok(Value::Float(value)),
        result => Err(format!(
            "TypeError: {}.__float__ returned non-float (type {})",
            type_name(receiver),
            type_name(&result)
        )),
    }
}

fn float_protocol_result_f64(receiver: &Value, result: Value) -> Result<f64, String> {
    match float_protocol_result(receiver, result)? {
        Value::Float(value) => Ok(*value),
        _ => unreachable!("float_protocol_result returns a float"),
    }
}

fn float_subclass_attribute(value: Value, name: &str) -> Option<Value> {
    let storage = float_subclass_value(&value)?;
    if name == "__hash__" {
        return Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("float.__hash__".to_string())),
            receiver: Box::new(value),
            identity: Rc::new(()),
        });
    }
    if name == "__getformat__" {
        return Some(Value::Builtin("float.__getformat__".to_string()));
    }
    match name {
        "conjugate" | "is_integer" | "as_integer_ratio" | "__ceil__" | "__floor__"
        | "__format__" | "__round__" | "hex" => Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("float.{name}"))),
            receiver: Box::new(storage),
            identity: Rc::new(()),
        }),
        "from_number" => {
            let Value::Instance {
                class_name,
                class_attrs,
                class_bases,
                ..
            } = value
            else {
                return None;
            };
            Some(Value::BoundMethod {
                function: Box::new(Value::Builtin("float.from_number.classmethod".to_string())),
                receiver: Box::new(instance_type_object(
                    &class_name,
                    &class_attrs,
                    &class_bases,
                )),
                identity: Rc::new(()),
            })
        }
        "real" => Some(storage),
        "imag" => Some(float_value(0.0)),
        _ => None,
    }
}

fn float_subclass_class_attribute(class: Value, name: &str) -> Option<Value> {
    let Value::Class { bases, .. } = &class else {
        return None;
    };
    if !class_bases_include_builtin(bases, "float") {
        return None;
    }
    match name {
        "__getformat__" => Some(Value::Builtin("float.__getformat__".to_string())),
        "from_number" | "fromhex" => Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("float.{name}.classmethod"))),
            receiver: Box::new(class),
            identity: Rc::new(()),
        }),
        "__new__" => Some(Value::Builtin("float.__new__".to_string())),
        "conjugate" | "is_integer" | "as_integer_ratio" | "__ceil__" | "__floor__"
        | "__format__" | "__hash__" | "__round__" | "hex" => {
            Some(Value::Builtin(format!("float.{name}")))
        }
        _ => None,
    }
}

fn complex_subclass_instance(
    name: String,
    attrs: Scope,
    bases: Vec<Value>,
    storage: Value,
) -> Value {
    if !matches!(storage, Value::Complex { .. }) {
        unreachable!("complex constructor always returns a complex value");
    }
    let fields = new_scope();
    fields
        .borrow_mut()
        .insert(COMPLEX_SUBCLASS_STORAGE_FIELD.to_string(), storage);
    Value::Instance {
        class_name: name,
        fields,
        class_attrs: attrs,
        class_bases: bases,
    }
}

fn complex_subclass_parts(value: &Value) -> Option<(f64, f64)> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "complex") {
        return None;
    }
    match fields.borrow().get(COMPLEX_SUBCLASS_STORAGE_FIELD).cloned() {
        Some(Value::Complex { real, imag, .. }) => Some((real, imag)),
        _ => None,
    }
}

fn complex_subclass_value(value: &Value) -> Option<Value> {
    complex_subclass_parts(value).map(|(real, imag)| complex_value(real, imag))
}

struct ComplexParts {
    real: f64,
    imag: f64,
    complex_compatible_type: Option<String>,
    strict_complex_subclass_result_type: Option<String>,
}

impl ComplexParts {
    fn new(real: f64, imag: f64) -> Self {
        Self {
            real,
            imag,
            complex_compatible_type: None,
            strict_complex_subclass_result_type: None,
        }
    }
}

fn complex_compatible_numeric_type(value: &Value) -> Option<String> {
    if matches!(value, Value::Complex { .. }) || complex_subclass_parts(value).is_some() {
        Some(type_name(value).to_string())
    } else {
        None
    }
}

fn complex_protocol_result_parts(_receiver: &Value, result: Value) -> Result<ComplexParts, String> {
    if let Some((real, imag)) = complex_subclass_parts(&result) {
        let mut parts = ComplexParts::new(real, imag);
        parts.strict_complex_subclass_result_type = Some(type_name(&result).to_string());
        return Ok(parts);
    }
    match result {
        Value::Complex { real, imag, .. } => Ok(ComplexParts::new(real, imag)),
        result => Err(format!(
            "TypeError: __complex__ returned non-complex (type {})",
            type_name(&result)
        )),
    }
}

fn complex_subclass_attribute(value: Value, name: &str) -> Option<Value> {
    let storage = complex_subclass_value(&value)?;
    match name {
        "from_number" => {
            let Value::Instance {
                class_name,
                class_attrs,
                class_bases,
                ..
            } = value
            else {
                return None;
            };
            Some(Value::BoundMethod {
                function: Box::new(Value::Builtin(
                    "complex.from_number.classmethod".to_string(),
                )),
                receiver: Box::new(instance_type_object(
                    &class_name,
                    &class_attrs,
                    &class_bases,
                )),
                identity: Rc::new(()),
            })
        }
        "real" => match storage {
            Value::Complex { real, .. } => Some(float_value(real)),
            _ => unreachable!("complex_subclass_value returns a complex"),
        },
        "imag" => match storage {
            Value::Complex { imag, .. } => Some(float_value(imag)),
            _ => unreachable!("complex_subclass_value returns a complex"),
        },
        name if is_builtin_complex_type_method(name) => Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("complex.{name}"))),
            receiver: Box::new(storage),
            identity: Rc::new(()),
        }),
        _ => None,
    }
}

fn complex_subclass_class_attribute(class: Value, name: &str) -> Option<Value> {
    let Value::Class { bases, .. } = &class else {
        return None;
    };
    if !class_bases_include_builtin(bases, "complex") {
        return None;
    }
    match name {
        "from_number" => Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(
                "complex.from_number.classmethod".to_string(),
            )),
            receiver: Box::new(class),
            identity: Rc::new(()),
        }),
        "__new__" => Some(Value::Builtin("complex.__new__".to_string())),
        name if is_builtin_complex_type_method(name) => {
            Some(Value::Builtin(format!("complex.{name}")))
        }
        _ => None,
    }
}

fn bytes_subclass_bytes(value: &Value) -> Option<Vec<u8>> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "bytes") {
        return None;
    }
    match fields.borrow().get(BYTES_SUBCLASS_STORAGE_FIELD).cloned() {
        Some(Value::Bytes(bytes)) => Some(bytes.as_ref().clone()),
        _ => None,
    }
}

fn bytes_subclass_attribute(receiver: Value, name: &str) -> Option<Value> {
    if bytes_subclass_bytes(&receiver).is_some() && is_immutable_sequence_type_method("bytes", name)
    {
        Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("bytes.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        })
    } else {
        None
    }
}

fn bytearray_subclass_attribute(receiver: Value, name: &str) -> Option<Value> {
    if name == "maketrans" && bytearray_subclass_storage(&receiver).is_some() {
        return Some(Value::Builtin("bytearray.maketrans".to_string()));
    }
    if bytearray_subclass_storage(&receiver).is_some() && is_bytearray_instance_method(name) {
        Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("bytearray.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        })
    } else {
        None
    }
}

fn bytes_subclass_class_attribute(class: Value, name: &str) -> Option<Value> {
    let Value::Class { bases, .. } = &class else {
        return None;
    };
    if !class_bases_include_builtin(bases, "bytes") {
        return None;
    }
    match name {
        "fromhex" => Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("bytes.fromhex.classmethod".to_string())),
            receiver: Box::new(class),
            identity: Rc::new(()),
        }),
        "__new__" => Some(Value::Builtin("bytes.__new__".to_string())),
        "__bytes__" => Some(Value::Builtin("bytes.__bytes__".to_string())),
        name if is_immutable_sequence_type_method("bytes", name) => {
            Some(Value::Builtin(format!("bytes.{name}")))
        }
        _ => None,
    }
}

fn bytes_subclass_instance(
    name: String,
    attrs: Scope,
    bases: Vec<Value>,
    storage: Vec<u8>,
) -> Value {
    let fields = new_scope();
    fields.borrow_mut().insert(
        BYTES_SUBCLASS_STORAGE_FIELD.to_string(),
        bytes_value(storage),
    );
    Value::Instance {
        class_name: name,
        fields,
        class_attrs: attrs,
        class_bases: bases,
    }
}

fn bytearray_subclass_storage(value: &Value) -> Option<ByteArrayRef> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "bytearray") {
        return None;
    }
    match fields
        .borrow()
        .get(BYTEARRAY_SUBCLASS_STORAGE_FIELD)
        .cloned()
    {
        Some(Value::ByteArray(bytes)) => Some(bytes),
        _ => None,
    }
}

fn bytearray_subclass_bytes(value: &Value) -> Option<Vec<u8>> {
    bytearray_subclass_storage(value).map(|bytes| bytearray_bytes(&bytes))
}

fn bytearray_subclass_class_attribute(class: Value, name: &str) -> Option<Value> {
    let Value::Class { bases, .. } = &class else {
        return None;
    };
    if !class_bases_include_builtin(bases, "bytearray") {
        return None;
    }
    match name {
        "fromhex" => Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("bytearray.fromhex.classmethod".to_string())),
            receiver: Box::new(class),
            identity: Rc::new(()),
        }),
        "__new__" => Some(Value::Builtin("bytearray.__new__".to_string())),
        "maketrans" => Some(Value::Builtin("bytearray.maketrans".to_string())),
        name if is_bytearray_instance_method(name) => {
            Some(Value::Builtin(format!("bytearray.{name}")))
        }
        _ => None,
    }
}

fn bytearray_subclass_instance(
    name: String,
    attrs: Scope,
    bases: Vec<Value>,
    storage: Vec<u8>,
) -> Value {
    let fields = new_scope();
    fields.borrow_mut().insert(
        BYTEARRAY_SUBCLASS_STORAGE_FIELD.to_string(),
        byte_array_value(storage),
    );
    Value::Instance {
        class_name: name,
        fields,
        class_attrs: attrs,
        class_bases: bases,
    }
}

fn bytes_base_value_bytes(value: &Value) -> Option<(Vec<u8>, BytesResultKind)> {
    match value {
        Value::Bytes(bytes) => Some((bytes.as_ref().clone(), BytesResultKind::Bytes)),
        Value::ByteArray(bytes) => Some((bytearray_bytes(bytes), BytesResultKind::ByteArray)),
        value => bytes_subclass_bytes(value)
            .map(|bytes| (bytes, BytesResultKind::Bytes))
            .or_else(|| {
                bytearray_subclass_bytes(value).map(|bytes| (bytes, BytesResultKind::ByteArray))
            }),
    }
}

fn bytearray_subclass_repr(value: &Value) -> Option<String> {
    let Value::Instance { class_name, .. } = value else {
        return None;
    };
    let bytes = bytearray_subclass_storage(value)?;
    Some(format!(
        "{class_name}({})",
        repr_bytearray_bytes(&bytes.borrow())
    ))
}

fn array_array_instance(typecode: Option<&str>, storage: Option<Vec<u8>>) -> Value {
    let fields = new_scope();
    if let Some(typecode) = typecode {
        fields.borrow_mut().insert(
            ARRAY_ARRAY_TYPECODE_FIELD.to_string(),
            Value::String(typecode.to_string()),
        );
    }
    if let Some(storage) = storage {
        fields.borrow_mut().insert(
            ARRAY_ARRAY_STORAGE_FIELD.to_string(),
            byte_array_value(storage),
        );
    }
    Value::Instance {
        class_name: "array".to_string(),
        fields,
        class_attrs: new_scope(),
        class_bases: vec![Value::Builtin("array.array".to_string())],
    }
}

fn array_array_subclass_instance(
    name: String,
    attrs: Scope,
    bases: Vec<Value>,
    typecode: &str,
    storage: Vec<u8>,
) -> Value {
    let fields = new_scope();
    fields.borrow_mut().insert(
        ARRAY_ARRAY_TYPECODE_FIELD.to_string(),
        Value::String(typecode.to_string()),
    );
    fields.borrow_mut().insert(
        ARRAY_ARRAY_STORAGE_FIELD.to_string(),
        byte_array_value(storage),
    );
    Value::Instance {
        class_name: name,
        fields,
        class_attrs: attrs,
        class_bases: bases,
    }
}

fn array_array_typecode_argument_type_name(value: &Value) -> String {
    match value {
        Value::None => "None".to_string(),
        value => type_name(value).to_string(),
    }
}

fn array_array_typecode(value: &Value) -> Option<String> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "array.array") {
        return None;
    }
    match fields.borrow().get(ARRAY_ARRAY_TYPECODE_FIELD).cloned() {
        Some(Value::String(typecode))
        | Some(Value::IdentityString {
            value: typecode, ..
        }) => Some(typecode),
        _ => None,
    }
}

fn array_array_storage(value: &Value) -> Option<ByteArrayRef> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    if !class_bases_include_builtin(class_bases, "array.array") {
        return None;
    }
    match fields.borrow().get(ARRAY_ARRAY_STORAGE_FIELD).cloned() {
        Some(Value::ByteArray(bytes)) => Some(bytes),
        _ => None,
    }
}

fn is_exact_array_array_instance(value: &Value) -> bool {
    let Value::Instance {
        class_name,
        class_attrs,
        class_bases,
        ..
    } = value
    else {
        return false;
    };
    class_name == "array"
        && class_attrs.borrow().is_empty()
        && matches!(
            class_bases.as_slice(),
            [Value::Builtin(name)] if name == "array.array"
        )
        && array_array_storage(value).is_some()
}

fn array_array_has_storage_field(value: &Value) -> bool {
    let Value::Instance { fields, .. } = value else {
        return false;
    };
    matches!(
        fields.borrow().get(ARRAY_ARRAY_STORAGE_FIELD),
        Some(Value::ByteArray(_))
    )
}

fn array_array_bytes(value: &Value) -> Option<Vec<u8>> {
    array_array_storage(value).map(|bytes| bytearray_bytes(&bytes))
}

fn array_array_itemsize_for_typecode(typecode: &str) -> Option<usize> {
    match typecode {
        "B" | "b" => Some(1),
        "h" | "H" => Some(2),
        "i" | "I" => Some(4),
        "l" | "L" => Some(array_array_c_long_itemsize()),
        "q" | "Q" => Some(8),
        "f" => Some(4),
        "d" => Some(8),
        "u" | "w" => Some(4),
        _ => None,
    }
}

fn array_array_c_long_itemsize() -> usize {
    if cfg!(windows) || cfg!(target_pointer_width = "32") {
        4
    } else {
        8
    }
}

fn array_array_itemsize(value: &Value) -> Option<usize> {
    let typecode = array_array_typecode(value).unwrap_or_else(|| "B".to_string());
    array_array_itemsize_for_typecode(&typecode)
}

fn array_array_validate_raw_bytes(typecode: &str, bytes: Vec<u8>) -> Result<Vec<u8>, String> {
    let itemsize = array_array_itemsize_for_typecode(typecode)
        .ok_or_else(|| "TypeError: unsupported array typecode".to_string())?;
    if bytes.len() % itemsize != 0 {
        return Err("ValueError: bytes length not a multiple of item size".to_string());
    }
    Ok(bytes)
}

fn array_array_unicode_text_bytes(text: &str) -> Vec<u8> {
    let mut bytes = Vec::with_capacity(text.chars().count() * 4);
    for ch in text.chars() {
        bytes.extend((ch as u32).to_ne_bytes());
    }
    bytes
}

fn array_array_unicode_string(value: &Value) -> Result<String, String> {
    let bytes = array_array_bytes(value)
        .ok_or_else(|| "tounicode() expected an array receiver".to_string())?;
    array_array_unicode_string_from_bytes(&bytes)
}

fn array_array_unicode_string_from_bytes(bytes: &[u8]) -> Result<String, String> {
    let mut text = String::new();
    for chunk in bytes.chunks_exact(4) {
        let codepoint = u32::from_ne_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]);
        let Some(ch) = char::from_u32(codepoint) else {
            return Err("ValueError: chr() arg not in range(0x110000)".to_string());
        };
        text.push(ch);
    }
    Ok(text)
}

fn array_array_decode_item(typecode: &str, bytes: &[u8]) -> Value {
    match typecode {
        "b" => Value::Number(i64::from(bytes[0] as i8)),
        "h" => Value::Number(i64::from(i16::from_ne_bytes([bytes[0], bytes[1]]))),
        "H" => Value::Number(i64::from(u16::from_ne_bytes([bytes[0], bytes[1]]))),
        "i" => Value::Number(i64::from(i32::from_ne_bytes([
            bytes[0], bytes[1], bytes[2], bytes[3],
        ]))),
        "I" => Value::Number(i64::from(u32::from_ne_bytes([
            bytes[0], bytes[1], bytes[2], bytes[3],
        ]))),
        "l" if array_array_c_long_itemsize() == 4 => {
            Value::Number(i64::from(i32::from_ne_bytes([
                bytes[0], bytes[1], bytes[2], bytes[3],
            ])))
        }
        "l" => Value::Number(i64::from_ne_bytes([
            bytes[0], bytes[1], bytes[2], bytes[3], bytes[4], bytes[5], bytes[6], bytes[7],
        ])),
        "L" if array_array_c_long_itemsize() == 4 => {
            Value::Number(i64::from(u32::from_ne_bytes([
                bytes[0], bytes[1], bytes[2], bytes[3],
            ])))
        }
        "L" => normalize_big_int(BigInt::from(u64::from_ne_bytes([
            bytes[0], bytes[1], bytes[2], bytes[3], bytes[4], bytes[5], bytes[6], bytes[7],
        ]))),
        "q" => Value::Number(i64::from_ne_bytes([
            bytes[0], bytes[1], bytes[2], bytes[3], bytes[4], bytes[5], bytes[6], bytes[7],
        ])),
        "Q" => normalize_big_int(BigInt::from(u64::from_ne_bytes([
            bytes[0], bytes[1], bytes[2], bytes[3], bytes[4], bytes[5], bytes[6], bytes[7],
        ]))),
        "f" => float_value(f64::from(f32::from_ne_bytes([
            bytes[0], bytes[1], bytes[2], bytes[3],
        ]))),
        "d" => float_value(f64::from_ne_bytes([
            bytes[0], bytes[1], bytes[2], bytes[3], bytes[4], bytes[5], bytes[6], bytes[7],
        ])),
        "u" | "w" => char::from_u32(u32::from_ne_bytes([bytes[0], bytes[1], bytes[2], bytes[3]]))
            .map(|ch| Value::String(ch.to_string()))
            .unwrap_or_else(|| Value::String(String::new())),
        _ => Value::Number(i64::from(bytes[0])),
    }
}

fn array_array_values_from_bytes(typecode: &str, bytes: &[u8]) -> Option<Vec<Value>> {
    let itemsize = array_array_itemsize_for_typecode(typecode)?;
    Some(
        bytes
            .chunks_exact(itemsize)
            .map(|chunk| array_array_decode_item(typecode, chunk))
            .collect(),
    )
}

fn array_array_values(value: &Value) -> Option<Vec<Value>> {
    let typecode = array_array_typecode(value).unwrap_or_else(|| "B".to_string());
    let bytes = array_array_bytes(value)?;
    array_array_values_from_bytes(&typecode, &bytes)
}

fn array_array_len(value: &Value) -> Option<usize> {
    let itemsize = array_array_itemsize(value)?;
    array_array_storage(value).map(|bytes| bytes.borrow().len() / itemsize)
}

fn array_array_item(value: &Value, index: Value) -> Result<Value, String> {
    let typecode = array_array_typecode(value).unwrap_or_else(|| "B".to_string());
    let itemsize = array_array_itemsize_for_typecode(&typecode)
        .ok_or_else(|| "TypeError: unsupported array typecode".to_string())?;
    let bytes = array_array_bytes(value).expect("array storage exists after guard");
    let len = bytes.len() / itemsize;
    let index = normalized_index(index, len, "array")?;
    let start = index
        .checked_mul(itemsize)
        .ok_or_else(|| "array index out of range".to_string())?;
    let end = start + itemsize;
    bytes
        .get(start..end)
        .map(|chunk| array_array_decode_item(&typecode, chunk))
        .ok_or_else(|| "array index out of range".to_string())
}

fn array_array_slice(
    value: Value,
    start: Option<Value>,
    stop: Option<Value>,
    step: Option<Value>,
) -> Result<Value, String> {
    let typecode = array_array_typecode(&value).unwrap_or_else(|| "B".to_string());
    let itemsize = array_array_itemsize_for_typecode(&typecode)
        .ok_or_else(|| "TypeError: unsupported array typecode".to_string())?;
    let bytes = array_array_bytes(&value).expect("array storage exists after guard");
    let len = bytes.len() / itemsize;
    let indices = slice_indices(
        len,
        slice_bound(start)?,
        slice_bound(stop)?,
        slice_bound(step)?,
    )?;
    let mut storage = Vec::with_capacity(indices.len() * itemsize);
    for index in indices {
        let start = index
            .checked_mul(itemsize)
            .ok_or_else(|| "array index out of range".to_string())?;
        storage.extend_from_slice(&bytes[start..start + itemsize]);
    }
    Ok(array_array_instance(Some(&typecode), Some(storage)))
}

fn array_array_slice_assignment_value(typecode: &str, value: &Value) -> Result<Vec<u8>, String> {
    let Some(source_storage) = array_array_storage(value) else {
        return Err(format!(
            "TypeError: can only assign array (not \"{}\") to array slice",
            type_name(value)
        ));
    };
    let source_typecode = array_array_typecode(value).unwrap_or_else(|| "B".to_string());
    if source_typecode != typecode {
        return Err("TypeError: bad argument type for built-in operation".to_string());
    }
    Ok(bytearray_bytes(&source_storage))
}

fn is_array_array_method_name(name: &str) -> bool {
    matches!(
        name,
        "append"
            | "buffer_info"
            | "byteswap"
            | "clear"
            | "count"
            | "extend"
            | "frombytes"
            | "fromfile"
            | "fromlist"
            | "fromunicode"
            | "index"
            | "insert"
            | "pop"
            | "remove"
            | "reverse"
            | "tobytes"
            | "tofile"
            | "tolist"
            | "tounicode"
            | "__add__"
            | "__contains__"
            | "__copy__"
            | "__deepcopy__"
            | "__delitem__"
            | "__eq__"
            | "__ge__"
            | "__getitem__"
            | "__gt__"
            | "__iadd__"
            | "__imul__"
            | "__iter__"
            | "__le__"
            | "__len__"
            | "__lt__"
            | "__mul__"
            | "__ne__"
            | "__reversed__"
            | "__rmul__"
            | "__setitem__"
    )
}

fn array_array_bound_method(receiver: Value, name: &str) -> Option<Value> {
    if !array_array_has_storage_field(&receiver) || !is_array_array_method_name(name) {
        return None;
    }
    Some(Value::BoundMethod {
        function: Box::new(Value::Builtin(format!("array.array.{name}"))),
        receiver: Box::new(receiver),
        identity: Rc::new(()),
    })
}

fn array_array_attribute(receiver: Value, name: &str) -> Result<Option<Value>, String> {
    if !array_array_has_storage_field(&receiver) {
        return Ok(None);
    }

    match name {
        "__class_getitem__" => Ok(Some(class_getitem_bound_method(Value::Builtin(
            "array.array".to_string(),
        )))),
        "typecode" => Ok(Some(Value::String(
            array_array_typecode(&receiver).unwrap_or_else(|| "B".to_string()),
        ))),
        "itemsize" => Ok(Some(Value::Number(
            i64::try_from(
                array_array_itemsize(&receiver)
                    .ok_or_else(|| "TypeError: unsupported array typecode".to_string())?,
            )
            .map_err(|_| "array itemsize is too large".to_string())?,
        ))),
        name if is_array_array_method_name(name) => Ok(array_array_bound_method(receiver, name)),
        _ => Ok(None),
    }
}

fn array_array_subclass_class_attribute(class: Value, name: &str) -> Option<Value> {
    let Value::Class { bases, .. } = &class else {
        return None;
    };
    if !class_bases_include_builtin(bases, "array.array") {
        return None;
    }
    match name {
        "__new__" => Some(Value::Builtin("array.array.__new__".to_string())),
        name if is_array_array_method_name(name) => {
            Some(Value::Builtin(format!("array.array.{name}")))
        }
        _ => None,
    }
}

fn bytes_buffer_value_bytes(value: &Value) -> Result<Option<Vec<u8>>, String> {
    match value {
        Value::MemoryView(view) => memoryview_bytes(view).map(Some),
        value if bytes_base_value_bytes(value).is_some() => Ok(Some(
            bytes_base_value_bytes(value)
                .expect("bytes-like value passed recognizer")
                .0,
        )),
        value => Ok(array_array_bytes(value)),
    }
}

fn namedtuple_subclass_storage(value: &Value) -> Option<(NamedTupleTypeRef, Rc<Vec<Value>>)> {
    let Value::Instance {
        fields,
        class_bases,
        ..
    } = value
    else {
        return None;
    };
    class_bases_namedtuple_type(class_bases)?;
    match fields
        .borrow()
        .get(NAMED_TUPLE_SUBCLASS_STORAGE_FIELD)
        .cloned()
    {
        Some(Value::NamedTuple { typ, values }) => Some((typ, values)),
        _ => None,
    }
}

fn namedtuple_subclass_repr_checked(
    value: &Value,
    active: &mut HashSet<usize>,
) -> Option<Result<String, String>> {
    let Value::Instance { class_name, .. } = value else {
        return None;
    };
    let (typ, values) = namedtuple_subclass_storage(value)?;
    let ptr = Rc::as_ptr(&values) as usize;
    if !active.insert(ptr) {
        return Some(Ok(format!("{class_name}(...)")));
    }

    let rendered = typ
        .fields
        .iter()
        .zip(values.iter())
        .map(|(field, value)| {
            repr_value_inner_checked(value, active).map(|value| format!("{field}={value}"))
        })
        .collect::<Result<Vec<_>, _>>();
    active.remove(&ptr);

    Some(rendered.map(|items| format!("{}({})", class_name, items.join(", "))))
}

fn namedtuple_subclass_repr(value: &Value, active: &mut HashSet<usize>) -> Option<String> {
    let Value::Instance { class_name, .. } = value else {
        return None;
    };
    let (typ, values) = namedtuple_subclass_storage(value)?;
    let ptr = Rc::as_ptr(&values) as usize;
    if !active.insert(ptr) {
        return Some(format!("{class_name}(...)"));
    }

    let rendered = typ
        .fields
        .iter()
        .zip(values.iter())
        .map(|(field, value)| format!("{field}={}", repr_value_inner(value, active)))
        .collect::<Vec<_>>()
        .join(", ");
    active.remove(&ptr);

    Some(format!("{class_name}({rendered})"))
}

fn bytes_ordering_value_bytes(value: &Value) -> Option<Vec<u8>> {
    match value {
        Value::Bytes(bytes) => Some(bytes.as_ref().clone()),
        Value::ByteArray(bytes) => Some(bytearray_bytes(bytes)),
        value => bytes_subclass_bytes(value).or_else(|| bytearray_subclass_bytes(value)),
    }
}

fn bytes_equality_value_bytes(value: &Value) -> Option<Vec<u8>> {
    match value {
        Value::MemoryView(view) => memoryview_bytes(view).ok(),
        value => bytes_ordering_value_bytes(value),
    }
}

fn is_simple_namespace_value(value: &Value) -> bool {
    match value {
        Value::SimpleNamespace { .. } => true,
        Value::Instance { class_bases, .. } => {
            class_bases_include_builtin(class_bases, "SimpleNamespace")
        }
        _ => false,
    }
}

fn simple_namespace_subclass_instance(name: String, attrs: Scope, bases: Vec<Value>) -> Value {
    Value::Instance {
        class_name: name,
        fields: new_scope(),
        class_attrs: attrs,
        class_bases: bases,
    }
}

fn simple_namespace_replace_type_error(class: &Value, value: &Value) -> String {
    format!(
        "TypeError: expect types.SimpleNamespace type, but {}() returned '{}' object",
        class_display_name(class),
        type_name(value)
    )
}

fn dict_subclass_method(receiver: Value, name: &str) -> Option<Value> {
    if dict_subclass_entries(&receiver).is_some()
        && (is_builtin_dict_type_method(name) || is_builtin_dict_union_type_method(name))
    {
        Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("dict.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        })
    } else {
        None
    }
}

