fn chain_map_subclass_attribute(receiver: Value, name: &str) -> Result<Option<Value>, String> {
    let Some(maps) = chain_map_subclass_maps(&receiver) else {
        return Ok(None);
    };

    match name {
        "maps" => Ok(Some(list_value(maps))),
        "parents" => Ok(Some(chain_map_parents(&maps)?)),
        "clear" | "copy" | "get" | "items" | "keys" | "new_child" | "pop" | "popitem"
        | "values" | "__contains__" | "__delitem__" | "__format__" | "__getitem__" | "__ior__"
        | "__iter__" | "__len__" | "__or__" | "__repr__" | "__ror__" | "__setitem__"
        | "__str__" => Ok(Some(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("ChainMap.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        })),
        _ => Ok(None),
    }
}

fn chain_map_subclass_display_class_attribute(class: Value, name: &str) -> Option<Value> {
    let Value::Class { bases, .. } = &class else {
        return None;
    };
    if !class_bases_include_builtin(bases, "ChainMap") {
        return None;
    }
    match name {
        "__format__" | "__repr__" | "__str__" => Some(Value::Builtin(format!("ChainMap.{name}"))),
        _ => None,
    }
}

