fn object_getattribute_type_object_missing_attribute(
    object: &Value,
    name: &str,
    result: &Result<Value, String>,
) -> bool {
    let Err(message) = result else {
        return false;
    };
    let Some(class_name) = type_object_missing_attribute_owner_name(object) else {
        return false;
    };
    message == &format!("AttributeError: type object '{class_name}' has no attribute '{name}'")
}

fn is_type_object_value(object: &Value) -> bool {
    type_object_owner_name(object).is_some()
}

fn object_setattr_type_object_value(object: &Value) -> bool {
    matches!(object, Value::NamedTupleType(_)) || is_type_object_value(object)
}

fn object_delattr_type_object_value(object: &Value) -> bool {
    matches!(object, Value::NamedTupleType(_)) || is_type_object_value(object)
}

fn type_object_owner_name(object: &Value) -> Option<&str> {
    match object {
        Value::Class { name, .. } => Some(name.as_str()),
        Value::Builtin(name) if is_builtin_type_object_name(name) => Some(name.as_str()),
        _ => None,
    }
}

fn type_object_missing_attribute_owner_name(object: &Value) -> Option<&str> {
    match object {
        Value::NamedTupleType(typ) => Some(typ.name.as_str()),
        _ => type_object_owner_name(object),
    }
}

fn immutable_sequence_method(
    type_name: &str,
    receiver: Value,
    name: &str,
) -> Result<Value, String> {
    if is_immutable_sequence_type_method(type_name, name) {
        Ok(Value::BoundMethod {
            function: Box::new(Value::Builtin(format!("{type_name}.{name}"))),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        })
    } else if matches!(type_name, "tuple" | "str" | "bytes" | "range") {
        Err(missing_type_attribute_error(type_name, name))
    } else {
        Err(format!(
            "AttributeError: {type_name} has no attribute '{name}'"
        ))
    }
}

fn range_index_missing_value_error(needle: &Value) -> &'static str {
    match needle {
        Value::Bool(_) | Value::Number(_) | Value::BigInt(_) => "range.index(x): x not in range",
        _ => "sequence.index(x): x not in sequence",
    }
}

fn is_immutable_sequence_type_method(type_name: &str, name: &str) -> bool {
    matches!(
        name,
        "__contains__" | "__getitem__" | "__iter__" | "__len__"
    ) || (matches!(type_name, "tuple" | "range") && matches!(name, "count" | "index"))
        || (type_name == "tuple" && matches!(name, "__add__" | "__mul__" | "__repr__" | "__rmul__"))
        || (type_name == "tuple"
            && matches!(
                name,
                "__eq__" | "__ne__" | "__lt__" | "__le__" | "__gt__" | "__ge__"
            ))
        || (type_name == "str"
            && matches!(
                name,
                "startswith"
                    | "endswith"
                    | "find"
                    | "rfind"
                    | "index"
                    | "rindex"
                    | "count"
                    | "lower"
                    | "upper"
                    | "capitalize"
                    | "title"
                    | "swapcase"
                    | "casefold"
                    | "islower"
                    | "isupper"
                    | "istitle"
                    | "isspace"
                    | "isalpha"
                    | "isalnum"
                    | "isdigit"
                    | "isdecimal"
                    | "isnumeric"
                    | "isascii"
                    | "isidentifier"
                    | "isprintable"
                    | "splitlines"
                    | "expandtabs"
                    | "replace"
                    | "removeprefix"
                    | "removesuffix"
                    | "split"
                    | "rsplit"
                    | "partition"
                    | "rpartition"
                    | "join"
                    | "translate"
                    | "encode"
                    | "format"
                    | "format_map"
                    | "strip"
                    | "lstrip"
                    | "rstrip"
                    | "ljust"
                    | "rjust"
                    | "center"
                    | "zfill"
            ))
        || (type_name == "bytes"
            && matches!(
                name,
                "__bytes__"
                    | "__format__"
                    | "__mod__"
                    | "lower"
                    | "upper"
                    | "capitalize"
                    | "title"
                    | "swapcase"
                    | "islower"
                    | "isupper"
                    | "istitle"
                    | "isspace"
                    | "isalpha"
                    | "isalnum"
                    | "isdigit"
                    | "isascii"
                    | "expandtabs"
                    | "zfill"
                    | "decode"
                    | "hex"
                    | "startswith"
                    | "endswith"
                    | "count"
                    | "find"
                    | "rfind"
                    | "index"
                    | "rindex"
                    | "replace"
                    | "removeprefix"
                    | "removesuffix"
                    | "partition"
                    | "rpartition"
                    | "translate"
                    | "splitlines"
                    | "rsplit"
                    | "split"
                    | "join"
                    | "strip"
                    | "lstrip"
                    | "rstrip"
                    | "ljust"
                    | "rjust"
                    | "center"
                    | "__rmod__"
            ))
}

