fn builtin_type_doc(name: &str) -> Option<&'static str> {
    match name {
        "bytes" => Some(concat!(
            "bytes(iterable_of_ints) -> bytes\n",
            "bytes(string, encoding[, errors]) -> bytes\n",
            "bytes(bytes_or_buffer) -> immutable copy of bytes_or_buffer\n",
            "bytes(int) -> bytes object of size given by the parameter initialized with null bytes\n",
            "bytes() -> empty bytes object\n",
            "\n",
            "Construct an immutable array of bytes from:\n",
            "  - an iterable yielding integers in range(256)\n",
            "  - a text string encoded using the specified encoding\n",
            "  - any object implementing the buffer API.\n",
            "  - an integer"
        )),
        "bytearray" => Some(concat!(
            "bytearray(iterable_of_ints) -> bytearray\n",
            "bytearray(string, encoding[, errors]) -> bytearray\n",
            "bytearray(bytes_or_buffer) -> mutable copy of bytes_or_buffer\n",
            "bytearray(int) -> bytes array of size given by the parameter initialized with null bytes\n",
            "bytearray() -> empty bytes array\n",
            "\n",
            "Construct a mutable bytearray object from:\n",
            "  - an iterable yielding integers in range(256)\n",
            "  - a text string encoded using the specified encoding\n",
            "  - a bytes or a buffer object\n",
            "  - any object implementing the buffer API.\n",
            "  - an integer"
        )),
        "deque" => Some("A list-like sequence optimized for data accesses near its endpoints."),
        "ChainMap" => Some(concat!(
            "A ChainMap groups multiple dicts (or other mappings) together\n",
            "to create a single, updateable view.\n",
            "\n",
            "The underlying mappings are stored in a list.  That list is public and can\n",
            "be accessed or updated using the *maps* attribute.  There is no other\n",
            "state.\n",
            "\n",
            "Lookups search the underlying mappings successively until a key is found.\n",
            "In contrast, writes, updates, and deletions only operate on the first\n",
            "mapping.\n",
            "\n"
        )),
        "Counter" => Some(concat!(
            "Dict subclass for counting hashable items.  Sometimes called a bag\n",
            "or multiset.  Elements are stored as dictionary keys and their counts\n",
            "are stored as dictionary values.\n",
            "\n",
            ">>> c = Counter('abcdeabcdabcaba')  # count elements from a string\n",
            "\n",
            ">>> c.most_common(3)                # three most common elements\n",
            "[('a', 5), ('b', 4), ('c', 3)]\n",
            ">>> sorted(c)                       # list all unique elements\n",
            "['a', 'b', 'c', 'd', 'e']\n",
            ">>> ''.join(sorted(c.elements()))   # list elements with repetitions\n",
            "'aaaaabbbbcccdde'\n",
            ">>> sum(c.values())                 # total of all counts\n",
            "15\n",
            "\n",
            ">>> c['a']                          # count of letter 'a'\n",
            "5\n",
            ">>> for elem in 'shazam':           # update counts from an iterable\n",
            "...     c[elem] += 1                # by adding 1 to each element's count\n",
            ">>> c['a']                          # now there are seven 'a'\n",
            "7\n",
            ">>> del c['b']                      # remove all 'b'\n",
            ">>> c['b']                          # now there are zero 'b'\n",
            "0\n",
            "\n",
            ">>> d = Counter('simsalabim')       # make another counter\n",
            ">>> c.update(d)                     # add in the second counter\n",
            ">>> c['a']                          # now there are nine 'a'\n",
            "9\n",
            "\n",
            ">>> c.clear()                       # empty the counter\n",
            ">>> c\n",
            "Counter()\n",
            "\n",
            "Note:  If a count is set to zero or reduced to zero, it will remain\n",
            "in the counter until the entry is deleted or the counter is cleared:\n",
            "\n",
            ">>> c = Counter('aaabbc')\n",
            ">>> c['b'] -= 2                     # reduce the count of 'b' by two\n",
            ">>> c.most_common()                 # 'b' is still in, but its count is zero\n",
            "[('a', 3), ('c', 1), ('b', 0)]\n",
            "\n"
        )),
        "defaultdict" => Some(concat!(
            "defaultdict(default_factory=None, /, [...]) --> dict with default factory\n",
            "\n",
            "The default factory is called without arguments to produce\n",
            "a new value when a key is not present, in __getitem__ only.\n",
            "A defaultdict compares equal to a dict with the same items.\n",
            "All remaining arguments are treated the same as if they were\n",
            "passed to the dict constructor, including keyword arguments.\n"
        )),
        "OrderedDict" => Some("Dictionary that remembers insertion order"),
        "UserList" => Some("A more or less complete user-defined wrapper around list objects."),
        "FrameLocalsProxy" => Some("A write-through proxy for frame locals."),
        "mappingproxy" => Some("Read-only proxy of a mapping."),
        _ => None,
    }
}

fn functools_total_ordering_builtin_name(root: &str, target: &str) -> String {
    format!("{FUNCTOOLS_TOTAL_ORDERING_PREFIX}{root}.{target}")
}

fn functools_total_ordering_parts(name: &str) -> Option<(&str, &str)> {
    let rest = name.strip_prefix(FUNCTOOLS_TOTAL_ORDERING_PREFIX)?;
    let (root, target) = rest.split_once('.')?;
    if FUNCTOOLS_TOTAL_ORDERING_METHODS.contains(&root)
        && functools_total_ordering_targets(root).contains(&target)
    {
        Some((root, target))
    } else {
        None
    }
}

fn functools_total_ordering_targets(root: &str) -> &'static [&'static str] {
    match root {
        "__lt__" => &["__gt__", "__le__", "__ge__"],
        "__le__" => &["__ge__", "__lt__", "__gt__"],
        "__gt__" => &["__lt__", "__ge__", "__le__"],
        "__ge__" => &["__le__", "__gt__", "__lt__"],
        _ => &[],
    }
}

fn functools_total_ordering_roots(attrs: &Scope, bases: &[Value]) -> Vec<&'static str> {
    FUNCTOOLS_TOTAL_ORDERING_METHODS
        .iter()
        .copied()
        .filter(|method| {
            find_class_attr(attrs, bases, method).is_some()
                || class_bases_have_builtin_order_method(bases, method)
        })
        .collect()
}

fn class_bases_have_builtin_order_method(bases: &[Value], method: &str) -> bool {
    bases.iter().any(|base| match base {
        Value::Builtin(name) => builtin_type_has_total_ordering_method(name, method),
        Value::NamedTupleType(_) => builtin_type_has_total_ordering_method("tuple", method),
        Value::Class { attrs, bases, .. } => {
            find_class_attr(attrs, bases, method).is_some()
                || class_bases_have_builtin_order_method(bases, method)
        }
        Value::GenericAlias { origin, .. } => match origin.as_ref() {
            Value::Builtin(name) => builtin_type_has_total_ordering_method(name, method),
            Value::Class { attrs, bases, .. } => {
                find_class_attr(attrs, bases, method).is_some()
                    || class_bases_have_builtin_order_method(bases, method)
            }
            _ => false,
        },
        _ => false,
    })
}

fn builtin_type_has_total_ordering_method(type_name: &str, method: &str) -> bool {
    FUNCTOOLS_TOTAL_ORDERING_METHODS.contains(&method)
        && (matches!(
            type_name,
            "int" | "bool" | "float" | "str" | "bytes" | "bytearray" | "tuple" | "list"
        ) || is_builtin_set_type_method(type_name, method))
}

fn functools_total_ordering_doc(root: &str, target: &str) -> String {
    match (root, target) {
        ("__lt__", "__gt__") => {
            "Return a > b.  Computed by @total_ordering from (not a < b) and (a != b)."
        }
        ("__lt__", "__le__") => {
            "Return a <= b.  Computed by @total_ordering from (a < b) or (a == b)."
        }
        ("__lt__", "__ge__") => "Return a >= b.  Computed by @total_ordering from (not a < b).",
        ("__le__", "__ge__") => {
            "Return a >= b.  Computed by @total_ordering from (not a <= b) or (a == b)."
        }
        ("__le__", "__lt__") => {
            "Return a < b.  Computed by @total_ordering from (a <= b) and (a != b)."
        }
        ("__le__", "__gt__") => "Return a > b.  Computed by @total_ordering from (not a <= b).",
        ("__gt__", "__lt__") => {
            "Return a < b.  Computed by @total_ordering from (not a > b) and (a != b)."
        }
        ("__gt__", "__ge__") => {
            "Return a >= b.  Computed by @total_ordering from (a > b) or (a == b)."
        }
        ("__gt__", "__le__") => "Return a <= b.  Computed by @total_ordering from (not a > b).",
        ("__ge__", "__le__") => {
            "Return a <= b.  Computed by @total_ordering from (not a >= b) or (a == b)."
        }
        ("__ge__", "__gt__") => {
            "Return a > b.  Computed by @total_ordering from (a >= b) and (a != b)."
        }
        ("__ge__", "__lt__") => "Return a < b.  Computed by @total_ordering from (not a >= b).",
        _ => "",
    }
    .to_string()
}

fn is_builtin_set_type_method(type_name: &str, name: &str) -> bool {
    match type_name {
        "set" => matches!(
            name,
            "add"
                | "clear"
                | "copy"
                | "difference"
                | "difference_update"
                | "discard"
                | "intersection"
                | "intersection_update"
                | "isdisjoint"
                | "issubset"
                | "issuperset"
                | "pop"
                | "remove"
                | "symmetric_difference"
                | "symmetric_difference_update"
                | "union"
                | "update"
                | "__and__"
                | "__contains__"
                | "__eq__"
                | "__ge__"
                | "__gt__"
                | "__init__"
                | "__iter__"
                | "__le__"
                | "__len__"
                | "__lt__"
                | "__ne__"
                | "__new__"
                | "__or__"
                | "__sub__"
                | "__xor__"
        ),
        "frozenset" => matches!(
            name,
            "copy"
                | "difference"
                | "intersection"
                | "isdisjoint"
                | "issubset"
                | "issuperset"
                | "symmetric_difference"
                | "union"
                | "__and__"
                | "__contains__"
                | "__eq__"
                | "__ge__"
                | "__gt__"
                | "__hash__"
                | "__init__"
                | "__iter__"
                | "__le__"
                | "__len__"
                | "__lt__"
                | "__ne__"
                | "__new__"
                | "__or__"
                | "__sub__"
                | "__xor__"
        ),
        _ => false,
    }
}

fn is_collections_abc_bytestring_module_attr(module: &Value, attr: &str) -> bool {
    matches!(module, Value::Module { name, .. } if name == "collections.abc")
        && attr == "ByteString"
}

fn store_attribute(object: Value, name: &str, value: Value) -> Result<(), String> {
    match object {
        Value::Instance {
            fields,
            class_bases,
            ..
        } => {
            let value = if class_bases_include_builtin(&class_bases, "AST") {
                ast_stored_value(value)
            } else {
                value
            };
            fields.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::SimpleNamespace { fields } => {
            insert_live_dict_entry(
                &mut fields.borrow_mut(),
                Value::String(name.to_string()),
                value,
            )?;
            Ok(())
        }
        Value::Cell {
            name: cell_name,
            scope,
            ..
        } if name == "cell_contents" => {
            set_cell_contents(&cell_name, &scope, value);
            Ok(())
        }
        Value::Cell { .. } => Err(format!(
            "AttributeError: 'cell' object has no attribute '{name}' and no __dict__ for setting new attributes"
        )),
        Value::UserDict { attrs, .. } => {
            insert_live_dict_entry(
                &mut attrs.borrow_mut(),
                Value::String(name.to_string()),
                value,
            )?;
            Ok(())
        }
        Value::UserList { data, attrs } => {
            if name == "data" {
                let values = match value {
                    Value::List(items) => items.borrow().clone(),
                    Value::UserList { data: items, .. } => items.borrow().clone(),
                    value => {
                        return Err(format!(
                            "TypeError: UserList.data does not support assignment from '{}'",
                            type_name(&value)
                        ));
                    }
                };
                *data.borrow_mut() = values;
            } else {
                insert_live_dict_entry(
                    &mut attrs.borrow_mut(),
                    Value::String(name.to_string()),
                    value,
                )?;
            }
            Ok(())
        }
        Value::UserString { data, attrs } => {
            if name == "data" {
                *data.borrow_mut() = str_value_checked(&value)?;
            } else {
                insert_live_dict_entry(
                    &mut attrs.borrow_mut(),
                    Value::String(name.to_string()),
                    value,
                )?;
            }
            Ok(())
        }
        Value::DefaultDict {
            default_factory, ..
        } if name == "default_factory" => {
            *default_factory.borrow_mut() = value;
            Ok(())
        }
        Value::DefaultDict { .. } => Err(default_dict_attribute_assignment_error(name)),
        Value::AstNode { attrs, .. } => {
            insert_live_dict_entry(
                &mut attrs.borrow_mut(),
                Value::String(name.to_string()),
                ast_stored_value(value),
            )?;
            Ok(())
        }
        Value::Exception { .. } if name == "__traceback__" => {
            if is_traceback_or_none(&value) {
                Ok(())
            } else {
                Err("TypeError: __traceback__ must be a traceback or None".to_string())
            }
        }
        Value::Class {
            name: class_name,
            attrs,
            ..
        } => {
            if let Some(error) = class_base_readonly_error(name) {
                return Err(error);
            }
            if let Some(error) = class_mro_readonly_error(name) {
                return Err(error);
            }
            if let Some(error) = class_dict_readonly_error(name) {
                return Err(error);
            }
            if let Some(error) = class_bases_assignment_error(&class_name, &attrs, name, &value) {
                return Err(error);
            }
            if matches!(name, "__name__" | "__qualname__") {
                return store_class_metadata_attribute(&class_name, &attrs, name, value);
            }
            if name == "__module__" {
                return store_class_module_attribute(&attrs, value);
            }
            store_ordered_scope_item(&attrs, name.to_string(), value);
            Ok(())
        }
        Value::Module { attrs, .. } => {
            attrs.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::Function { doc, attrs, .. } => {
            if is_readonly_function_attribute(name) {
                return Err(format!(
                    "AttributeError: function attribute '{name}' is read-only"
                ));
            }
            if name == "__dict__" {
                return set_function_dict(&attrs, value);
            }
            if name == "__defaults__" {
                return set_function_defaults_metadata(&attrs, value);
            }
            if name == "__kwdefaults__" {
                return set_function_keyword_defaults_metadata(&attrs, value);
            }
            if name == "__name__" {
                match value {
                    value @ Value::String(_) => {
                        attrs.borrow_mut().insert("__name__".to_string(), value);
                    }
                    value => {
                        return Err(format!(
                            "TypeError: __name__ must be set to a string object, not '{}'",
                            type_name(&value)
                        ));
                    }
                }
                return Ok(());
            }
            if name == "__module__" {
                attrs.borrow_mut().insert("__module__".to_string(), value);
                return Ok(());
            }
            if name == "__doc__" {
                *doc.borrow_mut() = value;
                return Ok(());
            }
            if name == "__qualname__" {
                match value {
                    value @ Value::String(_) => {
                        attrs
                            .borrow_mut()
                            .insert(FUNCTION_QUALNAME_ATTR.to_string(), value);
                    }
                    value => {
                        return Err(format!(
                            "TypeError: __qualname__ must be set to a string object, not '{}'",
                            type_name(&value)
                        ));
                    }
                }
                return Ok(());
            }
            if name == "__annotations__" {
                return set_function_annotations_metadata(&attrs, value);
            }
            if name == "__type_params__" {
                return set_function_type_params_metadata(&attrs, value);
            }
            if name == "__annotate__" {
                attrs.borrow_mut().insert(name.to_string(), value);
                return Ok(());
            }
            store_function_custom_attribute(&attrs, name, value)
        }
        Value::Property {
            name: property_name,
            ..
        } if name == "__name__" => {
            *property_name.borrow_mut() = Some(value);
            Ok(())
        }
        Value::Property { doc, .. } if name == "__doc__" => {
            *doc.borrow_mut() = Some(value);
            Ok(())
        }
        Value::Property { .. } => Err(property_attribute_assignment_error(name)),
        Value::WeakProxy { target, .. } => store_attribute(*target, name, value),
        Value::BytesIO(bytes_io) => {
            let mut state = bytes_io.borrow_mut();
            state.attrs_materialized = true;
            state.attrs.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::MagicMock {
            attrs, side_effect, ..
        } => {
            if name == "side_effect" {
                *side_effect.borrow_mut() = if matches!(value, Value::None) {
                    None
                } else {
                    Some(value)
                };
                return Ok(());
            }
            attrs
                .borrow_mut()
                .insert(name.to_string(), mock_stored_attribute_value(name, value));
            Ok(())
        }
        Value::MockMethod { side_effect, .. } => {
            if name == "side_effect" {
                *side_effect.borrow_mut() = if matches!(value, Value::None) {
                    None
                } else {
                    Some(value)
                };
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: MagicMock method has no attribute '{name}'"
                ))
            }
        }
        Value::Partial { attrs, .. } => {
            if matches!(name, "func" | "args" | "keywords") {
                return Err(format!("AttributeError: readonly attribute '{name}'"));
            }
            attrs.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::PartialMethod { attrs, .. } => {
            attrs.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::LruCacheWrapper { attrs, .. } => {
            attrs.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::SingleDispatch { attrs, .. } => {
            attrs.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::SingleDispatchRegister { .. } => Err(format!(
            "AttributeError: function object has no attribute '{name}'"
        )),
        Value::SingleDispatchMethod { attrs, .. } => {
            attrs.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::SingleDispatchMethodCallable { .. } => Err(format!(
            "AttributeError: function object has no attribute '{name}'"
        )),
        Value::CachedProperty {
            attrname, attrs, ..
        } if name == "attrname" => {
            match value {
                Value::None => {
                    *attrname.borrow_mut() = None;
                    attrs.borrow_mut().insert(name.to_string(), Value::None);
                }
                Value::String(value) => {
                    *attrname.borrow_mut() = Some(value.clone());
                    attrs
                        .borrow_mut()
                        .insert(name.to_string(), Value::String(value));
                }
                value => {
                    return Err(format!(
                        "TypeError: attrname must be set to a string object or None, not '{}'",
                        type_name(&value)
                    ));
                }
            }
            Ok(())
        }
        Value::CachedProperty { attrs, .. } => {
            attrs.borrow_mut().insert(name.to_string(), value);
            Ok(())
        }
        Value::CmpToKeyObject { object, .. } if name == "obj" => {
            *object.borrow_mut() = value;
            Ok(())
        }
        Value::CmpToKey { .. } | Value::CmpToKeyObject { .. } => Err(format!(
            "AttributeError: 'functools.KeyWrapper' object has no attribute '{name}' and no __dict__ for setting new attributes"
        )),
        Value::Builtin(function_name) if function_name == CONST_EVALUATOR_TYPE_NAME => {
            Err(format!(
                "TypeError: cannot set '{name}' attribute of immutable type '{CONST_EVALUATOR_TYPE_NAME}'"
            ))
        }
        Value::Builtin(function_name) if is_singleton_type_name(&function_name) => Err(format!(
            "TypeError: cannot set '{name}' attribute of immutable type '{function_name}'"
        )),
        Value::Builtin(function_name) if is_json_builtin(&function_name) => {
            store_json_builtin_attribute(&function_name, name, value)
        }
        Value::Builtin(function_name) if function_name == "deque" => {
            Err(deque_type_attribute_assignment_error(name))
        }
        Value::Builtin(function_name)
            if name == "_fields" && ast_builtin_kind(&function_name).is_some() =>
        {
            let kind = ast_builtin_kind(&function_name).expect("guard checked AST builtin kind");
            set_ast_builtin_class_attr_override(kind, name, Some(value));
            Ok(())
        }
        Value::NamedTupleType(typ) if name == "__doc__" => {
            let Value::String(value) = value else {
                return Err(format!(
                    "TypeError: can only assign string to .__doc__, not '{}'",
                    type_name(&value)
                ));
            };
            *typ.doc.borrow_mut() = value;
            Ok(())
        }
        Value::NamedTupleFieldDescriptor { typ, index } if name == "__doc__" => {
            let Value::String(value) = value else {
                return Err(format!(
                    "TypeError: can only assign string to .__doc__, not '{}'",
                    type_name(&value)
                ));
            };
            let Some(doc) = typ.field_docs.get(index) else {
                return Err("AttributeError: namedtuple field index out of range".to_string());
            };
            *doc.borrow_mut() = value;
            Ok(())
        }
        Value::NamedTuple { .. } => Err(format!(
            "AttributeError: can't set attribute '{name}' on namedtuple"
        )),
        Value::String(_) | Value::IdentityString { .. } => {
            Err(str_attribute_assignment_error(name))
        }
        Value::Bytes(_) => Err(bytes_attribute_assignment_error(name)),
        Value::ByteArray(_) => Err(bytearray_attribute_assignment_error(name)),
        Value::List(_) => Err(list_attribute_assignment_error(name)),
        Value::Tuple(_) => Err(tuple_attribute_assignment_error(name)),
        Value::Dict(_) => Err(dict_attribute_assignment_error(name)),
        Value::Set(_) => Err(set_attribute_assignment_error(name)),
        Value::FrozenSet(_) => Err(frozenset_attribute_assignment_error(name)),
        Value::MemoryView(_) => Err(memoryview_attribute_assignment_error(name)),
        Value::DictView { kind, ordered, .. } => {
            Err(dict_view_attribute_assignment_error(kind, ordered, name))
        }
        Value::MappingProxy { .. } | Value::MappingProxyObject { .. } => {
            Err(mappingproxy_attribute_assignment_error(name))
        }
        Value::Bool(_) => Err(bool_attribute_assignment_error(name)),
        Value::Number(_) | Value::BigInt(_) => Err(int_attribute_assignment_error(name)),
        Value::Float(_) => Err(float_attribute_assignment_error(name)),
        Value::Complex { .. } => Err(complex_attribute_assignment_error(name)),
        Value::Range { .. } => Err(range_attribute_assignment_error(name)),
        Value::Slice { .. } => Err(slice_attribute_assignment_error(name)),
        Value::Super { .. } => Err(super_attribute_assignment_error(name)),
        Value::Deque { .. } => Err(deque_attribute_assignment_error(name)),
        value => Err(format!(
            "AttributeError: cannot set attribute '{name}' on {value}"
        )),
    }
}

fn is_readonly_function_attribute(name: &str) -> bool {
    matches!(
        name,
        "__builtins__" | "__closure__" | "__code__" | "__globals__"
    )
}

fn property_attribute_assignment_error(name: &str) -> String {
    if matches!(name, "fget" | "fset" | "fdel") {
        "AttributeError: readonly attribute".to_string()
    } else if name == "__isabstractmethod__" {
        "AttributeError: attribute '__isabstractmethod__' of 'property' objects is not writable"
            .to_string()
    } else if is_property_readonly_instance_attribute(name) {
        format!("AttributeError: 'property' object attribute '{name}' is read-only")
    } else {
        format!(
            "AttributeError: 'property' object has no attribute '{name}' and no __dict__ for setting new attributes"
        )
    }
}

fn is_property_readonly_instance_attribute(name: &str) -> bool {
    matches!(
        name,
        "getter" | "setter" | "deleter" | "__get__" | "__set__" | "__delete__" | "__set_name__"
    )
}

fn super_attribute_assignment_error(name: &str) -> String {
    if matches!(name, "__thisclass__" | "__self__" | "__self_class__") {
        "AttributeError: readonly attribute".to_string()
    } else {
        format!(
            "AttributeError: 'super' object has no attribute '{name}' and no __dict__ for setting new attributes"
        )
    }
}

fn store_class_metadata_attribute(
    class_name: &str,
    attrs: &Scope,
    name: &str,
    value: Value,
) -> Result<(), String> {
    let Some(value) = value_as_string(&value) else {
        let public_name = class_public_name(class_name, attrs);
        return Err(format!(
            "TypeError: can only assign string to {public_name}.{name}, not '{}'",
            type_name_for_type_assignment_error(&value)
        ));
    };

    if name == "__name__" && value.contains('\0') {
        return Err("ValueError: type name must not contain null characters".to_string());
    }

    let storage_name = match name {
        "__name__" => CLASS_NAME_ATTR,
        "__qualname__" => CLASS_QUALNAME_ATTR,
        _ => unreachable!("caller filters class metadata attributes"),
    };
    attrs
        .borrow_mut()
        .insert(storage_name.to_string(), Value::String(value.to_string()));
    Ok(())
}

fn store_class_module_attribute(attrs: &Scope, value: Value) -> Result<(), String> {
    store_ordered_scope_item(attrs, "__module__".to_string(), value);
    attrs.borrow_mut().remove("__firstlineno__");
    Ok(())
}

fn class_base_readonly_error(name: &str) -> Option<String> {
    if name == "__base__" {
        Some("AttributeError: readonly attribute".to_string())
    } else {
        None
    }
}

fn class_mro_readonly_error(name: &str) -> Option<String> {
    if name == "__mro__" {
        Some("AttributeError: attribute '__mro__' of 'type' objects is not writable".to_string())
    } else {
        None
    }
}

fn class_dict_readonly_error(name: &str) -> Option<String> {
    if name == "__dict__" {
        Some("AttributeError: attribute '__dict__' of 'type' objects is not writable".to_string())
    } else {
        None
    }
}

fn class_bases_assignment_error(
    class_name: &str,
    attrs: &Scope,
    name: &str,
    value: &Value,
) -> Option<String> {
    if name == "__bases__" && !matches!(value, Value::Tuple(_)) {
        let public_name = class_public_name(class_name, attrs);
        Some(format!(
            "TypeError: can only assign tuple to {public_name}.__bases__, not {}",
            type_name(value)
        ))
    } else {
        None
    }
}

fn class_public_name(class_name: &str, attrs: &Scope) -> String {
    match class_name_value(class_name, attrs) {
        Value::String(name) => name,
        _ => class_name.to_string(),
    }
}

fn class_metadata_delete_error(class_name: &str, attrs: &Scope, name: &str) -> String {
    let public_name = class_public_name(class_name, attrs);
    format!("TypeError: cannot delete '{name}' attribute of immutable type '{public_name}'")
}

fn type_name_for_type_assignment_error(value: &Value) -> &str {
    type_name(value)
}

fn delete_attribute(object: Value, name: &str) -> Result<(), String> {
    match object {
        Value::Instance {
            class_name, fields, ..
        } => {
            if fields.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: '{class_name}' object has no attribute '{name}'"
                ))
            }
        }
        Value::SimpleNamespace { fields } => {
            let mut fields = fields.borrow_mut();
            if let Some(position) = fields
                .iter()
                .position(|(key, _)| matches!(key, Value::String(key_name) if key_name == name))
            {
                fields.remove(position);
                mark_dict_changed(&mut fields);
                Ok(())
            } else {
                Err(format!("AttributeError: object has no attribute '{name}'"))
            }
        }
        Value::Cell {
            name: cell_name,
            scope,
            ..
        } if name == "cell_contents" => {
            scope.borrow_mut().remove(&cell_name);
            Ok(())
        }
        Value::Cell { .. } => Err(format!(
            "AttributeError: 'cell' object has no attribute '{name}' and no __dict__ for setting new attributes"
        )),
        Value::AstNode { kind, attrs, .. } => {
            let mut attrs = attrs.borrow_mut();
            if let Some(position) = attrs
                .iter()
                .position(|(key, _)| matches!(key, Value::String(key_name) if key_name == name))
            {
                attrs.remove(position);
                mark_dict_changed(&mut attrs);
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: '{kind}' object has no attribute '{name}'"
                ))
            }
        }
        Value::UserString { attrs, .. } => {
            let mut attrs = attrs.borrow_mut();
            if let Some(position) = attrs
                .iter()
                .position(|(key, _)| matches!(key, Value::String(key_name) if key_name == name))
            {
                attrs.remove(position);
                mark_dict_changed(&mut attrs);
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: 'UserString' object has no attribute '{name}'"
                ))
            }
        }
        Value::Class {
            name: class_name,
            attrs,
            ..
        } => {
            if let Some(error) = class_base_readonly_error(name) {
                return Err(error);
            }
            if let Some(error) = class_mro_readonly_error(name) {
                return Err(error);
            }
            if let Some(error) = class_dict_readonly_error(name) {
                return Err(error);
            }
            if matches!(
                name,
                "__name__"
                    | "__qualname__"
                    | "__module__"
                    | "__doc__"
                    | "__bases__"
                    | "__type_params__"
            ) {
                return Err(class_metadata_delete_error(&class_name, &attrs, name));
            }
            if attrs.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: type object has no attribute '{name}'"
                ))
            }
        }
        Value::Module {
            name: module_name,
            attrs,
        } => {
            if attrs.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: module '{module_name}' has no attribute '{name}'"
                ))
            }
        }
        Value::Function { doc, attrs, .. } => {
            if name == "__doc__" {
                *doc.borrow_mut() = Value::None;
                return Ok(());
            }
            if name == "__dict__" {
                return Err("TypeError: cannot delete __dict__".to_string());
            }
            if name == "__defaults__" {
                return set_function_defaults_metadata(&attrs, Value::None);
            }
            if name == "__kwdefaults__" {
                return set_function_keyword_defaults_metadata(&attrs, Value::None);
            }
            if name == "__annotations__" {
                return set_function_annotations_metadata(&attrs, dict_value(Vec::new()));
            }
            if name == "__type_params__" {
                return Err("TypeError: __type_params__ must be set to a tuple".to_string());
            }
            delete_function_custom_attribute(&attrs, name)
        }
        Value::Property {
            name: property_name,
            ..
        } if name == "__name__" => {
            *property_name.borrow_mut() = None;
            Ok(())
        }
        Value::Property { doc, .. } if name == "__doc__" => {
            *doc.borrow_mut() = None;
            Ok(())
        }
        Value::Property { .. } => Err(property_attribute_assignment_error(name)),
        Value::WeakProxy { target, .. } => delete_attribute(*target, name),
        Value::BytesIO(bytes_io) => {
            let mut state = bytes_io.borrow_mut();
            if state.attrs.borrow_mut().remove(name).is_some() {
                state.attrs_materialized = true;
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: '_io.BytesIO' object has no attribute '{name}'"
                ))
            }
        }
        Value::Partial { attrs, .. } => {
            if matches!(name, "func" | "args" | "keywords") {
                return Err(format!("AttributeError: readonly attribute '{name}'"));
            }
            if attrs.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: partial object has no attribute '{name}'"
                ))
            }
        }
        Value::PartialMethod { attrs, .. } => {
            if attrs.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: partialmethod object has no attribute '{name}'"
                ))
            }
        }
        Value::LruCacheWrapper { attrs, .. } => {
            if attrs.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: _lru_cache_wrapper object has no attribute '{name}'"
                ))
            }
        }
        Value::SingleDispatch { attrs, .. } => {
            if attrs.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: function object has no attribute '{name}'"
                ))
            }
        }
        Value::SingleDispatchRegister { .. } => Err(format!(
            "AttributeError: function object has no attribute '{name}'"
        )),
        Value::SingleDispatchMethod { attrs, .. } => {
            if attrs.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: singledispatchmethod object has no attribute '{name}'"
                ))
            }
        }
        Value::SingleDispatchMethodCallable { .. } => Err(format!(
            "AttributeError: function object has no attribute '{name}'"
        )),
        Value::CachedProperty {
            attrname, attrs, ..
        } if name == "attrname" => {
            *attrname.borrow_mut() = None;
            attrs.borrow_mut().remove(name);
            Ok(())
        }
        Value::CachedProperty { attrs, .. } => {
            if attrs.borrow_mut().remove(name).is_some() {
                Ok(())
            } else {
                Err(format!(
                    "AttributeError: cached_property object has no attribute '{name}'"
                ))
            }
        }
        Value::CmpToKeyObject { object, .. } if name == "obj" => {
            *object.borrow_mut() = Value::None;
            Ok(())
        }
        Value::CmpToKey { .. } | Value::CmpToKeyObject { .. } => Err(format!(
            "AttributeError: 'functools.KeyWrapper' object has no attribute '{name}'"
        )),
        Value::Builtin(function_name)
            if name == "_fields" && ast_builtin_kind(&function_name).is_some() =>
        {
            let kind = ast_builtin_kind(&function_name).expect("guard checked AST builtin kind");
            if ast_builtin_class_attr_is_deleted(kind, name) {
                Err(format!(
                    "AttributeError: type object 'ast.{kind}' has no attribute '{name}'"
                ))
            } else {
                set_ast_builtin_class_attr_override(kind, name, None);
                Ok(())
            }
        }
        Value::Builtin(function_name) if function_name == "deque" => {
            Err(deque_type_attribute_assignment_error(name))
        }
        Value::Builtin(function_name) if is_json_builtin(&function_name) => {
            delete_json_builtin_attribute(&function_name, name)
        }
        Value::DefaultDict {
            default_factory, ..
        } if name == "default_factory" => {
            *default_factory.borrow_mut() = Value::None;
            Ok(())
        }
        Value::DefaultDict { .. } => Err(default_dict_attribute_assignment_error(name)),
        Value::NamedTupleType(typ) if name == "__doc__" => {
            *typ.doc.borrow_mut() = String::new();
            Ok(())
        }
        Value::NamedTuple { .. } => Err(format!(
            "AttributeError: can't delete attribute '{name}' on namedtuple"
        )),
        Value::String(_) | Value::IdentityString { .. } => {
            Err(str_attribute_assignment_error(name))
        }
        Value::Bytes(_) => Err(bytes_attribute_assignment_error(name)),
        Value::ByteArray(_) => Err(bytearray_attribute_assignment_error(name)),
        Value::List(_) => Err(list_attribute_assignment_error(name)),
        Value::Tuple(_) => Err(tuple_attribute_assignment_error(name)),
        Value::Dict(_) => Err(dict_attribute_assignment_error(name)),
        Value::Set(_) => Err(set_attribute_assignment_error(name)),
        Value::FrozenSet(_) => Err(frozenset_attribute_assignment_error(name)),
        Value::MemoryView(_) => Err(memoryview_attribute_assignment_error(name)),
        Value::DictView { kind, ordered, .. } => {
            Err(dict_view_attribute_assignment_error(kind, ordered, name))
        }
        Value::MappingProxy { .. } | Value::MappingProxyObject { .. } => {
            Err(mappingproxy_attribute_assignment_error(name))
        }
        Value::Bool(_) => Err(bool_attribute_assignment_error(name)),
        Value::Number(_) | Value::BigInt(_) => Err(int_attribute_assignment_error(name)),
        Value::Float(_) => Err(float_attribute_assignment_error(name)),
        Value::Complex { .. } => Err(complex_attribute_assignment_error(name)),
        Value::Range { .. } => Err(range_attribute_assignment_error(name)),
        Value::Slice { .. } => Err(slice_attribute_assignment_error(name)),
        Value::Super { .. } => Err(super_attribute_assignment_error(name)),
        Value::Deque { .. } => Err(deque_attribute_assignment_error(name)),
        value => Err(format!(
            "AttributeError: cannot delete attribute '{name}' on {value}"
        )),
    }
}

fn float_attribute_assignment_error(name: &str) -> String {
    if matches!(name, "real" | "imag") {
        format!("AttributeError: attribute '{name}' of 'float' objects is not writable")
    } else if is_float_readonly_instance_attribute(name) {
        format!("AttributeError: 'float' object attribute '{name}' is read-only")
    } else {
        format!(
            "AttributeError: 'float' object has no attribute '{name}' and no __dict__ for setting new attributes"
        )
    }
}

fn is_float_readonly_instance_attribute(name: &str) -> bool {
    !name.starts_with("__")
        && builtin_type_dir_names("float")
            .iter()
            .any(|candidate| candidate.as_str() == name)
}

