fn bind_method(value: Value, receiver: Value) -> Value {
    match value {
        Value::Function { .. } | Value::LruCacheWrapper { .. } => Value::BoundMethod {
            function: Box::new(value),
            receiver: Box::new(receiver),
            identity: Rc::new(()),
        },
        Value::Builtin(name) if name.starts_with("warnings.catch_warnings.") => {
            Value::BoundMethod {
                function: Box::new(Value::Builtin(name)),
                receiver: Box::new(receiver),
                identity: Rc::new(()),
            }
        }
        Value::Builtin(name) if functools_total_ordering_parts(&name).is_some() => {
            Value::BoundMethod {
                function: Box::new(Value::Builtin(name)),
                receiver: Box::new(receiver),
                identity: Rc::new(()),
            }
        }
        Value::Builtin(name)
            if matches!(
                name.as_str(),
                "decimal.Decimal.__round__" | "fractions.Fraction.__round__"
            ) =>
        {
            Value::BoundMethod {
                function: Box::new(Value::Builtin(name)),
                receiver: Box::new(receiver),
                identity: Rc::new(()),
            }
        }
        Value::Builtin(name) if builtin_method_descriptor_requires_receiver(&name) => {
            Value::BoundMethod {
                function: Box::new(Value::Builtin(name)),
                receiver: Box::new(receiver),
                identity: Rc::new(()),
            }
        }
        value => value,
    }
}

fn builtin_method_descriptor_requires_receiver(name: &str) -> bool {
    let Some((type_name, method)) = name.split_once('.') else {
        return false;
    };
    if method == "__new__" {
        return false;
    }

    match type_name {
        "object" => matches!(method, "__format__" | "__getstate__"),
        "dict" => is_builtin_dict_type_method(method) || is_builtin_dict_union_type_method(method),
        "OrderedDict" => is_builtin_dict_type_method(method),
        "defaultdict" => {
            is_builtin_dict_type_method(method) || matches!(method, "__copy__" | "__missing__")
        }
        "Counter" => is_builtin_counter_type_method(method),
        "ChainMap" => is_builtin_chain_map_type_method(method),
        "deque" => is_builtin_deque_type_method(method),
        "io" if matches!(
            method,
            "BytesIO.read"
                | "BytesIO.read1"
                | "BytesIO.readline"
                | "BytesIO.readlines"
                | "BytesIO.write"
                | "BytesIO.writelines"
                | "BytesIO.__enter__"
                | "BytesIO.__exit__"
                | "BytesIO.getvalue"
                | "BytesIO.getbuffer"
                | "BytesIO.tell"
                | "BytesIO.seek"
                | "BytesIO.truncate"
                | "BytesIO.readable"
                | "BytesIO.writable"
                | "BytesIO.seekable"
                | "BytesIO.isatty"
                | "BytesIO.flush"
                | "BytesIO._checkClosed"
                | "BytesIO._checkReadable"
                | "BytesIO._checkSeekable"
                | "BytesIO._checkWritable"
                | "BytesIO.fileno"
                | "BytesIO.detach"
                | "BytesIO.close"
                | "BytesIO.__getstate__"
                | "BytesIO.__setstate__"
        ) =>
        {
            true
        }
        "complex" => is_builtin_complex_type_method(method),
        "int" | "bool" => is_builtin_int_type_method(method) && method != "from_bytes",
        "list" => is_builtin_list_type_method(method),
        "set" | "frozenset" => is_builtin_set_type_method(type_name, method),
        "tuple" | "range" | "str" | "bytes" => is_immutable_sequence_type_method(type_name, method),
        _ => false,
    }
}

fn is_builtin_deque_type_method(name: &str) -> bool {
    matches!(
        name,
        "append"
            | "appendleft"
            | "clear"
            | "copy"
            | "count"
            | "extend"
            | "extendleft"
            | "index"
            | "insert"
            | "pop"
            | "popleft"
            | "remove"
            | "reverse"
            | "rotate"
            | "__add__"
            | "__class_getitem__"
            | "__contains__"
            | "__copy__"
            | "__delitem__"
            | "__eq__"
            | "__format__"
            | "__ge__"
            | "__getitem__"
            | "__gt__"
            | "__iadd__"
            | "__imul__"
            | "__iter__"
            | "__le__"
            | "__len__"
            | "__lt__"
            | "__mul__"
            | "__ne__"
            | "__repr__"
            | "__reversed__"
            | "__rmul__"
            | "__setitem__"
            | "__str__"
    )
}

fn is_builtin_method_descriptor_name(name: &str) -> bool {
    if is_builtin_wrapper_descriptor_name(name) {
        return false;
    }
    let Some((type_name, method)) = name.split_once('.') else {
        return false;
    };
    match type_name {
        "object" => matches!(
            method,
            "__dir__" | "__format__" | "__getstate__" | "__sizeof__"
        ),
        "defaultdict" => matches!(method, "__missing__" | "copy" | "__copy__"),
        "io" => matches!(
            method,
            "BytesIO.read"
                | "BytesIO.read1"
                | "BytesIO.readline"
                | "BytesIO.readlines"
                | "BytesIO.write"
                | "BytesIO.writelines"
                | "BytesIO.__enter__"
                | "BytesIO.__exit__"
                | "BytesIO.getvalue"
                | "BytesIO.getbuffer"
                | "BytesIO.tell"
                | "BytesIO.seek"
                | "BytesIO.truncate"
                | "BytesIO.readable"
                | "BytesIO.writable"
                | "BytesIO.seekable"
                | "BytesIO.isatty"
                | "BytesIO.flush"
                | "BytesIO._checkClosed"
                | "BytesIO._checkReadable"
                | "BytesIO._checkSeekable"
                | "BytesIO._checkWritable"
                | "BytesIO.fileno"
                | "BytesIO.detach"
                | "BytesIO.close"
                | "BytesIO.__getstate__"
                | "BytesIO.__setstate__"
        ),
        "int" | "bool" => {
            is_builtin_int_type_method(method) && !matches!(method, "__new__" | "from_bytes")
        }
        "list" => is_builtin_list_type_method(method),
        "str" => is_immutable_sequence_type_method(type_name, method),
        _ => false,
    }
}

fn is_builtin_wrapper_descriptor_name(name: &str) -> bool {
    let Some((type_name, method)) = name.split_once('.') else {
        return false;
    };
    match type_name {
        "object" => matches!(
            method,
            "__init__"
                | "__repr__"
                | "__str__"
                | "__eq__"
                | "__ne__"
                | "__lt__"
                | "__le__"
                | "__gt__"
                | "__ge__"
                | "__getattribute__"
                | "__setattr__"
                | "__delattr__"
                | "__hash__"
        ),
        "int" | "bool" => matches!(
            method,
            "__repr__"
                | "__str__"
                | "__eq__"
                | "__ne__"
                | "__lt__"
                | "__le__"
                | "__gt__"
                | "__ge__"
                | "__hash__"
        ),
        "tuple" => matches!(method, "__repr__" | "__hash__"),
        "defaultdict" => matches!(method, "__repr__" | "__getattribute__" | "__init__"),
        "io" => matches!(method, "BytesIO.__iter__" | "BytesIO.__next__"),
        "super" => is_super_wrapper_descriptor_name(method),
        _ => false,
    }
}

fn is_builtin_classmethod_descriptor_name(name: &str) -> bool {
    matches!(
        name,
        "int.from_bytes.classmethod_descriptor"
            | "defaultdict.__class_getitem__.classmethod_descriptor"
    )
}

