#[derive(Default)]
struct SortedOptions {
    key: Option<Value>,
    reverse: Option<bool>,
}

#[derive(Clone)]
struct SortItem {
    value: Value,
    key: Value,
}

fn sorted_options(
    vm: &mut Vm,
    positional_count: usize,
    keywords: Vec<(String, Value)>,
) -> Result<SortedOptions, String> {
    let mut options = SortedOptions::default();
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "key" => {
                if options.key.is_some() {
                    return Err(
                        "sorted() got multiple values for keyword argument 'key'".to_string()
                    );
                }
                options.key = Some(value);
            }
            "reverse" => {
                if options.reverse.is_some() {
                    return Err(
                        "sorted() got multiple values for keyword argument 'reverse'".to_string(),
                    );
                }
                options.reverse = Some(sorted_reverse_option(vm, value)?);
            }
            "iterable" if positional_count == 0 => {
                return Err("TypeError: sorted expected 1 argument, got 0".to_string());
            }
            _ => {
                return Err(format!(
                    "TypeError: '{keyword}' is an invalid keyword argument for sort()"
                ));
            }
        }
    }
    Ok(options)
}

fn list_sort_options(vm: &mut Vm, keywords: Vec<(String, Value)>) -> Result<SortedOptions, String> {
    let mut options = SortedOptions::default();
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "key" => {
                if options.key.is_some() {
                    return Err("sort() got multiple values for keyword argument 'key'".to_string());
                }
                options.key = Some(value);
            }
            "reverse" => {
                if options.reverse.is_some() {
                    return Err(
                        "sort() got multiple values for keyword argument 'reverse'".to_string()
                    );
                }
                options.reverse = Some(sorted_reverse_option(vm, value)?);
            }
            _ => {
                return Err(format!(
                    "'{keyword}' is an invalid keyword argument for sort()"
                ));
            }
        }
    }
    Ok(options)
}

fn sorted_reverse_option(vm: &mut Vm, value: Value) -> Result<bool, String> {
    vm.truth_value(value)
}

fn divmod_error_message(message: &str, left: Value, right: Value) -> String {
    if is_zero_division_error_message(message) {
        return message.to_string();
    }
    if message.starts_with("TypeError: ")
        && !message.starts_with("TypeError: unsupported operand type(s) for //")
        && !message.starts_with("TypeError: unsupported operand type(s) for %")
    {
        return message.to_string();
    }
    format!(
        "TypeError: unsupported operand type(s) for divmod(): '{}' and '{}'",
        type_name(&left),
        type_name(&right)
    )
}

fn call_template_convert(vm: &mut Vm, args: Vec<Value>) -> Result<Value, String> {
    let [value, conversion] = args.as_slice() else {
        return Err(format!(
            "TypeError: convert() expected 2 arguments, got {}",
            args.len()
        ));
    };

    match conversion {
        Value::None => Ok(value.clone()),
        Value::String(conversion) if conversion == "r" => {
            Ok(Value::String(repr_value_checked(value)?))
        }
        Value::String(conversion) if conversion == "s" => Ok(Value::String(vm.str_value(value)?)),
        Value::String(conversion) if conversion == "a" => {
            Ok(Value::String(ascii_repr_value_checked(value)?))
        }
        conversion => Err(format!(
            "ValueError: invalid conversion specifier: {conversion}"
        )),
    }
}

fn call_template_constructor(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err("TypeError: Template.__new__ only accepts *args arguments".to_string());
    }

    let mut strings: Vec<String> = Vec::new();
    let mut interpolations: Vec<TemplateInterpolation> = Vec::new();
    let mut last_was_str = false;

    for arg in args {
        match arg {
            Value::String(value) => {
                if last_was_str {
                    strings
                        .last_mut()
                        .expect("template constructor has a previous string")
                        .push_str(&value);
                } else {
                    strings.push(value);
                }
                last_was_str = true;
            }
            Value::TemplateInterpolation(interpolation) => {
                if !last_was_str {
                    strings.push(String::new());
                }
                interpolations.push(interpolation);
                last_was_str = false;
            }
            value => {
                return Err(format!(
                    "TypeError: Template.__new__ *args need to be of type 'str' or 'Interpolation', got {}",
                    type_name(&value)
                ));
            }
        }
    }

    if !last_was_str {
        strings.push(String::new());
    }

    Ok(Value::Template {
        strings,
        interpolations,
    })
}

fn call_interpolation_constructor(
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if args.len() > 4 {
        return Err(format!(
            "TypeError: Interpolation() expected at most 4 arguments, got {}",
            args.len()
        ));
    }

    let mut values = vec![None, None, None, None];
    for (index, value) in args.into_iter().enumerate() {
        values[index] = Some(value);
    }

    for (name, value) in keywords {
        let Some(index) = interpolation_argument_index(&name) else {
            return Err(format!(
                "TypeError: Interpolation() got an unexpected keyword argument '{name}'"
            ));
        };
        if values[index].is_some() {
            return Err(format!(
                "TypeError: Interpolation() got multiple values for argument '{name}'"
            ));
        }
        values[index] = Some(value);
    }

    let value = values[0].take().ok_or_else(|| {
        "TypeError: Interpolation() missing required argument 'value'".to_string()
    })?;
    let expression = template_string_argument(
        values[1]
            .take()
            .unwrap_or_else(|| Value::String(String::new())),
        "expression",
    )?;
    let conversion = template_conversion_argument(values[2].take().unwrap_or(Value::None))?;
    let format_spec = template_string_argument(
        values[3]
            .take()
            .unwrap_or_else(|| Value::String(String::new())),
        "format_spec",
    )?;

    Ok(Value::TemplateInterpolation(TemplateInterpolation {
        value: Box::new(value),
        expression,
        conversion,
        format_spec,
    }))
}

fn interpolation_argument_index(name: &str) -> Option<usize> {
    match name {
        "value" => Some(0),
        "expression" => Some(1),
        "conversion" => Some(2),
        "format_spec" => Some(3),
        _ => None,
    }
}

fn template_string_argument(value: Value, name: &str) -> Result<String, String> {
    match value {
        Value::String(value) => Ok(value),
        value => Err(format!(
            "TypeError: Interpolation() argument '{name}' must be str, not {}",
            type_name(&value)
        )),
    }
}

fn template_conversion_argument(value: Value) -> Result<Option<String>, String> {
    match value {
        Value::None => Ok(None),
        Value::String(value) if matches!(value.as_str(), "a" | "r" | "s") => Ok(Some(value)),
        Value::String(_) => Err(
            "ValueError: Interpolation() argument 'conversion' must be one of 's', 'a' or 'r'"
                .to_string(),
        ),
        value => Err(format!(
            "TypeError: Interpolation() argument 'conversion' must be str, not {}",
            type_name(&value)
        )),
    }
}

enum RoundNdigits {
    Finite(i64),
    TooLargePositive,
    TooLargeNegative,
}

fn round_ndigits_value(value: Value) -> Result<RoundNdigits, String> {
    match value {
        Value::Number(value) => Ok(RoundNdigits::Finite(value)),
        Value::BigInt(value) => match value.to_i64() {
            Some(value) => Ok(RoundNdigits::Finite(value)),
            None if value.is_negative() => Ok(RoundNdigits::TooLargeNegative),
            None => Ok(RoundNdigits::TooLargePositive),
        },
        value => Err(format!(
            "TypeError: ndigits must be an integer, got {}",
            type_name(&value)
        )),
    }
}

fn round_float_to_int(value: f64) -> Result<Value, String> {
    if value.is_nan() {
        return Err("ValueError: cannot convert float NaN to integer".to_string());
    }
    if value.is_infinite() {
        return Err("OverflowError: cannot convert float infinity to integer".to_string());
    }

    let rounded = round_ties_to_even(value);
    if rounded >= i64::MIN as f64 && rounded <= i64::MAX as f64 {
        Ok(Value::Number(rounded as i64))
    } else {
        Ok(normalize_big_int(BigInt::from(rounded as i128)))
    }
}

fn round_float_to_ndigits(value: f64, ndigits: i64) -> Result<f64, String> {
    const NDIGITS_MAX: i64 = 323;
    const NDIGITS_MIN: i64 = -308;

    if !value.is_finite() {
        return Ok(value);
    }
    if ndigits > NDIGITS_MAX {
        return Ok(value);
    }
    if ndigits < NDIGITS_MIN {
        return Ok(signed_zero_like(value));
    }

    if value == 0.0 {
        return Ok(value);
    }

    let negative = value.is_sign_negative();
    let (mantissa, binary_exponent) = positive_float_components(value.abs());
    let rounded_units = rounded_decimal_units(&mantissa, binary_exponent, ndigits);
    if rounded_units.is_zero() {
        return Ok(signed_zero_like(value));
    }

    let result = if ndigits >= 0 {
        let denominator = BigUint::from(10u8).pow(ndigits as u32);
        positive_rational_to_f64(&rounded_units, &denominator)?
    } else {
        let scale = BigUint::from(10u8).pow((-ndigits) as u32);
        let numerator = rounded_units * scale;
        rounded_hex_float_value(&numerator, 0)
            .map_err(|_| "OverflowError: rounded value too large to represent".to_string())?
    };

    Ok(if negative { -result } else { result })
}

fn signed_zero_like(value: f64) -> f64 {
    if value.is_sign_negative() { -0.0 } else { 0.0 }
}

fn positive_float_components(value: f64) -> (BigUint, i64) {
    let bits = value.to_bits();
    let exponent_bits = ((bits >> 52) & 0x7ff) as i64;
    let fraction_bits = bits & ((1_u64 << 52) - 1);
    if exponent_bits == 0 {
        (BigUint::from(fraction_bits), -1074)
    } else {
        (
            BigUint::from((1_u64 << 52) | fraction_bits),
            exponent_bits - 1023 - 52,
        )
    }
}

fn rounded_decimal_units(mantissa: &BigUint, binary_exponent: i64, ndigits: i64) -> BigUint {
    if ndigits >= 0 {
        let decimal_exponent = ndigits as u32;
        let mut numerator = mantissa * BigUint::from(5u8).pow(decimal_exponent);
        let binary_scale = binary_exponent + ndigits;
        let denominator = if binary_scale >= 0 {
            numerator <<= usize::try_from(binary_scale).unwrap_or(usize::MAX);
            BigUint::from(1u8)
        } else {
            BigUint::from(1u8) << usize::try_from(-binary_scale).unwrap_or(usize::MAX)
        };
        round_biguint_div_even(numerator, denominator)
    } else {
        let decimal_exponent = (-ndigits) as u32;
        let mut numerator = mantissa.clone();
        let mut denominator = BigUint::from(5u8).pow(decimal_exponent);
        let binary_scale = binary_exponent + ndigits;
        if binary_scale >= 0 {
            numerator <<= usize::try_from(binary_scale).unwrap_or(usize::MAX);
        } else {
            denominator <<= usize::try_from(-binary_scale).unwrap_or(usize::MAX);
        }
        round_biguint_div_even(numerator, denominator)
    }
}

fn positive_rational_to_f64(numerator: &BigUint, denominator: &BigUint) -> Result<f64, String> {
    if numerator.is_zero() {
        return Ok(0.0);
    }

    let mut exponent = rational_floor_log2(numerator, denominator);
    if exponent > 1023 {
        return Err("OverflowError: rounded value too large to represent".to_string());
    }

    if exponent >= -1022 {
        let mut significand = round_rational_scaled_even(numerator, denominator, 52 - exponent);
        if significand.bits() > 53 {
            significand >>= 1usize;
            exponent += 1;
            if exponent > 1023 {
                return Err("OverflowError: rounded value too large to represent".to_string());
            }
        }
        let significand = significand
            .to_u64()
            .ok_or_else(|| "OverflowError: rounded value too large to represent".to_string())?;
        let exponent_bits = ((exponent + 1023) as u64) << 52;
        let fraction = significand & 0x000f_ffff_ffff_ffff;
        return Ok(f64::from_bits(exponent_bits | fraction));
    }

    let units = round_rational_scaled_even(numerator, denominator, 1074);
    if units.is_zero() {
        return Ok(0.0);
    }
    rounded_hex_float_value(&units, -1074)
        .map_err(|_| "OverflowError: rounded value too large to represent".to_string())
}

fn rational_floor_log2(numerator: &BigUint, denominator: &BigUint) -> i64 {
    let mut exponent = i64::try_from(numerator.bits()).unwrap_or(i64::MAX)
        - i64::try_from(denominator.bits()).unwrap_or(i64::MAX);
    while compare_rational_power_of_two(numerator, denominator, exponent) == Ordering::Less {
        exponent -= 1;
    }
    while compare_rational_power_of_two(numerator, denominator, exponent + 1) != Ordering::Less {
        exponent += 1;
    }
    exponent
}

fn compare_rational_power_of_two(
    numerator: &BigUint,
    denominator: &BigUint,
    exponent: i64,
) -> Ordering {
    if exponent >= 0 {
        numerator.cmp(&(denominator << usize::try_from(exponent).unwrap_or(usize::MAX)))
    } else {
        (numerator << usize::try_from(-exponent).unwrap_or(usize::MAX)).cmp(denominator)
    }
}

fn round_rational_scaled_even(
    numerator: &BigUint,
    denominator: &BigUint,
    binary_scale: i64,
) -> BigUint {
    if binary_scale >= 0 {
        round_biguint_div_even(
            numerator << usize::try_from(binary_scale).unwrap_or(usize::MAX),
            denominator.clone(),
        )
    } else {
        round_biguint_div_even(
            numerator.clone(),
            denominator << usize::try_from(-binary_scale).unwrap_or(usize::MAX),
        )
    }
}

fn round_biguint_div_even(numerator: BigUint, denominator: BigUint) -> BigUint {
    let (mut quotient, remainder) = numerator.div_rem(&denominator);
    let twice_remainder = &remainder << 1usize;
    let one = BigUint::from(1u8);
    let quotient_is_odd = (&quotient & &one) == one;
    if twice_remainder > denominator || (twice_remainder == denominator && quotient_is_odd) {
        quotient += one;
    }
    quotient
}

fn round_ties_to_even(value: f64) -> f64 {
    let floor = value.floor();
    let fraction = value - floor;
    if fraction < 0.5 {
        floor
    } else if fraction > 0.5 {
        floor + 1.0
    } else if (floor as i128) % 2 == 0 {
        floor
    } else {
        floor + 1.0
    }
}

fn round_big_int_to_ndigits(value: BigInt, ndigits: i64) -> Value {
    if ndigits >= 0 || value.is_zero() {
        return normalize_big_int(value);
    }

    let Ok(places) = u32::try_from(-ndigits) else {
        return Value::Number(0);
    };
    if places > 1000 {
        return Value::Number(0);
    }

    let factor = BigInt::from(10).pow(places);
    let sign = if value.is_negative() { -1 } else { 1 };
    let abs_value = value.abs();
    let quotient = &abs_value / &factor;
    let remainder = &abs_value % &factor;
    let twice_remainder = &remainder * BigInt::from(2);
    let rounded_quotient = match twice_remainder.cmp(&factor) {
        Ordering::Less => quotient,
        Ordering::Greater => quotient + 1,
        Ordering::Equal if quotient.is_odd() => quotient + 1,
        Ordering::Equal => quotient,
    };
    let rounded = rounded_quotient * factor * BigInt::from(sign);
    normalize_big_int(rounded)
}

fn call_sqrt(args: Vec<Value>) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!(
            "TypeError: math.sqrt() takes exactly one argument ({} given)",
            args.len()
        ));
    };

    let value = math_real_as_f64(value)?;

    if value < 0.0 {
        return Err(format!(
            "ValueError: expected a nonnegative input, got {value}"
        ));
    }

    Ok(float_value(value.sqrt()))
}

