fn call_math_unit_interval(
    vm: &mut Vm,
    args: Vec<Value>,
    function_name: &str,
    op: fn(f64) -> f64,
) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!(
            "TypeError: {function_name}() expected 1 argument, got {}",
            args.len()
        ));
    };

    let value = math_real_number_as_f64(vm, value.clone())?;
    if !value.is_nan() && !(-1.0..=1.0).contains(&value) {
        return Err(format!(
            "ValueError: expected a number in range from -1 up to 1, got {value}"
        ));
    }

    Ok(float_value(op(value)))
}

fn call_math_at_least_one(
    vm: &mut Vm,
    args: Vec<Value>,
    function_name: &str,
    op: fn(f64) -> f64,
) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!(
            "TypeError: {function_name}() expected 1 argument, got {}",
            args.len()
        ));
    };

    let value = math_real_number_as_f64(vm, value.clone())?;
    if !value.is_nan() && value < 1.0 {
        return Err(format!(
            "ValueError: expected argument value not less than 1, got {value}"
        ));
    }

    Ok(float_value(op(value)))
}

fn call_math_open_unit_interval(
    vm: &mut Vm,
    args: Vec<Value>,
    function_name: &str,
    op: fn(f64) -> f64,
) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!(
            "TypeError: {function_name}() expected 1 argument, got {}",
            args.len()
        ));
    };

    let value = math_real_number_as_f64(vm, value.clone())?;
    if !value.is_nan() && (value <= -1.0 || value >= 1.0) {
        return Err(format!(
            "ValueError: expected a number between -1 and 1, got {value}"
        ));
    }

    Ok(float_value(op(value)))
}

fn call_math_finite_unary(
    vm: &mut Vm,
    args: Vec<Value>,
    function_name: &str,
    op: fn(f64) -> f64,
) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!(
            "TypeError: {function_name}() expected 1 argument, got {}",
            args.len()
        ));
    };

    let value = math_real_number_as_f64(vm, value.clone())?;
    if value.is_infinite() {
        return Err(format!("ValueError: expected a finite input, got {value}"));
    }

    Ok(float_value(op(value)))
}

fn call_math_overflowing_unary(
    vm: &mut Vm,
    args: Vec<Value>,
    function_name: &str,
    op: fn(f64) -> f64,
) -> Result<Value, String> {
    let [value] = args.as_slice() else {
        return Err(format!(
            "TypeError: {function_name}() expected 1 argument, got {}",
            args.len()
        ));
    };

    let value = math_real_number_as_f64(vm, value.clone())?;
    let result = op(value);
    if value.is_finite() && result.is_infinite() {
        return Err("OverflowError: math range error".to_string());
    }

    Ok(float_value(result))
}

