fn is_bytes_justify_method(name: &str) -> bool {
    matches!(
        name,
        "bytes.ljust"
            | "bytes.rjust"
            | "bytes.center"
            | "bytearray.ljust"
            | "bytearray.rjust"
            | "bytearray.center"
    )
}

fn is_bytes_translate_method(name: &str) -> bool {
    matches!(name, "bytes.translate" | "bytearray.translate")
}

fn is_bytes_replace_method(name: &str) -> bool {
    matches!(name, "bytes.replace" | "bytearray.replace")
}

fn is_bytes_partition_method(name: &str) -> bool {
    matches!(
        name,
        "bytes.partition" | "bytes.rpartition" | "bytearray.partition" | "bytearray.rpartition"
    )
}

fn is_bytes_percent_method(name: &str) -> bool {
    matches!(
        name,
        "bytes.__mod__" | "bytes.__rmod__" | "bytearray.__mod__" | "bytearray.__rmod__"
    )
}

fn is_bytes_format_method(name: &str) -> bool {
    matches!(name, "bytes.__format__" | "bytearray.__format__")
}

fn is_bytes_dunder_bytes_method(name: &str) -> bool {
    name == "bytes.__bytes__"
}

fn call_bytes_dunder_bytes_method(
    _name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err("TypeError: bytes.__bytes__() takes no keyword arguments".to_string());
    }
    let [receiver] = args.as_slice() else {
        return Err(format!(
            "TypeError: __bytes__() expected 0 arguments, got {}",
            method_arg_count(&args)
        ));
    };

    match receiver {
        Value::Bytes(bytes) => Ok(Value::Bytes(bytes.clone())),
        value if bytes_subclass_bytes(value).is_some() => Ok(bytes_value(
            bytes_subclass_bytes(value).expect("bytes subclass storage exists after guard"),
        )),
        value => Err(format!(
            "TypeError: descriptor '__bytes__' requires a 'bytes' object but received a '{}'",
            type_name(value)
        )),
    }
}

fn call_bytes_format_method(
    _name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<String, String> {
    if !keywords.is_empty() {
        return Err("TypeError: object.__format__() takes no keyword arguments".to_string());
    }
    let [receiver, format_spec] = args.as_slice() else {
        return Err(format!(
            "TypeError: object.__format__() takes exactly one argument ({} given)",
            method_arg_count(&args)
        ));
    };
    let format_spec = dunder_format_spec_string(format_spec)?;
    format_bytes_like_value(receiver, &format_spec)
}

fn dunder_format_spec_string(value: &Value) -> Result<String, String> {
    match value {
        Value::String(value) | Value::IdentityString { value, .. } => Ok(value.clone()),
        value if str_subclass_string(value).is_some() => {
            Ok(str_subclass_string(value).expect("str subclass storage exists after guard"))
        }
        value => Err(format!(
            "TypeError: __format__() argument must be str, not {}",
            type_name(value)
        )),
    }
}

fn call_bytes_percent_method(
    vm: &mut Vm,
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;
    let [receiver, other] = args.as_slice() else {
        return Err(format!(
            "TypeError: {}() expected 1 argument, got {}",
            method_display_name(name),
            method_arg_count(&args)
        ));
    };

    match name {
        "bytes.__mod__" => {
            let format = match receiver {
                Value::Bytes(bytes) => bytes.as_ref().clone(),
                value if bytes_subclass_bytes(value).is_some() => {
                    bytes_subclass_bytes(value).expect("bytes subclass storage exists after guard")
                }
                value => {
                    return Err(format!(
                        "TypeError: descriptor '__mod__' requires a 'bytes' object but received a '{}'",
                        type_name(value)
                    ));
                }
            };
            percent_format_bytes(Some(vm), &format, other.clone(), BytesResultKind::Bytes)
        }
        "bytearray.__mod__" => {
            let Some(storage) = bytearray_storage(receiver) else {
                return Err(format!(
                    "TypeError: descriptor '__mod__' requires a 'bytearray' object but received a '{}'",
                    type_name(receiver)
                ));
            };
            let _format_export = ByteArrayExportGuard::new(&storage);
            let format = bytearray_bytes(&storage);
            percent_format_bytes(Some(vm), &format, other.clone(), BytesResultKind::ByteArray)
        }
        "bytes.__rmod__" => {
            if matches!(receiver, Value::Bytes(_)) || bytes_subclass_bytes(receiver).is_some() {
                Ok(Value::NotImplemented)
            } else {
                Err(format!(
                    "TypeError: descriptor '__rmod__' requires a 'bytes' object but received a '{}'",
                    type_name(receiver)
                ))
            }
        }
        "bytearray.__rmod__" => {
            if bytearray_storage(receiver).is_some() {
                Ok(Value::NotImplemented)
            } else {
                Err(format!(
                    "TypeError: descriptor '__rmod__' requires a 'bytearray' object but received a '{}'",
                    type_name(receiver)
                ))
            }
        }
        _ => unreachable!("caller filters bytes percent methods"),
    }
}

#[derive(Clone, Copy)]
enum BytesResultKind {
    Bytes,
    ByteArray,
}

enum DunderBytesResult {
    Missing,
    Value(Value),
    Raised,
}

fn bytes_split_separator(
    receiver: &[u8],
    separator: &[u8],
    maxsplit: i64,
    reverse: bool,
) -> Vec<Vec<u8>> {
    if reverse {
        bytes_rsplit_separator(receiver, separator, maxsplit)
    } else {
        bytes_split_separator_forward(receiver, separator, maxsplit)
    }
}

fn bytes_split_separator_forward(receiver: &[u8], separator: &[u8], maxsplit: i64) -> Vec<Vec<u8>> {
    let limit = limited_replacement_count(maxsplit);
    if matches!(limit, Some(0)) {
        return vec![receiver.to_vec()];
    }

    let mut parts = Vec::new();
    let mut start = 0usize;
    let mut index = 0usize;
    let mut splits = 0usize;
    while index + separator.len() <= receiver.len() {
        if limit.is_some_and(|limit| splits >= limit) {
            break;
        }
        if receiver[index..index + separator.len()] == *separator {
            parts.push(receiver[start..index].to_vec());
            splits += 1;
            index += separator.len();
            start = index;
        } else {
            index += 1;
        }
    }
    parts.push(receiver[start..].to_vec());
    parts
}

fn bytes_rsplit_separator(receiver: &[u8], separator: &[u8], maxsplit: i64) -> Vec<Vec<u8>> {
    let limit = limited_replacement_count(maxsplit);
    if matches!(limit, Some(0)) {
        return vec![receiver.to_vec()];
    }

    let mut parts = Vec::new();
    let mut end = receiver.len();
    let mut search_end = receiver.len();
    let mut splits = 0usize;
    while search_end >= separator.len() {
        if limit.is_some_and(|limit| splits >= limit) {
            break;
        }
        let Some(position) = (0..=search_end - separator.len())
            .rev()
            .find(|position| receiver[*position..*position + separator.len()] == *separator)
        else {
            break;
        };
        parts.push(receiver[position + separator.len()..end].to_vec());
        splits += 1;
        end = position;
        search_end = position;
    }
    parts.push(receiver[..end].to_vec());
    parts.reverse();
    parts
}

fn bytes_split_whitespace(receiver: &[u8], maxsplit: i64, reverse: bool) -> Vec<Vec<u8>> {
    if reverse {
        bytes_rsplit_whitespace(receiver, maxsplit)
    } else {
        bytes_split_whitespace_forward(receiver, maxsplit)
    }
}

fn bytes_split_whitespace_forward(receiver: &[u8], maxsplit: i64) -> Vec<Vec<u8>> {
    let limit = limited_replacement_count(maxsplit);
    let mut parts = Vec::new();
    let mut index = 0usize;
    let mut splits = 0usize;

    while index < receiver.len() && is_bytes_whitespace(receiver[index]) {
        index += 1;
    }

    while index < receiver.len() {
        if limit.is_some_and(|limit| splits >= limit) {
            parts.push(receiver[index..].to_vec());
            return parts;
        }

        let start = index;
        while index < receiver.len() && !is_bytes_whitespace(receiver[index]) {
            index += 1;
        }
        parts.push(receiver[start..index].to_vec());

        while index < receiver.len() && is_bytes_whitespace(receiver[index]) {
            index += 1;
        }
        if index < receiver.len() {
            splits += 1;
        }
    }

    parts
}

fn bytes_rsplit_whitespace(receiver: &[u8], maxsplit: i64) -> Vec<Vec<u8>> {
    let limit = limited_replacement_count(maxsplit);
    let mut parts = Vec::new();
    let mut end = receiver.len();
    let mut splits = 0usize;

    while end > 0 && is_bytes_whitespace(receiver[end - 1]) {
        end -= 1;
    }

    while end > 0 {
        if limit.is_some_and(|limit| splits >= limit) {
            parts.push(receiver[..end].to_vec());
            parts.reverse();
            return parts;
        }

        let part_end = end;
        while end > 0 && !is_bytes_whitespace(receiver[end - 1]) {
            end -= 1;
        }
        parts.push(receiver[end..part_end].to_vec());

        while end > 0 && is_bytes_whitespace(receiver[end - 1]) {
            end -= 1;
        }
        if end > 0 {
            splits += 1;
        }
    }

    parts.reverse();
    parts
}

fn is_bytes_whitespace(byte: u8) -> bool {
    matches!(byte, b'\t' | b'\n' | 0x0b | 0x0c | b'\r' | b' ')
}

fn bytes_split_maxsplit_argument(value: &Value, method: &str) -> Result<i64, String> {
    match string_split_maxsplit_argument(value, method) {
        Ok(value) => Ok(value),
        Err(error) if error.contains(" maxsplit must be an integer, not ") => {
            Err(bytes_integer_argument_error(value))
        }
        Err(error) => Err(error),
    }
}

fn call_bytes_splitlines_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(bytes_method_unbound_error(name));
    };
    if rest.len() + keywords.len() > 1 {
        return Err(format!(
            "TypeError: {method}() takes at most 1 argument ({} given)",
            rest.len() + keywords.len()
        ));
    }

    let keepends = match (rest, keywords.as_slice()) {
        ([], []) => false,
        ([value], []) => is_truthy(value)?,
        ([], [(keyword, value)]) if keyword == "keepends" => is_truthy(value)?,
        ([], [(keyword, _)]) => {
            return Err(format!(
                "TypeError: '{keyword}' is an invalid keyword argument for {method}()"
            ));
        }
        _ => unreachable!("splitlines arity checked above"),
    };

    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    Ok(list_value(
        bytes_splitlines(&receiver, keepends)
            .into_iter()
            .map(|line| bytes_result_value(kind, line))
            .collect(),
    ))
}

fn bytes_splitlines(receiver: &[u8], keepends: bool) -> Vec<Vec<u8>> {
    let mut lines = Vec::new();
    let mut line_start = 0usize;
    let mut index = 0usize;

    while index < receiver.len() {
        let Some(line_break_end) = bytes_line_break_end(receiver, index) else {
            index += 1;
            continue;
        };
        let line_end = if keepends { line_break_end } else { index };
        lines.push(receiver[line_start..line_end].to_vec());
        index = line_break_end;
        line_start = line_break_end;
    }

    if line_start < receiver.len() {
        lines.push(receiver[line_start..].to_vec());
    }

    lines
}

fn bytes_line_break_end(receiver: &[u8], index: usize) -> Option<usize> {
    match receiver[index] {
        b'\n' => Some(index + 1),
        b'\r' if receiver.get(index + 1) == Some(&b'\n') => Some(index + 2),
        b'\r' => Some(index + 1),
        _ => None,
    }
}

fn call_bytes_ascii_case_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;
    let method = method_display_name(name);
    let [receiver] = args.as_slice() else {
        if args.is_empty() {
            return Err(bytes_method_unbound_error(name));
        }
        return Err(bytes_method_no_arg_error(name, method_arg_count(&args)));
    };
    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    let value = match method {
        "lower" => bytes_ascii_lower(&receiver),
        "upper" => bytes_ascii_upper(&receiver),
        "capitalize" => bytes_ascii_capitalize(&receiver),
        "title" => bytes_ascii_title(&receiver),
        "swapcase" => bytes_ascii_swapcase(&receiver),
        _ => unreachable!("byte ASCII case method checked before dispatch"),
    };
    Ok(bytes_result_value(kind, value))
}

fn call_bytes_ascii_predicate_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;
    let method = method_display_name(name);
    let [receiver] = args.as_slice() else {
        if args.is_empty() {
            return Err(bytes_method_unbound_error(name));
        }
        return Err(bytes_method_no_arg_error(name, method_arg_count(&args)));
    };
    let (receiver, _) = bytes_method_receiver(receiver, method)?;
    let value = match method {
        "islower" => bytes_ascii_islower(&receiver),
        "isupper" => bytes_ascii_isupper(&receiver),
        "istitle" => bytes_ascii_istitle(&receiver),
        "isspace" => !receiver.is_empty() && receiver.iter().copied().all(is_bytes_whitespace),
        "isalpha" => !receiver.is_empty() && receiver.iter().copied().all(is_ascii_alpha_byte),
        "isalnum" => !receiver.is_empty() && receiver.iter().copied().all(is_ascii_alnum_byte),
        "isdigit" => !receiver.is_empty() && receiver.iter().copied().all(is_ascii_digit_byte),
        "isascii" => receiver.iter().all(u8::is_ascii),
        _ => unreachable!("byte ASCII predicate method checked before dispatch"),
    };
    Ok(Value::Bool(value))
}

fn bytes_ascii_lower(bytes: &[u8]) -> Vec<u8> {
    bytes.iter().copied().map(ascii_lower_byte).collect()
}

fn bytes_ascii_upper(bytes: &[u8]) -> Vec<u8> {
    bytes.iter().copied().map(ascii_upper_byte).collect()
}

fn bytes_ascii_capitalize(bytes: &[u8]) -> Vec<u8> {
    let Some((&first, rest)) = bytes.split_first() else {
        return Vec::new();
    };
    let mut value = Vec::with_capacity(bytes.len());
    value.push(ascii_upper_byte(first));
    value.extend(rest.iter().copied().map(ascii_lower_byte));
    value
}

fn bytes_ascii_title(bytes: &[u8]) -> Vec<u8> {
    let mut value = Vec::with_capacity(bytes.len());
    let mut previous_cased = false;
    for byte in bytes.iter().copied() {
        if is_ascii_alpha_byte(byte) {
            value.push(if previous_cased {
                ascii_lower_byte(byte)
            } else {
                ascii_upper_byte(byte)
            });
            previous_cased = true;
        } else {
            value.push(byte);
            previous_cased = false;
        }
    }
    value
}

fn bytes_ascii_swapcase(bytes: &[u8]) -> Vec<u8> {
    bytes.iter().copied().map(ascii_swapcase_byte).collect()
}

fn bytes_ascii_islower(bytes: &[u8]) -> bool {
    let mut has_cased = false;
    for byte in bytes.iter().copied() {
        if is_ascii_upper_byte(byte) {
            return false;
        }
        if is_ascii_lower_byte(byte) {
            has_cased = true;
        }
    }
    has_cased
}

fn bytes_ascii_isupper(bytes: &[u8]) -> bool {
    let mut has_cased = false;
    for byte in bytes.iter().copied() {
        if is_ascii_lower_byte(byte) {
            return false;
        }
        if is_ascii_upper_byte(byte) {
            has_cased = true;
        }
    }
    has_cased
}

fn bytes_ascii_istitle(bytes: &[u8]) -> bool {
    let mut has_cased = false;
    let mut previous_cased = false;
    for byte in bytes.iter().copied() {
        if is_ascii_upper_byte(byte) {
            if previous_cased {
                return false;
            }
            has_cased = true;
            previous_cased = true;
        } else if is_ascii_lower_byte(byte) {
            if !previous_cased {
                return false;
            }
            has_cased = true;
            previous_cased = true;
        } else {
            previous_cased = false;
        }
    }
    has_cased
}

fn ascii_lower_byte(byte: u8) -> u8 {
    if is_ascii_upper_byte(byte) {
        byte + 32
    } else {
        byte
    }
}

fn ascii_upper_byte(byte: u8) -> u8 {
    if is_ascii_lower_byte(byte) {
        byte - 32
    } else {
        byte
    }
}

fn ascii_swapcase_byte(byte: u8) -> u8 {
    if is_ascii_lower_byte(byte) {
        ascii_upper_byte(byte)
    } else if is_ascii_upper_byte(byte) {
        ascii_lower_byte(byte)
    } else {
        byte
    }
}

fn is_ascii_lower_byte(byte: u8) -> bool {
    byte.is_ascii_lowercase()
}

fn is_ascii_upper_byte(byte: u8) -> bool {
    byte.is_ascii_uppercase()
}

fn is_ascii_alpha_byte(byte: u8) -> bool {
    byte.is_ascii_alphabetic()
}

fn is_ascii_digit_byte(byte: u8) -> bool {
    byte.is_ascii_digit()
}

fn is_ascii_alnum_byte(byte: u8) -> bool {
    byte.is_ascii_alphanumeric()
}

fn call_bytes_expandtabs_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(bytes_method_unbound_error(name));
    };
    if rest.len() + keywords.len() > 1 {
        return Err(format!(
            "TypeError: {method}() takes at most 1 argument ({} given)",
            rest.len() + keywords.len()
        ));
    }

    let tabsize = match (rest, keywords.as_slice()) {
        ([], []) => 8,
        ([value], []) => bytes_tabsize_argument(value)?,
        ([], [(keyword, value)]) if keyword == "tabsize" => bytes_tabsize_argument(value)?,
        ([], [(keyword, _)]) => {
            return Err(format!(
                "TypeError: '{keyword}' is an invalid keyword argument for {method}()"
            ));
        }
        _ => unreachable!("expandtabs arity checked above"),
    };

    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    Ok(bytes_result_value(
        kind,
        bytes_expandtabs(&receiver, tabsize)?,
    ))
}

fn call_bytes_zfill_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;
    let method = method_display_name(name);
    let [receiver, width] = args.as_slice() else {
        if args.is_empty() {
            return Err(bytes_method_unbound_error(name));
        }
        return Err(bytes_method_exactly_one_arg_error(
            name,
            method_arg_count(&args),
        ));
    };
    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    let width = bytes_width_argument(width, method)?;
    Ok(bytes_result_value(kind, bytes_zfill(&receiver, width)))
}

fn bytes_expandtabs(receiver: &[u8], tabsize: i32) -> Result<Vec<u8>, String> {
    let mut expanded = Vec::new();
    let mut column = 0usize;
    let tabsize = usize::try_from(tabsize).unwrap_or(0);

    for byte in receiver.iter().copied() {
        match byte {
            b'\t' if tabsize == 0 => {}
            b'\t' => {
                let spaces = tabsize - (column % tabsize);
                expanded.extend(std::iter::repeat_n(b' ', spaces));
                column = column
                    .checked_add(spaces)
                    .ok_or_else(|| "OverflowError: expanded string is too long".to_string())?;
            }
            b'\n' | b'\r' => {
                expanded.push(byte);
                column = 0;
            }
            byte => {
                expanded.push(byte);
                column = column
                    .checked_add(1)
                    .ok_or_else(|| "OverflowError: expanded string is too long".to_string())?;
            }
        }
    }

    Ok(expanded)
}

fn bytes_zfill(receiver: &[u8], width: usize) -> Vec<u8> {
    if width <= receiver.len() {
        return receiver.to_vec();
    }

    let zeros = width - receiver.len();
    let mut output = Vec::with_capacity(width);
    if let Some((sign @ (b'+' | b'-'), rest)) = receiver.split_first() {
        output.push(*sign);
        output.extend(std::iter::repeat_n(b'0', zeros));
        output.extend_from_slice(rest);
    } else {
        output.extend(std::iter::repeat_n(b'0', zeros));
        output.extend_from_slice(receiver);
    }
    output
}

fn call_bytes_remove_affix_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;

    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(bytes_method_unbound_error(name));
    };
    if rest.len() != 1 {
        return Err(bytes_method_exactly_one_arg_error(name, rest.len()));
    }

    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    let affix = bytes_c_contiguous_method_argument(&rest[0], method, "first")?;
    let remove_prefix = method == "removeprefix";
    Ok(bytes_result_value(
        kind,
        bytes_remove_affix(&receiver, &affix, remove_prefix),
    ))
}

fn bytes_remove_affix(receiver: &[u8], affix: &[u8], remove_prefix: bool) -> Vec<u8> {
    if affix.is_empty() {
        return receiver.to_vec();
    }

    if remove_prefix && receiver.starts_with(affix) {
        return receiver[affix.len()..].to_vec();
    }

    if !remove_prefix && receiver.ends_with(affix) {
        return receiver[..receiver.len() - affix.len()].to_vec();
    }

    receiver.to_vec()
}

fn call_bytes_strip_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;

    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(bytes_method_unbound_error(name));
    };
    if rest.len() > 1 {
        return Err(bytes_method_expected_at_most_arg_error(
            method,
            1,
            rest.len(),
        ));
    }

    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    let strip_left = method != "rstrip";
    let strip_right = method != "lstrip";
    let stripped = match rest.first() {
        None | Some(Value::None) => {
            bytes_strip_by(&receiver, strip_left, strip_right, is_bytes_whitespace)
        }
        Some(value) => {
            let strip_bytes = bytes_c_contiguous_method_argument(value, method, "first")?;
            bytes_strip_by(&receiver, strip_left, strip_right, |byte| {
                strip_bytes.contains(&byte)
            })
        }
    };

    Ok(bytes_result_value(kind, stripped))
}

fn bytes_strip_by(
    receiver: &[u8],
    strip_left: bool,
    strip_right: bool,
    should_strip: impl Fn(u8) -> bool,
) -> Vec<u8> {
    let mut start = 0usize;
    let mut end = receiver.len();

    if strip_left {
        while start < end && should_strip(receiver[start]) {
            start += 1;
        }
    }

    if strip_right {
        while end > start && should_strip(receiver[end - 1]) {
            end -= 1;
        }
    }

    receiver[start..end].to_vec()
}

fn call_bytes_justify_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;

    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(bytes_method_unbound_error(name));
    };
    if rest.is_empty() {
        return Err(bytes_method_expected_at_least_arg_error(method, 1, 0));
    }
    if rest.len() > 2 {
        return Err(bytes_method_expected_at_most_arg_error(
            method,
            2,
            rest.len(),
        ));
    }

    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    let width = bytes_width_argument(&rest[0], method)?;
    if width <= receiver.len() {
        return Ok(bytes_result_value(kind, receiver));
    }

    let fill = match rest.get(1) {
        Some(value) => bytes_fill_character(value, method)?,
        None => b' ',
    };
    let padding = width - receiver.len();
    let mode = match method {
        "ljust" => JustifyMode::Left,
        "rjust" => JustifyMode::Right,
        _ => JustifyMode::Center,
    };
    let (left, right) = match mode {
        JustifyMode::Left => (0, padding),
        JustifyMode::Right => (padding, 0),
        JustifyMode::Center => (padding / 2, padding - padding / 2),
    };

    let mut output = Vec::with_capacity(width);
    output.extend(std::iter::repeat_n(fill, left));
    output.extend_from_slice(&receiver);
    output.extend(std::iter::repeat_n(fill, right));
    Ok(bytes_result_value(kind, output))
}

fn bytes_fill_character(value: &Value, method: &str) -> Result<u8, String> {
    let (kind, fill) = match value {
        Value::Bytes(value) => ("bytes", value.as_ref().clone()),
        value if bytes_subclass_bytes(value).is_some() => (
            "bytes",
            bytes_subclass_bytes(value).expect("bytes subclass storage exists after guard"),
        ),
        Value::ByteArray(value) => ("bytearray", bytearray_bytes(value)),
        value if bytearray_subclass_storage(value).is_some() => (
            "bytearray",
            bytearray_subclass_bytes(value).expect("bytearray subclass storage exists after guard"),
        ),
        value => {
            return Err(format!(
                "TypeError: {method}() argument 2 must be a byte string of length 1, not {}",
                type_name(value)
            ));
        }
    };
    match fill.as_slice() {
        [byte] => Ok(*byte),
        _ => Err(format!(
            "TypeError: {method}(): argument 2 must be a byte string of length 1, not a {kind} object of length {}",
            fill.len()
        )),
    }
}

fn call_bytes_maketrans(args: Vec<Value>) -> Result<Value, String> {
    let [from, to] = args.as_slice() else {
        return Err(format!(
            "TypeError: maketrans expected 2 arguments, got {}",
            args.len()
        ));
    };
    let from = bytes_c_contiguous_method_argument(from, "maketrans", "first")?;
    let to = bytes_c_contiguous_method_argument(to, "maketrans", "second")?;
    if from.len() != to.len() {
        return Err("ValueError: maketrans arguments must have same length".to_string());
    }

    let mut table = (0u8..=255).collect::<Vec<_>>();
    for (from, to) in from.into_iter().zip(to) {
        table[from as usize] = to;
    }
    Ok(bytes_value(table))
}

fn call_bytes_translate_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(format!(
            "TypeError: unbound method {name}() needs an argument"
        ));
    };
    if rest.is_empty() {
        return Err(format!(
            "TypeError: {method}() takes at least 1 positional argument (0 given)"
        ));
    }

    let mut delete = rest.get(1).cloned();
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "delete" => {
                if delete.is_some() || rest.len() > 1 {
                    return Err(format!(
                        "TypeError: {method}() expected at most 2 arguments, got {}",
                        rest.len() + 1
                    ));
                }
                delete = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: '{keyword}' is an invalid keyword argument for {method}()"
                ));
            }
        }
    }
    if rest.len() > 2 {
        return Err(format!(
            "TypeError: {method}() expected at most 2 arguments, got {}",
            rest.len()
        ));
    }

    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    let table = match &rest[0] {
        Value::None => None,
        value => {
            let table = bytes_c_contiguous_method_argument(value, method, "translation table")?;
            if table.len() != 256 {
                return Err("ValueError: translation table must be 256 characters long".to_string());
            }
            Some(table)
        }
    };
    let delete = match delete {
        Some(value) => bytes_c_contiguous_method_argument(&value, method, "delete")?,
        None => Vec::new(),
    };

    let mut output = Vec::with_capacity(receiver.len());
    for byte in receiver {
        if delete.contains(&byte) {
            continue;
        }
        output.push(table.as_ref().map_or(byte, |table| table[byte as usize]));
    }
    Ok(bytes_result_value(kind, output))
}

fn call_bytes_replace_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(bytes_method_unbound_error(name));
    };
    if rest.len() < 2 {
        return Err(bytes_method_expected_at_least_arg_error(
            method,
            2,
            rest.len(),
        ));
    }
    if rest.len() > 3 {
        return Err(bytes_method_expected_at_most_arg_error(
            method,
            3,
            rest.len(),
        ));
    }

    let mut count_arg = rest.get(2).cloned();
    for (keyword, value) in keywords {
        match keyword.as_str() {
            "count" => {
                if count_arg.is_some() {
                    return Err(format!(
                        "TypeError: {method}() got multiple values for argument 'count'"
                    ));
                }
                count_arg = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: '{keyword}' is an invalid keyword argument for {method}()"
                ));
            }
        }
    }

    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    let old = bytes_c_contiguous_method_argument(&rest[0], method, "first")?;
    let new = bytes_c_contiguous_method_argument(&rest[1], method, "second")?;
    let count = match count_arg.as_ref() {
        Some(value) => bytes_replace_count_argument(value, method)?,
        None => -1,
    };

    Ok(bytes_result_value(
        kind,
        bytes_replace(&receiver, &old, &new, count)?,
    ))
}

fn call_bytes_partition_method(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;

    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(bytes_method_unbound_error(name));
    };
    if rest.len() != 1 {
        return Err(bytes_method_exactly_one_arg_error(name, rest.len()));
    }

    let (receiver, kind) = bytes_method_receiver(receiver, method)?;
    if matches!(kind, BytesResultKind::Bytes) {
        if let Value::MemoryView(view) = &rest[0] {
            if !memoryview_is_contiguous(view)? {
                return Err(bytes_noncontiguous_memoryview_buffer_error());
            }
        }
    }
    let separator = bytes_like_method_argument(&rest[0], method, "first")?;
    if separator.is_empty() {
        return Err("ValueError: empty separator".to_string());
    }

    let len = i64::try_from(receiver.len()).map_err(|_| "bytes object is too large".to_string())?;
    let reverse = method == "rpartition";
    let index = bytes_find_index(&receiver, &separator, 0, len, reverse)?;

    if index < 0 {
        return Ok(tuple_value(match (kind, reverse) {
            (BytesResultKind::Bytes, false) => vec![
                bytes_value(receiver),
                bytes_value(Vec::new()),
                bytes_value(Vec::new()),
            ],
            (BytesResultKind::Bytes, true) => vec![
                bytes_value(Vec::new()),
                bytes_value(Vec::new()),
                bytes_value(receiver),
            ],
            (BytesResultKind::ByteArray, false) => vec![
                byte_array_value(receiver),
                byte_array_value(Vec::new()),
                byte_array_value(Vec::new()),
            ],
            (BytesResultKind::ByteArray, true) => vec![
                byte_array_value(Vec::new()),
                byte_array_value(Vec::new()),
                byte_array_value(receiver),
            ],
        }));
    }

    let start = usize::try_from(index).map_err(|_| "bytes index out of range".to_string())?;
    let after = start
        .checked_add(separator.len())
        .ok_or_else(|| "bytes index out of range".to_string())?;
    let head = receiver[..start].to_vec();
    let tail = receiver[after..].to_vec();

    Ok(tuple_value(match kind {
        BytesResultKind::Bytes => vec![
            bytes_value(head),
            partition_separator_value(&rest[0], separator),
            bytes_value(tail),
        ],
        BytesResultKind::ByteArray => vec![
            byte_array_value(head),
            byte_array_value(separator),
            byte_array_value(tail),
        ],
    }))
}

fn bytes_method_receiver(
    receiver: &Value,
    method: &str,
) -> Result<(Vec<u8>, BytesResultKind), String> {
    match bytes_base_value_bytes(receiver) {
        Some(value) => Ok(value),
        None => Err(format!(
            "TypeError: {method}() expected a bytes-like receiver, got {}",
            type_name(receiver)
        )),
    }
}

fn bytes_result_value(kind: BytesResultKind, bytes: Vec<u8>) -> Value {
    match kind {
        BytesResultKind::Bytes => bytes_value(bytes),
        BytesResultKind::ByteArray => byte_array_value(bytes),
    }
}

fn partition_separator_value(original: &Value, bytes: Vec<u8>) -> Value {
    match original {
        Value::Bytes(_) | Value::ByteArray(_) | Value::MemoryView(_) => original.clone(),
        _ => bytes_value(bytes),
    }
}

fn bytes_like_method_argument(
    value: &Value,
    method: &str,
    position: &str,
) -> Result<Vec<u8>, String> {
    let _ = (method, position);
    match value {
        Value::MemoryView(view) => memoryview_bytes(view),
        value if bytes_base_value_bytes(value).is_some() => Ok(bytes_base_value_bytes(value)
            .expect("bytes-like value passed recognizer")
            .0),
        value if array_array_bytes(value).is_some() => {
            Ok(array_array_bytes(value).expect("array storage exists after guard"))
        }
        value => Err(format!(
            "TypeError: a bytes-like object is required, not '{}'",
            type_name(value)
        )),
    }
}

fn bytes_noncontiguous_memoryview_buffer_error() -> String {
    "BufferError: memoryview: underlying buffer is not C-contiguous".to_string()
}

fn bytes_c_contiguous_method_argument(
    value: &Value,
    method: &str,
    position: &str,
) -> Result<Vec<u8>, String> {
    if let Value::MemoryView(view) = value {
        if !memoryview_is_contiguous(view)? {
            return Err(bytes_noncontiguous_memoryview_buffer_error());
        }
    }
    bytes_like_method_argument(value, method, position)
}

fn call_bytes_prefix_suffix_method(
    vm: &mut Vm,
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    reject_method_keywords(name, &keywords)?;

    let method = method_display_name(name);
    let [receiver, rest @ ..] = args.as_slice() else {
        return Err(bytes_method_unbound_error(name));
    };
    if rest.is_empty() {
        return Err(bytes_method_expected_at_least_arg_error(method, 1, 0));
    }
    if rest.len() > 3 {
        return Err(format!(
            "TypeError: {method} expected at most 3 arguments, got {}",
            rest.len()
        ));
    }

    let haystack = bytes_search_receiver(receiver, method)?;
    let (start, stop) = bytes_prefix_suffix_bounds(vm, &rest[1..], haystack.len(), method)?;
    let starts_with = method == "startswith";
    bytes_prefix_suffix_matches(&haystack, &rest[0], start, stop, starts_with, method, false)
        .map(Value::Bool)
}

fn bytes_search_receiver(receiver: &Value, method: &str) -> Result<Vec<u8>, String> {
    match bytes_base_value_bytes(receiver) {
        Some((bytes, _)) => Ok(bytes),
        None => Err(format!(
            "TypeError: {method}() expected a bytes-like receiver, got {}",
            type_name(receiver)
        )),
    }
}

fn bytes_prefix_suffix_bounds(
    vm: &mut Vm,
    args: &[Value],
    len: usize,
    method: &str,
) -> Result<(i64, i64), String> {
    let len = i64::try_from(len).map_err(|_| "bytes object is too large".to_string())?;
    let start = match args.first() {
        Some(value) => bytes_bound_argument(vm, value, 0, method)?,
        None => 0,
    };
    let stop = match args.get(1) {
        Some(value) => bytes_bound_argument(vm, value, len, method)?,
        None => len,
    };
    Ok((
        normalize_string_start_bound(start, len),
        normalize_string_stop_bound(stop, len),
    ))
}

fn bytes_subsequence_bounds(
    vm: &mut Vm,
    args: &[Value],
    len: usize,
    method: &str,
) -> Result<(i64, i64), String> {
    let len = i64::try_from(len).map_err(|_| "bytes object is too large".to_string())?;
    let start = match args.first() {
        Some(value) => bytes_bound_argument(vm, value, 0, method)?,
        None => 0,
    };
    let stop = match args.get(1) {
        Some(value) => bytes_bound_argument(vm, value, len, method)?,
        None => len,
    };
    Ok((
        normalize_string_start_bound(start, len),
        normalize_string_stop_bound(stop, len),
    ))
}

fn bytes_bound_argument(
    vm: &mut Vm,
    value: &Value,
    default: i64,
    method: &str,
) -> Result<i64, String> {
    if matches!(value, Value::None) {
        return Ok(default);
    }

    let index_value = vm.index_integer_value(value.clone()).map_err(|error| {
        if error.contains("object cannot be interpreted as an integer") {
            "TypeError: slice indices must be integers or None or have an __index__ method"
                .to_string()
        } else {
            error
        }
    })?;

    match index_value {
        Value::Number(value) => Ok(value),
        Value::BigInt(value) => Ok(value.to_i64().unwrap_or_else(|| {
            if value.is_negative() {
                i64::MIN
            } else {
                i64::MAX
            }
        })),
        value => Err(format!(
            "TypeError: {method} slice indices must be integers or None, got {}",
            type_name(&value)
        )),
    }
}

fn bytes_prefix_suffix_matches(
    haystack: &[u8],
    prefix: &Value,
    start: i64,
    stop: i64,
    starts_with: bool,
    method: &str,
    in_tuple: bool,
) -> Result<bool, String> {
    match prefix {
        Value::Tuple(items) => {
            for item in items.iter() {
                if bytes_prefix_suffix_matches(
                    haystack,
                    item,
                    start,
                    stop,
                    starts_with,
                    method,
                    true,
                )? {
                    return Ok(true);
                }
            }
            Ok(false)
        }
        value => {
            let prefix = bytes_like_prefix_suffix_argument(value, method, in_tuple)?;
            if start > stop {
                return Ok(false);
            }
            let start =
                usize::try_from(start).map_err(|_| "bytes index out of range".to_string())?;
            let stop = usize::try_from(stop).map_err(|_| "bytes index out of range".to_string())?;
            let window = &haystack[start..stop];
            if starts_with {
                Ok(window.starts_with(&prefix))
            } else {
                Ok(window.ends_with(&prefix))
            }
        }
    }
}

fn bytes_like_prefix_suffix_argument(
    value: &Value,
    method: &str,
    in_tuple: bool,
) -> Result<Vec<u8>, String> {
    match value {
        Value::MemoryView(view) => {
            if !memoryview_is_contiguous(view)? {
                return Err(bytes_noncontiguous_memoryview_buffer_error());
            }
            memoryview_bytes(view)
        }
        value if bytes_base_value_bytes(value).is_some() => Ok(bytes_base_value_bytes(value)
            .expect("bytes-like value passed recognizer")
            .0),
        value if array_array_bytes(value).is_some() => {
            Ok(array_array_bytes(value).expect("array storage exists after guard"))
        }
        value if in_tuple => Err(format!(
            "TypeError: a bytes-like object is required, not '{}'",
            type_name(value)
        )),
        value => Err(format!(
            "TypeError: {method} first arg must be bytes or a tuple of bytes, not {}",
            type_name(value)
        )),
    }
}

fn bytes_count_matches(
    haystack: &[u8],
    needle: &[u8],
    start: i64,
    stop: i64,
) -> Result<usize, String> {
    if start > stop {
        return Ok(0);
    }
    let start = usize::try_from(start).map_err(|_| "bytes index out of range".to_string())?;
    let stop = usize::try_from(stop).map_err(|_| "bytes index out of range".to_string())?;
    if needle.is_empty() {
        return stop
            .checked_sub(start)
            .and_then(|count| count.checked_add(1))
            .ok_or_else(|| "bytes count is too large".to_string());
    }
    if needle.len() > stop.saturating_sub(start) {
        return Ok(0);
    }

    let mut index = start;
    let mut count = 0usize;
    while index + needle.len() <= stop {
        if haystack[index..index + needle.len()] == *needle {
            count = count
                .checked_add(1)
                .ok_or_else(|| "bytes count is too large".to_string())?;
            index += needle.len();
        } else {
            index += 1;
        }
    }
    Ok(count)
}

fn bytes_find_index(
    haystack: &[u8],
    needle: &[u8],
    start: i64,
    stop: i64,
    reverse: bool,
) -> Result<i64, String> {
    if start > stop {
        return Ok(-1);
    }
    let start = usize::try_from(start).map_err(|_| "bytes index out of range".to_string())?;
    let stop = usize::try_from(stop).map_err(|_| "bytes index out of range".to_string())?;
    if needle.is_empty() {
        let index = if reverse { stop } else { start };
        return i64::try_from(index).map_err(|_| "bytes index out of range".to_string());
    }
    if needle.len() > stop.saturating_sub(start) {
        return Ok(-1);
    }

    let last_start = stop - needle.len();
    let found = if reverse {
        (start..=last_start)
            .rev()
            .find(|candidate| haystack[*candidate..*candidate + needle.len()] == *needle)
    } else {
        (start..=last_start)
            .find(|candidate| haystack[*candidate..*candidate + needle.len()] == *needle)
    };

    found
        .map(|index| i64::try_from(index).map_err(|_| "bytes index out of range".to_string()))
        .transpose()
        .map(|index| index.unwrap_or(-1))
}

fn reject_method_keywords(name: &str, keywords: &[(String, Value)]) -> Result<(), String> {
    if keywords.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "TypeError: {}() takes no keyword arguments",
            method_keyword_error_name(name)
        ))
    }
}

fn reject_generator_like_method_keywords(
    name: &str,
    keywords: &[(String, Value)],
) -> Result<(), String> {
    if keywords.is_empty() {
        Ok(())
    } else {
        let display = method_keyword_error_name(name);
        Err(format!("TypeError: {display}() takes no keyword arguments"))
    }
}

fn reject_memoryview_method_keywords(
    name: &str,
    keywords: &[(String, Value)],
) -> Result<(), String> {
    if keywords.is_empty() {
        Ok(())
    } else if matches!(
        name,
        "memoryview.tolist"
            | "memoryview.toreadonly"
            | "memoryview.release"
            | "memoryview.__enter__"
    ) {
        Err(format!("TypeError: {name}() takes no keyword arguments"))
    } else if name == "memoryview.__exit__" {
        Err("TypeError: memoryview.__exit__() takes no keyword arguments".to_string())
    } else if name == "memoryview.__len__" {
        Err("TypeError: wrapper __len__() takes no keyword arguments".to_string())
    } else if name == "memoryview.__getitem__" {
        Err("TypeError: wrapper __getitem__() takes no keyword arguments".to_string())
    } else if name == "memoryview.__setitem__" {
        Err("TypeError: wrapper __setitem__() takes no keyword arguments".to_string())
    } else if name == "memoryview.__delitem__" {
        Err("TypeError: wrapper __delitem__() takes no keyword arguments".to_string())
    } else {
        reject_method_keywords(name, keywords)
    }
}

fn reject_bytesio_method_keywords(
    method: &str,
    keywords: &[(String, Value)],
) -> Result<(), String> {
    if keywords.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "TypeError: BytesIO.{method}() takes no keyword arguments"
        ))
    }
}

fn reject_array_method_keywords(name: &str, keywords: &[(String, Value)]) -> Result<(), String> {
    if keywords.is_empty() {
        return Ok(());
    }

    let method = name.strip_prefix("array.array.").unwrap_or(name);
    match method {
        "append" | "extend" | "frombytes" | "fromlist" | "tolist" | "tobytes" | "byteswap"
        | "buffer_info" | "insert" | "tofile" | "fromfile" | "fromunicode" | "tounicode"
        | "pop" | "remove" | "reverse" | "clear" | "count" | "index" | "__copy__" => Err(format!(
            "TypeError: array.{method}() takes no keyword arguments"
        )),
        _ => reject_method_keywords(name, keywords),
    }
}

fn array_extend_positional_only_error(positional: usize, keywords: usize) -> String {
    if positional == 0 {
        "TypeError: extend() takes exactly 1 positional argument (0 given)".to_string()
    } else {
        format!(
            "TypeError: extend() takes at most 1 argument ({} given)",
            positional + keywords
        )
    }
}

fn namedtuple_fields_value(typ: &NamedTupleType) -> Value {
    tuple_value(typ.fields.iter().cloned().map(Value::String).collect())
}

fn sys_structseq_attr(typ: &NamedTupleType, name: &str) -> Option<Value> {
    if !is_sys_structseq(typ) {
        return None;
    }
    match name {
        "n_fields" => Some(Value::Number(sys_structseq_field_count(typ))),
        "n_sequence_fields" => Some(Value::Number(typ.fields.len() as i64)),
        "n_unnamed_fields" => Some(Value::Number(0)),
        _ => None,
    }
}

fn sys_structseq_field_count(typ: &NamedTupleType) -> i64 {
    if typ.name == "flags" {
        21
    } else {
        typ.fields.len() as i64
    }
}

fn is_sys_structseq(typ: &NamedTupleType) -> bool {
    matches!(
        typ.name.as_str(),
        "version_info" | "float_info" | "hash_info" | "flags"
    ) && matches!(&typ.module, Value::String(module) if module == "sys")
}

fn is_sys_structseq_hidden_namedtuple_attr(typ: &NamedTupleType, name: &str) -> bool {
    is_sys_structseq(typ)
        && matches!(
            name,
            "__slots__" | "_asdict" | "_field_defaults" | "_fields" | "_make" | "_replace"
        )
}

fn sys_structseq_getnewargs(instance: &Value) -> Result<Value, String> {
    let Value::NamedTuple { typ, values } = instance else {
        return Err(
            "TypeError: descriptor '__getnewargs__' requires a sys structseq object".to_string(),
        );
    };
    if !is_sys_structseq(typ) {
        return Err(
            "TypeError: descriptor '__getnewargs__' requires a sys structseq object".to_string(),
        );
    }
    Ok(tuple_value(vec![tuple_value(values.as_ref().clone())]))
}

fn sys_structseq_type_dict(typ: &NamedTupleTypeRef) -> Value {
    let mut entries = vec![
        (
            Value::String("n_fields".to_string()),
            Value::Number(sys_structseq_field_count(typ)),
        ),
        (
            Value::String("n_sequence_fields".to_string()),
            Value::Number(typ.fields.len() as i64),
        ),
        (
            Value::String("n_unnamed_fields".to_string()),
            Value::Number(0),
        ),
        (
            Value::String("__match_args__".to_string()),
            namedtuple_fields_value(typ),
        ),
        (
            Value::String("__doc__".to_string()),
            Value::String(typ.doc.borrow().clone()),
        ),
        (
            Value::String("__repr__".to_string()),
            Value::NamedTupleTypeMethod {
                typ: typ.clone(),
                name: "__repr__".to_string(),
            },
        ),
    ];
    for (index, field) in typ.fields.iter().enumerate() {
        entries.push((
            Value::String(field.clone()),
            namedtuple_field_descriptor(typ, index),
        ));
    }
    mapping_proxy_from_entries(entries)
}

fn sys_structseq_names() -> impl Iterator<Item = String> {
    [
        "n_fields",
        "n_sequence_fields",
        "n_unnamed_fields",
        "__getnewargs__",
        "__match_args__",
        "__repr__",
    ]
    .into_iter()
    .map(str::to_string)
}

fn namedtuple_field_descriptor(typ: &NamedTupleTypeRef, index: usize) -> Value {
    Value::NamedTupleFieldDescriptor {
        typ: typ.clone(),
        index,
    }
}

fn namedtuple_field_defaults_value(typ: &NamedTupleType) -> Result<Value, String> {
    build_dict(
        typ.field_defaults
            .iter()
            .cloned()
            .map(|(field, value)| (Value::String(field), value))
            .collect(),
    )
}

fn typing_named_tuple_field_name(value: Value) -> Result<String, String> {
    match value {
        Value::String(name) => Ok(name),
        Value::Tuple(items) => match items.first() {
            Some(Value::String(name)) => Ok(name.clone()),
            _ => Err("TypeError: NamedTuple field names must be strings".to_string()),
        },
        Value::List(items) => match items.borrow().first() {
            Some(Value::String(name)) => Ok(name.clone()),
            _ => Err("TypeError: NamedTuple field names must be strings".to_string()),
        },
        _ => Err("TypeError: NamedTuple fields must be strings or name/type pairs".to_string()),
    }
}

fn typing_typed_dict_annotations(fields: &Value) -> Result<Vec<(Value, Value)>, String> {
    mapping_entries(fields)?
        .into_iter()
        .map(|(key, value)| match key {
            Value::String(_) => Ok((key, value)),
            _ => Err("TypeError: TypedDict field names must be strings".to_string()),
        })
        .collect()
}

fn typed_dict_class_value(
    name: String,
    annotations: Vec<(Value, Value)>,
    original_bases: Option<Value>,
) -> Result<Value, String> {
    let attrs = new_scope();
    {
        let mut attrs = attrs.borrow_mut();
        attrs.insert(
            "__module__".to_string(),
            Value::String("__main__".to_string()),
        );
        attrs.insert("__annotations__".to_string(), build_dict(annotations)?);
        attrs.insert(TYPED_DICT_CLASS_ATTR.to_string(), Value::Bool(true));
        if let Some(original_bases) = original_bases {
            attrs.insert("__orig_bases__".to_string(), original_bases);
        }
    }
    Ok(Value::Class {
        name,
        type_params: Vec::new(),
        metaclass: None,
        bases: vec![builtin_type_value("dict")],
        attrs,
    })
}

fn typing_named_tuple_from_class_attrs(
    name: &str,
    attrs: &Scope,
    bases: Vec<Value>,
    original_bases: Option<Value>,
) -> Result<Value, String> {
    let fields = typing_named_tuple_fields_from_class_attrs(attrs)?;
    let module = attrs
        .borrow()
        .get("__module__")
        .cloned()
        .unwrap_or_else(|| Value::String("__main__".to_string()));
    Ok(named_tuple_type_value(
        name.to_string(),
        fields.clone(),
        bases,
        original_bases,
        Vec::new(),
        None,
        module,
        namedtuple_doc_text(name, &fields),
    ))
}

fn typing_named_tuple_fields_from_class_attrs(attrs: &Scope) -> Result<Vec<String>, String> {
    let Some(annotations) = attrs.borrow().get("__annotations__").cloned() else {
        return Ok(Vec::new());
    };
    class_annotation_field_names(&annotations)
}

fn class_annotation_field_names(annotations: &Value) -> Result<Vec<String>, String> {
    let entries = match annotations {
        Value::Dict(entries) | Value::OrderedDict(entries) => entries.borrow().entries.clone(),
        Value::ScopeDict(scope) => scope_dict_entries(scope),
        value => {
            return Err(format!(
                "TypeError: __annotations__ must be a dict, got {value}"
            ));
        }
    };
    entries
        .into_iter()
        .map(|(key, _)| match key {
            Value::String(name) => Ok(name),
            _ => Err("TypeError: __annotations__ keys must be strings".to_string()),
        })
        .collect()
}

fn call_typing_class_mro_entries(
    name: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if !keywords.is_empty() {
        return Err("__mro_entries__() does not accept keyword arguments".to_string());
    }
    if args.len() != 1 {
        return Err(format!(
            "TypeError: __mro_entries__() expected 1 argument, got {}",
            args.len()
        ));
    }
    let marker_name = name
        .strip_suffix(".__mro_entries__")
        .expect("typing mro_entries builtin name is guarded by caller");
    let marker = typing_class_marker_mro_entries(marker_name)
        .expect("typing marker name is guarded by caller");
    Ok(tuple_value(vec![marker]))
}

fn list_search_bounds(args: &[Value], len: usize) -> Result<(usize, usize), String> {
    let len = i64::try_from(len).map_err(|_| "list is too large".to_string())?;
    let start = match args.first() {
        Some(value) => list_bound_argument(value, "list index")?,
        None => 0,
    };
    let stop = match args.get(1) {
        Some(value) => list_bound_argument(value, "list index")?,
        None => len,
    };

    let start = normalize_positive_slice_bound(start, len);
    let stop = normalize_positive_slice_bound(stop, len).max(start);
    let start = usize::try_from(start).map_err(|_| "list index out of range".to_string())?;
    let stop = usize::try_from(stop).map_err(|_| "list index out of range".to_string())?;
    Ok((start, stop))
}

fn normalized_insert_index(index: &Value, len: usize) -> Result<usize, String> {
    let len = i64::try_from(len).map_err(|_| "list is too large".to_string())?;
    let index = list_bound_argument(index, "insert index")?;
    let index = normalize_positive_slice_bound(index, len);
    usize::try_from(index).map_err(|_| "list index out of range".to_string())
}

fn list_bound_argument(value: &Value, context: &str) -> Result<i64, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value)),
        Value::Number(value) => Ok(*value),
        Value::BigInt(value) => Ok(value.to_i64().unwrap_or_else(|| {
            if value.is_negative() {
                i64::MIN
            } else {
                i64::MAX
            }
        })),
        value => Err(format!("{context} must be an integer, got {value}")),
    }
}

fn method_arg_count(args: &[Value]) -> usize {
    args.len().saturating_sub(1)
}

fn bytes_method_unbound_error(name: &str) -> String {
    format!("TypeError: unbound method {name}() needs an argument")
}

fn bytes_method_no_arg_error(name: &str, given: usize) -> String {
    format!("TypeError: {name}() takes no arguments ({given} given)")
}

fn bytes_method_exactly_one_arg_error(name: &str, given: usize) -> String {
    format!("TypeError: {name}() takes exactly one argument ({given} given)")
}

fn bytes_method_expected_at_least_arg_error(method: &str, expected: usize, given: usize) -> String {
    format!(
        "TypeError: {method} expected at least {expected} {}, got {given}",
        argument_word(expected)
    )
}

fn bytes_method_expected_at_most_arg_error(method: &str, expected: usize, given: usize) -> String {
    format!(
        "TypeError: {method} expected at most {expected} {}, got {given}",
        argument_word(expected)
    )
}

fn argument_word(count: usize) -> &'static str {
    if count == 1 { "argument" } else { "arguments" }
}

fn bytes_integer_argument_error(value: &Value) -> String {
    format!(
        "TypeError: '{}' object cannot be interpreted as an integer",
        type_name(value)
    )
}

fn bytes_tabsize_argument(value: &Value) -> Result<i32, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value) as i32),
        Value::Number(value) => i32::try_from(*value)
            .map_err(|_| "OverflowError: Python int too large to convert to C int".to_string()),
        Value::BigInt(value) => value
            .to_i32()
            .ok_or_else(|| "OverflowError: Python int too large to convert to C int".to_string()),
        value => Err(bytes_integer_argument_error(value)),
    }
}

fn bytes_width_argument(value: &Value, method: &str) -> Result<usize, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(*value) as usize),
        Value::Number(value) if *value <= 0 => Ok(0),
        Value::Number(value) => {
            usize::try_from(*value).map_err(|_| format!("{method} width is too large"))
        }
        Value::BigInt(value) if value.is_negative() => Ok(0),
        Value::BigInt(value) => value
            .to_usize()
            .ok_or_else(|| format!("{method} width is too large")),
        value => Err(bytes_integer_argument_error(value)),
    }
}

fn byte_sequence_constructor_length_from_index(value: Value) -> Result<usize, String> {
    let count = match value {
        Value::Number(value) => value,
        Value::BigInt(value) => value
            .to_i64()
            .ok_or_else(byte_sequence_index_overflow_error)?,
        _ => unreachable!("byte sequence constructor index value must be an integer"),
    };
    if count < 0 {
        return Err("ValueError: negative count".to_string());
    }
    let length = usize::try_from(count).map_err(|_| byte_sequence_index_overflow_error())?;
    checked_byte_sequence_alloc_length(length)
}

fn byte_sequence_index_overflow_error() -> String {
    "OverflowError: cannot fit 'int' into an index-sized integer".to_string()
}

fn checked_byte_sequence_alloc_length(length: usize) -> Result<usize, String> {
    if length > MAX_BYTEARRAY_RESIZE_LEN {
        Err("MemoryError".to_string())
    } else {
        Ok(length)
    }
}

fn checked_bytearray_resize_length(length: usize) -> Result<usize, String> {
    checked_byte_sequence_alloc_length(length)
}

fn is_iterator_protocol_method(name: &str) -> bool {
    if method_display_name(name) == "__reduce__" && is_dict_view_builtin_name(name) {
        return false;
    }
    if name == "Counter.__iter__" {
        return false;
    }
    if name == "Sequence.__iter__" {
        return false;
    }

    matches!(
        method_display_name(name),
        "__iter__" | "__next__" | "__length_hint__" | "__reduce__"
    ) || matches!(
        name,
        "arrayiterator.__setstate__"
            | "range_iterator.__setstate__"
            | "list_iterator.__setstate__"
            | "list_reverseiterator.__setstate__"
            | "reversed.__setstate__"
            | "tuple_iterator.__setstate__"
            | "bytes_iterator.__setstate__"
            | "bytearray_iterator.__setstate__"
            | "str_ascii_iterator.__setstate__"
            | "str_iterator.__setstate__"
    )
}

fn is_dict_view_builtin_name(name: &str) -> bool {
    name.starts_with("dict_keys.")
        || name.starts_with("dict_items.")
        || name.starts_with("dict_values.")
        || name.starts_with("odict_keys.")
        || name.starts_with("odict_items.")
        || name.starts_with("odict_values.")
}

fn method_display_name(name: &str) -> &str {
    if name.starts_with("int.from_bytes.") {
        return "from_bytes";
    }
    name.rsplit('.').next().unwrap_or(name)
}

fn method_keyword_error_name(name: &str) -> String {
    let method = method_display_name(name);
    if method.starts_with("__") && method.ends_with("__") {
        format!("wrapper {method}")
    } else if name.contains('.') {
        name.to_string()
    } else {
        method.to_string()
    }
}

fn value_len(value: &Value) -> Result<usize, String> {
    match value {
        Value::String(value) | Value::IdentityString { value, .. } => Ok(value.chars().count()),
        Value::Bytes(value) => Ok(value.len()),
        Value::ByteArray(value) => Ok(value.borrow().len()),
        Value::MemoryView(view) => memoryview_len(view),
        value if array_array_storage(value).is_some() => {
            Ok(array_array_len(value).expect("array storage exists after guard"))
        }
        Value::List(items) => Ok(items.borrow().len()),
        value if list_subclass_storage(value).is_some() => Ok(list_subclass_storage(value)
            .expect("list subclass storage exists after guard")
            .borrow()
            .len()),
        Value::UserList { data, .. } => Ok(data.borrow().len()),
        Value::UserString { data, .. } => Ok(data.borrow().chars().count()),
        Value::Deque { data, .. } => Ok(data.borrow().len()),
        Value::Tuple(items) => Ok(items.len()),
        Value::NamedTuple { values, .. } => Ok(values.len()),
        value if tuple_subclass_items(value).is_some() => Ok(tuple_subclass_items(value)
            .expect("tuple subclass items exist after guard")
            .len()),
        Value::Set(items) => Ok(items.borrow().len()),
        Value::FrozenSet(items) => Ok(items.len()),
        Value::Dict(entries) | Value::OrderedDict(entries) | Value::DefaultDict { entries, .. } => {
            Ok(entries.borrow().len())
        }
        Value::Counter { entries } => Ok(entries.borrow().len()),
        Value::MappingProxy { entries, .. } => Ok(entries.borrow().len()),
        value if counter_subclass_entries(value).is_some() => Ok(counter_subclass_entries(value)
            .expect("Counter subclass entries exist after guard")
            .borrow()
            .len()),
        Value::ChainMap { maps } => chain_map_key_count(maps),
        value if chain_map_subclass_maps(value).is_some() => {
            let maps =
                chain_map_subclass_maps(value).expect("ChainMap subclass maps exist after guard");
            chain_map_key_count(&maps)
        }
        Value::UserDict { data, .. } => Ok(data.borrow().len()),
        Value::ScopeDict(scope) => Ok(scope.borrow().len()),
        Value::FrameLocalsProxy { locals, .. } => Ok(locals.borrow().len()),
        Value::DictView { entries, .. } => Ok(entries.borrow().len()),
        Value::MappingView { mapping, .. } => value_len(mapping),
        Value::Range {
            start, stop, step, ..
        } => Ok(range_len_usize(start, stop, step)?),
        value => Err(format!(
            "TypeError: object of type '{}' has no len()",
            type_name(value)
        )),
    }
}

fn len_result_from_value(value: Value) -> Result<usize, String> {
    match value {
        Value::Bool(value) => Ok(bool_as_i64(value) as usize),
        Value::Number(value) if value >= 0 => usize::try_from(value)
            .map_err(|_| "OverflowError: len() result is too large".to_string()),
        Value::Number(_) => Err("ValueError: __len__() should return >= 0".to_string()),
        Value::BigInt(value) if !value.is_negative() => value
            .to_usize()
            .ok_or_else(|| "OverflowError: len() result is too large".to_string()),
        Value::BigInt(_) => Err("ValueError: __len__() should return >= 0".to_string()),
        value => Err(format!(
            "TypeError: '{}' object cannot be interpreted as an integer",
            type_name(&value)
        )),
    }
}

fn operator_length_hint_default_value(default: &Value) -> Result<Value, String> {
    match default {
        Value::Bool(value) => Ok(Value::Number(bool_as_i64(*value))),
        Value::Number(value) => Ok(Value::Number(*value)),
        Value::BigInt(value) => value.to_i64().map(Value::Number).ok_or_else(|| {
            "OverflowError: Python int too large to convert to C ssize_t".to_string()
        }),
        value if int_subclass_integer(value).is_some() => operator_length_hint_default_value(
            &int_subclass_integer(value).expect("int subclass value exists after guard"),
        ),
        value => Err(format!(
            "TypeError: '{}' object cannot be interpreted as an integer",
            type_name(value)
        )),
    }
}

fn operator_length_hint_result(value: Value, default: Value) -> Result<Value, String> {
    match value {
        Value::NotImplemented => Ok(default),
        Value::Bool(value) => Ok(Value::Number(bool_as_i64(value))),
        Value::Number(value) if value >= 0 => Ok(Value::Number(value)),
        Value::Number(_) => Err("ValueError: __length_hint__() should return >= 0".to_string()),
        Value::BigInt(value) if !value.is_negative() => {
            value.to_i64().map(Value::Number).ok_or_else(|| {
                "OverflowError: Python int too large to convert to C ssize_t".to_string()
            })
        }
        Value::BigInt(_) => Err("ValueError: __length_hint__() should return >= 0".to_string()),
        value if int_subclass_integer(&value).is_some() => operator_length_hint_result(
            int_subclass_integer(&value).expect("int subclass value exists after guard"),
            default,
        ),
        value => Err(format!(
            "TypeError: __length_hint__ must be an integer, not {}",
            type_name(&value)
        )),
    }
}

fn operator_unary_arg(function: &str, args: Vec<Value>) -> Result<Value, String> {
    let count = args.len();
    let [value]: [Value; 1] = args.try_into().map_err(|_| {
        format!("TypeError: _operator.{function}() takes exactly one argument ({count} given)")
    })?;
    Ok(value)
}

fn operator_binary_args(function: &str, args: Vec<Value>) -> Result<(Value, Value), String> {
    let count = args.len();
    let [left, right]: [Value; 2] = args
        .try_into()
        .map_err(|_| format!("TypeError: {function} expected 2 arguments, got {count}"))?;
    Ok((left, right))
}

fn operator_ternary_args(
    function: &str,
    args: Vec<Value>,
) -> Result<(Value, Value, Value), String> {
    let count = args.len();
    let [first, second, third]: [Value; 3] = args
        .try_into()
        .map_err(|_| format!("TypeError: {function} expected 3 arguments, got {count}"))?;
    Ok((first, second, third))
}

fn operator_call_object_arg(function: &str, args: Vec<Value>) -> Result<Value, String> {
    let count = args.len();
    let [object]: [Value; 1] = args
        .try_into()
        .map_err(|_| format!("TypeError: {function} expected 1 argument, got {count}"))?;
    Ok(object)
}

fn operator_getter_result(values: Vec<Value>) -> Value {
    if values.len() == 1 {
        values
            .into_iter()
            .next()
            .expect("single getter result exists after len check")
    } else {
        tuple_value(values)
    }
}

fn operator_concat_operand(value: &Value) -> bool {
    matches!(
        value,
        Value::String(_)
            | Value::Bytes(_)
            | Value::ByteArray(_)
            | Value::List(_)
            | Value::Tuple(_)
            | Value::Instance { .. }
    ) || str_subclass_string(value).is_some()
        || bytes_subclass_bytes(value).is_some()
        || bytearray_subclass_storage(value).is_some()
}

fn is_type_exception_message(message: &str) -> bool {
    message.starts_with("TypeError: ") || is_type_error_message(message)
}

fn uses_sequence_index_protocol(value: &Value) -> bool {
    matches!(
        value,
        Value::List(_)
            | Value::Tuple(_)
            | Value::NamedTuple { .. }
            | Value::String(_)
            | Value::UserString { .. }
            | Value::Bytes(_)
            | Value::ByteArray(_)
            | Value::Deque { .. }
            | Value::Range { .. }
    ) || list_subclass_storage(value).is_some()
        || array_array_storage(value).is_some()
}

fn integer_dunder_result(method: &str, result: Value) -> Result<Value, String> {
    if let Some(value) = int_subclass_integer(&result) {
        return Ok(value);
    }
    match numeric_bool_value(result) {
        Value::Number(value) => Ok(Value::Number(value)),
        Value::BigInt(value) => Ok(normalize_big_int(value)),
        value => Err(format!(
            "TypeError: {method} returned non-int (type {})",
            type_name(&value)
        )),
    }
}

fn integer_value_to_i64(value: Value, context: &str) -> Result<i64, String> {
    match value {
        Value::Number(value) => Ok(value),
        Value::BigInt(value) => value
            .to_i64()
            .ok_or_else(|| format!("{context} is too large")),
        value => Err(format!(
            "TypeError: {context} must be an integer, got {}",
            type_name(&value)
        )),
    }
}

fn integer_value_to_c_int(value: Value) -> Result<i32, String> {
    match value {
        Value::Number(value) => i32::try_from(value)
            .map_err(|_| "OverflowError: Python int too large to convert to C int".to_string()),
        Value::BigInt(value) => value
            .to_i32()
            .ok_or_else(|| "OverflowError: Python int too large to convert to C int".to_string()),
        value => Err(format!(
            "TypeError: '{}' object cannot be interpreted as an integer",
            type_name(&value)
        )),
    }
}

fn advance_plain_iterator(iterator: &mut Value) -> Result<IteratorAdvance, String> {
    match iterator {
        Value::Iterator(state) => advance_plain_iterator(&mut state.borrow_mut()),
        Value::RangeIterator {
            current,
            stop,
            step,
        } => {
            if range_is_exhausted(current, stop, step) {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = current.clone();
            *current += step.clone();
            Ok(IteratorAdvance::Yield(normalize_big_int(value)))
        }
        Value::ListIterator {
            items,
            index,
            exhausted,
        } => {
            if *exhausted {
                return Ok(IteratorAdvance::Complete(Value::None));
            }
            let value = {
                let items = items.borrow();
                if *index >= items.len() {
                    *exhausted = true;
                    return Ok(IteratorAdvance::Complete(Value::None));
                }
                items[*index].clone()
            };
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::TupleIterator { items, index } | Value::TemplateIterator { items, index } => {
            if *index >= items.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = items[*index].clone();
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::StringIterator { chars, index } => {
            if *index >= chars.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = Value::String(chars[*index].clone());
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::BytesIterator { bytes, index } => {
            if *index >= bytes.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = Value::Number(bytes[*index] as i64);
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::ByteArrayIterator {
            bytes,
            index,
            exhausted,
        } => {
            if *exhausted {
                return Ok(IteratorAdvance::Complete(Value::None));
            }
            let bytes = bytes.borrow();
            if *index >= bytes.len() {
                *exhausted = true;
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = Value::Number(bytes[*index] as i64);
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::ArrayIterator { object, index } => {
            let len = array_array_len(object.as_ref())
                .ok_or_else(|| "TypeError: arrayiterator source is not an array".to_string())?;
            if *index >= len {
                return Ok(IteratorAdvance::Complete(Value::None));
            }
            let index_value =
                i64::try_from(*index).map_err(|_| "OverflowError: iterator index is too large")?;
            let value = array_array_item(object.as_ref(), Value::Number(index_value))?;
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::BytesIO(bytes_io) => {
            bytes_io_ensure_open(bytes_io)?;
            let line = bytes_io_readline_chunk(bytes_io, None);
            if line.is_empty() {
                Ok(IteratorAdvance::Complete(Value::None))
            } else {
                Ok(IteratorAdvance::Yield(bytes_value(line)))
            }
        }
        Value::SetIterator {
            items,
            index,
            source,
            expected_len,
        } => {
            if source
                .as_ref()
                .is_some_and(|items| items.borrow().len() != *expected_len)
            {
                *index = items.len();
                return Err("RuntimeError: Set changed size during iteration".to_string());
            }
            if *index >= items.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let value = items[*index].clone();
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::DictIterator {
            kind,
            entries,
            index,
            expected_len,
            expected_version,
        } => {
            let value = {
                let entries = entries.borrow();
                if entries.len() != *expected_len {
                    return Err(
                        "RuntimeError: dictionary changed size during iteration".to_string()
                    );
                }
                if entries.version != *expected_version {
                    return Err(
                        "RuntimeError: dictionary keys changed during iteration".to_string()
                    );
                }
                if *index >= entries.len() {
                    return Ok(IteratorAdvance::Complete(Value::None));
                }
                let (key, value) = &entries[*index];
                match kind {
                    DictViewKind::Keys => key.clone(),
                    DictViewKind::Values => value.clone(),
                    DictViewKind::Items => tuple_value(vec![key.clone(), value.clone()]),
                }
            };
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::ReverseIterator { items, index } => {
            if *index >= items.len() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }

            let reverse_index = items.len() - 1 - *index;
            let value = items[reverse_index].clone();
            *index += 1;
            Ok(IteratorAdvance::Yield(value))
        }
        Value::DictReverseIterator {
            kind,
            entries,
            keys,
            index,
            expected_len,
            expected_version: _,
        } => {
            let value = 'next_value: {
                let entries = entries.borrow();
                if entries.len() != *expected_len {
                    return Err(
                        "RuntimeError: dictionary changed size during iteration".to_string()
                    );
                }
                while *index < keys.len() {
                    let original_index = keys.len() - 1 - *index;
                    *index += 1;
                    let Some((current_index, (key, value))) =
                        entries.iter().enumerate().find(|(_, (candidate, _))| {
                            dict_keys_equal(candidate, &keys[original_index])
                        })
                    else {
                        continue;
                    };
                    if current_index > original_index {
                        continue;
                    }
                    break 'next_value Some(match kind {
                        DictViewKind::Keys => key.clone(),
                        DictViewKind::Values => value.clone(),
                        DictViewKind::Items => tuple_value(vec![key.clone(), value.clone()]),
                    });
                }
                None
            };
            match value {
                Some(value) => Ok(IteratorAdvance::Yield(value)),
                None => Ok(IteratorAdvance::Complete(Value::None)),
            }
        }
        Value::EnumerateIterator { iterator, index } => {
            match advance_plain_iterator(iterator.as_mut())? {
                IteratorAdvance::Yield(value) => {
                    let item_index = normalize_big_int(index.clone());
                    *index += BigInt::from(1);
                    Ok(IteratorAdvance::Yield(tuple_value(vec![item_index, value])))
                }
                IteratorAdvance::Complete(value) => Ok(IteratorAdvance::Complete(value)),
                IteratorAdvance::Raised => Ok(IteratorAdvance::Raised),
            }
        }
        Value::ZipIterator { iterators, strict } => advance_plain_zip_iterator(iterators, *strict),
        Value::ItertoolsCount { .. } => {
            Err("count iterator requires runtime arithmetic".to_string())
        }
        Value::ItertoolsRepeat { value, remaining } => {
            if let Some(remaining) = remaining {
                if remaining.is_zero() {
                    return Ok(IteratorAdvance::Complete(Value::None));
                }
                *remaining -= BigInt::from(1);
            }
            Ok(IteratorAdvance::Yield(value.as_ref().clone()))
        }
        Value::ItertoolsCycle {
            iterator,
            saved,
            index,
            exhausted,
        } => {
            if !*exhausted {
                match advance_plain_iterator(iterator.as_mut())? {
                    IteratorAdvance::Yield(value) => {
                        saved.push(value.clone());
                        return Ok(IteratorAdvance::Yield(value));
                    }
                    IteratorAdvance::Complete(_) => *exhausted = true,
                    IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
                }
            }
            if saved.is_empty() {
                return Ok(IteratorAdvance::Complete(Value::None));
            }
            let value = saved[*index].clone();
            *index = (*index + 1) % saved.len();
            Ok(IteratorAdvance::Yield(value))
        }
        Value::ItertoolsChain { iterators, index } => {
            while *index < iterators.len() {
                match advance_plain_iterator(&mut iterators[*index])? {
                    IteratorAdvance::Yield(value) => return Ok(IteratorAdvance::Yield(value)),
                    IteratorAdvance::Complete(_) => *index += 1,
                    IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
                }
            }
            Ok(IteratorAdvance::Complete(Value::None))
        }
        Value::ItertoolsChainFromIterable { iterator, current } => loop {
            if let Some(current_iterator) = current.as_mut() {
                match advance_plain_iterator(current_iterator.as_mut())? {
                    IteratorAdvance::Yield(value) => return Ok(IteratorAdvance::Yield(value)),
                    IteratorAdvance::Complete(_) => *current = None,
                    IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
                }
            }
            match advance_plain_iterator(iterator.as_mut())? {
                IteratorAdvance::Yield(iterable) => {
                    *current = Some(Box::new(get_iter(iterable)?));
                }
                IteratorAdvance::Complete(value) => return Ok(IteratorAdvance::Complete(value)),
                IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
            }
        },
        Value::ItertoolsCompress { data, selectors } => loop {
            let value = match advance_plain_iterator(data.as_mut())? {
                IteratorAdvance::Yield(value) => value,
                IteratorAdvance::Complete(value) => return Ok(IteratorAdvance::Complete(value)),
                IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
            };
            let selector = match advance_plain_iterator(selectors.as_mut())? {
                IteratorAdvance::Yield(selector) => selector,
                IteratorAdvance::Complete(value) => return Ok(IteratorAdvance::Complete(value)),
                IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
            };
            if is_truthy(&selector)? {
                return Ok(IteratorAdvance::Yield(value));
            }
        },
        Value::ItertoolsIslice {
            iterator,
            position,
            next_position,
            stop,
            step,
        } => {
            if stop.is_some_and(|stop| *next_position >= stop) {
                return Ok(IteratorAdvance::Complete(Value::None));
            }
            loop {
                match advance_plain_iterator(iterator.as_mut())? {
                    IteratorAdvance::Yield(value) => {
                        let current_position = *position;
                        *position = position.saturating_add(1);
                        if current_position == *next_position {
                            *next_position = next_position.saturating_add(*step);
                            return Ok(IteratorAdvance::Yield(value));
                        }
                    }
                    IteratorAdvance::Complete(value) => {
                        return Ok(IteratorAdvance::Complete(value));
                    }
                    IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
                }
                if stop.is_some_and(|stop| *position >= stop) {
                    return Ok(IteratorAdvance::Complete(Value::None));
                }
            }
        }
        Value::ItertoolsPairwise {
            iterator,
            previous,
            initialized,
        } => {
            if !*initialized {
                match advance_plain_iterator(iterator.as_mut())? {
                    IteratorAdvance::Yield(value) => {
                        *previous = Some(Box::new(value));
                        *initialized = true;
                    }
                    IteratorAdvance::Complete(value) => {
                        return Ok(IteratorAdvance::Complete(value));
                    }
                    IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
                }
            }
            match advance_plain_iterator(iterator.as_mut())? {
                IteratorAdvance::Yield(value) => {
                    let Some(left) = previous.as_ref() else {
                        return Ok(IteratorAdvance::Complete(Value::None));
                    };
                    let pair = tuple_value(vec![left.as_ref().clone(), value.clone()]);
                    *previous = Some(Box::new(value));
                    Ok(IteratorAdvance::Yield(pair))
                }
                IteratorAdvance::Complete(value) => Ok(IteratorAdvance::Complete(value)),
                IteratorAdvance::Raised => Ok(IteratorAdvance::Raised),
            }
        }
        value => Err(format!("TypeError: {value} is not an iterator")),
    }
}

fn advance_plain_zip_iterator(
    iterators: &mut [Value],
    strict: bool,
) -> Result<IteratorAdvance, String> {
    if iterators.is_empty() {
        return Ok(IteratorAdvance::Complete(Value::None));
    }

    let mut values = Vec::new();
    for index in 0..iterators.len() {
        match advance_plain_iterator(&mut iterators[index])? {
            IteratorAdvance::Yield(value) => values.push(value),
            IteratorAdvance::Complete(value) => {
                if strict {
                    return advance_plain_strict_zip_after_complete(iterators, index, value);
                }
                return Ok(IteratorAdvance::Complete(value));
            }
            IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
        }
    }

    Ok(IteratorAdvance::Yield(tuple_value(values)))
}

fn advance_plain_strict_zip_after_complete(
    iterators: &mut [Value],
    completed_index: usize,
    completion: Value,
) -> Result<IteratorAdvance, String> {
    if completed_index > 0 {
        return Err(format!(
            "ValueError: {}",
            zip_strict_length_error(completed_index + 1, "shorter")
        ));
    }

    for index in 1..iterators.len() {
        match advance_plain_iterator(&mut iterators[index])? {
            IteratorAdvance::Yield(_) => {
                return Err(format!(
                    "ValueError: {}",
                    zip_strict_length_error(index + 1, "longer")
                ));
            }
            IteratorAdvance::Complete(_) => {}
            IteratorAdvance::Raised => return Ok(IteratorAdvance::Raised),
        }
    }

    Ok(IteratorAdvance::Complete(completion))
}

fn zip_strict_length_error(argument_index: usize, relation: &str) -> String {
    let prior = if argument_index == 2 {
        "argument 1".to_string()
    } else {
        format!("arguments 1-{}", argument_index - 1)
    };
    format!("zip() argument {argument_index} is {relation} than {prior}")
}

fn map_strict_length_error(argument_index: usize, relation: &str) -> String {
    let prior = if argument_index == 2 {
        "argument 1".to_string()
    } else {
        format!("arguments 1-{}", argument_index - 1)
    };
    format!("map() argument {argument_index} is {relation} than {prior}")
}

fn shared_iterator(iterator: Value) -> Value {
    Value::Iterator(Rc::new(RefCell::new(iterator)))
}

fn itertools_tee_flatten_source(value: &Value) -> Option<(TeeRef, usize)> {
    let Value::Iterator(iterator) = value else {
        return None;
    };
    let borrowed = iterator.borrow();
    let Value::ItertoolsTee { state, index } = &*borrowed else {
        return None;
    };
    Some((state.clone(), *index))
}

fn list_iterator_from_values(items: Vec<Value>) -> Value {
    let Value::List(items) = list_value(items) else {
        unreachable!("list_value returns a list")
    };
    shared_iterator(Value::ListIterator {
        items,
        index: 0,
        exhausted: false,
    })
}

fn empty_generator_value(name: &str, globals: Scope) -> Value {
    let name_value = identity_string_value(name.to_string());
    let state = Rc::new(RefCell::new(GeneratorState {
        name: name.to_string(),
        name_value: name_value.clone(),
        qualname_value: name_value,
        instructions: vec![Instruction::Return { src: None }],
        ip: 0,
        registers: Vec::new(),
        globals,
        locals: new_scope(),
        closure: Vec::new(),
        current_class: None,
        first_arg_name: None,
        qualname_prefix: None,
        exception_handlers: Vec::new(),
        current_exception: None,
        pending_exception_after_clear: None,
        resume_dst: None,
        done: false,
        running: false,
        is_iterable_coroutine: false,
        first_line: 1,
        line_sequence: vec![1],
        code_identity: Rc::new(()),
        frame_fields: None,
        yield_from: None,
    }));
    let frame_fields = {
        let state_ref = state.borrow();
        generator_frame_fields(&state_ref).expect("empty generator frame fields are valid")
    };
    state.borrow_mut().frame_fields = Some(frame_fields);
    Value::Generator(state)
}

fn build_dict(entries: Vec<(Value, Value)>) -> Result<Value, String> {
    dict_ref_from_entries(entries).map(Value::Dict)
}

fn build_ordered_dict(entries: Vec<(Value, Value)>) -> Result<Value, String> {
    dict_ref_from_entries(entries).map(Value::OrderedDict)
}

fn build_default_dict(entries: Vec<(Value, Value)>) -> Result<Value, String> {
    Ok(Value::DefaultDict {
        entries: dict_ref_from_entries(entries)?,
        default_factory: Rc::new(RefCell::new(Value::None)),
    })
}

fn dict_ref_from_entries(entries: Vec<(Value, Value)>) -> Result<DictRef, String> {
    let mut dict = Vec::new();

    for (key, value) in entries {
        insert_dict_entry(&mut dict, key, value)?;
    }

    let Value::Dict(entries) = dict_value(dict) else {
        unreachable!("dict_value always returns a dict")
    };
    Ok(entries)
}

#[derive(Clone, Copy)]
enum SequenceOrder {
    Less,
    LessEqual,
    Greater,
    GreaterEqual,
}

fn sequence_order_operands(left: &Value, right: &Value) -> Option<(Vec<Value>, Vec<Value>)> {
    if let (Some(left), Some(right)) = (
        list_order_operand_values(left),
        list_order_operand_values(right),
    ) {
        return Some((left, right));
    }
    if let (Some(left), Some(right)) = (
        tuple_order_operand_values(left),
        tuple_order_operand_values(right),
    ) {
        return Some((left, right));
    }
    None
}

fn list_order_operand_values(value: &Value) -> Option<Vec<Value>> {
    match value {
        Value::List(items) | Value::UserList { data: items, .. } => Some(items.borrow().clone()),
        _ => None,
    }
}

fn list_equality_operand_values(value: &Value) -> Option<Vec<Value>> {
    match value {
        Value::List(items) => Some(items.borrow().clone()),
        _ => None,
    }
}

fn user_list_comparison_operand(value: &Value) -> Value {
    match value {
        Value::UserList { data, .. } => Value::List(data.clone()),
        value => value.clone(),
    }
}

fn tuple_order_operand_values(value: &Value) -> Option<Vec<Value>> {
    match value {
        Value::Tuple(items) | Value::NamedTuple { values: items, .. } => {
            Some(items.as_ref().clone())
        }
        value => namedtuple_subclass_storage(value).map(|(_, values)| values.as_ref().clone()),
    }
}

fn tuple_concat_operand_values(value: &Value) -> Option<Vec<Value>> {
    match value {
        Value::Tuple(items) | Value::NamedTuple { values: items, .. } => {
            Some(items.as_ref().clone())
        }
        value if tuple_subclass_items(value).is_some() => Some(
            tuple_subclass_items(value)
                .expect("tuple subclass items exist after guard")
                .as_ref()
                .clone(),
        ),
        value => namedtuple_subclass_storage(value).map(|(_, values)| values.as_ref().clone()),
    }
}

fn tuple_repr_receiver_value(value: &Value) -> Option<Value> {
    match value {
        Value::Tuple(_) => Some(value.clone()),
        Value::NamedTuple { values, .. } => Some(Value::Tuple(values.clone())),
        value if tuple_subclass_items(value).is_some() => {
            let items =
                tuple_subclass_items(value).expect("tuple subclass items exist after guard");
            Some(Value::Tuple(items))
        }
        value if namedtuple_subclass_storage(value).is_some() => {
            let (_, values) = namedtuple_subclass_storage(value)
                .expect("namedtuple subclass storage exists after guard");
            Some(Value::Tuple(values))
        }
        _ => None,
    }
}

fn tuple_hash_receiver_value(value: &Value) -> Option<Value> {
    tuple_repr_receiver_value(value)
}

#[derive(Clone, Copy)]
enum CounterUpdateMode {
    Add,
    Subtract,
}

#[derive(Clone, Copy)]
enum CounterBinaryOp {
    Add,
    Subtract,
    Union,
    Intersection,
}

#[derive(Clone, Copy)]
enum CounterCompareOp {
    Less,
    LessEqual,
    Greater,
    GreaterEqual,
}

fn counter_entries_if_value(value: &Value) -> Option<DictRef> {
    match value {
        Value::Counter { entries } => Some(entries.clone()),
        value => counter_subclass_entries(value),
    }
}

fn counter_binary_op_from_method(name: &str) -> Option<CounterBinaryOp> {
    match name {
        "__add__" => Some(CounterBinaryOp::Add),
        "__sub__" => Some(CounterBinaryOp::Subtract),
        "__or__" => Some(CounterBinaryOp::Union),
        "__and__" => Some(CounterBinaryOp::Intersection),
        _ => None,
    }
}

fn counter_binary_method_operands(
    method: &str,
    args: Vec<Value>,
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value), String> {
    let mut self_value = None;
    let mut other_value = None;
    let mut duplicate_self = false;
    let mut duplicate_other = false;
    let mut duplicate_keyword = None;
    let mut unexpected_keyword = None;
    let mut seen_keywords: Vec<String> = Vec::new();

    for (index, value) in args.iter().enumerate() {
        match index {
            0 => self_value = Some(value.clone()),
            1 => other_value = Some(value.clone()),
            _ => {
                return Err(format!(
                    "TypeError: Counter.{method}() takes 2 positional arguments but {} were given",
                    args.len()
                ));
            }
        }
    }

    for (keyword, value) in keywords {
        if seen_keywords.iter().any(|seen| seen == &keyword) {
            duplicate_keyword.get_or_insert(keyword);
            continue;
        }
        seen_keywords.push(keyword.clone());
        match keyword.as_str() {
            "self" => {
                if self_value.is_some() {
                    duplicate_self = true;
                } else {
                    self_value = Some(value);
                }
            }
            "other" => {
                if other_value.is_some() {
                    duplicate_other = true;
                } else {
                    other_value = Some(value);
                }
            }
            _ => {
                unexpected_keyword.get_or_insert(keyword);
            }
        }
    }

    if let Some(keyword) = duplicate_keyword {
        return Err(format!(
            "TypeError: collections.Counter.{method}() got multiple values for keyword argument '{keyword}'"
        ));
    }
    if duplicate_self {
        return Err(format!(
            "TypeError: Counter.{method}() got multiple values for argument 'self'"
        ));
    }
    if duplicate_other {
        return Err(format!(
            "TypeError: Counter.{method}() got multiple values for argument 'other'"
        ));
    }
    if let Some(keyword) = unexpected_keyword {
        return Err(format!(
            "TypeError: Counter.{method}() got an unexpected keyword argument '{keyword}'"
        ));
    }

    match (self_value, other_value) {
        (None, None) => Err(format!(
            "TypeError: Counter.{method}() missing 2 required positional arguments: 'self' and 'other'"
        )),
        (None, Some(_)) => Err(format!(
            "TypeError: Counter.{method}() missing 1 required positional argument: 'self'"
        )),
        (Some(_), None) => Err(format!(
            "TypeError: Counter.{method}() missing 1 required positional argument: 'other'"
        )),
        (Some(left), Some(right)) => Ok((left, right)),
    }
}

fn counter_in_place_op_from_method(name: &str) -> Option<CounterBinaryOp> {
    match name {
        "__iadd__" => Some(CounterBinaryOp::Add),
        "__isub__" => Some(CounterBinaryOp::Subtract),
        "__ior__" => Some(CounterBinaryOp::Union),
        "__iand__" => Some(CounterBinaryOp::Intersection),
        _ => None,
    }
}

fn counter_union_keys(left: &[(Value, Value)], right: &[(Value, Value)]) -> Vec<Value> {
    let mut keys = left.iter().map(|(key, _)| key.clone()).collect::<Vec<_>>();
    for (key, _) in right {
        if !keys.iter().any(|existing| dict_keys_equal(existing, key)) {
            keys.push(key.clone());
        }
    }
    keys
}

fn counter_binary_value_from_operands(
    left: &Value,
    right: &Value,
    op: CounterBinaryOp,
) -> Result<Option<Value>, String> {
    let (Some(left), Some(right)) = (
        counter_entries_if_value(left),
        counter_entries_if_value(right),
    ) else {
        return Ok(None);
    };
    counter_binary_value(&left, &right, op).map(Some)
}

fn counter_in_place_value_from_operands(
    left: &Value,
    right: &Value,
    op: CounterBinaryOp,
) -> Result<Option<Value>, String> {
    let (Some(left_entries), Some(right_entries)) = (
        counter_entries_if_value(left),
        counter_entries_if_value(right),
    ) else {
        return Ok(None);
    };
    counter_in_place_value(&left_entries, &right_entries, op)?;
    Ok(Some(Value::Counter {
        entries: left_entries.clone(),
    }))
}

fn counter_binary_value(
    left: &DictRef,
    right: &DictRef,
    op: CounterBinaryOp,
) -> Result<Value, String> {
    Ok(Value::Counter {
        entries: dict_ref_from_entries(counter_binary_entries(left, right, op)?)?,
    })
}

fn counter_in_place_value(
    left: &DictRef,
    right: &DictRef,
    op: CounterBinaryOp,
) -> Result<(), String> {
    let result = counter_binary_entries(left, right, op)?;
    let mut left_ref = left.borrow_mut();
    if !left_ref.entries.is_empty() || !result.is_empty() {
        left_ref.entries.clear();
        mark_dict_changed(&mut left_ref);
    }
    for (key, value) in result {
        insert_live_dict_entry(&mut left_ref, key, value)?;
    }
    Ok(())
}

fn counter_binary_entries(
    left: &DictRef,
    right: &DictRef,
    op: CounterBinaryOp,
) -> Result<Vec<(Value, Value)>, String> {
    let left_entries = left.borrow().entries.clone();
    let right_entries = right.borrow().entries.clone();
    let keys = counter_union_keys(&left_entries, &right_entries);
    let mut result = Vec::new();

    for key in keys {
        let left_count = dict_lookup(&left_entries, &key).unwrap_or(Value::Number(0));
        let right_count = dict_lookup(&right_entries, &key).unwrap_or(Value::Number(0));
        let count = counter_binary_count(left_count, right_count, op)?;
        if compare_values(count.clone(), Value::Number(0))?.is_gt() {
            result.push((key, count));
        }
    }

    Ok(result)
}

fn counter_binary_count(left: Value, right: Value, op: CounterBinaryOp) -> Result<Value, String> {
    match op {
        CounterBinaryOp::Add => add_values(left, right),
        CounterBinaryOp::Subtract => subtract_values(left, right),
        CounterBinaryOp::Union => counter_max_count(left, right),
        CounterBinaryOp::Intersection => counter_min_count(left, right),
    }
}

fn counter_max_count(left: Value, right: Value) -> Result<Value, String> {
    if compare_values(left.clone(), right.clone())?.is_lt() {
        Ok(right)
    } else {
        Ok(left)
    }
}

fn counter_min_count(left: Value, right: Value) -> Result<Value, String> {
    if compare_values(left.clone(), right.clone())?.is_lt() {
        Ok(left)
    } else {
        Ok(right)
    }
}

fn counter_entries_sorted(entries: &DictRef) -> Vec<(Value, Value)> {
    let mut indexed = entries
        .borrow()
        .entries
        .iter()
        .cloned()
        .enumerate()
        .collect::<Vec<_>>();
    indexed.sort_by(
        |(left_index, (_, left_value)), (right_index, (_, right_value))| {
            counter_count_i128(right_value)
                .cmp(&counter_count_i128(left_value))
                .then_with(|| left_index.cmp(right_index))
        },
    );
    indexed.into_iter().map(|(_, entry)| entry).collect()
}

fn counter_count_i128(value: &Value) -> i128 {
    match numeric_bool_value(value.clone()) {
        Value::Number(value) => value as i128,
        Value::BigInt(value) => value.to_i128().unwrap_or_else(|| {
            if value.is_negative() {
                i128::MIN
            } else {
                i128::MAX
            }
        }),
        _ => 0,
    }
}

fn counter_count_i64(vm: &mut Vm, value: Value) -> Result<i64, String> {
    match vm.index_integer_value(value.clone())? {
        Value::Number(value) => Ok(value),
        Value::BigInt(value) => value
            .to_i64()
            .ok_or_else(|| "OverflowError: Counter count is too large".to_string()),
        value => Err(format!(
            "TypeError: '{}' object cannot be interpreted as an integer",
            type_name(&value)
        )),
    }
}

fn insert_set_item(items: &mut Vec<Value>, item: Value) -> Result<(), String> {
    ensure_hashable_key(&item)?;

    if !items.iter().any(|existing| existing == &item) {
        items.push(item);
    }

    Ok(())
}

fn set_lookup_key_value(value: &Value) -> Value {
    match value {
        Value::Set(items) => frozen_set_value(items.borrow().clone()),
        value => value.clone(),
    }
}

fn insert_dict_entry(
    entries: &mut Vec<(Value, Value)>,
    key: Value,
    value: Value,
) -> Result<bool, String> {
    ensure_hashable_key(&key)?;

    if let Some((_, existing_value)) = entries
        .iter_mut()
        .find(|(existing_key, _)| dict_keys_equal(existing_key, &key))
    {
        *existing_value = value;
        Ok(false)
    } else {
        entries.push((key, value));
        Ok(true)
    }
}

fn insert_live_dict_entry(
    entries: &mut DictStorage,
    key: Value,
    value: Value,
) -> Result<(), String> {
    if insert_dict_entry(&mut entries.entries, key, value)? {
        mark_dict_changed(entries);
    }
    Ok(())
}

fn mark_dict_changed(entries: &mut DictStorage) {
    entries.version = entries.version.wrapping_add(1);
}

fn dict_entries_from_mapping(value: Value) -> Result<Vec<(Value, Value)>, String> {
    match value {
        Value::Dict(entries) | Value::OrderedDict(entries) | Value::DefaultDict { entries, .. } => {
            Ok(entries.borrow().clone())
        }
        value => Err(format!("dict update source must be a dict, got {value}")),
    }
}

fn instance_hash_method(value: &Value) -> Result<Option<Value>, String> {
    let Value::Instance {
        class_name,
        class_attrs,
        class_bases,
        ..
    } = value
    else {
        return Ok(None);
    };

    if let Some(method) = class_attrs.borrow().get("__hash__").cloned() {
        if matches!(method, Value::None) {
            return Err(format!("TypeError: unhashable type: '{class_name}'"));
        }
        return Ok(Some(bind_method(method, value.clone())));
    }

    if set_subclass_items(value).is_some() {
        Err(format!("TypeError: unhashable type: '{class_name}'"))
    } else if let Some(value) = int_subclass_integer(value) {
        Ok(Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("int.__hash__".to_string())),
            receiver: Box::new(value),
            identity: Rc::new(()),
        }))
    } else if float_subclass_float(value).is_some() {
        Ok(Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("float.__hash__".to_string())),
            receiver: Box::new(value.clone()),
            identity: Rc::new(()),
        }))
    } else if let Some(value) = complex_subclass_value(value) {
        Ok(Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("complex.__hash__".to_string())),
            receiver: Box::new(value),
            identity: Rc::new(()),
        }))
    } else if let Some(items) = frozen_set_subclass_items(value) {
        Ok(Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("frozenset.__hash__".to_string())),
            receiver: Box::new(Value::FrozenSet(items)),
            identity: Rc::new(()),
        }))
    } else if let Some(items) = tuple_subclass_items(value) {
        Ok(Some(Value::BoundMethod {
            function: Box::new(Value::Builtin("tuple.__hash__".to_string())),
            receiver: Box::new(Value::Tuple(items)),
            identity: Rc::new(()),
        }))
    } else if let Some(method) = find_base_attr_by_mro(class_bases, "__hash__") {
        if matches!(method, Value::None) {
            return Err(format!("TypeError: unhashable type: '{class_name}'"));
        }
        Ok(Some(bind_method(method, value.clone())))
    } else {
        Ok(None)
    }
}

fn class_hash_method(value: &Value) -> Result<Option<Value>, String> {
    let class @ Value::Class { .. } = value else {
        return Ok(None);
    };
    let metaclass = class_metaclass_value(class);
    let Value::Class {
        name: metaclass_name,
        attrs,
        bases,
        ..
    } = metaclass
    else {
        return Ok(None);
    };

    let Some(method) = find_class_attr(&attrs, &bases, "__hash__") else {
        return Ok(None);
    };
    if matches!(method, Value::None) {
        return Err(format!("TypeError: unhashable type: '{metaclass_name}'"));
    }
    Ok(Some(match method {
        Value::StaticMethod { function, .. } => *function,
        Value::ClassMethod { function, .. } => Value::BoundMethod {
            function,
            receiver: Box::new(class.clone()),
            identity: Rc::new(()),
        },
        method => bind_method(method, class.clone()),
    }))
}

fn hash_result_from_special_method(value: Value) -> Result<Value, String> {
    if let Some(value) = int_subclass_integer(&value) {
        return hash_result_from_special_method(value);
    }
    match numeric_bool_value(value) {
        Value::Number(value) => Ok(python_integer_hash_value(&BigInt::from(value))),
        Value::BigInt(value) => Ok(python_integer_hash_value(&value)),
        _ => Err("TypeError: __hash__ method should return an integer".to_string()),
    }
}

fn py_hash_to_u64(value: Value) -> Result<u64, String> {
    let value = match numeric_bool_value(value) {
        Value::Bool(value) => BigInt::from(bool_as_i64(value)),
        Value::Number(value) => BigInt::from(value),
        Value::BigInt(value) => value,
        _ => return Err("TypeError: __hash__ method should return an integer".to_string()),
    };
    let modulus = BigInt::from(1_u128 << 64);
    let masked = value.mod_floor(&modulus);
    masked
        .to_u64()
        .ok_or_else(|| "TypeError: __hash__ method should return an integer".to_string())
}

fn identity_value(value: &Value) -> Value {
    normalize_big_int(BigInt::from(identity_bits(value)))
}

fn identity_hash_value(value: &Value) -> Value {
    python_integer_hash_value(&BigInt::from(identity_bits(value)))
}

fn direct_numeric_hash_value(value: &Value) -> Option<Value> {
    if let Value::Complex { real, imag, .. } = value
        && *imag == 0.0
    {
        return Some(float_hash_f64_value(*real, value, real.is_nan()));
    }

    match numeric_bool_value(value.clone()) {
        Value::Bool(value) => Some(python_integer_hash_value(&BigInt::from(bool_as_i64(value)))),
        Value::Number(value) => Some(python_integer_hash_value(&BigInt::from(value))),
        Value::BigInt(value) => Some(python_integer_hash_value(&value)),
        Value::Float(float) => Some(float_hash_f64_value(*float, value, float.is_nan())),
        _ => None,
    }
}

fn python_integer_hash_value(value: &BigInt) -> Value {
    if value == &BigInt::from(-1) {
        Value::Number(-2)
    } else {
        normalize_big_int(value.clone())
    }
}

fn float_hash_value(receiver: &Value) -> Result<Value, String> {
    if let Some(value) = float_subclass_float(receiver) {
        return Ok(float_hash_f64_value(*value, receiver, value.is_nan()));
    }
    let Value::Float(value) = receiver else {
        return Err("TypeError: __hash__() expected a float receiver".to_string());
    };
    Ok(float_hash_f64_value(**value, receiver, value.is_nan()))
}

fn float_getformat_result() -> &'static str {
    if cfg!(target_endian = "little") {
        "IEEE, little-endian"
    } else {
        "IEEE, big-endian"
    }
}

fn float_hash_f64_value(value: f64, identity_source: &Value, identity_hash: bool) -> Value {
    if identity_hash {
        return identity_hash_value(identity_source);
    }
    if value == f64::INFINITY {
        return Value::Number(PY_HASH_INF);
    }
    if value == f64::NEG_INFINITY {
        return Value::Number(-PY_HASH_INF);
    }
    if let Some(integer) = integral_float_bigint(value) {
        return python_integer_hash_value(&integer);
    }

    let mut hasher = DefaultHasher::new();
    hash_float_value(value, &mut hasher);
    Value::Number(hasher.finish() as i64)
}

fn integral_float_bigint(value: f64) -> Option<BigInt> {
    if !value.is_finite() || value.fract() != 0.0 {
        return None;
    }
    Some(truncated_float_bigint(value))
}

fn truncated_float_bigint(value: f64) -> BigInt {
    if value == 0.0 {
        return BigInt::zero();
    }

    let bits = value.to_bits();
    let sign = bits >> 63;
    let exponent = ((bits >> 52) & 0x7ff) as i32;
    let fraction = bits & ((1_u64 << 52) - 1);
    if exponent == 0 {
        return BigInt::zero();
    }

    let mut integer = BigInt::from((1_u64 << 52) | fraction);
    let shift = exponent - 1023 - 52;
    if shift >= 0 {
        integer <<= shift as usize;
    } else {
        integer >>= (-shift) as usize;
    }

    if sign == 1 {
        integer = -integer;
    }
    integer
}

fn identity_bits(value: &Value) -> u64 {
    match value {
        Value::List(items) => rc_identity_bits(items),
        Value::UserList { data, .. } => rc_identity_bits(data),
        Value::IdentityString { identity, .. } => rc_plain_identity_bits(identity),
        Value::Bytes(bytes) if bytes.is_empty() => empty_bytes_identity_bits(),
        Value::Bytes(bytes) => rc_plain_identity_bits(bytes),
        Value::Tuple(items) => rc_plain_identity_bits(items),
        Value::NamedTuple { values, .. } => rc_plain_identity_bits(values),
        Value::ByteArray(bytes) => rc_identity_bits(bytes),
        Value::Set(items) => rc_identity_bits(items),
        Value::FrozenSet(items) => rc_plain_identity_bits(items),
        Value::Range { identity, .. } => rc_plain_identity_bits(identity),
        Value::Dict(entries) => rc_identity_bits(entries),
        Value::OrderedDict(entries) => rc_identity_bits(entries),
        Value::DefaultDict { entries, .. } => rc_identity_bits(entries),
        Value::Counter { entries } => rc_identity_bits(entries),
        Value::ScopeDict(scope) => scope_identity_bits(scope),
        Value::FrameLocalsProxy { identity, .. } => rc_plain_identity_bits(identity),
        Value::DictView { identity, .. } => rc_plain_identity_bits(identity),
        Value::MappingView { identity, .. } => rc_plain_identity_bits(identity),
        Value::MappingProxy { identity, .. } => rc_plain_identity_bits(identity),
        Value::MappingProxyObject { identity, .. } => rc_plain_identity_bits(identity),
        Value::ChainMap { maps } => maps.as_ptr() as usize as u64,
        Value::UserDict { data, .. } => rc_identity_bits(data),
        Value::SimpleNamespace { fields } => rc_identity_bits(fields),
        Value::TypesCoroutineFunction { identity, .. } => rc_plain_identity_bits(identity),
        Value::WeakRef { identity, .. } => rc_plain_identity_bits(identity),
        Value::Generator(state) => rc_identity_bits(state),
        Value::GeneratorWrapper { identity, .. } => rc_plain_identity_bits(identity),
        Value::Coroutine(state) => rc_identity_bits(state),
        Value::CoroutineAwait(state) => rc_identity_bits(state),
        Value::AsyncGenerator(state) => rc_identity_bits(state),
        Value::AsyncGeneratorNext { identity, .. } => rc_plain_identity_bits(identity),
        Value::AsyncGeneratorThrow { state, .. } => rc_identity_bits(state),
        Value::AsyncGeneratorClose(state) => rc_identity_bits(state),
        Value::Iterator(value) => rc_identity_bits(value),
        Value::Class { attrs, .. } => scope_identity_bits(attrs),
        Value::NamedTupleFieldDescriptor { typ, index } => {
            let mut hasher = DefaultHasher::new();
            "namedtuple_field_descriptor".hash(&mut hasher);
            rc_plain_identity_bits(&typ.identity).hash(&mut hasher);
            index.hash(&mut hasher);
            hasher.finish()
        }
        Value::Instance { fields, .. } => scope_identity_bits(fields),
        Value::Exception { identity, .. } => rc_plain_identity_bits(identity),
        Value::Module { attrs, .. } => scope_identity_bits(attrs),
        Value::Function { identity, .. } => rc_plain_identity_bits(identity),
        Value::CodeObject { identity, .. } => rc_plain_identity_bits(identity),
        Value::Cell { identity, .. } => rc_plain_identity_bits(identity),
        Value::TypeParam { identity, .. } => rc_plain_identity_bits(identity),
        Value::ParamSpecAccess { identity, .. } => rc_plain_identity_bits(identity),
        Value::DeferredTypeParamExpr(deferred) => rc_plain_identity_bits(&deferred.identity),
        Value::NewType { identity, .. } => rc_plain_identity_bits(identity),
        Value::Frame { fields } => rc_identity_bits(fields),
        Value::Traceback { identity } => rc_plain_identity_bits(identity),
        Value::Float(value) => rc_plain_identity_bits(value),
        Value::Complex { identity, .. } => rc_plain_identity_bits(identity),
        Value::MemoryView(view) => rc_identity_bits(view),
        Value::BytesIO(bytes_io) => rc_identity_bits(bytes_io),
        Value::PartialMethod { identity, .. }
        | Value::PartialMethodCall { identity, .. }
        | Value::SingleDispatch { identity, .. }
        | Value::SingleDispatchRegister { identity, .. }
        | Value::SingleDispatchMethod { identity, .. }
        | Value::SingleDispatchMethodCallable { identity, .. }
        | Value::CachedProperty { identity, .. }
        | Value::CmpToKey { identity, .. }
        | Value::CmpToKeyObject { identity, .. } => rc_plain_identity_bits(identity),
        Value::OperatorAttrGetter { identity, .. }
        | Value::OperatorItemGetter { identity, .. }
        | Value::OperatorMethodCaller { identity, .. } => rc_plain_identity_bits(identity),
        _ => stable_identity_bits(value),
    }
}

fn stable_identity_bits(value: &Value) -> u64 {
    let mut hasher = DefaultHasher::new();
    "id".hash(&mut hasher);
    format!("{value:?}").hash(&mut hasher);
    hasher.finish()
}

fn scope_identity_bits(scope: &Scope) -> u64 {
    Rc::as_ptr(scope) as usize as u64
}

fn rc_identity_bits<T>(value: &Rc<RefCell<T>>) -> u64 {
    Rc::as_ptr(value) as usize as u64
}

fn rc_plain_identity_bits<T>(value: &Rc<T>) -> u64 {
    Rc::as_ptr(value) as usize as u64
}

fn empty_bytes_identity_bits() -> u64 {
    let mut hasher = DefaultHasher::new();
    "empty-bytes-singleton".hash(&mut hasher);
    hasher.finish()
}

fn hash_value(value: &Value) -> Result<Value, String> {
    if let Some(value) = direct_numeric_hash_value(value) {
        return Ok(value);
    }

    let mut hasher = DefaultHasher::new();
    hash_value_into(value, &mut hasher)?;
    Ok(Value::Number(hasher.finish() as i64))
}

fn hash_value_into(value: &Value, hasher: &mut DefaultHasher) -> Result<(), String> {
    if let Some(value) = complex_subclass_value(value) {
        return hash_value_into(&value, hasher);
    }
    if let Some(value) = generic_alias_subclass_alias(value) {
        return hash_value_into(&value, hasher);
    }
    match value {
        Value::Number(value) => hash_integer_value(&BigInt::from(*value), hasher),
        Value::BigInt(value) => hash_integer_value(value, hasher),
        Value::Bool(value) => hash_integer_value(&BigInt::from(bool_as_i64(*value)), hasher),
        Value::Float(value) if value.is_finite() && value.fract() == 0.0 => {
            if let Some(value) = integral_float_bigint(**value) {
                hash_integer_value(&value, hasher);
            } else {
                hash_float_value(**value, hasher);
            }
        }
        Value::Float(value) => hash_float_value(**value, hasher),
        Value::Complex { real, imag, .. } if *imag == 0.0 => {
            hash_value_into(&float_value(*real), hasher)?;
        }
        Value::Complex { real, imag, .. } => {
            "complex".hash(hasher);
            real.to_bits().hash(hasher);
            imag.to_bits().hash(hasher);
        }
        Value::String(value) | Value::IdentityString { value, .. } => {
            hash_bytes_like(value.as_bytes(), hasher)
        }
        Value::UserString { data, .. } => hash_bytes_like(data.borrow().as_bytes(), hasher),
        Value::Bytes(value) => hash_bytes_like(value, hasher),
        Value::MemoryView(view) => {
            let bytes = memoryview_hash_bytes(view)?;
            hash_bytes_like(&bytes, hasher)
        }
        Value::Tuple(items) => {
            "tuple".hash(hasher);
            items.len().hash(hasher);
            for item in items.iter() {
                hash_value_into(item, hasher)?;
            }
        }
        Value::NamedTuple { values, .. } => {
            "tuple".hash(hasher);
            values.len().hash(hasher);
            for item in values.iter() {
                hash_value_into(item, hasher)?;
            }
        }
        Value::FrozenSet(items) => {
            "frozenset".hash(hasher);
            let mut hash = 0_u64;
            for item in items.iter() {
                let mut item_hasher = DefaultHasher::new();
                hash_value_into(item, &mut item_hasher)?;
                hash ^= item_hasher.finish();
            }
            items.len().hash(hasher);
            hash.hash(hasher);
        }
        Value::Slice {
            start, stop, step, ..
        } => {
            "slice".hash(hasher);
            hash_optional_slice_part(start, hasher)?;
            hash_optional_slice_part(stop, hasher)?;
            hash_optional_slice_part(step, hasher)?;
        }
        Value::CodeObject {
            mode, instructions, ..
        } => {
            "code".hash(hasher);
            mode.hash(hasher);
            format!("{:?}", instructions_without_debug_positions(instructions)).hash(hasher);
        }
        Value::Cell { identity, .. } => {
            "cell".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::Range {
            start, stop, step, ..
        } => {
            "range".hash(hasher);
            start.hash(hasher);
            stop.hash(hasher);
            step.hash(hasher);
        }
        Value::Function { identity, .. } => {
            "function".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::TypesCoroutineFunction { identity, .. } => {
            "types_coroutine_function".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::BytesIO(bytes_io) => hash_rc_identity("_io.BytesIO", bytes_io, hasher),
        Value::MagicMock { identity, .. } => {
            "magic_mock".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::MockMethod { identity, .. } => {
            "magic_mock_method".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::WeakRef { identity, .. } => {
            "weakref".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::WeakProxy { .. } => {
            return Err("TypeError: unhashable type: 'weakref.ProxyType'".to_string());
        }
        Value::Generator(state) => hash_rc_identity("generator", state, hasher),
        Value::GeneratorWrapper { identity, .. } => {
            "generator_wrapper".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::Coroutine(state) => hash_rc_identity("coroutine", state, hasher),
        Value::CoroutineAwait(state) => hash_rc_identity("coroutine_wrapper", state, hasher),
        Value::AwaitIterator(value) => {
            "await_iterator".hash(hasher);
            hash_value_into(value, hasher)?;
        }
        Value::AsyncGenerator(state) => hash_rc_identity("async_generator", state, hasher),
        Value::AsyncGeneratorNext { identity, .. } => {
            "async_generator_asend".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::AsyncGeneratorThrow { state, exception } => {
            hash_rc_identity("async_generator_athrow", state, hasher);
            hash_value_into(exception, hasher)?;
        }
        Value::AsyncGeneratorClose(state) => {
            hash_rc_identity("async_generator_aclose", state, hasher)
        }
        Value::AsyncGeneratorAthrowMixin { done, .. } => {
            "coroutine".hash(hasher);
            (Rc::as_ptr(done) as usize).hash(hasher);
        }
        Value::AsyncGeneratorAcloseMixin { done, .. } => {
            "coroutine".hash(hasher);
            (Rc::as_ptr(done) as usize).hash(hasher);
        }
        Value::AnextDefault { awaitable, default } => {
            "anext_awaitable".hash(hasher);
            hash_value_into(awaitable, hasher)?;
            hash_value_into(default, hasher)?;
        }
        Value::Class { name, attrs, .. } => {
            "type".hash(hasher);
            name.hash(hasher);
            hash_scope_identity(attrs, hasher);
        }
        Value::NamedTupleType(typ) => {
            "namedtuple_type".hash(hasher);
            rc_plain_identity_bits(&typ.identity).hash(hasher);
        }
        Value::NamedTupleFieldDescriptor { typ, index } => {
            "namedtuple_field_descriptor".hash(hasher);
            rc_plain_identity_bits(&typ.identity).hash(hasher);
            index.hash(hasher);
        }
        Value::NamedTupleTypeMethod { typ, name } => {
            "namedtuple_type_method".hash(hasher);
            rc_plain_identity_bits(&typ.identity).hash(hasher);
            name.hash(hasher);
        }
        Value::NamedTupleInstanceMethod { instance, name } => {
            "namedtuple_instance_method".hash(hasher);
            hash_value_into(instance, hasher)?;
            name.hash(hasher);
        }
        Value::TypeParam { identity, .. } => {
            "type_param".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::NewType { identity, .. } => {
            "new_type".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::ParamSpecAccess { identity, .. } => {
            "paramspec_access".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::DeferredTypeParamExpr(deferred) => {
            "deferred_type_param_expr".hash(hasher);
            rc_plain_identity_bits(&deferred.identity).hash(hasher);
        }
        Value::TypeAlias { name, .. } => {
            "type_alias".hash(hasher);
            name.hash(hasher);
        }
        Value::ForwardRef { arg } => {
            "forward_ref".hash(hasher);
            arg.hash(hasher);
        }
        Value::ConstEvaluator { kind, target } => {
            "const_evaluator".hash(hasher);
            kind.hash(hasher);
            hash_value_into(target, hasher)?;
        }
        Value::GenericAlias { origin, args, .. } if matches!(origin.as_ref(), Value::Builtin(name) if name == "Union") =>
        {
            "union_alias".hash(hasher);
            let mut arg_hashes = Vec::with_capacity(args.len());
            for arg in args {
                let mut arg_hasher = DefaultHasher::new();
                hash_value_into(arg, &mut arg_hasher)?;
                arg_hashes.push(arg_hasher.finish());
            }
            arg_hashes.sort_unstable();
            arg_hashes.hash(hasher);
        }
        Value::GenericAlias { origin, args, .. } if matches!(origin.as_ref(), Value::Builtin(name) if name == "typing.Literal") =>
        {
            "literal_alias".hash(hasher);
            for arg in args {
                std::mem::discriminant(arg).hash(hasher);
                hash_value_into(arg, hasher)?;
            }
        }
        Value::GenericAlias { origin, args, .. } => {
            "generic_alias".hash(hasher);
            hash_value_into(origin, hasher)?;
            for arg in args {
                hash_value_into(arg, hasher)?;
            }
        }
        Value::Unpack(value) => {
            "unpack".hash(hasher);
            hash_value_into(value, hasher)?;
        }
        Value::PicklePayload(value) => {
            "pickle_payload".hash(hasher);
            hash_value_into(value, hasher)?;
        }
        Value::TemplateInterpolation(interpolation) => {
            "interpolation".hash(hasher);
            interpolation.expression.hash(hasher);
            interpolation.format_spec.hash(hasher);
            hash_value_into(&interpolation.value, hasher)?;
        }
        Value::Instance {
            class_name, fields, ..
        } => {
            "instance".hash(hasher);
            class_name.hash(hasher);
            hash_scope_identity(fields, hasher);
        }
        Value::Property { .. } => "property".hash(hasher),
        Value::MemberDescriptor {
            name, owner_name, ..
        } => {
            "member_descriptor".hash(hasher);
            name.hash(hasher);
            owner_name.hash(hasher);
        }
        Value::StaticMethod { function, .. } => {
            "staticmethod".hash(hasher);
            hash_value_into(function, hasher)?;
        }
        Value::ClassMethod { function, .. } => {
            "classmethod".hash(hasher);
            hash_value_into(function, hasher)?;
        }
        Value::Super {
            class,
            object,
            identity,
        } => {
            "super".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
            hash_value_into(class, hasher)?;
            hash_value_into(object, hasher)?;
        }
        Value::BoundMethod {
            function, receiver, ..
        } => {
            "method".hash(hasher);
            hash_value_into(function, hasher)?;
            hash_value_into(receiver, hasher)?;
        }
        Value::FunctoolsPlaceholder => "functools.Placeholder".hash(hasher),
        Value::Partial { identity, .. } => {
            "partial".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::PartialMethod { identity, .. } => {
            "partialmethod".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::PartialMethodCall { identity, .. } => {
            "partial".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::LruCacheWrapper { identity, .. } => {
            "_lru_cache_wrapper".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::SingleDispatch { identity, .. } => {
            "singledispatch".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::SingleDispatchRegister { identity, .. } => {
            "singledispatch_register".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::SingleDispatchMethod { identity, .. } => {
            "singledispatchmethod".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::SingleDispatchMethodCallable { identity, .. } => {
            "singledispatchmethod_callable".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::CachedProperty { identity, .. } => {
            "cached_property".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::CmpToKey { .. } | Value::CmpToKeyObject { .. } => {
            return Err("TypeError: unhashable type: 'functools.KeyWrapper'".to_string());
        }
        Value::OperatorAttrGetter { identity, .. } => {
            "operator.attrgetter".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::OperatorItemGetter { identity, .. } => {
            "operator.itemgetter".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::OperatorMethodCaller { identity, .. } => {
            "operator.methodcaller".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::InspectSignature { text } => {
            "Signature".hash(hasher);
            text.hash(hasher);
        }
        Value::AstNode { identity, .. } => {
            "ast_node".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::Frame { fields } => {
            "frame".hash(hasher);
            rc_identity_bits(fields).hash(hasher);
        }
        Value::FrameLocalsProxy { .. } => {
            return Err("TypeError: unhashable type: 'FrameLocalsProxy'".to_string());
        }
        Value::Traceback { identity } => {
            "traceback".hash(hasher);
            rc_plain_identity_bits(identity).hash(hasher);
        }
        Value::Module { name, attrs } => {
            "module".hash(hasher);
            name.hash(hasher);
            hash_scope_identity(attrs, hasher);
        }
        Value::Builtin(name) => {
            "builtin".hash(hasher);
            name.hash(hasher);
        }
        Value::None => "None".hash(hasher),
        Value::NotImplemented => "NotImplemented".hash(hasher),
        Value::Ellipsis => "Ellipsis".hash(hasher),
        Value::MappingProxyObject { mapping, .. } => hash_value_into(mapping, hasher)?,
        value if dict_view_is_values_hashable_value(value) => {
            hash_value_into(&identity_hash_value(value), hasher)?
        }
        Value::List(_)
        | Value::UserList { .. }
        | Value::Deque { .. }
        | Value::ByteArray(_)
        | Value::Set(_)
        | Value::Dict(_)
        | Value::OrderedDict(_)
        | Value::DefaultDict { .. }
        | Value::ScopeDict(_)
        | Value::SimpleNamespace { .. }
        | Value::DictView { .. }
        | Value::MappingView { .. }
        | Value::MappingProxy { .. }
        | Value::ChainMap { .. }
        | Value::Counter { .. }
        | Value::UserDict { .. }
        | Value::Template { .. }
        | Value::Exception { .. }
        | Value::RangeIterator { .. }
        | Value::ListIterator { .. }
        | Value::TupleIterator { .. }
        | Value::TemplateIterator { .. }
        | Value::StringIterator { .. }
        | Value::BytesIterator { .. }
        | Value::ByteArrayIterator { .. }
        | Value::ArrayIterator { .. }
        | Value::SetIterator { .. }
        | Value::DictIterator { .. }
        | Value::ReverseIterator { .. }
        | Value::DictReverseIterator { .. }
        | Value::SequenceReverseIterator { .. }
        | Value::EnumerateIterator { .. }
        | Value::ZipIterator { .. }
        | Value::MapIterator { .. }
        | Value::FilterIterator { .. }
        | Value::ItertoolsCount { .. }
        | Value::ItertoolsRepeat { .. }
        | Value::ItertoolsCycle { .. }
        | Value::ItertoolsAccumulate { .. }
        | Value::ItertoolsChain { .. }
        | Value::ItertoolsChainFromIterable { .. }
        | Value::ItertoolsCompress { .. }
        | Value::ItertoolsDropwhile { .. }
        | Value::ItertoolsFilterFalse { .. }
        | Value::ItertoolsTakewhile { .. }
        | Value::ItertoolsStarmap { .. }
        | Value::ItertoolsZipLongest { .. }
        | Value::ItertoolsIslice { .. }
        | Value::ItertoolsPairwise { .. }
        | Value::ItertoolsProduct { .. }
        | Value::ItertoolsCombinations { .. }
        | Value::ItertoolsCombinationsWithReplacement { .. }
        | Value::ItertoolsPermutations { .. }
        | Value::ItertoolsTee { .. }
        | Value::ItertoolsBatched { .. }
        | Value::ItertoolsGroupBy { .. }
        | Value::ItertoolsGroup { .. }
        | Value::CallIterator { .. }
        | Value::SequenceIterator { .. }
        | Value::Iterator(_) => {
            return Err(format!(
                "TypeError: unhashable type: '{}'",
                type_name(value)
            ));
        }
    }

    Ok(())
}

fn hash_integer_value(value: &BigInt, hasher: &mut DefaultHasher) {
    "int".hash(hasher);
    value.hash(hasher);
}

fn hash_float_value(value: f64, hasher: &mut DefaultHasher) {
    "float".hash(hasher);
    if value == 0.0 {
        0_u64.hash(hasher);
    } else {
        value.to_bits().hash(hasher);
    }
}

fn hash_bytes_like(value: &[u8], hasher: &mut DefaultHasher) {
    "bytes_like".hash(hasher);
    value.hash(hasher);
}

fn hash_optional_slice_part(
    value: &Option<Box<Value>>,
    hasher: &mut DefaultHasher,
) -> Result<(), String> {
    match value {
        Some(value) => hash_value_into(value, hasher),
        None => {
            "None".hash(hasher);
            Ok(())
        }
    }
}

fn hash_scope_identity(scope: &Scope, hasher: &mut DefaultHasher) {
    "scope".hash(hasher);
    (Rc::as_ptr(scope) as usize).hash(hasher);
}

fn hash_rc_identity<T>(tag: &str, value: &Rc<RefCell<T>>, hasher: &mut DefaultHasher) {
    tag.hash(hasher);
    (Rc::as_ptr(value) as usize).hash(hasher);
}

fn ensure_hashable_key(value: &Value) -> Result<(), String> {
    if let Value::MemoryView(view) = value {
        let readonly = memoryview_readonly(view)?;
        if !readonly {
            return Err("ValueError: cannot hash writable memoryview object".to_string());
        }
        return Ok(());
    }
    if is_hashable_key(value) {
        Ok(())
    } else {
        Err(format!("TypeError: unhashable key: {value}"))
    }
}

fn ensure_set_lookup_key(value: &Value) -> Result<(), String> {
    match value {
        Value::Set(items) => {
            for item in items.borrow().iter() {
                ensure_hashable_key(item)?;
            }
            Ok(())
        }
        value => ensure_hashable_key(value),
    }
}

fn is_hashable_key(value: &Value) -> bool {
    match value {
        Value::MemoryView(view) => memoryview_readonly(view).unwrap_or(false),
        Value::Number(_)
        | Value::BigInt(_)
        | Value::Float(_)
        | Value::Complex { .. }
        | Value::String(_)
        | Value::IdentityString { .. }
        | Value::UserString { .. }
        | Value::Bytes(_)
        | Value::BytesIO(_)
        | Value::Bool(_)
        | Value::CodeObject { .. }
        | Value::Range { .. }
        | Value::Function { .. }
        | Value::TypesCoroutineFunction { .. }
        | Value::MagicMock { .. }
        | Value::MockMethod { .. }
        | Value::WeakRef { .. }
        | Value::Generator(_)
        | Value::GeneratorWrapper { .. }
        | Value::Coroutine(_)
        | Value::CoroutineAwait(_)
        | Value::AwaitIterator(_)
        | Value::AsyncGenerator(_)
        | Value::AsyncGeneratorNext { .. }
        | Value::AsyncGeneratorThrow { .. }
        | Value::AsyncGeneratorClose(_)
        | Value::AsyncGeneratorAthrowMixin { .. }
        | Value::AsyncGeneratorAcloseMixin { .. }
        | Value::AnextDefault { .. }
        | Value::Class { .. }
        | Value::NamedTupleType(_)
        | Value::NamedTupleFieldDescriptor { .. }
        | Value::NamedTupleTypeMethod { .. }
        | Value::NamedTupleInstanceMethod { .. }
        | Value::TypeParam { .. }
        | Value::ParamSpecAccess { .. }
        | Value::DeferredTypeParamExpr(_)
        | Value::TypeAlias { .. }
        | Value::ForwardRef { .. }
        | Value::NewType { .. }
        | Value::ConstEvaluator { .. }
        | Value::GenericAlias { .. }
        | Value::Unpack(_)
        | Value::PicklePayload(_)
        | Value::TemplateInterpolation(_)
        | Value::Instance { .. }
        | Value::Property { .. }
        | Value::MemberDescriptor { .. }
        | Value::StaticMethod { .. }
        | Value::ClassMethod { .. }
        | Value::Super { .. }
        | Value::BoundMethod { .. }
        | Value::FunctoolsPlaceholder
        | Value::Partial { .. }
        | Value::PartialMethod { .. }
        | Value::PartialMethodCall { .. }
        | Value::LruCacheWrapper { .. }
        | Value::SingleDispatch { .. }
        | Value::SingleDispatchRegister { .. }
        | Value::SingleDispatchMethod { .. }
        | Value::SingleDispatchMethodCallable { .. }
        | Value::CachedProperty { .. }
        | Value::OperatorAttrGetter { .. }
        | Value::OperatorItemGetter { .. }
        | Value::OperatorMethodCaller { .. }
        | Value::InspectSignature { .. }
        | Value::AstNode { .. }
        | Value::Frame { .. }
        | Value::Traceback { .. }
        | Value::Module { .. }
        | Value::Builtin(_)
        | Value::None
        | Value::NotImplemented
        | Value::Ellipsis => true,
        Value::Tuple(items) => items.iter().all(is_hashable_key),
        Value::NamedTuple { values, .. } => values.iter().all(is_hashable_key),
        Value::FrozenSet(items) => items.iter().all(is_hashable_key),
        Value::Slice {
            start, stop, step, ..
        } => {
            optional_slice_part_is_hashable(start)
                && optional_slice_part_is_hashable(stop)
                && optional_slice_part_is_hashable(step)
        }
        Value::MappingProxyObject { mapping, .. } => is_hashable_key(mapping),
        value if dict_view_is_values_hashable_value(value) => true,
        Value::CmpToKey { .. }
        | Value::CmpToKeyObject { .. }
        | Value::WeakProxy { .. }
        | Value::Cell { .. }
        | Value::List(_)
        | Value::UserList { .. }
        | Value::Deque { .. }
        | Value::ByteArray(_)
        | Value::Set(_)
        | Value::Dict(_)
        | Value::OrderedDict(_)
        | Value::DefaultDict { .. }
        | Value::ScopeDict(_)
        | Value::FrameLocalsProxy { .. }
        | Value::SimpleNamespace { .. }
        | Value::DictView { .. }
        | Value::MappingView { .. }
        | Value::MappingProxy { .. }
        | Value::ChainMap { .. }
        | Value::Counter { .. }
        | Value::UserDict { .. }
        | Value::Template { .. }
        | Value::Exception { .. }
        | Value::RangeIterator { .. }
        | Value::ListIterator { .. }
        | Value::TupleIterator { .. }
        | Value::TemplateIterator { .. }
        | Value::StringIterator { .. }
        | Value::BytesIterator { .. }
        | Value::ByteArrayIterator { .. }
        | Value::ArrayIterator { .. }
        | Value::SetIterator { .. }
        | Value::DictIterator { .. }
        | Value::ReverseIterator { .. }
        | Value::DictReverseIterator { .. }
        | Value::SequenceReverseIterator { .. }
        | Value::EnumerateIterator { .. }
        | Value::ZipIterator { .. }
        | Value::MapIterator { .. }
        | Value::FilterIterator { .. }
        | Value::ItertoolsCount { .. }
        | Value::ItertoolsRepeat { .. }
        | Value::ItertoolsCycle { .. }
        | Value::ItertoolsAccumulate { .. }
        | Value::ItertoolsChain { .. }
        | Value::ItertoolsChainFromIterable { .. }
        | Value::ItertoolsCompress { .. }
        | Value::ItertoolsDropwhile { .. }
        | Value::ItertoolsFilterFalse { .. }
        | Value::ItertoolsTakewhile { .. }
        | Value::ItertoolsStarmap { .. }
        | Value::ItertoolsZipLongest { .. }
        | Value::ItertoolsIslice { .. }
        | Value::ItertoolsPairwise { .. }
        | Value::ItertoolsProduct { .. }
        | Value::ItertoolsCombinations { .. }
        | Value::ItertoolsCombinationsWithReplacement { .. }
        | Value::ItertoolsPermutations { .. }
        | Value::ItertoolsTee { .. }
        | Value::ItertoolsBatched { .. }
        | Value::ItertoolsGroupBy { .. }
        | Value::ItertoolsGroup { .. }
        | Value::CallIterator { .. }
        | Value::SequenceIterator { .. }
        | Value::Iterator(_) => false,
    }
}

fn optional_slice_part_is_hashable(value: &Option<Box<Value>>) -> bool {
    value.as_deref().map(is_hashable_key).unwrap_or(true)
}

fn dict_keys_equal(left: &Value, right: &Value) -> bool {
    hash_container_items_match(left, right)
}

fn dict_lookup(entries: &[(Value, Value)], key: &Value) -> Option<Value> {
    entries
        .iter()
        .find(|(existing_key, _)| dict_keys_equal(existing_key, key))
        .map(|(_, value)| value.clone())
}

fn dict_entries_equal(left: &[(Value, Value)], right: &[(Value, Value)]) -> bool {
    left.len() == right.len()
        && left.iter().all(|(key, value)| {
            right
                .iter()
                .find(|(other_key, _)| dict_keys_equal(other_key, key))
                .is_some_and(|(_, other_value)| other_value == value)
        })
}

fn format_key_error(value: &Value) -> String {
    match value {
        Value::String(value) | Value::IdentityString { value, .. } => repr_string(value),
        value => value.to_string(),
    }
}

fn key_error_exception(key: Value) -> MiniException {
    let message = format_key_error(&key);
    MiniException {
        type_name: "KeyError".to_string(),
        type_hierarchy: builtin_exception_type_hierarchy("KeyError"),
        type_object: None,
        message: Some(message),
        args: vec![key],
        attrs: Vec::new(),
        cause: None,
        context: None,
        suppress_context: false,
        exceptions: None,
        identity: Rc::new(()),
    }
}

fn key_error_empty_exception() -> MiniException {
    MiniException {
        type_name: "KeyError".to_string(),
        type_hierarchy: builtin_exception_type_hierarchy("KeyError"),
        type_object: None,
        message: None,
        args: Vec::new(),
        attrs: Vec::new(),
        cause: None,
        context: None,
        suppress_context: false,
        exceptions: None,
        identity: Rc::new(()),
    }
}

fn chain_map_first_mapping_key_error_payload(message: &str) -> Option<String> {
    message
        .strip_prefix("KeyError: ")
        .filter(|payload| {
            payload.starts_with("Key not found in the first mapping: ")
                || *payload == "No keys found in the first mapping."
        })
        .map(str::to_string)
}

fn raise_key_error_string(vm: &mut Vm, message: String) -> Result<Value, String> {
    raise_key_error_value(vm, Value::String(message))
}

fn raise_key_error_value(vm: &mut Vm, key: Value) -> Result<Value, String> {
    vm.raise_exception(key_error_exception(key), true)?;
    Ok(Value::None)
}

fn raise_key_error_empty(vm: &mut Vm) -> Result<Value, String> {
    vm.raise_exception(key_error_empty_exception(), true)?;
    Ok(Value::None)
}

fn load_subscript_or_raise_key_error(
    vm: &mut Vm,
    object: Value,
    index: Value,
) -> Result<Value, String> {
    let key = index.clone();
    match load_subscript(object, index) {
        Ok(value) => Ok(value),
        Err(message) if message.starts_with("KeyError: ") => raise_key_error_value(vm, key),
        Err(message) => Err(message),
    }
}

fn get_iter(value: Value) -> Result<Value, String> {
    match value {
        Value::Range {
            start, stop, step, ..
        } => Ok(shared_iterator(Value::RangeIterator {
            current: start,
            stop,
            step,
        })),
        Value::List(items) => Ok(shared_iterator(Value::ListIterator {
            items,
            index: 0,
            exhausted: false,
        })),
        Value::UserList { data, .. } => Ok(shared_iterator(Value::ListIterator {
            items: data,
            index: 0,
            exhausted: false,
        })),
        Value::Deque { data, .. } => Ok(shared_iterator(Value::ListIterator {
            items: data,
            index: 0,
            exhausted: false,
        })),
        Value::Tuple(items) => Ok(shared_iterator(Value::TupleIterator {
            items: items.as_ref().clone(),
            index: 0,
        })),
        Value::NamedTuple { values, .. } => Ok(shared_iterator(Value::TupleIterator {
            items: values.as_ref().clone(),
            index: 0,
        })),
        value if tuple_subclass_items(&value).is_some() => {
            let items =
                tuple_subclass_items(&value).expect("tuple subclass items exist after guard");
            Ok(shared_iterator(Value::TupleIterator {
                items: items.as_ref().clone(),
                index: 0,
            }))
        }
        Value::Template {
            strings,
            interpolations,
        } => Ok(shared_iterator(Value::TemplateIterator {
            items: template_iter_values(strings, interpolations),
            index: 0,
        })),
        Value::String(value) | Value::IdentityString { value, .. } => {
            Ok(shared_iterator(Value::StringIterator {
                chars: value.chars().map(|ch| ch.to_string()).collect(),
                index: 0,
            }))
        }
        Value::UserString { data, .. } => user_string_iter_value(&data.borrow()),
        Value::Bytes(value) => Ok(shared_iterator(Value::BytesIterator {
            bytes: value.as_ref().clone(),
            index: 0,
        })),
        Value::ByteArray(value) => Ok(shared_iterator(Value::ByteArrayIterator {
            bytes: value,
            index: 0,
            exhausted: false,
        })),
        value @ Value::BytesIO(_) => Ok(value),
        value if array_array_values(&value).is_some() => {
            Ok(shared_iterator(Value::ArrayIterator {
                object: Box::new(value),
                index: 0,
            }))
        }
        Value::MemoryView(view) => {
            if memoryview_ndim(&view)? == 0 {
                return Err("TypeError: invalid indexing of 0-dim memory".to_string());
            }
            Ok(list_iterator_from_values(memoryview_values(&view)?))
        }
        Value::GenericAlias {
            origin,
            args,
            union_unhashable_count,
        } => {
            let alias = Value::GenericAlias {
                origin,
                args,
                union_unhashable_count,
            };
            Ok(shared_iterator(Value::TupleIterator {
                items: vec![Value::Unpack(Box::new(alias))],
                index: 0,
            }))
        }
        Value::Set(items) => {
            let items_ref = items.borrow();
            let values = items_ref.clone();
            let expected_len = items_ref.len();
            drop(items_ref);
            Ok(shared_iterator(Value::SetIterator {
                items: values,
                index: 0,
                source: Some(items),
                expected_len,
            }))
        }
        Value::FrozenSet(items) => Ok(shared_iterator(Value::SetIterator {
            items: items.as_ref().clone(),
            index: 0,
            source: None,
            expected_len: items.len(),
        })),
        Value::Dict(entries)
        | Value::OrderedDict(entries)
        | Value::DefaultDict { entries, .. }
        | Value::Counter { entries } => {
            let (expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (entries_ref.len(), entries_ref.version)
            };
            Ok(shared_iterator(Value::DictIterator {
                kind: DictViewKind::Keys,
                entries,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        Value::MappingProxy { entries, .. } => {
            let (expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (entries_ref.len(), entries_ref.version)
            };
            Ok(shared_iterator(Value::DictIterator {
                kind: DictViewKind::Keys,
                entries,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        Value::ChainMap { maps } => Ok(list_iterator_from_values(chain_map_keys(&maps)?)),
        Value::ScopeDict(scope) => get_iter(scope_dict_snapshot(&scope)),
        Value::FrameLocalsProxy { locals, .. } => get_iter(scope_dict_snapshot(&locals)),
        Value::DictView { kind, entries, .. } => {
            let (expected_len, expected_version) = {
                let entries_ref = entries.borrow();
                (entries_ref.len(), entries_ref.version)
            };
            Ok(shared_iterator(Value::DictIterator {
                kind,
                entries,
                index: 0,
                expected_len,
                expected_version,
            }))
        }
        Value::RangeIterator {
            current,
            stop,
            step,
        } => Ok(shared_iterator(Value::RangeIterator {
            current,
            stop,
            step,
        })),
        Value::ListIterator {
            items,
            index,
            exhausted,
        } => Ok(shared_iterator(Value::ListIterator {
            items,
            index,
            exhausted,
        })),
        Value::TupleIterator { items, index } => {
            Ok(shared_iterator(Value::TupleIterator { items, index }))
        }
        Value::TemplateIterator { items, index } => {
            Ok(shared_iterator(Value::TemplateIterator { items, index }))
        }
        Value::StringIterator { chars, index } => {
            Ok(shared_iterator(Value::StringIterator { chars, index }))
        }
        Value::BytesIterator { bytes, index } => {
            Ok(shared_iterator(Value::BytesIterator { bytes, index }))
        }
        Value::ByteArrayIterator {
            bytes,
            index,
            exhausted,
        } => Ok(shared_iterator(Value::ByteArrayIterator {
            bytes,
            index,
            exhausted,
        })),
        Value::ArrayIterator { object, index } => {
            Ok(shared_iterator(Value::ArrayIterator { object, index }))
        }
        Value::SetIterator {
            items,
            index,
            source,
            expected_len,
        } => Ok(shared_iterator(Value::SetIterator {
            items,
            index,
            source,
            expected_len,
        })),
        Value::DictIterator {
            kind,
            entries,
            index,
            expected_len,
            expected_version,
        } => Ok(shared_iterator(Value::DictIterator {
            kind,
            entries,
            index,
            expected_len,
            expected_version,
        })),
        Value::ReverseIterator { items, index } => {
            Ok(shared_iterator(Value::ReverseIterator { items, index }))
        }
        Value::DictReverseIterator {
            kind,
            entries,
            keys,
            index,
            expected_len,
            expected_version,
        } => Ok(shared_iterator(Value::DictReverseIterator {
            kind,
            entries,
            keys,
            index,
            expected_len,
            expected_version,
        })),
        Value::EnumerateIterator { iterator, index } => {
            Ok(shared_iterator(Value::EnumerateIterator {
                iterator,
                index,
            }))
        }
        Value::ZipIterator { iterators, strict } => {
            Ok(shared_iterator(Value::ZipIterator { iterators, strict }))
        }
        Value::MapIterator {
            function,
            iterators,
            strict,
        } => Ok(shared_iterator(Value::MapIterator {
            function,
            iterators,
            strict,
        })),
        Value::FilterIterator { function, iterator } => {
            Ok(shared_iterator(Value::FilterIterator {
                function,
                iterator,
            }))
        }
        Value::ItertoolsCount { current, step } => {
            Ok(shared_iterator(Value::ItertoolsCount { current, step }))
        }
        Value::ItertoolsRepeat { value, remaining } => {
            Ok(shared_iterator(Value::ItertoolsRepeat { value, remaining }))
        }
        Value::ItertoolsCycle {
            iterator,
            saved,
            index,
            exhausted,
        } => Ok(shared_iterator(Value::ItertoolsCycle {
            iterator,
            saved,
            index,
            exhausted,
        })),
        Value::ItertoolsAccumulate {
            iterator,
            function,
            total,
            initial,
        } => Ok(shared_iterator(Value::ItertoolsAccumulate {
            iterator,
            function,
            total,
            initial,
        })),
        Value::ItertoolsChain { iterators, index } => {
            Ok(shared_iterator(Value::ItertoolsChain { iterators, index }))
        }
        Value::ItertoolsChainFromIterable { iterator, current } => {
            Ok(shared_iterator(Value::ItertoolsChainFromIterable {
                iterator,
                current,
            }))
        }
        Value::ItertoolsCompress { data, selectors } => {
            Ok(shared_iterator(Value::ItertoolsCompress {
                data,
                selectors,
            }))
        }
        Value::ItertoolsTakewhile {
            predicate,
            iterator,
            done,
        } => Ok(shared_iterator(Value::ItertoolsTakewhile {
            predicate,
            iterator,
            done,
        })),
        Value::ItertoolsDropwhile {
            predicate,
            iterator,
            dropping,
        } => Ok(shared_iterator(Value::ItertoolsDropwhile {
            predicate,
            iterator,
            dropping,
        })),
        Value::ItertoolsStarmap { function, iterator } => {
            Ok(shared_iterator(Value::ItertoolsStarmap {
                function,
                iterator,
            }))
        }
        Value::ItertoolsZipLongest {
            iterators,
            fillvalue,
        } => Ok(shared_iterator(Value::ItertoolsZipLongest {
            iterators,
            fillvalue,
        })),
        Value::ItertoolsIslice {
            iterator,
            position,
            next_position,
            stop,
            step,
        } => Ok(shared_iterator(Value::ItertoolsIslice {
            iterator,
            position,
            next_position,
            stop,
            step,
        })),
        Value::ItertoolsPairwise {
            iterator,
            previous,
            initialized,
        } => Ok(shared_iterator(Value::ItertoolsPairwise {
            iterator,
            previous,
            initialized,
        })),
        Value::ItertoolsProduct {
            pools,
            indices,
            first,
            done,
        } => Ok(shared_iterator(Value::ItertoolsProduct {
            pools,
            indices,
            first,
            done,
        })),
        Value::ItertoolsCombinations {
            pool,
            indices,
            r,
            first,
            done,
        } => Ok(shared_iterator(Value::ItertoolsCombinations {
            pool,
            indices,
            r,
            first,
            done,
        })),
        Value::ItertoolsCombinationsWithReplacement {
            pool,
            indices,
            r,
            first,
            done,
        } => Ok(shared_iterator(
            Value::ItertoolsCombinationsWithReplacement {
                pool,
                indices,
                r,
                first,
                done,
            },
        )),
        Value::ItertoolsPermutations {
            pool,
            indices,
            cycles,
            r,
            first,
            done,
        } => Ok(shared_iterator(Value::ItertoolsPermutations {
            pool,
            indices,
            cycles,
            r,
            first,
            done,
        })),
        Value::ItertoolsTee { state, index } => {
            Ok(shared_iterator(Value::ItertoolsTee { state, index }))
        }
        Value::ItertoolsBatched {
            iterator,
            n,
            strict,
        } => Ok(shared_iterator(Value::ItertoolsBatched {
            iterator,
            n,
            strict,
        })),
        Value::ItertoolsGroupBy { state } => Ok(shared_iterator(Value::ItertoolsGroupBy { state })),
        Value::ItertoolsGroup {
            state,
            key,
            group_id,
        } => Ok(shared_iterator(Value::ItertoolsGroup {
            state,
            key,
            group_id,
        })),
        Value::CallIterator {
            callable,
            sentinel,
            done,
        } => Ok(shared_iterator(Value::CallIterator {
            callable,
            sentinel,
            done,
        })),
        Value::Iterator(state) => Ok(Value::Iterator(state)),
        Value::Generator(state) => Ok(Value::Generator(state)),
        wrapper @ Value::GeneratorWrapper { .. } => generator_wrapper_iter_value(&wrapper),
        Value::CoroutineAwait(state) => Ok(Value::CoroutineAwait(state)),
        Value::AwaitIterator(iterator) => Ok(Value::AwaitIterator(iterator)),
        value => Err(format!("'{}' object is not iterable", type_name(&value))),
    }
}

fn match_mapping_keys(mapping: &Value, keys: &[Value]) -> Result<bool, String> {
    match mapping {
        Value::Dict(entries) => {
            let entries = entries.borrow();
            if entries.len() < keys.len() {
                return Ok(false);
            }

            let mut seen = Vec::new();
            for key in keys {
                ensure_hashable_key(key)?;
                if seen
                    .iter()
                    .any(|existing_key| dict_keys_equal(existing_key, key))
                {
                    return Err(format!(
                        "ValueError: mapping pattern checks duplicate key ({})",
                        repr_value(key)
                    ));
                }
                seen.push(key.clone());
            }

            Ok(keys.iter().all(|key| {
                entries
                    .iter()
                    .any(|(existing_key, _)| dict_keys_equal(existing_key, key))
            }))
        }
        _ => Ok(false),
    }
}

fn match_class_pattern(subject: &Value, class: &Value) -> Result<bool, String> {
    match class {
        Value::Class { name, attrs, .. } => match subject {
            Value::Instance {
                class_name,
                class_attrs,
                class_bases,
                ..
            } => Ok(class_matches_target(
                class_name,
                class_attrs,
                class_bases,
                name,
                attrs,
            )),
            _ => Ok(false),
        },
        Value::Builtin(name) if is_class_like_builtin(name) => {
            Ok(value_matches_builtin_class(subject, name))
        }
        Value::NamedTupleType(_) => Ok(value_matches_class_value(subject, class)),
        _ => Err("called match pattern must be a class".to_string()),
    }
}

fn class_matches_target(
    class_name: &str,
    class_attrs: &Scope,
    class_bases: &[Value],
    target_name: &str,
    target_attrs: &Scope,
) -> bool {
    (class_name == target_name && Rc::ptr_eq(class_attrs, target_attrs))
        || class_bases
            .iter()
            .any(|base| class_value_matches_target(base, target_name, target_attrs))
}

fn class_value_matches_target(class: &Value, target_name: &str, target_attrs: &Scope) -> bool {
    match class {
        Value::Class {
            name, attrs, bases, ..
        } => {
            (name == target_name && Rc::ptr_eq(attrs, target_attrs))
                || bases
                    .iter()
                    .any(|base| class_value_matches_target(base, target_name, target_attrs))
        }
        _ => false,
    }
}

fn value_matches_user_class(
    subject: &Value,
    target_name: &str,
    target_attrs: &Scope,
    target_bases: &[Value],
) -> bool {
    match subject {
        Value::Instance {
            class_name,
            class_attrs,
            class_bases,
            ..
        } => class_matches_target(
            class_name,
            class_attrs,
            class_bases,
            target_name,
            target_attrs,
        ),
        Value::Exception { type_hierarchy, .. }
            if class_bases_derive_from_exception(target_bases) =>
        {
            type_hierarchy
                .iter()
                .any(|type_name| type_name == target_name)
        }
        class @ Value::Class { .. } => {
            class_value_matches_target(&class_metaclass_value(class), target_name, target_attrs)
        }
        _ => false,
    }
}

fn value_matches_builtin_class(subject: &Value, class_name: &str) -> bool {
    match class_name {
        "object" => true,
        "int" => {
            matches!(
                subject,
                Value::Bool(_) | Value::Number(_) | Value::BigInt(_)
            ) || int_subclass_integer(subject).is_some()
        }
        "float" => matches!(subject, Value::Float(_)) || float_subclass_float(subject).is_some(),
        "complex" => {
            matches!(subject, Value::Complex { .. }) || complex_subclass_parts(subject).is_some()
        }
        "str" => {
            matches!(subject, Value::String(_) | Value::IdentityString { .. })
                || str_subclass_string(subject).is_some()
        }
        "bytes" => matches!(subject, Value::Bytes(_)) || bytes_subclass_bytes(subject).is_some(),
        "bytearray" => {
            matches!(subject, Value::ByteArray(_)) || bytearray_subclass_storage(subject).is_some()
        }
        "memoryview" => matches!(subject, Value::MemoryView(_)),
        "io.BytesIO" => matches!(subject, Value::BytesIO(_)),
        "bool" => matches!(subject, Value::Bool(_)),
        "list" => matches!(subject, Value::List(_)) || list_subclass_storage(subject).is_some(),
        "dict" => {
            matches!(
                subject,
                Value::Dict(_)
                    | Value::OrderedDict(_)
                    | Value::DefaultDict { .. }
                    | Value::Counter { .. }
                    | Value::ScopeDict(_)
            ) || counter_subclass_entries(subject).is_some()
                || dict_subclass_entries(subject).is_some()
        }
        "Counter" => {
            matches!(subject, Value::Counter { .. }) || counter_subclass_entries(subject).is_some()
        }
        "defaultdict" => matches!(subject, Value::DefaultDict { .. }),
        "ChainMap" => matches!(subject, Value::ChainMap { .. }),
        "UserList" => matches!(subject, Value::UserList { .. }),
        "UserString" => matches!(subject, Value::UserString { .. }),
        "deque" => matches!(subject, Value::Deque { .. }),
        "UserDict" => matches!(subject, Value::UserDict { .. }),
        "module" => {
            matches!(subject, Value::Module { .. })
                || matches!(
                    subject,
                    Value::Instance { class_bases, .. }
                        if class_bases_include_builtin(class_bases, "module")
                )
        }
        "weakref.ReferenceType" | "ReferenceType" => matches!(subject, Value::WeakRef { .. }),
        "weakref.ProxyType" | "ProxyType" => {
            matches!(
                subject,
                Value::WeakProxy {
                    callable: false,
                    ..
                }
            )
        }
        "weakref.CallableProxyType" | "CallableProxyType" => {
            matches!(subject, Value::WeakProxy { callable: true, .. })
        }
        "functools._PlaceholderType" => matches!(subject, Value::FunctoolsPlaceholder),
        "function" => {
            matches!(
                subject,
                Value::Function { .. } | Value::TypesCoroutineFunction { .. }
            ) || matches!(
                subject,
                Value::Builtin(name) if is_json_builtin(name)
            )
        }
        "code" => matches!(subject, Value::CodeObject { .. }),
        "frame" => matches!(subject, Value::Frame { .. }),
        "FrameLocalsProxy" => matches!(subject, Value::FrameLocalsProxy { .. }),
        "generator" => matches!(subject, Value::Generator(_)),
        "_GeneratorWrapper" => matches!(subject, Value::GeneratorWrapper { .. }),
        "coroutine" => matches!(
            subject,
            Value::Coroutine(_)
                | Value::AsyncGeneratorAthrowMixin { .. }
                | Value::AsyncGeneratorAcloseMixin { .. }
        ),
        "async_generator" => matches!(subject, Value::AsyncGenerator(_)),
        "builtin_function_or_method" => match subject {
            Value::Builtin(name) => {
                !is_builtin_type_object_name(name)
                    && !is_exception_type_name(name)
                    && !is_json_builtin(name)
                    && !is_builtin_getset_descriptor_name(name)
                    && !is_builtin_wrapper_descriptor_name(name)
                    && !is_builtin_method_descriptor_name(name)
                    && !is_builtin_classmethod_descriptor_name(name)
            }
            Value::BoundMethod { function, .. } => matches!(
                function.as_ref(),
                Value::Builtin(name)
                    if !is_builtin_wrapper_descriptor_name(name)
                        && !is_descriptor_get_wrapper_name(name)
                        && !is_method_wrapper_name(name)
            ),
            _ => false,
        },
        "wrapper_descriptor" => {
            matches!(subject, Value::Builtin(name) if is_builtin_wrapper_descriptor_name(name))
        }
        "method-wrapper" => {
            matches!(
                subject,
                Value::BoundMethod { function, .. }
                    if matches!(function.as_ref(), Value::Builtin(name) if is_builtin_wrapper_descriptor_name(name) || is_descriptor_get_wrapper_name(name) || is_method_wrapper_name(name))
            )
        }
        "method_descriptor" => {
            matches!(subject, Value::Builtin(name) if is_builtin_method_descriptor_name(name))
        }
        "classmethod_descriptor" => {
            matches!(subject, Value::Builtin(name) if is_builtin_classmethod_descriptor_name(name))
        }
        "getset_descriptor" => {
            matches!(subject, Value::Builtin(name) if is_builtin_getset_descriptor_name(name))
        }
        "method" => {
            matches!(subject, Value::BoundMethod { function, .. } if !matches!(function.as_ref(), Value::Builtin(_)))
                || matches!(
                    subject,
                    Value::NamedTupleTypeMethod { .. } | Value::NamedTupleInstanceMethod { .. }
                )
        }
        "array.array" => {
            matches!(
                subject,
                Value::Instance { class_bases, .. }
                    if class_bases_include_builtin(class_bases, class_name)
            )
        }
        "SimpleNamespace" => is_simple_namespace_value(subject),
        "tuple" => {
            matches!(subject, Value::Tuple(_) | Value::NamedTuple { .. })
                || tuple_subclass_items(subject).is_some()
        }
        "set" => matches!(subject, Value::Set(_)) || set_subclass_items(subject).is_some(),
        "frozenset" => {
            matches!(subject, Value::FrozenSet(_)) || frozen_set_subclass_items(subject).is_some()
        }
        "range" => matches!(subject, Value::Range { .. }),
        "slice" => matches!(subject, Value::Slice { .. }),
        "property" => matches!(subject, Value::Property { .. }),
        "super" => matches!(subject, Value::Super { .. }),
        "staticmethod" => matches!(subject, Value::StaticMethod { .. }),
        "classmethod" => matches!(subject, Value::ClassMethod { .. }),
        "CellType" => matches!(subject, Value::Cell { .. }),
        "traceback" => matches!(subject, Value::Traceback { .. }),
        "NoneType" => matches!(subject, Value::None),
        "NotImplementedType" => matches!(subject, Value::NotImplemented),
        "ellipsis" => matches!(subject, Value::Ellipsis),
        "typing.TypeVar" => {
            matches!(subject, Value::TypeParam { kind, .. } if kind == "TypeVar")
        }
        "typing.TypeVarTuple" => {
            matches!(subject, Value::TypeParam { kind, .. } if kind == "TypeVarTuple")
        }
        "typing.ParamSpec" => {
            matches!(subject, Value::TypeParam { kind, .. } if kind == "ParamSpec")
        }
        "typing.ForwardRef" | "ForwardRef" => matches!(subject, Value::ForwardRef { .. }),
        "ParamSpecArgs" => {
            matches!(subject, Value::ParamSpecAccess { is_kwargs, .. } if !*is_kwargs)
        }
        "ParamSpecKwargs" => {
            matches!(subject, Value::ParamSpecAccess { is_kwargs, .. } if *is_kwargs)
        }
        "GenericAlias" => {
            matches!(subject, Value::GenericAlias { .. } if !is_union_alias(subject))
                || generic_alias_subclass_alias(subject).is_some()
        }
        "UnionType" => matches!(subject, Value::GenericAlias { .. } if is_union_alias(subject)),
        "type" => {
            matches!(subject, Value::Class { .. })
                || matches!(subject, Value::Builtin(name) if is_builtin_type_object_name(name))
        }
        name if is_ast_type_name(name) => {
            let kind = ast_builtin_kind(name).expect("guard checked AST builtin kind");
            match subject {
                Value::AstNode {
                    kind: subject_kind, ..
                } => ast_kind_inherits(subject_kind, kind),
                Value::Instance { class_bases, .. } => {
                    class_bases_include_builtin(class_bases, name)
                }
                _ => false,
            }
        }
        "Template" => matches!(subject, Value::Template { .. }),
        "Interpolation" => matches!(subject, Value::TemplateInterpolation(_)),
        "NodeVisitor" => matches!(
            subject,
            Value::Instance {
                class_name,
                class_bases,
                ..
            } if class_name == "NodeVisitor" || class_bases_include_builtin(class_bases, "NodeVisitor")
        ),
        "NodeTransformer" => matches!(
            subject,
            Value::Instance {
                class_name,
                class_bases,
                ..
            } if class_name == "NodeTransformer" || class_bases_include_builtin(class_bases, "NodeTransformer")
        ),
        "Hashable" => is_hashable_abc_value(subject),
        "Iterable" => is_iterable_abc_value(subject),
        "Iterator" => is_iterator_abc_value(subject),
        "Generator" => is_generator_abc_value(subject),
        "Reversible" => is_reversible_abc_value(subject),
        "Awaitable" => is_awaitable_abc_value(subject),
        "Coroutine" => is_coroutine_abc_value(subject),
        "AsyncIterable" => is_async_iterable_abc_value(subject),
        "AsyncIterator" => is_async_iterator_abc_value(subject),
        "AsyncGenerator" => is_async_generator_abc_value(subject),
        "Sized" => is_sized_abc_value(subject),
        "Container" => is_container_abc_value(subject),
        "Callable" => is_callable_abc_value(subject),
        "Collection" => is_collection_abc_value(subject),
        "Buffer" => is_buffer_abc_value(subject),
        "Sequence" => is_sequence_abc_value(subject),
        "MutableSequence" => is_mutable_sequence_abc_value(subject),
        "ByteString" => is_byte_string_abc_value(subject),
        "Mapping" => is_mapping_abc_value(subject),
        "MutableMapping" => is_mutable_mapping_abc_value(subject),
        "MappingView" => is_mapping_view_abc_value(subject),
        "KeysView" => is_keys_view_abc_value(subject),
        "ItemsView" => is_items_view_abc_value(subject),
        "ValuesView" => is_values_view_abc_value(subject),
        "Set" => is_set_abc_value(subject),
        "MutableSet" => is_mutable_set_abc_value(subject),
        name if is_builtin_iterator_type_name(name) => type_name(subject) == name,
        name if is_builtin_iterable_type_name(name) => type_name(subject) == name,
        name if is_exception_type_name(name) => matches!(
            subject,
            Value::Exception {
                type_name,
                type_hierarchy,
                ..
            } if exception_matches_type_name(
                &MiniException {
                    type_name: type_name.clone(),
                    type_hierarchy: type_hierarchy.clone(),
                    type_object: None,
                    message: None,
                    args: Vec::new(),
                    attrs: Vec::new(),
                    exceptions: None,
        identity: Rc::new(()),
                    cause: None,
                    context: None,
                    suppress_context: false,
                },
                name,
            )
        ),
        _ => false,
    }
}

fn validate_match_class_arguments(
    class: &Value,
    positional_count: usize,
    keyword_names: &[String],
) -> Result<(), String> {
    if let Value::Builtin(name) = class
        && is_class_like_builtin(name)
    {
        if let Some(match_args) = builtin_match_args(name) {
            if positional_count > match_args.len() {
                return Err(format!(
                    "{name}() accepts {} positional sub-patterns",
                    match_args.len()
                ));
            }

            let mut positional_names: Vec<&str> = Vec::new();
            for attr_name in match_args.iter().take(positional_count) {
                if positional_names
                    .iter()
                    .copied()
                    .chain(keyword_names.iter().map(String::as_str))
                    .any(|existing| existing == *attr_name)
                {
                    return Err(format!(
                        "{name}() got multiple sub-patterns for attribute '{attr_name}'"
                    ));
                }
                positional_names.push(attr_name.as_str());
            }

            return Ok(());
        }

        let max_positional = if builtin_accepts_match_self(name) {
            1
        } else {
            0
        };
        if positional_count > max_positional {
            return Err(match_class_positional_count_error(
                name,
                max_positional,
                positional_count,
            ));
        }
        return Ok(());
    }

    if let Value::NamedTupleType(typ) = class {
        if positional_count > typ.fields.len() {
            return Err(format!(
                "{}() accepts {} positional sub-patterns",
                typ.name,
                typ.fields.len()
            ));
        }

        let mut positional_names: Vec<&str> = Vec::new();
        for attr_name in typ.fields.iter().take(positional_count) {
            if positional_names
                .iter()
                .copied()
                .chain(keyword_names.iter().map(String::as_str))
                .any(|existing| existing == attr_name)
            {
                return Err(format!(
                    "{}() got multiple sub-patterns for attribute '{}'",
                    typ.name, attr_name
                ));
            }
            positional_names.push(attr_name.as_str());
        }

        return Ok(());
    }

    let Value::Class {
        name, attrs, bases, ..
    } = class
    else {
        return Ok(());
    };

    let Some(match_args) = find_class_attr(attrs, bases, "__match_args__") else {
        if positional_count > 0 {
            return Err(match_class_positional_count_error(
                name,
                0,
                positional_count,
            ));
        }
        return Ok(());
    };

    let Value::Tuple(items) = match_args else {
        return Err(match_class_match_args_tuple_error(name, &match_args));
    };

    if positional_count > items.len() {
        return Err(match_class_positional_count_error(
            name,
            items.len(),
            positional_count,
        ));
    }

    let mut positional_names = Vec::new();
    for value in items.iter().take(positional_count) {
        let Some(attr_name) = value_as_string(value) else {
            return Err(format!(
                "{name}.__match_args__ elements must be strings, got {value}"
            ));
        };

        if positional_names
            .iter()
            .chain(keyword_names.iter())
            .any(|existing| existing == attr_name)
        {
            return Err(format!(
                "{name}() got multiple sub-patterns for attribute '{attr_name}'"
            ));
        }

        positional_names.push(attr_name.to_string());
    }

    Ok(())
}

fn load_match_class_positional(
    subject: Value,
    class: &Value,
    index: usize,
) -> Result<Option<Value>, String> {
    if let Value::Builtin(name) = class
        && is_class_like_builtin(name)
    {
        if let Some(match_args) = builtin_match_args(name) {
            let Some(attr_name) = match_args.get(index) else {
                return Ok(None);
            };
            return load_match_attribute(subject, attr_name);
        }

        if index == 0 && builtin_accepts_match_self(name) {
            return Ok(Some(subject));
        }
        let max_positional = if builtin_accepts_match_self(name) {
            1
        } else {
            0
        };
        return Err(match_class_positional_count_error(
            name,
            max_positional,
            index + 1,
        ));
    }

    let Some(name) = match_class_positional_attr_name(class, index)? else {
        return Ok(None);
    };

    load_match_attribute(subject, &name)
}

fn match_class_positional_attr_name(class: &Value, index: usize) -> Result<Option<String>, String> {
    if let Value::NamedTupleType(typ) = class {
        return typ.fields.get(index).cloned().map(Some).ok_or_else(|| {
            format!(
                "{}() accepts {} positional sub-patterns",
                typ.name,
                typ.fields.len()
            )
        });
    }

    let Value::Class {
        name, attrs, bases, ..
    } = class
    else {
        return Ok(None);
    };

    let Some(match_args) = find_class_attr(attrs, bases, "__match_args__") else {
        return Ok(None);
    };

    let Value::Tuple(items) = match_args else {
        return Err(match_class_match_args_tuple_error(name, &match_args));
    };

    if index >= items.len() {
        return Err(format!(
            "{name}() accepts {} positional sub-patterns",
            items.len()
        ));
    }

    match &items[index] {
        Value::String(attr_name)
        | Value::IdentityString {
            value: attr_name, ..
        } => Ok(Some(attr_name.clone())),
        value => Err(format!(
            "{name}.__match_args__ elements must be strings, got {value}"
        )),
    }
}

fn match_class_positional_count_error(name: &str, max_positional: usize, given: usize) -> String {
    format!(
        "{name}() accepts {max_positional} positional sub-pattern{} ({given} given)",
        if max_positional == 1 { "" } else { "s" }
    )
}

fn match_class_match_args_tuple_error(name: &str, value: &Value) -> String {
    format!(
        "{name}.__match_args__ must be a tuple (got {})",
        type_name(value)
    )
}

fn load_match_attribute(object: Value, name: &str) -> Result<Option<Value>, String> {
    match load_attribute(object, name) {
        Ok(value) => Ok(Some(value)),
        Err(message) if message.starts_with("AttributeError:") => Ok(None),
        Err(message) => Err(message),
    }
}

fn load_mapping_rest(mapping: Value, keys: &[Value]) -> Result<Value, String> {
    match mapping {
        Value::Dict(entries) => {
            let entries = entries.borrow();
            let mut rest = Vec::new();
            for (key, value) in entries.iter() {
                if !keys
                    .iter()
                    .any(|matched_key| dict_keys_equal(matched_key, key))
                {
                    insert_dict_entry(&mut rest, key.clone(), value.clone())?;
                }
            }
            Ok(dict_value(rest))
        }
        value => Err(format!("{value} is not a mapping pattern subject")),
    }
}

fn match_sequence_length(value: &Value, min_len: usize, exact: bool) -> bool {
    sequence_pattern_len(value)
        .map(|len| {
            if exact {
                len == min_len
            } else {
                len >= min_len
            }
        })
        .unwrap_or(false)
}

fn sequence_pattern_len(value: &Value) -> Option<usize> {
    match value {
        Value::List(items) => Some(items.borrow().len()),
        Value::UserList { data, .. } => Some(data.borrow().len()),
        Value::Tuple(items) => Some(items.len()),
        Value::NamedTuple { values, .. } => Some(values.len()),
        Value::Range {
            start, stop, step, ..
        } => range_len_usize(start, stop, step).ok(),
        _ => None,
    }
}

fn load_sequence_rest(value: Value, start: usize, suffix: usize) -> Result<Value, String> {
    let values = sequence_pattern_values(value)?;
    let stop = values
        .len()
        .checked_sub(suffix)
        .ok_or_else(|| "sequence pattern suffix is longer than the subject".to_string())?;
    if start > stop {
        return Err("sequence pattern rest bounds are invalid".to_string());
    }

    Ok(list_value(values[start..stop].to_vec()))
}

fn sequence_pattern_values(value: Value) -> Result<Vec<Value>, String> {
    match value {
        Value::List(items) => Ok(items.borrow().clone()),
        Value::UserList { data, .. } => Ok(data.borrow().clone()),
        Value::Tuple(items) => Ok(items.as_ref().clone()),
        Value::NamedTuple { values, .. } => Ok(values.as_ref().clone()),
        Value::Range {
            start, stop, step, ..
        } => Ok(range_values(&start, &stop, &step)?
            .into_iter()
            .map(normalize_big_int)
            .collect()),
        value => Err(format!("{value} is not a sequence pattern subject")),
    }
}

fn sequence_values(value: Value) -> Result<Vec<Value>, String> {
    match value {
        Value::List(items) => Ok(items.borrow().clone()),
        Value::UserList { data, .. } => Ok(data.borrow().clone()),
        Value::Tuple(items) => Ok(items.as_ref().clone()),
        Value::NamedTuple { values, .. } => Ok(values.as_ref().clone()),
        Value::Set(items) => Ok(items.borrow().clone()),
        Value::FrozenSet(items) => Ok(items.as_ref().clone()),
        Value::Dict(entries) => Ok(entries
            .borrow()
            .iter()
            .map(|(key, _)| key.clone())
            .collect()),
        Value::Counter { entries } => Ok(entries
            .borrow()
            .iter()
            .map(|(key, _)| key.clone())
            .collect()),
        value if counter_subclass_entries(&value).is_some() => {
            let entries = counter_subclass_entries(&value)
                .expect("Counter subclass entries exist after guard");
            Ok(entries
                .borrow()
                .iter()
                .map(|(key, _)| key.clone())
                .collect())
        }
        Value::MappingProxy { entries, .. } => Ok(entries
            .borrow()
            .iter()
            .map(|(key, _)| key.clone())
            .collect()),
        Value::UserDict { data, .. } => {
            Ok(data.borrow().iter().map(|(key, _)| key.clone()).collect())
        }
        Value::ChainMap { maps } => Ok(chain_map_keys(&maps)?),
        value if chain_map_subclass_maps(&value).is_some() => {
            let maps =
                chain_map_subclass_maps(&value).expect("ChainMap subclass maps exist after guard");
            Ok(chain_map_keys(&maps)?)
        }
        Value::ScopeDict(scope) => Ok(scope_dict_keys(&scope)),
        Value::DictView { kind, entries, .. } => Ok(dict_view_values(kind, &entries)),
        Value::String(value) | Value::IdentityString { value, .. } => Ok(value
            .chars()
            .map(|ch| Value::String(ch.to_string()))
            .collect()),
        Value::Bytes(value) => Ok(value
            .iter()
            .map(|byte| Value::Number(*byte as i64))
            .collect()),
        Value::ByteArray(value) => Ok(bytearray_bytes(&value)
            .into_iter()
            .map(|byte| Value::Number(byte as i64))
            .collect()),
        Value::MemoryView(view) => memoryview_values(&view),
        Value::Range {
            start, stop, step, ..
        } => Ok(range_values(&start, &stop, &step)?
            .into_iter()
            .map(normalize_big_int)
            .collect()),
        Value::RangeIterator { .. }
        | Value::ListIterator { .. }
        | Value::TupleIterator { .. }
        | Value::TemplateIterator { .. }
        | Value::StringIterator { .. }
        | Value::BytesIterator { .. }
        | Value::ByteArrayIterator { .. }
        | Value::SetIterator { .. }
        | Value::DictIterator { .. }
        | Value::ReverseIterator { .. }
        | Value::DictReverseIterator { .. }
        | Value::EnumerateIterator { .. }
        | Value::ZipIterator { .. }
        | Value::MapIterator { .. }
        | Value::FilterIterator { .. }
        | Value::Iterator(_) => collect_plain_iterator_values(value),
        value => Err(format!("{value} is not iterable")),
    }
}

fn user_list_value(values: Vec<Value>) -> Result<Value, String> {
    Ok(Value::UserList {
        data: Rc::new(RefCell::new(values)),
        attrs: dict_ref_from_entries(Vec::new())?,
    })
}

fn user_string_value(value: String) -> Result<Value, String> {
    Ok(Value::UserString {
        data: Rc::new(RefCell::new(value)),
        attrs: dict_ref_from_entries(Vec::new())?,
    })
}

fn user_string_contains_value(haystack: &str, needle: Value) -> Result<bool, String> {
    let needle = match needle {
        Value::String(value) | Value::IdentityString { value, .. } => value,
        Value::UserString { data, .. } => data.borrow().clone(),
        value if str_subclass_string(&value).is_some() => {
            str_subclass_string(&value).expect("str subclass storage exists after guard")
        }
        value => {
            return Err(format!(
                "TypeError: 'in <string>' requires string as left operand, not {}",
                type_name(&value)
            ));
        }
    };
    Ok(haystack.contains(&needle))
}

fn user_string_equal_value(left: &str, right: &Value) -> bool {
    match right {
        Value::String(value) | Value::IdentityString { value, .. } => left == value,
        Value::UserString { data, .. } => left == data.borrow().as_str(),
        value if str_subclass_string(value).is_some() => {
            left == str_subclass_string(value)
                .expect("str subclass storage exists after guard")
                .as_str()
        }
        _ => false,
    }
}

fn user_string_order_operand(value: &Value) -> Option<String> {
    match value {
        Value::String(value) | Value::IdentityString { value, .. } => Some(value.clone()),
        Value::UserString { data, .. } => Some(data.borrow().clone()),
        value if str_subclass_string(value).is_some() => {
            Some(str_subclass_string(value).expect("str subclass storage exists after guard"))
        }
        _ => None,
    }
}

fn reflected_order_op(op: &str) -> &str {
    match op {
        "<" => ">",
        "<=" => ">=",
        ">" => "<",
        ">=" => "<=",
        _ => op,
    }
}

fn user_string_order_type_error(op: &str, other: &Value) -> String {
    format!(
        "TypeError: '{op}' not supported between instances of 'str' and '{}'",
        type_name(other)
    )
}

fn user_string_ordering_values(
    left: &Value,
    right: &Value,
    op: &str,
) -> Option<Result<Ordering, String>> {
    let left_is_user_string = matches!(left, Value::UserString { .. });
    let right_is_user_string = matches!(right, Value::UserString { .. });
    if !left_is_user_string && !right_is_user_string {
        return None;
    }

    let left_string = user_string_order_operand(left);
    let right_string = user_string_order_operand(right);
    match (left_string, right_string) {
        (Some(left), Some(right)) => Some(Ok(left.cmp(&right))),
        (Some(_), None) if left_is_user_string => {
            Some(Err(user_string_order_type_error(op, right)))
        }
        (None, Some(_)) if right_is_user_string => Some(Err(user_string_order_type_error(
            reflected_order_op(op),
            left,
        ))),
        _ => None,
    }
}

fn user_string_order_value(
    receiver: &Value,
    string: &Value,
    method: &str,
) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };
    let Some(right) = user_string_order_operand(string) else {
        return Err(user_string_order_type_error(
            method_order_operator(method),
            string,
        ));
    };
    let ordering = data.borrow().cmp(&right);
    let value = match method {
        "__lt__" => ordering.is_lt(),
        "__le__" => ordering.is_lt() || ordering.is_eq(),
        "__gt__" => ordering.is_gt(),
        "__ge__" => ordering.is_gt() || ordering.is_eq(),
        _ => unreachable!("UserString order method is filtered before dispatch"),
    };
    Ok(Value::Bool(value))
}

fn user_string_case_transform_value(receiver: &Value, method: &str) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };
    let text = data.borrow();
    let transformed = match method {
        "lower" => string_lower(&text),
        "upper" => text.chars().flat_map(char::to_uppercase).collect(),
        "capitalize" => string_capitalize(&text),
        "casefold" => string_casefold(&text),
        "swapcase" => string_swapcase(&text),
        "title" => string_title(&text),
        _ => unreachable!("UserString case-transform method is filtered before dispatch"),
    };
    user_string_value(transformed)
}

fn user_string_int_value(receiver: &Value) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };
    parse_int_string_base(&data.borrow(), 10)
}

fn user_string_float_value(receiver: &Value) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };
    parse_float_string(&data.borrow(), repr_string(&data.borrow()))
}

fn user_string_complex_value(receiver: &Value) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };
    let (real, imag) = parse_complex_string(&data.borrow())?;
    Ok(complex_value(real, imag))
}

fn user_string_getnewargs_value(receiver: &Value) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };
    Ok(tuple_value(vec![Value::String(data.borrow().clone())]))
}

fn user_string_self_argument(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<Value, String> {
    if args.len() > 1 {
        return Err(format!(
            "TypeError: UserString.{method}() takes 1 positional argument but {} were given",
            args.len()
        ));
    }
    let mut receiver = args.first().cloned();
    for (name, value) in keywords {
        if name != "self" {
            return Err(format!(
                "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
            ));
        }
        if receiver.is_some() {
            return Err(format!(
                "TypeError: UserString.{method}() got multiple values for argument 'self'"
            ));
        }
        receiver = Some(value);
    }
    receiver.ok_or_else(|| {
        format!("TypeError: UserString.{method}() missing 1 required positional argument: 'self'")
    })
}

fn user_string_search_arguments(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value, Option<Value>, Option<Value>), String> {
    if args.len() > 4 {
        return Err(format!(
            "TypeError: UserString.{method}() takes from 2 to 4 positional arguments but {} were given",
            args.len()
        ));
    }

    let mut receiver = args.first().cloned();
    let mut sub = args.get(1).cloned();
    let mut start = args.get(2).cloned();
    let mut end = args.get(3).cloned();
    for (name, value) in keywords {
        match name.as_str() {
            "self" => {
                if receiver.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'self'"
                    ));
                }
                receiver = Some(value);
            }
            "sub" => {
                if sub.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'sub'"
                    ));
                }
                sub = Some(value);
            }
            "start" => {
                if start.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'start'"
                    ));
                }
                start = Some(value);
            }
            "end" => {
                if end.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'end'"
                    ));
                }
                end = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                ));
            }
        }
    }

    let Some(receiver) = receiver else {
        return Err(if sub.is_some() {
            format!(
                "TypeError: UserString.{method}() missing 1 required positional argument: 'self'"
            )
        } else {
            format!(
                "TypeError: UserString.{method}() missing 2 required positional arguments: 'self' and 'sub'"
            )
        });
    };
    let Some(sub) = sub else {
        return Err(format!(
            "TypeError: UserString.{method}() missing 1 required positional argument: 'sub'"
        ));
    };

    Ok((receiver, sub, start, end))
}

fn user_string_prefix_suffix_arguments(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value, Option<Value>, Option<Value>), String> {
    let first_arg_name = if method == "startswith" {
        "prefix"
    } else {
        "suffix"
    };
    if args.len() > 4 {
        return Err(format!(
            "TypeError: UserString.{method}() takes from 2 to 4 positional arguments but {} were given",
            args.len()
        ));
    }

    let mut receiver = args.first().cloned();
    let mut affix = args.get(1).cloned();
    let mut start = args.get(2).cloned();
    let mut end = args.get(3).cloned();
    for (name, value) in keywords {
        match name.as_str() {
            "self" => {
                if receiver.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'self'"
                    ));
                }
                receiver = Some(value);
            }
            name if name == first_arg_name => {
                if affix.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument '{first_arg_name}'"
                    ));
                }
                affix = Some(value);
            }
            "start" => {
                if start.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'start'"
                    ));
                }
                start = Some(value);
            }
            "end" => {
                if end.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'end'"
                    ));
                }
                end = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                ));
            }
        }
    }

    let Some(receiver) = receiver else {
        return Err(if affix.is_some() {
            format!(
                "TypeError: UserString.{method}() missing 1 required positional argument: 'self'"
            )
        } else {
            format!(
                "TypeError: UserString.{method}() missing 2 required positional arguments: 'self' and '{first_arg_name}'"
            )
        });
    };
    let Some(affix) = affix else {
        return Err(format!(
            "TypeError: UserString.{method}() missing 1 required positional argument: '{first_arg_name}'"
        ));
    };

    Ok((receiver, affix, start, end))
}

fn user_string_prefix_suffix_values(value: &Value, method: &str) -> Result<Vec<String>, String> {
    match value {
        Value::String(value) | Value::IdentityString { value, .. } => Ok(vec![value.clone()]),
        value if str_subclass_string(value).is_some() => Ok(vec![
            str_subclass_string(value).expect("str subclass storage exists after guard"),
        ]),
        Value::Tuple(items) => items
            .iter()
            .map(|item| match item {
                Value::String(value) | Value::IdentityString { value, .. } => Ok(value.clone()),
                item if str_subclass_string(item).is_some() => {
                    Ok(str_subclass_string(item).expect("str subclass storage exists after guard"))
                }
                item => Err(format!(
                    "TypeError: tuple for {method} must only contain str, not {}",
                    type_name(item)
                )),
            })
            .collect(),
        value => Err(format!(
            "TypeError: {method} first arg must be str or a tuple of str, not {}",
            type_name(value)
        )),
    }
}

fn user_string_strip_arguments(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Option<Value>), String> {
    if args.len() > 2 {
        return Err(format!(
            "TypeError: UserString.{method}() takes from 1 to 2 positional arguments but {} were given",
            args.len()
        ));
    }

    let mut receiver = args.first().cloned();
    let mut chars = args.get(1).cloned();
    for (name, value) in keywords {
        match name.as_str() {
            "self" => {
                if receiver.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'self'"
                    ));
                }
                receiver = Some(value);
            }
            "chars" => {
                if chars.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'chars'"
                    ));
                }
                chars = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                ));
            }
        }
    }

    let Some(receiver) = receiver else {
        return Err(format!(
            "TypeError: UserString.{method}() missing 1 required positional argument: 'self'"
        ));
    };
    Ok((receiver, chars))
}

fn user_string_strip_value(
    receiver: &Value,
    chars: Option<&Value>,
    method: &str,
) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };

    let text = data.borrow();
    let strip_left = method != "rstrip";
    let strip_right = method != "lstrip";
    let stripped = match chars {
        None | Some(Value::None) => {
            string_strip_by(&text, strip_left, strip_right, |ch| ch.is_whitespace())
        }
        Some(Value::String(chars)) | Some(Value::IdentityString { value: chars, .. }) => {
            let strip_chars = chars.chars().collect::<Vec<_>>();
            string_strip_by(&text, strip_left, strip_right, |ch| {
                strip_chars.contains(&ch)
            })
        }
        Some(value) if str_subclass_string(value).is_some() => {
            let chars =
                str_subclass_string(value).expect("str subclass storage exists after guard");
            let strip_chars = chars.chars().collect::<Vec<_>>();
            string_strip_by(&text, strip_left, strip_right, |ch| {
                strip_chars.contains(&ch)
            })
        }
        Some(_) => {
            return Err(format!("TypeError: {method} arg must be None or str"));
        }
    };
    user_string_value(stripped)
}

fn user_string_remove_affix_arguments(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value), String> {
    let first_arg_name = if method == "removeprefix" {
        "prefix"
    } else {
        "suffix"
    };
    let mut positional_only = Vec::new();
    if keywords.iter().any(|(name, _)| name == "self") {
        positional_only.push("self");
    }
    if keywords.iter().any(|(name, _)| name == first_arg_name) {
        positional_only.push(first_arg_name);
    }
    if !positional_only.is_empty() {
        return Err(format!(
            "TypeError: UserString.{method}() got some positional-only arguments passed as keyword arguments: '{}'",
            positional_only.join(", ")
        ));
    }
    if let Some((name, _)) = keywords.first() {
        return Err(format!(
            "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
        ));
    }
    if args.len() > 2 {
        return Err(format!(
            "TypeError: UserString.{method}() takes 2 positional arguments but {} were given",
            args.len()
        ));
    }
    match args {
        [receiver, affix] => Ok((receiver.clone(), affix.clone())),
        [_receiver] => Err(format!(
            "TypeError: UserString.{method}() missing 1 required positional argument: '{first_arg_name}'"
        )),
        [] => Err(format!(
            "TypeError: UserString.{method}() missing 2 required positional arguments: 'self' and '{first_arg_name}'"
        )),
        _ => unreachable!("argument length is bounded above"),
    }
}

fn user_string_remove_affix_value(
    receiver: &Value,
    affix: &Value,
    remove_prefix: bool,
    method: &str,
) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };
    let Some(affix) = user_string_order_operand(affix) else {
        return Err(format!(
            "TypeError: {method}() argument must be str, not {}",
            type_name(affix)
        ));
    };
    let text = data.borrow();
    let value = if remove_prefix {
        text.strip_prefix(&affix).unwrap_or(&text)
    } else if affix.is_empty() {
        &text
    } else {
        text.strip_suffix(&affix).unwrap_or(&text)
    };
    user_string_value(value.to_string())
}

fn user_string_partition_arguments(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value), String> {
    if args.len() > 2 {
        return Err(format!(
            "TypeError: UserString.{method}() takes 2 positional arguments but {} were given",
            args.len()
        ));
    }
    let mut receiver = args.first().cloned();
    let mut sep = args.get(1).cloned();
    for (name, value) in keywords {
        match name.as_str() {
            "self" => {
                if receiver.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'self'"
                    ));
                }
                receiver = Some(value);
            }
            "sep" => {
                if sep.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'sep'"
                    ));
                }
                sep = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                ));
            }
        }
    }
    let Some(receiver) = receiver else {
        return Err(if sep.is_some() {
            format!(
                "TypeError: UserString.{method}() missing 1 required positional argument: 'self'"
            )
        } else {
            format!(
                "TypeError: UserString.{method}() missing 2 required positional arguments: 'self' and 'sep'"
            )
        });
    };
    let Some(sep) = sep else {
        return Err(format!(
            "TypeError: UserString.{method}() missing 1 required positional argument: 'sep'"
        ));
    };
    Ok((receiver, sep))
}

fn user_string_partition_separator(sep: &Value, _method: &str) -> Result<String, String> {
    let text = match sep {
        Value::String(value) | Value::IdentityString { value, .. } => value.clone(),
        value if str_subclass_string(value).is_some() => {
            str_subclass_string(value).expect("str subclass storage exists after guard")
        }
        value => {
            return Err(format!("TypeError: must be str, not {}", type_name(value)));
        }
    };
    if text.is_empty() {
        return Err("ValueError: empty separator".to_string());
    }
    Ok(text)
}

fn user_string_partition_value(
    receiver: &Value,
    sep: &Value,
    leftmost: bool,
    method: &str,
) -> Result<Value, String> {
    let Value::UserString { data, .. } = receiver else {
        return Err(format!(
            "AttributeError: '{}' object has no attribute 'data'",
            type_name(receiver)
        ));
    };
    let sep_text = user_string_partition_separator(sep, method)?;
    let text = data.borrow();
    let Some(index) = (if leftmost {
        text.find(&sep_text)
    } else {
        text.rfind(&sep_text)
    }) else {
        return Ok(if leftmost {
            tuple_value(vec![
                Value::String(text.clone()),
                Value::String(String::new()),
                Value::String(String::new()),
            ])
        } else {
            tuple_value(vec![
                Value::String(String::new()),
                Value::String(String::new()),
                Value::String(text.clone()),
            ])
        });
    };
    let before = Value::String(text[..index].to_string());
    let after_index = index + sep_text.len();
    let after = Value::String(text[after_index..].to_string());
    Ok(tuple_value(vec![before, sep.clone(), after]))
}

