fn user_string_replace_arguments(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value, Value, Option<Value>), String> {
    if args.len() > 4 {
        return Err(format!(
            "TypeError: UserString.{method}() takes from 3 to 4 positional arguments but {} were given",
            args.len()
        ));
    }
    let mut receiver = args.first().cloned();
    let mut old = args.get(1).cloned();
    let mut new = args.get(2).cloned();
    let mut maxsplit = args.get(3).cloned();
    for (name, value) in keywords {
        match name.as_str() {
            "self" => {
                if receiver.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'self'"
                    ));
                }
                receiver = Some(value);
            }
            "old" => {
                if old.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'old'"
                    ));
                }
                old = Some(value);
            }
            "new" => {
                if new.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'new'"
                    ));
                }
                new = Some(value);
            }
            "maxsplit" => {
                if maxsplit.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'maxsplit'"
                    ));
                }
                maxsplit = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                ));
            }
        }
    }
    let mut missing = Vec::new();
    if receiver.is_none() {
        missing.push("self");
    }
    if old.is_none() {
        missing.push("old");
    }
    if new.is_none() {
        missing.push("new");
    }
    if !missing.is_empty() {
        return Err(user_string_method_missing_required(method, &missing));
    }
    Ok((
        receiver.expect("missing receiver handled above"),
        old.expect("missing old handled above"),
        new.expect("missing new handled above"),
        maxsplit,
    ))
}

fn user_string_center_arguments(
    method: &str,
    args: &[Value],
    keywords: Vec<(String, Value)>,
) -> Result<(Value, Value, Option<Value>, Option<usize>), String> {
    let mut receiver = args.first().cloned();
    let mut width = args.get(1).cloned();
    let fillchar = args.get(2).cloned();
    for (name, value) in keywords {
        match name.as_str() {
            "self" => {
                if receiver.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'self'"
                    ));
                }
                receiver = Some(value);
            }
            "width" => {
                if width.is_some() {
                    return Err(format!(
                        "TypeError: UserString.{method}() got multiple values for argument 'width'"
                    ));
                }
                width = Some(value);
            }
            _ => {
                return Err(format!(
                    "TypeError: UserString.{method}() got an unexpected keyword argument '{name}'"
                ));
            }
        }
    }
    let mut missing = Vec::new();
    if receiver.is_none() {
        missing.push("self");
    }
    if width.is_none() {
        missing.push("width");
    }
    if !missing.is_empty() {
        return Err(user_string_method_missing_required(method, &missing));
    }
    let too_many_args = if args.len() > 3 {
        Some(args.len() - 1)
    } else {
        None
    };
    Ok((
        receiver.expect("missing receiver handled above"),
        width.expect("missing width handled above"),
        fillchar,
        too_many_args,
    ))
}

